def _google_drive_sync_warning(exc: Exception) -> str:
    message = str(exc or "")
    lowered = message.lower()
    if "storagequotaexceeded" in lowered or "service accounts do not have storage quota" in lowered:
        return (
            "אישור המסירה נשמר מקומית ובשיטס, אבל לא הועלה לגוגל דרייב. "
            "חבר את Google Drive שלך בכתובת /google-drive/oauth/start כדי שהעלאות יעבדו ישירות ל-My Drive שלך."
        )
    if "accessnotconfigured" in lowered or "google drive api has not been used" in lowered:
        return (
            "אישור המסירה נשמר מקומית ובשיטס, אבל לא הועלה לגוגל דרייב כי Google Drive API "
            "עדיין לא זמין בפועל לפרויקט הזה. נסה שוב בעוד כמה דקות."
        )
    return "אישור המסירה נשמר מקומית ובשיטס, אבל הסנכרון לגוגל דרייב נכשל כרגע."


def _admin_drive_asset_view_link(asset: dict) -> str:
    web_view = str(asset.get("web_view_link") or "").strip()
    if web_view:
        return web_view
    file_id = str(asset.get("id") or "").strip()
    if not file_id:
        raise FileNotFoundError("קובץ מנהלה לא סונכרן ל-Google Drive.")
    return f"https://drive.google.com/file/d/{file_id}/view"


def _absolute_greeninvoice_url(base_url: str, value: str) -> str:
    raw = str(value or "").strip()
    if not raw:
        return ""
    if raw.startswith("http://") or raw.startswith("https://"):
        return _normalize_greeninvoice_url(raw)
    normalized_base = str(base_url or "").strip()
    if not normalized_base:
        return raw
    return _normalize_greeninvoice_url(urljoin(normalized_base.rstrip("/") + "/", raw.lstrip("/")))


def _looks_like_http_url(value: str) -> bool:
    raw = str(value or "").strip()
    return raw.startswith("http://") or raw.startswith("https://")


def _looks_like_drive_file_id(value: str) -> bool:
    raw = str(value or "").strip()
    return bool(re.fullmatch(r"[A-Za-z0-9_-]{20,}", raw))


def _drive_file_view_link(file_id: str) -> str:
    raw = str(file_id or "").strip()
    if not raw:
        return ""
    return f"https://drive.google.com/file/d/{raw}/view"


def _normalize_drive_view_link(value: str) -> str:
    raw = str(value or "").strip()
    if not raw:
        return ""
    file_id = _extract_drive_file_id_from_url(raw)
    if file_id:
        return _drive_file_view_link(file_id)
    return raw.replace("usp=drivesdk", "usp=sharing")


def _extract_drive_file_id_from_url(value: str) -> str:
    raw = str(value or "").strip()
    if not raw:
        return ""
    match = re.search(r"/file/d/([A-Za-z0-9_-]{20,})", raw)
    if match:
        return str(match.group(1) or "").strip()
    match = re.search(r"[?&]id=([A-Za-z0-9_-]{20,})", raw)
    if match:
        return str(match.group(1) or "").strip()
    return ""


def _extract_marketing_pipeline_quote_link_from_row(row: dict) -> tuple[str, str]:
    preferred_id_fields = (
        "quote_drive_file_id",
        "comm_sent_at",
    )
    preferred_url_fields = (
        "quote_drive_url",
        "quote_source_url",
        "comm_status",
        "mail_subject",
    )

    for field in preferred_id_fields:
        value = str(row.get(field) or "").strip()
        if _looks_like_drive_file_id(value):
            return _drive_file_view_link(value), field

    for field in preferred_url_fields:
        value = str(row.get(field) or "").strip()
        if field in {"quote_drive_url", "comm_status"}:
            paired_id = str(row.get("quote_drive_file_id") or row.get("comm_sent_at") or "").strip()
            if _looks_like_drive_file_id(paired_id):
                return _drive_file_view_link(paired_id), field
            drive_id_from_url = _extract_drive_file_id_from_url(value)
            if _looks_like_drive_file_id(drive_id_from_url):
                return _drive_file_view_link(drive_id_from_url), field
        if _looks_like_http_url(value):
            return value, field

    for field, raw_value in row.items():
        value = str(raw_value or "").strip()
        if _looks_like_http_url(value):
            drive_id_from_url = _extract_drive_file_id_from_url(value)
            if _looks_like_drive_file_id(drive_id_from_url):
                return _drive_file_view_link(drive_id_from_url), str(field)
            return value, str(field)

    for field, raw_value in row.items():
        value = str(raw_value or "").strip()
        if _looks_like_drive_file_id(value):
            return _drive_file_view_link(value), str(field)

    return "", ""


