async def _prime_marketing_drive_assets() -> list[dict]:
    assets: list[dict] = []
    async with MARKETING_DRIVE_ASSET_LOCK:
        for key, spec in MARKETING_DRIVE_ASSETS.items():
            try:
                asset = _ensure_marketing_drive_asset(key)
                assets.append(
                    {
                        "asset_key": key,
                        "label": str(spec.get("label") or key),
                        "category": str(spec.get("category") or ""),
                        "drive_name": str(asset.get("name") or spec.get("drive_name") or ""),
                        "drive_url": _marketing_drive_asset_view_link(asset),
                    }
                )
            except Exception as exc:
                log_handled_error(f"marketing drive asset prime failed for {key}", exc)
                assets.append(
                    {
                        "asset_key": key,
                        "label": str(spec.get("label") or key),
                        "category": str(spec.get("category") or ""),
                        "drive_name": str(spec.get("drive_name") or Path(spec["local_path"]).name),
                        "drive_url": "",
                        "error": str(exc),
                    }
                )
    return assets


def _marketing_drive_thumbnail_url(asset_key: str) -> str:
    """Return a Google Drive thumbnail URL — uses cache or does a live Drive lookup."""
    cached = MARKETING_DRIVE_ASSET_CACHE.get(asset_key) or {}
    file_id = str(cached.get("id") or "").strip()
    if file_id:
        return f"https://drive.google.com/thumbnail?id={file_id}&sz=w480"
    # Live lookup: find the file in Drive by name
    try:
        from services.google_drive_sync import _find_file_in_folder, _find_child_folder
        spec = MARKETING_DRIVE_ASSETS.get(asset_key)
        if not spec:
            return ""
        service = _google_drive_service()
        root_id = _ensure_marketing_drive_root_folder()
        # Navigate into sub-folders (spec["folders"])
        folder_id = root_id
        for folder_name in (spec.get("folders") or []):
            fid = _find_child_folder(service, folder_id, folder_name)
            if not fid:
                return ""
            folder_id = fid
        drive_name = str(spec.get("drive_name") or "")
        if not drive_name:
            return ""
        record = _find_file_in_folder(service, folder_id, drive_name)
        if record and record.get("id"):
            MARKETING_DRIVE_ASSET_CACHE[asset_key] = record
            return f"https://drive.google.com/thumbnail?id={record['id']}&sz=w480"
    except Exception:
        pass
    return ""


def _ensure_marketing_preview_image(asset_key: str) -> str:
    spec = MARKETING_DRIVE_ASSETS.get(asset_key)
    if not spec:
        return _marketing_drive_thumbnail_url(asset_key) or f"/marketing-doc-preview/{asset_key}"
    local_path = Path(spec["local_path"])
    if not local_path.exists():
        # On Vercel: always use proxy endpoint (not direct Drive URL which requires browser auth)
        return f"/marketing-doc-preview/{asset_key}"

    source_mtime = 0.0
    try:
        source_mtime = local_path.stat().st_mtime
    except Exception:
        source_mtime = 0.0

    suffix = local_path.suffix.lower()
    if suffix in {".jpg", ".jpeg", ".png", ".webp", ".gif"}:
        target_name = f"{asset_key}{suffix}"
        target_path = MARKETING_PREVIEW_CACHE_DIR / target_name
        try:
            if not target_path.exists() or target_path.stat().st_mtime < source_mtime:
                shutil.copy2(local_path, target_path)
            version = int(target_path.stat().st_mtime)
            return f"/static/cache/marketing_previews/{quote(target_name)}?v={version}"
        except Exception:
            return f"/marketing-doc-preview/{asset_key}"

    if suffix == ".pdf":
        target_name = f"{asset_key}.png"
        target_path = MARKETING_PREVIEW_CACHE_DIR / target_name
        try:
            if not target_path.exists() or target_path.stat().st_mtime < source_mtime:
                generated = False
                # Try qlmanage (macOS)
                try:
                    with tempfile.TemporaryDirectory(prefix="marketing-preview-") as tmpdir:
                        subprocess.run(
                            ["qlmanage", "-t", "-s", "420", "-o", tmpdir, str(local_path)],
                            check=True, capture_output=True, text=True,
                        )
                        gen = Path(tmpdir) / f"{local_path.name}.png"
                        if gen.exists():
                            shutil.copy2(gen, target_path)
                            generated = True
                except Exception:
                    pass
                # Fallback: PyMuPDF
                if not generated:
                    import fitz
                    doc = fitz.open(str(local_path))
                    page = doc.load_page(0)
                    pix = page.get_pixmap(matrix=fitz.Matrix(1.5, 1.5), alpha=False)
                    pix.save(str(target_path))
                    doc.close()
            version = int(target_path.stat().st_mtime)
            return f"/static/cache/marketing_previews/{quote(target_name)}?v={version}"
        except Exception as exc:
            log_handled_error(f"marketing preview build failed for {asset_key}", exc)
            return _marketing_drive_thumbnail_url(asset_key) or f"/marketing-doc-preview/{asset_key}"

    return f"/marketing-doc-preview/{asset_key}"


def _parse_iso_datetime_safe(value: str) -> datetime | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    for candidate in (raw, raw.replace("Z", "+00:00")):
        try:
            return datetime.fromisoformat(candidate)
        except Exception:
            continue
    for pattern in ("%Y-%m-%d", "%d/%m/%Y", "%Y-%m-%d %H:%M:%S", "%d.%m.%Y"):
        try:
            return datetime.strptime(raw, pattern)
        except Exception:
            continue
    return None


def _app_state_enabled(domain: str) -> bool:
    return supabase_store.is_enabled() and supabase_store.supports_domain(domain)


def _load_supabase_app_state(domain: str) -> dict | None:
    if not _app_state_enabled(domain):
        return None
    try:
        rows = supabase_store.fetch_domain_rows(domain)
    except Exception:
        return None
    for row in rows:
        if isinstance(row, dict):
            return dict(row)
    return None


def _save_supabase_app_state(domain: str, payload: dict) -> dict | None:
    if not _app_state_enabled(domain):
        return None
    normalized = dict(payload or {})
    try:
        supabase_store.replace_domain_rows(domain, [normalized])
        return normalized
    except Exception:
        return None


_ORDER_HISTORY_VISIBLE_FROM = date(2025, 11, 1)


def _order_history_row_passes_cutoff(row: dict | None) -> bool:
    candidate = dict(row or {})
    for field in ("created_at", "po_date", "updated_at"):
        parsed = _parse_iso_datetime_safe(candidate.get(field) or "")
        if parsed:
            return parsed.date() >= _ORDER_HISTORY_VISIBLE_FROM
    return False


def _marketing_customer_key(row: dict | None) -> str:
    row = dict(row or {})
    for field in ("customer_key", "customer_guid", "customer_id"):
        value = str(row.get(field) or "").strip()
        if value:
            return value
    name = _canonical_income_customer_name(row.get("customer_name") or "")
    return f"name:{name}" if name else ""


def _load_hidden_marketing_pipeline_keys() -> set[str]:
    try:
        hidden: set[str] = set()
        supabase_payload = _load_supabase_app_state("app_hidden_marketing_pipeline_keys")
        if isinstance(supabase_payload, dict):
            items = supabase_payload.get("hidden_keys") or []
            if isinstance(items, list):
                hidden.update(str(item or "").strip() for item in items if str(item or "").strip())
        if MARKETING_PIPELINE_HIDDEN_FILE.exists():
            payload = json.loads(MARKETING_PIPELINE_HIDDEN_FILE.read_text(encoding="utf-8"))
            if isinstance(payload, dict):
                items = payload.get("hidden_keys") or []
            else:
                items = payload
            if isinstance(items, list):
                hidden.update(str(item or "").strip() for item in items if str(item or "").strip())

        # Rebuild deletions from the durable marketing history sheet as a fallback,
        # so rows that were deleted in the past do not come back after rebuilds.
        try:
            for history_row in load_marketing_rows("history"):
                if str(history_row.get("action_type") or "").strip() != "pipeline_delete":
                    continue
                customer_key = str(history_row.get("customer_key") or "").strip()
                if customer_key:
                    hidden.add(customer_key)
                details_raw = str(history_row.get("details_json") or "").strip()
                if not details_raw:
                    continue
                try:
                    details = json.loads(details_raw)
                except Exception:
                    continue
                quote_number = str((details or {}).get("quote_number") or "").strip()
                if quote_number:
                    hidden.add(f"quote:{quote_number}")
        except Exception:
            pass
        return hidden
    except Exception:
        return set()


def _save_hidden_marketing_pipeline_keys(hidden_keys: set[str]) -> None:
    payload = {
        "updated_at": datetime.now().isoformat(timespec="seconds"),
        "hidden_keys": sorted({str(key or "").strip() for key in hidden_keys if str(key or "").strip()}),
    }
    _save_supabase_app_state("app_hidden_marketing_pipeline_keys", payload)
    try:
        MARKETING_PIPELINE_HIDDEN_FILE.write_text(
            json.dumps(payload, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
    except Exception:
        pass


def _customer_hidden_key(row: dict | None) -> str:
    row = dict(row or {})
    mode = _customer_mode_label(row.get("source_mode") or "")
    guid = str(row.get("customer_guid") or "").strip()
    if guid:
        return f"{mode}|guid:{guid}"
    customer_id = re.sub(r"\D+", "", str(row.get("customer_id") or ""))
    if customer_id:
        return f"{mode}|id:{customer_id}"
    customer_name = _canonical_income_customer_name(row.get("customer_name") or "")
    return f"{mode}|name:{customer_name}" if customer_name else ""


def _load_hidden_customer_keys() -> set[str]:
    try:
        hidden: set[str] = set()
        supabase_payload = _load_supabase_app_state("app_hidden_customer_keys")
        if isinstance(supabase_payload, dict):
            items = supabase_payload.get("hidden_keys") or []
            if isinstance(items, list):
                hidden.update(str(item or "").strip() for item in items if str(item or "").strip())
        if CUSTOMERS_HIDDEN_FILE.exists():
            payload = json.loads(CUSTOMERS_HIDDEN_FILE.read_text(encoding="utf-8"))
            items = payload.get("hidden_keys") if isinstance(payload, dict) else payload
            if isinstance(items, list):
                hidden.update(str(item or "").strip() for item in items if str(item or "").strip())
        return hidden
    except Exception:
        return set()


def _save_hidden_customer_keys(hidden_keys: set[str]) -> None:
    payload = {
        "updated_at": datetime.now().isoformat(timespec="seconds"),
        "hidden_keys": sorted({str(key or "").strip() for key in hidden_keys if str(key or "").strip()}),
    }
    _save_supabase_app_state("app_hidden_customer_keys", payload)
