def _filter_hidden_customer_rows(rows: list[dict]) -> list[dict]:
    hidden_keys = _load_hidden_customer_keys()
    if not hidden_keys:
        return [dict(row) for row in (rows or [])]
    return [dict(row) for row in (rows or []) if _customer_hidden_key(row) not in hidden_keys]


def _default_payments_receipt_sync_meta() -> dict:
    return {
        "pending_sync": False,
        "last_checked_date": "",
        "last_receipt_generated_at": "",
        "updated_at": "",
    }


def _load_payments_receipt_sync_meta() -> dict:
    try:
        supabase_payload = _load_supabase_app_state("app_payments_receipt_sync_meta")
        if isinstance(supabase_payload, dict):
            merged = _default_payments_receipt_sync_meta()
            merged.update(supabase_payload)
            merged["pending_sync"] = bool(merged.get("pending_sync"))
            merged["last_checked_date"] = str(merged.get("last_checked_date") or "").strip()
            merged["last_receipt_generated_at"] = str(merged.get("last_receipt_generated_at") or "").strip()
            merged["updated_at"] = str(merged.get("updated_at") or "").strip()
            return merged
        if not PAYMENTS_RECEIPT_SYNC_META_FILE.exists():
            return _default_payments_receipt_sync_meta()
        payload = json.loads(PAYMENTS_RECEIPT_SYNC_META_FILE.read_text(encoding="utf-8"))
        if not isinstance(payload, dict):
            return _default_payments_receipt_sync_meta()
        merged = _default_payments_receipt_sync_meta()
        merged.update(payload)
        merged["pending_sync"] = bool(merged.get("pending_sync"))
        merged["last_checked_date"] = str(merged.get("last_checked_date") or "").strip()
        merged["last_receipt_generated_at"] = str(merged.get("last_receipt_generated_at") or "").strip()
        merged["updated_at"] = str(merged.get("updated_at") or "").strip()
        return merged
    except Exception:
        return _default_payments_receipt_sync_meta()


def _save_payments_receipt_sync_meta(meta: dict) -> dict:
    payload = _default_payments_receipt_sync_meta()
    payload.update(meta or {})
    payload["pending_sync"] = bool(payload.get("pending_sync"))
    payload["last_checked_date"] = str(payload.get("last_checked_date") or "").strip()
    payload["last_receipt_generated_at"] = str(payload.get("last_receipt_generated_at") or "").strip()
    payload["updated_at"] = datetime.now().isoformat(timespec="seconds")
    _save_supabase_app_state("app_payments_receipt_sync_meta", payload)
    try:
        PAYMENTS_RECEIPT_SYNC_META_FILE.write_text(
            json.dumps(payload, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
    except Exception:
        pass
    return payload


def _mark_payments_receipt_sync_pending() -> dict:
    meta = _load_payments_receipt_sync_meta()
    meta["pending_sync"] = True
    meta["last_receipt_generated_at"] = datetime.now().isoformat(timespec="seconds")
    return _save_payments_receipt_sync_meta(meta)


def _complete_payments_receipt_sync_check() -> dict:
    meta = _load_payments_receipt_sync_meta()
    meta["pending_sync"] = False
    meta["last_checked_date"] = date.today().isoformat()
    return _save_payments_receipt_sync_meta(meta)


def _parse_payment_sync_date(value: str) -> date | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    for pattern in ("%Y-%m-%d", "%d/%m/%Y", "%d/%m/%y"):
        try:
            return datetime.strptime(raw, pattern).date()
        except Exception:
            continue
    return None


def _payment_row_invoice_date(row: dict | None) -> date | None:
    row = dict(row or {})
    return _parse_payment_sync_date(row.get("invoice_date") or "")


def _marketing_pipeline_customer_key(
    customer_name: str = "",
    customer_id: str = "",
    customer_guid: str = "",
    client_id: str = "",
) -> str:
    customer_id_digits = re.sub(r"\D+", "", str(customer_id or ""))
    if customer_id_digits:
        return f"tax:{customer_id_digits}"
    guid_value = str(customer_guid or client_id or "").strip()
    if guid_value:
        return f"guid:{guid_value}"
    canonical_name = _canonical_income_customer_name(customer_name or "")
    return f"name:{canonical_name}" if canonical_name else ""


