async def _marketing_pipeline_quote_documents_by_id(
    rows: list[dict],
    progress_callback=None,
) -> tuple[GreenInvoiceClient, str, dict[str, dict], list[str]]:
    cfg = get_mode_config("prod")
    client = GreenInvoiceClient(
        base_url=cfg["base_url"],
        api_key=cfg["api_key"],
        api_secret=cfg["api_secret"],
    )
    token = await client._get_token()
    documents_by_id: dict[str, dict] = {}
    warnings: list[str] = []
    unique_document_ids = [
        str(row.get("quote_document_id") or "").strip()
        for row in rows or []
        if str(row.get("quote_document_id") or "").strip()
    ]
    total_documents = len(dict.fromkeys(unique_document_ids))
    processed_documents = 0
    if callable(progress_callback):
        progress_callback(
            percent=8 if total_documents else 72,
            title="מכין אקסל מחירים...",
            message=f"מושך עכשיו את פרטי הצעות המחיר מחשבונית ירוקה ({processed_documents}/{total_documents}).",
        )
    for row in rows or []:
        document_id = str(row.get("quote_document_id") or "").strip()
        customer_name = str(row.get("customer_name") or "").strip()
        quote_number = str(row.get("quote_number") or "").strip()
        if not document_id or document_id in documents_by_id:
            continue
        try:
            detail = await _marketing_fetch_quote_document_detail(client, token, document_id)
            if isinstance(detail, dict):
                documents_by_id[document_id] = detail
        except Exception as exc:
            warnings.append(f"{customer_name or 'לקוח ללא שם'} / {quote_number or document_id}: {exc}")
        finally:
            processed_documents += 1
            if callable(progress_callback):
                percent = 8 + ((processed_documents / total_documents) * 64 if total_documents else 64)
                progress_callback(
                    percent=percent,
                    title="מכין אקסל מחירים...",
                    message=f"מושך עכשיו את פרטי הצעות המחיר מחשבונית ירוקה ({processed_documents}/{total_documents}).",
                )
    return client, token, documents_by_id, warnings


async def _build_marketing_pipeline_pricing_export_file(progress_callback=None) -> tuple[Path, dict]:
    from openpyxl import Workbook
    from openpyxl.styles import Alignment, Font, PatternFill

    rows = load_marketing_rows("pipeline", force_refresh=False)
    if callable(progress_callback):
        progress_callback(percent=3, title="מכין אקסל מחירים...", message="טוען עכשיו את טבלת לקוחות השיווק השמורה.")
    _client, _token, documents_by_id, warnings = await _marketing_pipeline_quote_documents_by_id(rows, progress_callback=progress_callback)
    workbook = Workbook()
    sheet = workbook.active
    sheet.title = "הצעות שיווק"
    headers = [
        "שם החברה",
        "ח.פ",
        "מספר הצעת מחיר",
        "תאריך הצעת מחיר",
        "שורה",
        "פירוט מוצר / שירות",
        "מק\"ט",
        "יחידה",
        "כמות",
        "מחיר יחידה",
        "סה\"כ שורה",
        "customer_key",
        "customer_guid",
        "quote_document_id",
        "quote_number_meta",
        "line_index",
        "original_description",
        "original_sku",
        "original_unit",
        "original_quantity",
        "original_unit_price",
        "original_line_total",
    ]
    sheet.append(headers)
    header_fill = PatternFill(fill_type="solid", fgColor="E8F1FB")
    for cell in sheet[1]:
        cell.font = Font(bold=True)
        cell.alignment = Alignment(horizontal="center")
        cell.fill = header_fill
    for column, width in {
        "A": 28,
        "B": 16,
        "C": 16,
        "D": 16,
        "E": 8,
        "F": 60,
        "G": 18,
        "H": 12,
        "I": 10,
        "J": 14,
        "K": 14,
    }.items():
        sheet.column_dimensions[column].width = width
    for hidden_col in ("L", "M", "N", "O", "P", "Q", "R", "S", "T", "U", "V"):
        sheet.column_dimensions[hidden_col].hidden = True

    exported_quotes = 0
    exported_lines = 0
    total_rows = len(rows or [])
    for row_index, row in enumerate(rows, start=1):
        document_id = str(row.get("quote_document_id") or "").strip()
        detail = documents_by_id.get(document_id) or {}
        items = _marketing_quote_items_from_document_detail(detail)
        if not items:
            fallback_description = str(row.get("item_name") or "").strip()
            if fallback_description:
                items = [{"description": fallback_description, "sku": "", "unit": "", "quantity": "", "unit_price": "", "line_total": ""}]
            else:
                warnings.append(f"{row.get('customer_name') or 'לקוח ללא שם'} / {row.get('quote_number') or document_id}: לא נמצאו שורות להצעת המחיר.")
                continue
        exported_quotes += 1
        for index, item in enumerate(items, start=1):
            normalized_item = _normalize_marketing_quote_update_item(item)
            sheet.append([
                str(row.get("customer_name") or "").strip(),
                str(row.get("customer_id") or "").strip(),
                str(row.get("quote_number") or "").strip(),
                str(row.get("quote_date") or "").strip(),
                index,
                normalized_item.get("description") or "",
                normalized_item.get("sku") or "",
                normalized_item.get("unit") or "",
                normalized_item.get("quantity") if normalized_item.get("quantity") else "",
                normalized_item.get("unit_price") if normalized_item.get("unit_price") else "",
                normalized_item.get("line_total") if normalized_item.get("line_total") else "",
                str(row.get("customer_key") or "").strip(),
                str(row.get("customer_guid") or "").strip(),
                document_id,
                str(row.get("quote_number") or "").strip(),
                index,
                normalized_item.get("description") or "",
                normalized_item.get("sku") or "",
                normalized_item.get("unit") or "",
                normalized_item.get("quantity") if normalized_item.get("quantity") else "",
                normalized_item.get("unit_price") if normalized_item.get("unit_price") else "",
                normalized_item.get("line_total") if normalized_item.get("line_total") else "",
            ])
            exported_lines += 1
        if callable(progress_callback):
            percent = 74 + ((row_index / total_rows) * 22 if total_rows else 22)
            progress_callback(
                percent=percent,
                title="מכין אקסל מחירים...",
                message=f"בונה עכשיו את שורות האקסל מתוך הצעות המחיר ({row_index}/{total_rows}).",
            )
    sheet.freeze_panes = "A2"
    if callable(progress_callback):
        progress_callback(percent=98, title="מכין אקסל מחירים...", message="שומר עכשיו את קובץ האקסל ומכין אותו להורדה.")
    export_path = _marketing_quote_export_dir() / _marketing_quote_export_file_name()
    workbook.save(export_path)
    return export_path, {
        "quotes_count": exported_quotes,
        "lines_count": exported_lines,
        "warnings": warnings,
        "documents_loaded": len(documents_by_id),
        "source": "greeninvoice",
    }


async def _run_marketing_pipeline_pricing_export_task(task_id: str) -> None:
    def report(percent: float, title: str, message: str) -> None:
        _set_marketing_pipeline_pricing_export_task(
            task_id,
            status="running",
            percent=max(0, min(100, round(float(percent or 0), 1))),
            title=title,
            message=message,
            error="",
        )

    try:
        report(1, "מכין אקסל מחירים...", "מתחיל עכשיו לבנות את קובץ המחירים מתוך הצעות המחיר שנשלחו.")
        export_path, summary = await _build_marketing_pipeline_pricing_export_file(progress_callback=report)
        _set_marketing_pipeline_pricing_export_task(
            task_id,
            status="ready",
            percent=100,
            title="האקסל מוכן",
            message="הקובץ הוכן בהצלחה ומוכן עכשיו להורדה למחשב.",
            file_path=str(export_path),
            filename=export_path.name,
            summary=summary,
            error="",
        )
    except Exception as exc:
        log_handled_error("marketing pipeline pricing export task failed", exc)
        _set_marketing_pipeline_pricing_export_task(
            task_id,
            status="error",
            percent=100,
            title="הייצוא נכשל",
            message="לא הצלחתי להשלים את יצירת האקסל.",
            error=str(exc),
        )


