WORK_MANAGERS_CSV_PATH = Path("/Users/asafbeny/Downloads/שיווק - מאגר נתונים מעודכן/מנהלי_עבודה_עם_טלפון.csv")
WORK_MANAGERS_PROJECT_MANAGER_SYNC_INTERVAL = timedelta(days=7)


def _work_manager_phone_digits(value: str) -> str:
    digits = re.sub(r"\D+", "", str(value or ""))
    if len(digits) == 9 and digits.startswith("5"):
        return f"0{digits}"
    return digits


def _work_manager_mobile_digits(value: str) -> str:
    digits = _work_manager_phone_digits(value)
    return digits if len(digits) == 10 and digits.startswith("05") else ""


def _work_manager_phone_display(value: str) -> str:
    digits = _work_manager_phone_digits(value)
    if len(digits) == 10 and digits.startswith("0"):
        return f"{digits[:3]}-{digits[3:]}"
    if len(digits) == 9 and digits.startswith("0"):
        return f"{digits[:2]}-{digits[2:]}"
    return str(value or "").strip()


def _split_work_manager_phones(value) -> list[str]:
    if isinstance(value, list):
        parts = [str(item or "").strip() for item in value]
    else:
        parts = re.split(r"[,\n;/|]+", str(value or ""))
    values: list[str] = []
    seen: set[str] = set()
    for part in parts:
        digits = _work_manager_phone_digits(part)
        if not digits or digits in seen:
            continue
        seen.add(digits)
        values.append(_work_manager_phone_display(digits))
    return values[:3]


def _work_manager_name_key(value: str) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip().lower())


def _work_manager_company_key(value: str) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip().lower())


def _work_manager_row_id(row: dict) -> str:
    details_url = str(row.get("details_url") or row.get("דף פרטים") or "").strip()
    if details_url:
        try:
            query = parse_qs(urlparse(details_url).query)
            auth_id = str((query.get("AuthorizationId") or [""])[0] or "").strip()
            if auth_id:
                return f"wm-{auth_id}"
        except Exception:
            pass
    phones = "".join(_split_work_manager_phones(row.get("טלפונים") or [row.get("phone_1"), row.get("phone_2"), row.get("phone_3")]))
    basis = f"{row.get('שם מלא') or row.get('full_name') or ''}|{phones}"
    return f"wm-{abs(hash(basis))}"


def _normalize_work_manager_row_app(row: dict) -> dict:
    name = re.sub(r"\s+", " ", str(row.get("full_name") or row.get("שם מלא") or "").strip())
    employer = re.sub(r"\s+", " ", str(row.get("current_employer") or row.get("מעסיק נוכחי") or row.get("company_name") or "").strip())
    workplace = re.sub(r"\s+", " ", str(row.get("current_workplace") or row.get("מקום עבודה נוכחי") or "").strip())
    email_text = ", ".join([item.strip() for item in re.split(r"[;,]+", str(row.get("email") or row.get('דוא"ל') or "")) if item.strip()])
    phones = _split_work_manager_phones(row.get("טלפונים") or [row.get("phone_1"), row.get("phone_2"), row.get("phone_3")])
    normalized = {
        "row_id": str(row.get("row_id") or _work_manager_row_id(row)).strip(),
        "full_name": name,
        "company_name": re.sub(r"\s+", " ", str(row.get("company_name") or employer).strip()),
        "email": email_text,
        "phone_1": phones[0] if len(phones) > 0 else "",
        "phone_2": phones[1] if len(phones) > 1 else "",
        "phone_3": phones[2] if len(phones) > 2 else "",
        "active_status": "כן" if str(row.get("active_status") or row.get("מינוי נוכחי") or "").strip().lower() in {"כן", "yes", "true", "1", "active"} else "לא",
        "current_employer": employer,
        "current_workplace": workplace,
        "details_url": str(row.get("details_url") or row.get("דף פרטים") or "").strip(),
        "project_manager_match": "true" if str(row.get("project_manager_match") or "").strip().lower() in {"1", "true", "yes", "כן"} else "false",
        "project_manager_checked_at": str(row.get("project_manager_checked_at") or "").strip(),
        "updated_at": str(row.get("updated_at") or datetime.now().isoformat(timespec="seconds")).strip(),
    }
    if not normalized["current_employer"] and normalized["company_name"]:
        normalized["current_employer"] = normalized["company_name"]
    if not normalized["company_name"] and normalized["current_employer"]:
        normalized["company_name"] = normalized["current_employer"]
    return normalized


def _dedupe_work_manager_rows(rows: list[dict]) -> list[dict]:
    deduped: dict[str, dict] = {}
    for row in rows or []:
        normalized = _normalize_work_manager_row_app(row)
        key = normalized["row_id"] or f"{_work_manager_name_key(normalized['full_name'])}|{_work_manager_phone_digits(normalized['phone_1'])}"
        current = deduped.get(key)
        if not current:
            deduped[key] = normalized
            continue
        for field_name in ("full_name", "company_name", "email", "phone_1", "phone_2", "phone_3", "current_employer", "current_workplace", "details_url"):
            if str(current.get(field_name) or "").strip():
                continue
            value = str(normalized.get(field_name) or "").strip()
            if value:
                current[field_name] = value
        if current.get("active_status") != "כן" and normalized.get("active_status") == "כן":
            current["active_status"] = "כן"
        current["updated_at"] = normalized.get("updated_at") or current.get("updated_at") or datetime.now().isoformat(timespec="seconds")
    return list(deduped.values())


def _seed_work_manager_rows_from_csv() -> list[dict]:
    if not WORK_MANAGERS_CSV_PATH.exists():
        return []
    with WORK_MANAGERS_CSV_PATH.open("r", encoding="utf-8-sig", newline="") as handle:
        reader = csv.DictReader(handle)
        rows = []
        for raw in reader:
            if not any(str(value or "").strip() for value in raw.values()):
                continue
            rows.append(_normalize_work_manager_row_app(raw))
    rows = _dedupe_work_manager_rows(rows)
    if rows:
        save_marketing_rows("work_managers", rows)
    return rows


def _maybe_refresh_work_manager_project_matches(rows: list[dict], force: bool = False) -> tuple[list[dict], bool]:
    now = datetime.now()
    def _checked_at_is_stale(value: str) -> bool:
        raw = str(value or "").strip()
        if not raw:
            return True
        try:
            parsed = datetime.fromisoformat(raw.replace("Z", "+00:00"))
        except Exception:
            return True
        if parsed.tzinfo is not None:
            parsed = parsed.astimezone().replace(tzinfo=None)
        return (now - parsed) >= WORK_MANAGERS_PROJECT_MANAGER_SYNC_INTERVAL

    should_refresh = force or any(_checked_at_is_stale(row.get("project_manager_checked_at", "")) for row in (rows or [])[:25])
    if not should_refresh:
        return rows, False
    pm_phone_digits = {
        _work_manager_phone_digits(str(item.get("contact_phone") or ""))
        for item in load_project_manager_rows()
        if _work_manager_phone_digits(str(item.get("contact_phone") or ""))
    }
    changed = False
    refreshed: list[dict] = []
    checked_at = now.isoformat(timespec="seconds")
    for row in rows or []:
        updated = dict(row)
        row_phones = {
            _work_manager_phone_digits(updated.get("phone_1", "")),
            _work_manager_phone_digits(updated.get("phone_2", "")),
            _work_manager_phone_digits(updated.get("phone_3", "")),
        }
        row_phones.discard("")
        matched = "true" if row_phones & pm_phone_digits else "false"
        if matched != str(updated.get("project_manager_match") or "").strip().lower() or str(updated.get("project_manager_checked_at") or "").strip() != checked_at:
            updated["project_manager_match"] = matched
            updated["project_manager_checked_at"] = checked_at
            updated["updated_at"] = datetime.now().isoformat(timespec="seconds")
            changed = True
        refreshed.append(_normalize_work_manager_row_app(updated))
    return refreshed, changed


def _construction_company_row_id(row: dict) -> str:
    company_id = re.sub(r"\D+", "", str(row.get("company_id") or row.get("ח.פ") or "").strip())
    if company_id:
        return f"cc-{company_id}"
    details_url = str(row.get("details_url") or row.get("אתר אינטרנט") or row.get("דף פרטים") or "").strip()
    if details_url:
        return f"cc-{abs(hash(details_url))}"
    company_name = row.get("company_name") or row.get("חברה") or ""
    phone = row.get("phone") or row.get("טלפון") or ""
    email = row.get("email") or row.get('דוא"ל') or ""
    basis = f"{company_name}|{phone}|{email}"
    return f"cc-{abs(hash(basis))}"


def _normalize_construction_company_row_app(row: dict) -> dict:
    company_name = re.sub(r"\s+", " ", str(row.get("company_name") or row.get("חברה") or "").strip())
    email_text = ", ".join([item.strip() for item in re.split(r"[;,]+", str(row.get("email") or row.get('דוא"ל') or "")) if item.strip()])
    normalized = {
        "row_id": str(row.get("row_id") or _construction_company_row_id(row)).strip(),
        "company_name": company_name,
        "company_id": re.sub(r"\D+", "", str(row.get("company_id") or row.get("ח.פ") or "")),
        "phone": _work_manager_phone_display(row.get("phone") or row.get("טלפון") or ""),
        "address": re.sub(r"\s+", " ", str(row.get("address") or row.get("כתובת") or "").strip()),
        "email": email_text,
        "details_url": str(row.get("details_url") or row.get("אתר אינטרנט") or row.get("דף פרטים") or "").strip(),
        "notes": str(row.get("notes") or row.get("הערות") or "").strip(),
        "updated_at": str(row.get("updated_at") or datetime.now().isoformat(timespec="seconds")).strip(),
    }
    return normalized


def _dedupe_construction_company_rows(rows: list[dict]) -> list[dict]:
    deduped: dict[str, dict] = {}
    for row in rows or []:
        normalized = _normalize_construction_company_row_app(row)
        key = normalized["row_id"] or f"{normalized['company_id']}|{normalized['company_name']}|{_work_manager_phone_digits(normalized['phone'])}"
        current = deduped.get(key)
        if not current:
            deduped[key] = normalized
            continue
        for field_name in ("company_name", "company_id", "phone", "address", "email", "details_url", "notes"):
            if str(current.get(field_name) or "").strip():
                continue
            value = str(normalized.get(field_name) or "").strip()
            if value:
                current[field_name] = value
        current["updated_at"] = normalized.get("updated_at") or current.get("updated_at") or datetime.now().isoformat(timespec="seconds")
    return list(deduped.values())


def _build_marketing_construction_companies_payload(force_refresh: bool = False) -> dict:
    rows = load_marketing_rows("construction_companies", force_refresh=force_refresh)
    rows = _dedupe_construction_company_rows(rows)
    if rows != load_marketing_rows("construction_companies", force_refresh=False):
        save_marketing_rows("construction_companies", rows)
    phones = [_work_manager_phone_digits(row.get("phone", "")) for row in rows if _work_manager_phone_digits(row.get("phone", ""))]
    emails = [
        email.strip()
        for row in rows
        for email in re.split(r"[;,]+", str(row.get("email") or ""))
        if email.strip()
    ]
    links = [str(row.get("details_url") or "").strip() for row in rows if str(row.get("details_url") or "").strip()]
    return {
        "rows": rows,
        "summary": {
            "count": len(rows),
            "phone_count": len({item for item in phones}),
            "email_count": len({item.lower() for item in emails}),
            "link_count": len(links),
        },
    }


def _build_marketing_construction_companies_xlsx(rows: list[dict]) -> bytes:
    headers = [
        "מזהה רשומה",
        "חברה",
        "ח.פ",
        "טלפון",
        "כתובת",
        "דוא\"ל",
        "אתר אינטרנט",
        "הערות",
        "עודכן לאחרונה",
    ]
    sheet_rows: list[list[str]] = []
    for row in rows or []:
        normalized = _normalize_construction_company_row_app(row)
        sheet_rows.append([
            normalized.get("row_id") or "",
            normalized.get("company_name") or "",
            normalized.get("company_id") or "",
            normalized.get("phone") or "",
            normalized.get("address") or "",
            normalized.get("email") or "",
            normalized.get("details_url") or "",
            normalized.get("notes") or "",
            normalized.get("updated_at") or "",
        ])
    return _build_simple_xlsx(headers, sheet_rows, "חברות בנייה")


def _merge_marketing_construction_companies_import(existing_rows: list[dict], imported_rows: list[dict]) -> list[dict]:
    existing = [_normalize_construction_company_row_app(row) for row in (existing_rows or [])]
    by_row_id = {
        str(row.get("row_id") or "").strip(): row
        for row in existing
        if str(row.get("row_id") or "").strip()
    }
    by_identity = {
        (
            re.sub(r"\D+", "", str(row.get("company_id") or "")),
            _canonical_income_customer_name(str(row.get("company_name") or "")),
            _work_manager_phone_digits(str(row.get("phone") or "")),
        ): row
        for row in existing
    }

    for imported in imported_rows or []:
        normalized = _normalize_construction_company_row_app(imported)
        row_id = str(normalized.get("row_id") or "").strip()
        identity = (
            re.sub(r"\D+", "", str(normalized.get("company_id") or "")),
            _canonical_income_customer_name(str(normalized.get("company_name") or "")),
            _work_manager_phone_digits(str(normalized.get("phone") or "")),
        )
        target = by_row_id.get(row_id) or by_identity.get(identity)
        if target:
            for field_name in ("company_name", "company_id", "phone", "address", "email", "details_url", "notes"):
                value = str(normalized.get(field_name) or "").strip()
                if value or field_name == "notes":
                    target[field_name] = value
            target["updated_at"] = datetime.now().isoformat(timespec="seconds")
            continue

        normalized["updated_at"] = datetime.now().isoformat(timespec="seconds")
        existing.insert(0, normalized)
        new_row_id = str(normalized.get("row_id") or "").strip()
        if new_row_id:
            by_row_id[new_row_id] = normalized
        by_identity[identity] = normalized

    return _dedupe_construction_company_rows(existing)


def _build_marketing_work_managers_payload(force_refresh: bool = False) -> dict:
    rows = load_marketing_rows("work_managers", force_refresh=force_refresh)
    if not rows:
        rows = _seed_work_manager_rows_from_csv()
    rows = _dedupe_work_manager_rows(rows)
    rows, changed = _maybe_refresh_work_manager_project_matches(rows)
    if changed:
        save_marketing_rows("work_managers", rows)
    mobile_numbers = [
        mobile
        for row in rows
        for mobile in (
            _work_manager_mobile_digits(row.get("phone_1", "")),
            _work_manager_mobile_digits(row.get("phone_2", "")),
            _work_manager_mobile_digits(row.get("phone_3", "")),
        )
        if mobile
    ]
    emails = [
        email.strip()
        for row in rows
        for email in re.split(r"[;,]+", str(row.get("email") or ""))
        if email.strip()
    ]
    return {
        "rows": rows,
        "summary": {
            "count": len(rows),
            "active_count": sum(1 for row in rows if str(row.get("active_status") or "") == "כן"),
            "matched_count": sum(1 for row in rows if str(row.get("project_manager_match") or "").strip().lower() == "true"),
            "mobile_count": len({item for item in mobile_numbers}),
            "email_count": len({item.lower() for item in emails}),
        },
    }


def _finance_invoice_row_id(row: dict) -> str:
    row_id = str((row or {}).get("row_id") or "").strip()
    if row_id:
        return row_id
    basis = "|".join(
        [
            str((row or {}).get("invoice_date") or "").strip(),
            str((row or {}).get("supplier_name") or "").strip(),
            str((row or {}).get("service_or_product") or "").strip(),
            str((row or {}).get("subtotal") or "").strip(),
            str((row or {}).get("source_file_name") or "").strip(),
        ]
    )
    return f"finance-invoice-{abs(hash(basis))}"


def _finance_clean_reference_token(value: str) -> str:
    return re.sub(r"\s+", "", str(value or "").strip()).upper()


def _finance_supplier_dedupe_key(value: str) -> str:
    return _normalize_company_name(str(value or "").strip())


def _finance_service_dedupe_key(value: str) -> str:
    cleaned = re.sub(r"\([^)]*\)", "", str(value or "").strip())
    cleaned = re.sub(r"\s+", " ", cleaned).strip().lower()
    return cleaned


def _finance_row_identity_key(row: dict) -> str:
    normalized = _normalize_finance_invoice_row_app(row or {})
    supplier_key = _finance_supplier_dedupe_key(normalized.get("supplier_name"))
    reference_key = _finance_clean_reference_token(normalized.get("reference_number"))
    allocation_key = _finance_clean_reference_token(normalized.get("allocation_number"))
    if supplier_key and reference_key:
        return f"ref|{supplier_key}|{reference_key}"
    if supplier_key and allocation_key:
        return f"alloc|{supplier_key}|{allocation_key}"
    subtotal = f"{_finance_parse_number(normalized.get('subtotal')):.2f}"
    vat = f"{_finance_parse_number(normalized.get('vat')):.2f}"
    total = f"{_finance_parse_number(normalized.get('total')):.2f}"
    return "|".join(
        [
            "content",
            supplier_key,
            str(normalized.get("invoice_date") or "").strip(),
            _finance_service_dedupe_key(normalized.get("service_or_product")),
            subtotal,
            vat,
            total,
        ]
    )


def _normalize_finance_invoice_row_app(row: dict) -> dict:
    normalized = {
        "row_id": str((row or {}).get("row_id") or _finance_invoice_row_id(row)).strip(),
        "invoice_date": str((row or {}).get("invoice_date") or "").strip(),
        "supplier_name": re.sub(r"\s+", " ", str((row or {}).get("supplier_name") or "").strip()),
        "reference_number": str((row or {}).get("reference_number") or (row or {}).get("supplier_invoice_number") or (row or {}).get("invoice_number") or "").strip(),
        "allocation_number": str((row or {}).get("allocation_number") or "").strip(),
        "currency_code": str((row or {}).get("currency_code") or "").strip().upper() or "ILS",
        "service_or_product": re.sub(r"\s+", " ", str((row or {}).get("service_or_product") or "").strip()),
        "subtotal": str((row or {}).get("subtotal") or "").strip(),
        "vat": str((row or {}).get("vat") or "").strip(),
        "total": str((row or {}).get("total") or "").strip(),
        "source_file_name": str((row or {}).get("source_file_name") or "").strip(),
        "source_file_path": str((row or {}).get("source_file_path") or "").strip(),
        "report_due_date": str((row or {}).get("report_due_date") or "").strip(),
        "report_due_overrides": str((row or {}).get("report_due_overrides") or "").strip(),
        "drive_file_id": str((row or {}).get("drive_file_id") or "").strip(),
        "drive_url": str((row or {}).get("drive_url") or "").strip(),
        "supplier_invoice_number": str((row or {}).get("supplier_invoice_number") or (row or {}).get("reference_number") or "").strip(),
        "payment_due_date": str((row or {}).get("payment_due_date") or (row or {}).get("due_date") or "").strip(),
        "payment_terms_days": str((row or {}).get("payment_terms_days") or "").strip(),
        "payment_supplier_name": str((row or {}).get("payment_supplier_name") or "").strip(),
        "create_payable_row": str((row or {}).get("create_payable_row") or "").strip(),
        "source_mode": str((row or {}).get("source_mode") or "PROD").strip().upper() or "PROD",
        "updated_at": str((row or {}).get("updated_at") or datetime.now().isoformat(timespec="seconds")).strip(),
    }
    if (
        str(normalized.get("source_file_name") or "").strip().count("/") == 2
        and str(normalized.get("total") or "").strip().startswith("/")
    ):
        legacy = dict(normalized)
        normalized["reference_number"] = ""
        normalized["allocation_number"] = ""
        normalized["service_or_product"] = str(legacy.get("reference_number") or "").strip()
        normalized["subtotal"] = str(legacy.get("allocation_number") or "").strip()
        normalized["vat"] = str(legacy.get("service_or_product") or "").strip()
        normalized["total"] = str(legacy.get("subtotal") or "").strip()
        normalized["source_file_name"] = str(legacy.get("vat") or "").strip()
        normalized["source_file_path"] = str(legacy.get("total") or "").strip()
        normalized["report_due_date"] = str(legacy.get("source_file_name") or "").strip()
        normalized["report_due_overrides"] = str(legacy.get("source_file_path") or "").strip()
        candidate_drive_id = str(legacy.get("report_due_date") or "").strip()
        candidate_drive_url = str(legacy.get("report_due_overrides") or "").strip()
        normalized["drive_file_id"] = candidate_drive_id if re.fullmatch(r"[A-Za-z0-9_-]{10,}", candidate_drive_id) else ""
        normalized["drive_url"] = candidate_drive_url if candidate_drive_url.startswith("http") else ""
        normalized["updated_at"] = str(legacy.get("drive_file_id") or legacy.get("updated_at") or "").strip()
    for key in ("subtotal", "vat", "total"):
        raw = str(normalized.get(key) or "").strip().replace(",", "")
        try:
            normalized[key] = f"{float(raw):.2f}" if raw else ""
        except Exception:
            normalized[key] = raw
    report_due_date = _finance_due_date_display(normalized.get("report_due_date"))
    normalized["report_due_date"] = report_due_date or _finance_due_date_display(normalized.get("invoice_date"))
    override_values = _finance_normalize_due_dates(
        [item.strip() for item in str(normalized.get("report_due_overrides") or "").split(",") if item.strip()]
    )
    if override_values:
        normalized["report_due_date"] = override_values[0]
        normalized["report_due_overrides"] = ""
    else:
        normalized["report_due_overrides"] = ""
    normalized["reference_number"] = str(normalized.get("reference_number") or "").strip()
    normalized["allocation_number"] = str(normalized.get("allocation_number") or "").strip()
    normalized["currency_code"] = str(normalized.get("currency_code") or "ILS").strip().upper() or "ILS"
    return normalized


def _finance_customer_withholding_row_id(row: dict) -> str:
    row_id = str((row or {}).get("row_id") or "").strip()
    if row_id:
        return row_id
    basis = "|".join(
        [
            str((row or {}).get("receipt_date") or "").strip(),
            str((row or {}).get("customer_name") or "").strip(),
            str((row or {}).get("invoice_number") or "").strip(),
            str((row or {}).get("receipt_number") or "").strip(),
            str((row or {}).get("gross_amount") or "").strip(),
        ]
    )
    return f"finance-withholding-{abs(hash(basis))}"


def _finance_withholding_flag(value) -> bool:
    return str(value or "").strip().upper() == "TRUE"


def _finance_customer_withholding_is_applied(row: dict) -> bool:
    if _finance_withholding_flag((row or {}).get("withholding_applied")):
        return True
    return (_finance_parse_number((row or {}).get("withholding_percent")) > 0) or (_finance_parse_number((row or {}).get("withheld_amount")) > 0)


def _finance_customer_withholding_mark_applied(row: dict, percent: float = 3.0) -> dict:
    normalized = _normalize_finance_customer_withholding_row_app(row)
    gross_amount = round(_finance_parse_number(normalized.get("gross_amount")), 2)
    if gross_amount <= 0:
        return normalized
    applied_percent = round(float(percent or 0), 2)
    withheld_amount = round(gross_amount * (applied_percent / 100), 2)
    paid_amount = round(gross_amount - withheld_amount, 2)
    normalized["withholding_applied"] = "TRUE"
    normalized["withholding_percent"] = f"{applied_percent:.2f}"
    normalized["withheld_amount"] = f"{withheld_amount:.2f}"
    normalized["paid_amount"] = f"{paid_amount:.2f}"
    normalized["review_pending"] = ""
    normalized["updated_at"] = datetime.now().isoformat(timespec="seconds")
    return normalized


def _normalize_finance_customer_withholding_row_app(row: dict) -> dict:
    raw_row = row or {}
    raw_withholding_applied = str(raw_row.get("withholding_applied") or "").strip()
    normalized = {
        "row_id": str(raw_row.get("row_id") or _finance_customer_withholding_row_id(row)).strip(),
        "receipt_date": str(raw_row.get("receipt_date") or "").strip(),
        "customer_name": re.sub(r"\s+", " ", str(raw_row.get("customer_name") or "").strip()),
        "invoice_number": str(raw_row.get("invoice_number") or "").strip(),
        "receipt_number": str(raw_row.get("receipt_number") or "").strip(),
        "withholding_applied": "TRUE" if _finance_withholding_flag(raw_row.get("withholding_applied")) else "",
        "gross_amount": str(raw_row.get("gross_amount") or "").strip(),
        "withholding_percent": str(raw_row.get("withholding_percent") or "").strip(),
        "withheld_amount": str(raw_row.get("withheld_amount") or "").strip(),
        "paid_amount": str(raw_row.get("paid_amount") or "").strip(),
        "source_mode": str(raw_row.get("source_mode") or "").strip().upper(),
        "review_pending": "TRUE" if _finance_withholding_flag(raw_row.get("review_pending")) else "",
        "migration_batch": str(raw_row.get("migration_batch") or "").strip(),
        "updated_at": str(raw_row.get("updated_at") or datetime.now().isoformat(timespec="seconds")).strip(),
    }
    if (
        raw_withholding_applied
        and raw_withholding_applied.upper() not in {"TRUE", "FALSE"}
        and str(raw_row.get("paid_amount") or "").strip().upper() in {"PROD", "SB"}
        and re.match(r"^\d{4}-\d{2}-\d{2}T", str(raw_row.get("source_mode") or "").strip())
    ):
        normalized["withholding_applied"] = "TRUE"
        normalized["gross_amount"] = raw_withholding_applied
        normalized["withholding_percent"] = str(raw_row.get("gross_amount") or "").strip()
        normalized["withheld_amount"] = str(raw_row.get("withholding_percent") or "").strip()
        normalized["paid_amount"] = str(raw_row.get("withheld_amount") or "").strip()
        normalized["source_mode"] = str(raw_row.get("paid_amount") or "").strip().upper()
        normalized["review_pending"] = ""
        normalized["migration_batch"] = ""
        normalized["updated_at"] = str(raw_row.get("source_mode") or "").strip() or normalized["updated_at"]
    for key in ("gross_amount", "withholding_percent", "withheld_amount", "paid_amount"):
        raw = str(normalized.get(key) or "").strip().replace(",", "")
        try:
            normalized[key] = f"{float(raw):.2f}" if raw else ""
        except Exception:
            normalized[key] = raw
    normalized["receipt_date"] = _finance_format_display_date(normalized.get("receipt_date"))
    return normalized


def _dedupe_finance_customer_withholding_rows(rows: list[dict]) -> list[dict]:
    deduped: dict[str, dict] = {}
    for row in rows or []:
        normalized = _normalize_finance_customer_withholding_row_app(row)
        existing = deduped.get(normalized["row_id"])
        if not existing:
            deduped[normalized["row_id"]] = normalized
            continue
        for field_name in (
            "receipt_date",
            "customer_name",
            "invoice_number",
            "receipt_number",
            "withholding_applied",
            "gross_amount",
            "withholding_percent",
            "withheld_amount",
            "paid_amount",
            "source_mode",
            "review_pending",
            "migration_batch",
        ):
            if str(existing.get(field_name) or "").strip():
                continue
            value = str(normalized.get(field_name) or "").strip()
            if value:
                existing[field_name] = value
        existing["updated_at"] = normalized.get("updated_at") or existing.get("updated_at") or datetime.now().isoformat(timespec="seconds")
    rows_out = list(deduped.values())
    rows_out.sort(
        key=lambda row: (
            _finance_parse_date_value(row.get("receipt_date")) or date.min,
            str(row.get("customer_name") or ""),
            str(row.get("receipt_number") or ""),
        ),
        reverse=True,
    )
    return rows_out


def _append_finance_customer_withholding_row(row: dict) -> dict:
    normalized = _normalize_finance_customer_withholding_row_app(row)
    rows = _dedupe_finance_customer_withholding_rows(load_marketing_rows("finance_customer_withholdings"))
    rows.insert(0, normalized)
    rows = _dedupe_finance_customer_withholding_rows(rows)
    save_result = save_marketing_rows("finance_customer_withholdings", rows)
    saved_row = next((item for item in rows if str(item.get("row_id") or "").strip() == normalized["row_id"]), normalized)
    _invalidate_finance_state_cache(schedule_refresh=False)
    return {"row": saved_row, "save_result": save_result}


def _finance_customer_withholdings_epoch_payload() -> dict:
    rows = get_cached_marketing_rows("finance_customer_withholdings") or load_marketing_rows("finance_customer_withholdings")
    rows = _dedupe_finance_customer_withholding_rows(rows)
    latest_updated_at = ""
    for row in rows:
        updated_at = str(row.get("updated_at") or "").strip()
        if updated_at and updated_at > latest_updated_at:
            latest_updated_at = updated_at
    return {
        "count": len(rows),
        "latest_updated_at": latest_updated_at,
    }


def _finance_invoices_epoch_payload() -> dict:
    rows = _dedupe_finance_invoice_rows(
        get_cached_marketing_rows("finance_invoices") or load_marketing_rows("finance_invoices")
    )
    latest_updated_at = ""
    for row in rows:
        updated_at = str(row.get("updated_at") or "").strip()
        if updated_at and updated_at > latest_updated_at:
            latest_updated_at = updated_at
    return {
        "count": len(rows),
        "latest_updated_at": latest_updated_at,
    }


async def _build_finance_customer_withholding_prod_migration_rows_2026() -> list[dict]:
    current_rows = _dedupe_finance_customer_withholding_rows(load_marketing_rows("finance_customer_withholdings", force_refresh=True))
    existing_invoice_numbers = {str(row.get("invoice_number") or "").strip() for row in current_rows if str(row.get("invoice_number") or "").strip()}
    existing_receipt_numbers = {str(row.get("receipt_number") or "").strip() for row in current_rows if str(row.get("receipt_number") or "").strip()}

    cfg = get_mode_config("prod")
    client = GreenInvoiceClient(
        base_url=cfg["base_url"],
        api_key=cfg["api_key"],
        api_secret=cfg["api_secret"],
    )
    invoice_documents = await client.get_invoice_documents(
        date_from="2026-01-01",
        date_to="2026-12-31",
        page_size=100,
        max_pages=100,
    )
    receipt_links = await client.list_receipt_links(
        date_from="2026-01-01",
        date_to="2026-12-31",
        page_size=100,
        max_pages=100,
    )

    invoices_by_number: dict[str, dict] = {}
    for doc in invoice_documents:
        invoice_number = str(doc.get("number") or "").strip()
        if not invoice_number:
            continue
        invoices_by_number[invoice_number] = doc

    migration_rows: list[dict] = []
    pending_row_ids = {str(row.get("row_id") or "").strip() for row in current_rows if str(row.get("row_id") or "").strip()}
    for link in receipt_links:
        invoice_number = str(link.get("linked_invoice_number") or "").strip()
        receipt_number = str(link.get("receipt_number") or "").strip()
        if not invoice_number or not receipt_number:
            continue
        if invoice_number in existing_invoice_numbers or receipt_number in existing_receipt_numbers:
            continue
        invoice_doc = invoices_by_number.get(invoice_number)
        if not invoice_doc:
            continue
        gross_amount = round(float(invoice_doc.get("amount") or 0), 2)
        if gross_amount <= 0:
            continue
        customer_name = str(invoice_doc.get("customer_name") or link.get("customer_name") or "").strip()
        receipt_date = str(link.get("document_date") or "").strip() or str(invoice_doc.get("date") or "").strip()
        row_id = f"finance-withholding-migration-prod-2026-{re.sub(r'[^0-9A-Za-z]+', '-', invoice_number).strip('-')}-{re.sub(r'[^0-9A-Za-z]+', '-', receipt_number).strip('-')}"
        if row_id in pending_row_ids:
            continue
        migration_rows.append(
            _normalize_finance_customer_withholding_row_app(
                {
                    "row_id": row_id,
                    "receipt_date": receipt_date,
                    "customer_name": customer_name,
                    "invoice_number": invoice_number,
                    "receipt_number": receipt_number,
                    "withholding_applied": "",
                    "gross_amount": f"{gross_amount:.2f}",
                    "withholding_percent": "",
                    "withheld_amount": "",
                    "paid_amount": "",
                    "source_mode": "PROD",
                    "review_pending": "TRUE",
                    "migration_batch": "prod_receipts_2026",
                    "updated_at": datetime.now().isoformat(timespec="seconds"),
                }
            )
        )
    return migration_rows


def _finance_load_source_text_for_row(row: dict, text_cache: dict[str, str] | None = None) -> str:
    source_file_path = str((row or {}).get("source_file_path") or "").strip()
    if not source_file_path:
        return ""
    if text_cache is not None and source_file_path in text_cache:
        return text_cache[source_file_path]
    source_path = Path(source_file_path)
    if not (source_path.exists() and source_path.is_file()):
        return ""
    raw_text, fixed_text = _finance_extract_uploaded_invoice_texts(source_path)
    combined = "\n".join([fixed_text or "", raw_text or ""]).strip()
    if text_cache is not None:
        text_cache[source_file_path] = combined
    return combined


def _finance_backfill_source_metadata(row: dict) -> dict:
    normalized = _normalize_finance_invoice_row_app(row or {})
    source_file_path = str(normalized.get("source_file_path") or "").strip()
    if not source_file_path:
        return normalized
    source_path = Path(source_file_path)
    if not (source_path.exists() and source_path.is_file()):
        return normalized
    source_name = str(normalized.get("source_file_name") or source_path.name).strip()
    if _finance_reference_looks_suspicious(str(normalized.get("reference_number") or "").strip(), normalized):
        normalized["reference_number"] = ""
    if not str(normalized.get("reference_number") or "").strip():
        normalized["reference_number"] = _finance_extract_reference_number("", source_name)
    need_text = (
        not str(normalized.get("reference_number") or "").strip()
        or _finance_parse_number(normalized.get("total")) >= 10000
        or str(normalized.get("invoice_date") or "").strip().startswith("01/")
    )
    if need_text:
        raw_text, fixed_text = _finance_extract_uploaded_invoice_texts_light(source_path)
        source_text = "\n".join([fixed_text or "", raw_text or ""]).strip()
        if not source_text and (
            _finance_parse_number(normalized.get("total")) >= 10000
            or str(normalized.get("invoice_date") or "").strip().startswith("01/")
        ):
            raw_text, fixed_text = _finance_extract_uploaded_invoice_texts(source_path)
            source_text = "\n".join([fixed_text or "", raw_text or ""]).strip()
        if not str(normalized.get("reference_number") or "").strip():
            normalized["reference_number"] = _finance_extract_reference_number(source_text, source_name)
        if _finance_parse_number(normalized.get("total")) >= 10000:
            extracted_allocation_number = _finance_extract_allocation_number(source_text)
            if extracted_allocation_number:
                normalized["allocation_number"] = extracted_allocation_number
        if str(normalized.get("invoice_date") or "").strip().startswith("01/"):
            if _finance_detect_flaxi_invoice(raw_text, fixed_text, source_name):
                reparsed = _finance_parse_flaxi_invoice(raw_text, fixed_text, source_name, source_path)
                parsed_invoice_date = normalize_date(str(reparsed.get("invoice_date") or "").strip())
                if parsed_invoice_date:
                    normalized["invoice_date"] = parsed_invoice_date
    if (
        str(normalized.get("drive_file_id") or "").strip()
        and str(normalized.get("drive_file_id") or "").strip() == str(normalized.get("report_due_date") or "").strip()
        and not str(normalized.get("drive_url") or "").strip()
    ):
        normalized["drive_file_id"] = ""
    return _normalize_finance_invoice_row_app(normalized)


def _finance_should_impute_vat_from_total(row: dict, source_text: str) -> bool:
    normalized_text = fix_hebrew_text(source_text or "")
    lowered = normalized_text.lower()
    supplier_name = str((row or {}).get("supplier_name") or "").strip().lower()
    service_name = str((row or {}).get("service_or_product") or "").strip().lower()
    if not lowered:
        return False
    if any(
        token in lowered
        for token in (
            "this is not a bill",
            "summary of billing activity",
            "google ads",
            "openai",
            "anthropic",
            "serial kombi",
        )
    ):
        return False
    if any(
        token in supplier_name
        for token in (
            "google ads",
            "openai",
            "anthropic",
            "serial kombi",
            "עיריית חיפה",
            "שריף כנען",
        )
    ):
        return False
    if "פטור" in normalized_text and "מע" in normalized_text:
        return False
    if re.search(r"מע[\"״']?מ\s*(?:0|0\.0|0\.00|אפס)", normalized_text):
        return False
    if "טיב טעם" in supplier_name:
        return True
    invoice_markers = (
        "חשבונית מס",
        "חשבונית",
        "חשבווית",
        "השבונית",
        "חשבונית/קבלה",
        "חשבונית מס קבלה",
        "חשבון תקופתי",
        "העברנית",
        "תינרבעה",
    )
    if any(marker in normalized_text for marker in invoice_markers):
        return True
    if "מע" in normalized_text and ("קבלה" in normalized_text or "לתשלום" in normalized_text):
        return True
    return False


def _finance_impute_vat_from_total_if_needed(row: dict, text_cache: dict[str, str] | None = None) -> dict:
    normalized = _normalize_finance_invoice_row_app(row or {})
    total_value = _finance_parse_number(normalized.get("total"))
    vat_value = _finance_parse_number(normalized.get("vat"))
    subtotal_value = _finance_parse_number(normalized.get("subtotal"))
    if total_value <= 0 or vat_value > 0.009:
        return normalized
    source_text = _finance_load_source_text_for_row(normalized, text_cache=text_cache)
    if not _finance_should_impute_vat_from_total(normalized, source_text):
        return normalized
    computed_subtotal = round(total_value / 1.18, 2)
    computed_vat = round(total_value - computed_subtotal, 2)
    normalized["subtotal"] = f"{computed_subtotal:.2f}"
    normalized["vat"] = f"{computed_vat:.2f}"
    normalized["total"] = f"{total_value:.2f}"
    return normalized


def _dedupe_finance_invoice_rows(rows: list[dict]) -> list[dict]:
    deduped: dict[str, dict] = {}
    for row in rows or []:
        normalized = _normalize_finance_invoice_row_app(row)
        key = _finance_row_identity_key(normalized)
        existing = deduped.get(key)
        if not existing:
            deduped[key] = normalized
            continue
        for field_name in (
            "invoice_date",
            "supplier_name",
            "reference_number",
            "allocation_number",
            "service_or_product",
            "subtotal",
            "vat",
            "total",
            "source_file_name",
            "source_file_path",
            "report_due_date",
            "report_due_overrides",
            "drive_file_id",
            "drive_url",
        ):
            existing_value = str(existing.get(field_name) or "").strip()
            new_value = str(normalized.get(field_name) or "").strip()
            if field_name == "service_or_product":
                if len(new_value) > len(existing_value):
                    existing[field_name] = new_value
                continue
            if field_name == "invoice_date":
                if not existing_value and new_value:
                    existing[field_name] = new_value
                    continue
                if (
                    existing_value
                    and new_value
                    and existing_value.startswith("01/")
                    and not new_value.startswith("01/")
                ):
                    existing[field_name] = new_value
                continue
            if existing_value:
                continue
            if new_value:
                existing[field_name] = new_value
        existing["updated_at"] = normalized.get("updated_at") or existing.get("updated_at") or datetime.now().isoformat(timespec="seconds")
    rows_out = list(deduped.values())
    rows_out.sort(key=lambda row: (_finance_parse_date_value(row.get("invoice_date")) or date.min, str(row.get("supplier_name") or "")), reverse=True)
    return rows_out


def _finance_payment_invoice_key(value: str) -> str:
    return re.sub(r"\D+", "", str(value or "").strip())


def _finance_merge_payment_notes(existing_notes: str, service_or_product: str) -> str:
    existing = str(existing_notes or "").strip()
    service = str(service_or_product or "").strip()
    if not existing:
        return service
    if not service:
        return existing
    if service in existing:
        return existing
    if existing in service:
        return service
    return f"{existing} | {service}"


def _finance_upsert_payable_row_for_invoice(
    invoice_row: dict,
    *,
    supplier_invoice_number: str = "",
    payment_terms_days: str = "",
    payment_due_date: str = "",
    payment_supplier_name: str = "",
    source_mode: str = "PROD",
) -> dict | None:
    normalized_invoice = _normalize_finance_invoice_row_app(invoice_row or {})
    invoice_number = str(supplier_invoice_number or "").strip()
    if not invoice_number:
        return None

    target_row = _finance_find_payable_row_for_invoice(invoice_number)
    display_supplier = str(payment_supplier_name or normalized_invoice.get("payment_supplier_name") or normalized_invoice.get("supplier_name") or "").strip()
    due_date = normalize_date(payment_due_date) or str((target_row or {}).get("due_date") or "").strip()
    terms_days = str(payment_terms_days or normalized_invoice.get("payment_terms_days") or (target_row or {}).get("payment_terms_days") or "").strip()
    payment_terms_label = f"שוטף + {terms_days}" if terms_days and terms_days not in {"0", "-"} else ""
    row_payload = {
        "invoice_date": str(normalized_invoice.get("invoice_date") or "").strip(),
        "customer_name": display_supplier,
        "payment_terms_days": terms_days,
        "payment_terms_label": payment_terms_label,
        "payment_direction": "תשלום",
        "amount": str(normalized_invoice.get("total") or "").strip(),
        "po_number": invoice_number,
        "delivery_number": str((target_row or {}).get("delivery_number") or "").strip(),
        "proforma_invoice_number": str((target_row or {}).get("proforma_invoice_number") or "").strip(),
        "tax_invoice_number": str((target_row or {}).get("tax_invoice_number") or "").strip(),
        "receipt_number": str((target_row or {}).get("receipt_number") or "").strip(),
        "notes": _finance_merge_payment_notes(
            str((target_row or {}).get("notes") or "").strip(),
            str(normalized_invoice.get("service_or_product") or "").strip(),
        ),
        "due_date": due_date,
        "paid": str((target_row or {}).get("paid") or "FALSE").strip() or "FALSE",
        "source_mode": str(source_mode or normalized_invoice.get("source_mode") or (target_row or {}).get("source_mode") or "PROD").strip() or "PROD",
    }

    if target_row and str(target_row.get("_sheet_title") or "").strip() and int(target_row.get("_sheet_row") or 0) > 0:
        result = update_payment_transfer_row(
            str(target_row.get("_sheet_title") or "").strip(),
            int(target_row.get("_sheet_row") or 0),
            row_payload,
        )
        return {"status": "updated", **result}

    result = append_manual_payment_transfer_row(row_payload)
    return {"status": "created", **result}


def _finance_find_payable_row_for_invoice(invoice_number: str) -> dict | None:
    normalized_invoice_key = _finance_payment_invoice_key(invoice_number)
    rows_state = load_payment_transfer_rows()
    all_rows = list((rows_state or {}).get("all_rows") or [])
    return next(
        (
            row
            for row in all_rows
            if str(row.get("payment_direction") or "").strip() == "תשלום"
            and (
                _finance_payment_invoice_key(str(row.get("po_number") or "").strip()) == normalized_invoice_key
                or _finance_payment_invoice_key(str(row.get("tax_invoice_number") or "").strip()) == normalized_invoice_key
            )
        ),
        None,
    )


def _finance_month_label_to_invoice_date(month_label: str) -> str:
    raw = str(month_label or "").strip()
    match = re.fullmatch(r"(\d{2})/(\d{4})", raw)
    if not match:
        return ""
    month_value = int(match.group(1))
    year_value = int(match.group(2))
    try:
        return date(year_value, month_value, 1).strftime("%d/%m/%Y")
    except Exception:
        return ""


def _finance_auto_invoice_row_id(source_kind: str, month_label: str, invoice_number: str = "") -> str:
    invoice_key = re.sub(r"[^A-Za-z0-9]+", "-", str(invoice_number or "").strip()).strip("-")
    month_key = re.sub(r"[^0-9]+", "-", str(month_label or "").strip()).strip("-")
    suffix = invoice_key or month_key or uuid.uuid4().hex[:8]
    return f"finance-auto-{source_kind}-{suffix}"


def _finance_build_row_from_pazomat_admin_row(source_row: dict) -> dict | None:
    if str(source_row.get("status") or "").strip() != "pdf_available":
        return None
    local_path = Path(str(source_row.get("local_path") or "").strip())
    if not (local_path.exists() and local_path.is_file()):
        return None
    source_name = str(source_row.get("source_file_name") or local_path.name or "").strip() or local_path.name
    drafts = _finance_parse_uploaded_invoice_drafts(local_path, source_name)
    draft = drafts[0] if drafts else {}
    month_label = str(source_row.get("month") or "").strip()
    invoice_number = str(source_row.get("invoice_number") or "").strip()
    fallback_invoice_date = (
        normalize_date(str(source_row.get("debit_date") or "").strip())
        or _finance_month_label_to_invoice_date(month_label)
        or date.today().strftime("%d/%m/%Y")
    )
    if not draft:
        draft = {
            "invoice_date": fallback_invoice_date,
            "supplier_name": "פז קמעונאות ואנרגיה בע״מ",
            "service_or_product": f"פזומט - דמי שימוש חודשיים וחיובי דלק ({month_label})" if month_label else "פזומט - דמי שימוש חודשיים וחיובי דלק",
            "subtotal": "",
            "vat": "",
            "total": str(source_row.get("total_amount") or "").strip(),
            "source_file_name": source_name,
            "source_file_path": str(local_path),
            "report_due_date": _finance_due_date_display(fallback_invoice_date),
        }
    draft["row_id"] = _finance_auto_invoice_row_id("pazomat", month_label, invoice_number)
    draft["invoice_date"] = normalize_date(str(draft.get("invoice_date") or "").strip()) or fallback_invoice_date
    draft["supplier_name"] = str(draft.get("supplier_name") or "").strip() or "פז קמעונאות ואנרגיה בע״מ"
    draft["service_or_product"] = str(draft.get("service_or_product") or "").strip() or (
        f"פזומט - דמי שימוש חודשיים וחיובי דלק ({month_label})" if month_label else "פזומט - דמי שימוש חודשיים וחיובי דלק"
    )
    draft["source_file_name"] = source_name
    draft["source_file_path"] = str(local_path)
    draft["report_due_date"] = _finance_due_date_display(draft.get("invoice_date")) or _finance_due_date_display(fallback_invoice_date)
    if invoice_number:
        draft["reference_number"] = invoice_number
    draft["updated_at"] = datetime.now().isoformat(timespec="seconds")
    return _finance_impute_vat_from_total_if_needed(_normalize_finance_invoice_row_app(draft))


def _finance_build_row_from_sibus_admin_row(source_row: dict) -> dict | None:
    if str(source_row.get("status") or "").strip() != "pdf_available":
        return None
    local_path = Path(str(source_row.get("local_path") or "").strip())
    if not (local_path.exists() and local_path.is_file()):
        return None
    month_label = str(source_row.get("month") or "").strip()
    invoice_number = str(source_row.get("invoice_number") or "").strip()
    source_name = str(source_row.get("source_file_name") or local_path.name or "").strip() or local_path.name
    invoice_date = (
        normalize_date(str(source_row.get("invoice_date") or "").strip())
        or _finance_month_label_to_invoice_date(month_label)
        or date.today().strftime("%d/%m/%Y")
    )
    billing_period = str(source_row.get("billing_period") or "").strip()
    service_label = "עסקאות בתי עסק cibus"
    if billing_period:
        service_label = f"{service_label} ({billing_period})"
    draft = {
        "row_id": _finance_auto_invoice_row_id("sibus", month_label, invoice_number),
        "invoice_date": invoice_date,
        "supplier_name": "פלאקסי ישראל בע\"מ",
        "reference_number": invoice_number,
        "service_or_product": service_label,
        "subtotal": str(source_row.get("subtotal_amount") or "").strip(),
        "vat": str(source_row.get("vat_amount") or "").strip(),
        "total": str(source_row.get("total_amount") or "").strip(),
        "source_file_name": source_name,
        "source_file_path": str(local_path),
        "report_due_date": _finance_due_date_display(invoice_date),
        "updated_at": datetime.now().isoformat(timespec="seconds"),
    }
    return _finance_impute_vat_from_total_if_needed(_normalize_finance_invoice_row_app(draft))


def _finance_sync_admin_invoice_rows_to_finance(source_kind: str, source_rows: list[dict]) -> dict:
    builders = {
        "pazomat": _finance_build_row_from_pazomat_admin_row,
        "sibus": _finance_build_row_from_sibus_admin_row,
    }
    builder = builders.get(str(source_kind or "").strip().lower())
    if builder is None:
        raise ValueError("סוג מקור לא נתמך לסנכרון חשבוניות כספים.")

    existing_rows = _dedupe_finance_invoice_rows(load_marketing_rows("finance_invoices"))
    existing_by_id = {str(row.get("row_id") or "").strip(): dict(row) for row in existing_rows}
    changed = False
    added_count = 0
    updated_count = 0
    skipped_count = 0
    warnings: list[str] = []

    for source_row in source_rows or []:
        normalized = builder(source_row)
        if not normalized:
            skipped_count += 1
            continue
        row_id = str(normalized.get("row_id") or "").strip()
        if not row_id:
            skipped_count += 1
            continue
        existing = existing_by_id.get(row_id)
        if existing:
            normalized["drive_file_id"] = str(existing.get("drive_file_id") or "").strip()
            normalized["drive_url"] = str(existing.get("drive_url") or "").strip()
        try:
            normalized = _finance_sync_invoice_row_drive_targets(normalized)
        except Exception as drive_exc:
            warnings.append(f"{source_kind}: {_google_drive_sync_warning(drive_exc)}")
        if existing:
            merged = dict(existing)
            merged.update(normalized)
            merged["updated_at"] = str(existing.get("updated_at") or "").strip()
            candidate = _normalize_finance_invoice_row_app(merged)
            if _normalize_finance_invoice_row_app(existing) != candidate:
                candidate["updated_at"] = datetime.now().isoformat(timespec="seconds")
                candidate = _normalize_finance_invoice_row_app(candidate)
                existing_by_id[row_id] = candidate
                updated_count += 1
                changed = True
            else:
                existing_by_id[row_id] = candidate
        else:
            normalized["updated_at"] = datetime.now().isoformat(timespec="seconds")
            existing_by_id[row_id] = _normalize_finance_invoice_row_app(normalized)
            added_count += 1
            changed = True

    if changed:
        rows_to_save = _dedupe_finance_invoice_rows(list(existing_by_id.values()))
        save_marketing_rows("finance_invoices", rows_to_save)

    return {
        "status": "ok",
        "source_kind": source_kind,
        "added_count": added_count,
        "updated_count": updated_count,
        "skipped_count": skipped_count,
        "warnings": warnings,
    }


def _finance_backfill_stored_rows(rows: list[dict], *, persist: bool = False) -> list[dict]:
    normalized_rows: list[dict] = []
    changed = False
    text_cache: dict[str, str] = {}
    for row in rows or []:
        original = _normalize_finance_invoice_row_app(row)
        enriched = _finance_backfill_source_metadata(dict(original))
        report_due_date = str(enriched.get("report_due_date") or "").strip()
        if not report_due_date:
            enriched["report_due_date"] = _finance_due_date_display(enriched.get("invoice_date"))
        enriched = _finance_impute_vat_from_total_if_needed(enriched, text_cache=text_cache)
        if enriched != original:
            changed = True
        normalized_rows.append(enriched)
    normalized_rows = _dedupe_finance_invoice_rows(normalized_rows)
    if persist and (changed or len(normalized_rows) != len(rows or [])):
        save_marketing_rows("finance_invoices", normalized_rows)
    return normalized_rows


def _finance_parse_date_value(value) -> date | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    for parser in (
        lambda text: datetime.strptime(text, "%d/%m/%Y").date(),
        lambda text: date.fromisoformat(text[:10]),
        lambda text: datetime.strptime(text, "%d.%m.%Y").date(),
    ):
        try:
            return parser(raw)
        except Exception:
            continue
    return None


def _finance_format_display_date(value) -> str:
    if isinstance(value, date):
        target = value
    else:
        target = _finance_parse_date_value(value)
    if not target:
        return str(value or "").strip()
    return target.strftime("%d/%m/%Y")


def _finance_parse_number(value) -> float:
    if value is None:
        return 0.0
    if isinstance(value, (int, float)):
        try:
            return float(value)
        except Exception:
            return 0.0
    raw = str(value).strip()
    if not raw:
        return 0.0
    normalized = raw.replace("₪", "").replace(",", "").replace(" ", "")
    normalized = normalized.replace("\u200f", "").replace("\u200e", "")
    try:
        return float(normalized)
    except Exception:
        return 0.0


def _finance_deep_find_scalar(source, wanted_keys: set[str]):
    if isinstance(source, dict):
        for key, value in source.items():
            if str(key or "").strip().lower() in wanted_keys and not isinstance(value, (dict, list)):
                return value
        for value in source.values():
            found = _finance_deep_find_scalar(value, wanted_keys)
            if found not in (None, ""):
                return found
    elif isinstance(source, list):
        for item in source:
            found = _finance_deep_find_scalar(item, wanted_keys)
            if found not in (None, ""):
                return found
    return None


def _finance_document_totals(document: dict) -> dict:
    raw = (document or {}).get("raw") or {}
    subtotal = _finance_parse_number(
        (document or {}).get("subtotal")
        or _finance_deep_find_scalar(raw, {"beforevatamount", "subtotal", "subtotalamount", "amountbeforevat", "subTotal".lower()})
    )
    vat = _finance_parse_number(
        (document or {}).get("vat")
        or _finance_deep_find_scalar(raw, {"vatamount", "vat", "tax", "taxamount"})
    )
    total = _finance_parse_number(
        (document or {}).get("total")
        or (document or {}).get("amount")
        or _finance_deep_find_scalar(raw, {"amount", "amountlocal", "total", "totalamount", "calculatedamountlocal"})
    )
    if subtotal <= 0 and total > 0 and vat > 0:
        subtotal = max(0.0, round(total - vat, 2))
    if vat <= 0 and total > 0 and subtotal > 0:
        vat = max(0.0, round(total - subtotal, 2))
    if total <= 0 and subtotal > 0:
        total = round(subtotal + vat, 2)
    return {
        "subtotal": round(subtotal, 2),
        "vat": round(vat, 2),
        "total": round(total, 2),
    }


