def _finance_text_haystacks(*parts: str) -> tuple[str, str]:
    raw = "\n".join(str(part or "") for part in parts if str(part or "").strip())
    lowered = raw.lower()
    return raw, lowered


def _finance_guess_supplier_from_known_patterns(*parts: str) -> str:
    _raw, lowered = _finance_text_haystacks(*parts)
    for needle, label in FINANCE_KNOWN_SUPPLIERS:
        if needle.lower() in lowered:
            return label
    return ""


def _finance_parse_english_date(text: str) -> str:
    month_names = (
        "Jan(?:uary)?",
        "Feb(?:ruary)?",
        "Mar(?:ch)?",
        "Apr(?:il)?",
        "May",
        "Jun(?:e)?",
        "Jul(?:y)?",
        "Aug(?:ust)?",
        "Sep(?:tember)?",
        "Oct(?:ober)?",
        "Nov(?:ember)?",
        "Dec(?:ember)?",
    )
    pattern = rf"({'|'.join(month_names)})\s+(\d{{1,2}}),\s*(\d{{4}})"
    match = re.search(pattern, text or "", re.IGNORECASE)
    if not match:
        return ""
    token = match.group(0)
    for fmt in ("%b %d, %Y", "%B %d, %Y"):
        try:
            return datetime.strptime(token, fmt).strftime("%d/%m/%Y")
        except Exception:
            continue
    return ""


def _finance_first_amount_after_label(text: str, labels: list[str], *, max_gap: int = 80) -> float | None:
    for label in labels:
        pattern = rf"{label}.{{0,{max_gap}}}?([0-9][0-9,.\s]*\d)"
        match = re.search(pattern, text or "", re.IGNORECASE | re.DOTALL)
        if not match:
            continue
        amount = normalize_amount(match.group(1))
        if amount is not None:
            return float(amount)
    return None


def _finance_last_amount_before_label(text: str, labels: list[str], *, max_gap: int = 80) -> float | None:
    for label in labels:
        pattern = rf"([0-9][0-9,.\s]*\d).{{0,{max_gap}}}?{label}"
        match = re.search(pattern, text or "", re.IGNORECASE | re.DOTALL)
        if not match:
            continue
        amount = normalize_amount(match.group(1))
        if amount is not None:
            return float(amount)
    return None


def _finance_extract_invoice_reference(text: str) -> str:
    patterns = (
        r"חשבונית\s*מס(?:/קבלה)?\s*(?:מס['\":]?)?\s*([A-Za-z0-9/\-]{3,})",
        r"חשבונית(?:\s*מרכזת)?\s*([A-Za-z0-9/\-]{3,})",
        r"invoice\s*(?:number|no\.?|#)?\s*([A-Za-z0-9\-]{3,})",
        r"receipt\s*(?:number|#)?\s*([A-Za-z0-9\-]{3,})",
        r"statement\s*issue\s*date.*?([A-Za-z]{3,9}\s+\d{1,2},\s+\d{4})",
        r"מספר\s*תעודה[:\s]*([A-Za-z0-9/\-]{3,})",
    )
    for pattern in patterns:
        match = re.search(pattern, text or "", re.IGNORECASE)
        if match:
            return normalize_ws(match.group(1))
    return ""


def _finance_extract_reference_number(text: str, original_name: str = "") -> str:
    patterns = (
        r"אסמכתא(?:\s*מס(?:פר)?|\s*מס['\":]?)?\s*[:#]?\s*([A-Za-z0-9/\-]{3,})",
        r"מס(?:פר)?\s*אסמכתא\s*[:#]?\s*([A-Za-z0-9/\-]{3,})",
        r"reference(?:\s*number|\s*no\.?|\s*#)?\s*[:#]?\s*([A-Za-z0-9/\-]{3,})",
        r"חשבונית\s*מס(?:/קבלה)?\s*(?:מס['\":]?)?\s*([A-Za-z0-9/\-]{3,})",
        r"invoice(?:\s*number|\s*no\.?|\s*#)?\s*[:#]?\s*([A-Za-z0-9/\-]{3,})",
        r"\b(SI\d{6,})\b",
    )
    haystack = str(text or "")
    for pattern in patterns:
        match = re.search(pattern, haystack, re.IGNORECASE)
        if not match:
            continue
        return normalize_ws(match.group(1))
    filename_match = re.search(r"\b(SI\d{6,})\b", str(original_name or ""), re.IGNORECASE)
    if filename_match:
        return normalize_ws(filename_match.group(1))
    fallback = _finance_extract_invoice_reference(haystack) if haystack else ""
    return normalize_ws(fallback)


def _finance_reference_looks_suspicious(reference_number: str, row: dict) -> bool:
    reference = str(reference_number or "").strip()
    if not reference:
        return False
    file_stem = Path(str((row or {}).get("source_file_name") or "")).stem.strip()
    service = str((row or {}).get("service_or_product") or "").strip()
    return reference in {file_stem, service}


def _finance_extract_allocation_number(text: str) -> str:
    def _digits(token: str) -> str:
        return re.sub(r"\D+", "", token or "")

    def _normalize_allocation_from_window(candidate: str) -> str:
        digit_tokens = [_digits(token) for token in re.findall(r"[A-Za-z0-9\-]{6,}", normalize_ws(candidate))]
        digit_tokens = [token for token in digit_tokens if len(token) >= 8]
        if not digit_tokens:
            return ""
        short_tokens = [token for token in digit_tokens if 8 <= len(token) <= 10]
        long_tokens = [token for token in digit_tokens if len(token) >= 17 and token.startswith("20")]
        for index, long_token in enumerate(digit_tokens):
            if long_token not in long_tokens:
                continue
            adjacent_short_tokens = []
            if index + 1 < len(digit_tokens) and 8 <= len(digit_tokens[index + 1]) <= 10:
                adjacent_short_tokens.append(digit_tokens[index + 1])
            if index - 1 >= 0 and 8 <= len(digit_tokens[index - 1]) <= 10:
                adjacent_short_tokens.append(digit_tokens[index - 1])
            for short_token in adjacent_short_tokens:
                if long_token.endswith(short_token) and len(long_token) - len(short_token) >= 17:
                    return f"{short_token} {long_token[:-len(short_token)]}"
                return f"{short_token} {long_token}"
        for long_token in long_tokens:
            for short_token in short_tokens:
                if long_token.endswith(short_token) and len(long_token) - len(short_token) >= 17:
                    return f"{short_token} {long_token[:-len(short_token)]}"
        for long_token in long_tokens:
            for short_token in short_tokens:
                return f"{short_token} {long_token}"
        for long_token in long_tokens:
            if len(long_token) >= 25:
                for short_len in (9, 8, 10):
                    if len(long_token) - short_len >= 17:
                        short_token = long_token[-short_len:]
                        prefix = long_token[:-short_len]
                        if prefix.startswith("20"):
                            return f"{short_token} {prefix}"
            return long_token
        return short_tokens[0] if short_tokens else digit_tokens[0]

    def _score_allocation_candidate(candidate: str) -> int:
        digits_only = re.sub(r"\D+", "", candidate or "")
        score = len(digits_only)
        parts = [part for part in str(candidate or "").split() if part]
        if len(parts) >= 2:
            first_digits = _digits(parts[0])
            second_digits = _digits(parts[1])
            if 8 <= len(first_digits) <= 10:
                score += 20
            if len(second_digits) >= 17 and second_digits.startswith("20"):
                score += 50
        return score

    keyword_patterns = (
        (r"מס(?:פר|')?\s*הקצאה", "after"),
        (r"מספ[הא]\s*הקצאה", "after"),
        (r"אישור\s*הקצאה", "after"),
        (r"allocation(?:\s*number|\s*no\.?|\s*#)?", "after"),
        (r"האצקה\s*רפסמ", "before"),
        (r"הקצאה", "after"),
    )
    best_candidate = ""
    best_score = -1
    source_text = text or ""
    for pattern, direction in keyword_patterns:
        for match in re.finditer(pattern, source_text, re.IGNORECASE):
            if direction == "before":
                window = source_text[max(0, match.start() - 120):match.start()]
            else:
                window = source_text[match.end():match.end() + 120]
            candidate = _normalize_allocation_from_window(window)
            if not candidate:
                continue
            score = _score_allocation_candidate(candidate)
            if score > best_score:
                best_score = score
                best_candidate = candidate
    return best_candidate


def _finance_allocation_looks_suspicious(allocation_number: str) -> bool:
    raw = str(allocation_number or "").strip()
    if not raw:
        return False
    digits = re.sub(r"\D+", "", raw)
    return len(digits) < 15


def _finance_extract_table_line_item_service(text: str) -> str:
    lines = [normalize_ws(line) for line in str(text or "").splitlines() if normalize_ws(line)]
    header_patterns = (
        r"מפתח\s*פריט.*שם\s*פריט.*כמות.*מחיר",
        r"שם\s*פריט.*כמות.*מחיר.*מטבע",
        r"תיאור\s*הפריט.*כמות.*מחיר",
    )
    stop_markers = (
        "תאריך תשלום",
        "סה\"כ",
        "סה״כ",
        "סהכ",
        "מע\"מ",
        "מע״מ",
        "העברה ישירה",
        "הופק ע\"י",
        "הופק על ידי",
        "לכבוד",
    )
    for index, line in enumerate(lines):
        if not any(re.search(pattern, line, re.IGNORECASE) for pattern in header_patterns):
            continue
        parts: list[str] = []
        for candidate in lines[index + 1:index + 6]:
            if any(marker in candidate for marker in stop_markers):
                break
            cleaned = re.sub(r"^\d{4,}\s+", "", candidate).strip()
            cleaned = re.sub(r"\s+\|\s*\d[\d.,]*.*$", "", cleaned).strip()
            cleaned = re.sub(
                r"\s+\d[\d.,]*\s+[0-9,.\-]{1,20}\s+\S+\s+[0-9,.\-]{1,20}\s+[0-9,.\-]{1,20}\s*$",
                "",
                cleaned,
            ).strip()
            if not cleaned:
                continue
            if parts and re.search(r"[A-Za-z]{3,}", cleaned):
                break
            token_chars = [re.sub(r"[^א-תA-Za-z0-9]", "", token) for token in cleaned.split()]
            compact_tokens = [token for token in token_chars if token]
            short_token_count = sum(1 for token in compact_tokens if len(token) <= 2)
            if parts and compact_tokens and short_token_count >= max(3, len(compact_tokens) - 1):
                break
            if parts and re.fullmatch(r"[\d()\s-]+", cleaned):
                digits_only = re.sub(r"\D+", "", cleaned)
                if digits_only:
                    previous = parts[-1].rstrip()
                    if previous.endswith(")"):
                        parts[-1] = previous[:-1].rstrip() + f" ({digits_only})"
                    elif previous.endswith("("):
                        parts[-1] = previous + digits_only + ")"
                continue
            if re.fullmatch(r"[\W_]+", cleaned):
                continue
            parts.append(cleaned)
        if not parts:
            continue
        service = normalize_ws(" ".join(parts))
        service = re.sub(r"\bב\s+(\d+\s*נושאים)", r"ב-\1", service)
        service = service.replace(" ,", ",").replace(" )", ")").strip(" -")
        if service:
            return service
    return ""


def _finance_extract_line_item_service(text: str) -> str:
    table_service = _finance_extract_table_line_item_service(text)
    if table_service:
        return table_service
    patterns = (
        r"(ChatGPT Plus Subscription[^\n]{0,80})",
        r"(Claude ai[^\n]{0,80})",
        r"(Google Ads[^\n]{0,80})",
        r"(דמי שימוש חודשיים[^\n]{0,80})",
        r"(מנויי סלולר[^\n]{0,80})",
        r"(סט מברשות[^\n]{0,80})",
        r"(הפצה נוספת[^\n]{0,80})",
        r"(משטחים[^\n]{0,80})",
    )
    for pattern in patterns:
        match = re.search(pattern, text or "", re.IGNORECASE)
        if match:
            return normalize_ws(match.group(1))
    return ""


def _finance_ocr_pdf_page_texts(file_path: Path) -> list[dict]:
    import fitz
    from services.ocr_service import _ocr_image_bytes_via_vision

    page_entries: list[dict] = []
    pdf = fitz.open(str(file_path))
    try:
        for page_index in range(pdf.page_count):
            page = pdf.load_page(page_index)
            pixmap = page.get_pixmap(matrix=fitz.Matrix(1.2, 1.2), alpha=False)
            img_bytes = pixmap.tobytes("png")
            raw_text = _ocr_image_bytes_via_vision(img_bytes)
            if not raw_text:
                try:
                    from PIL import Image
                    import pytesseract
                    image = Image.frombytes("RGB", [pixmap.width, pixmap.height], pixmap.samples)
                    raw_text = pytesseract.image_to_string(image, lang="heb+eng", config="--psm 6")
                except Exception:
                    raw_text = ""
            fixed_text = fix_hebrew_text(raw_text or "").strip()
            page_entries.append(
                {
                    "page_number": page_index + 1,
                    "raw_text": (raw_text or "").strip(),
                    "fixed_text": fixed_text,
                }
            )
    finally:
        pdf.close()
    return page_entries


def _finance_is_bundle_financial_start(raw_text: str, fixed_text: str) -> bool:
    raw, lowered = _finance_text_haystacks(raw_text, fixed_text)
    if not normalize_ws(raw):
        return False
    if any(token in lowered for token in FINANCE_BUNDLE_NON_FINANCIAL_PATTERNS):
        return False
    if "google ads" in lowered and "summary for" in lowered:
        return True
    if "openai" in lowered or "chatgpt plus" in lowered or "anthropic" in lowered or "claude ai" in lowered:
        return True
    return any(token in lowered for token in FINANCE_BUNDLE_FINANCIAL_START_PATTERNS)


def _finance_is_bundle_continuation_page(raw_text: str, fixed_text: str, current_doc: dict) -> bool:
    raw, lowered = _finance_text_haystacks(raw_text, fixed_text)
    if not normalize_ws(raw):
        return True
    if "אישור תשלום" in raw:
        return False
    if len(normalize_ws(raw)) <= 40:
        return True
    current_signature = current_doc.get("signature") or {}
    current_invoice_ref = str(current_signature.get("invoice_ref") or "").strip()
    if current_invoice_ref and current_invoice_ref in raw:
        return True
    current_supplier = str(current_signature.get("supplier_name") or "").strip()
    if current_supplier and current_supplier.lower() in lowered:
        return True
    return False


def _finance_bundle_page_signature(raw_text: str, fixed_text: str) -> dict:
    combined = "\n".join([fixed_text or "", raw_text or ""]).strip()
    return {
        "supplier_name": _finance_guess_supplier_from_known_patterns(combined),
        "invoice_ref": _finance_extract_invoice_reference(combined),
    }


def _finance_split_invoice_bundle(file_path: Path) -> list[dict]:
    if file_path.suffix.lower() != ".pdf":
        return []
    page_entries = _finance_ocr_pdf_page_texts(file_path)
    if not page_entries:
        return []
    groups: list[dict] = []
    current_doc: dict | None = None
    for entry in page_entries:
        raw_text = entry.get("raw_text") or ""
        fixed_text = entry.get("fixed_text") or ""
        signature = _finance_bundle_page_signature(raw_text, fixed_text)
        is_start = _finance_is_bundle_financial_start(raw_text, fixed_text)
        if is_start:
            if current_doc:
                current_signature = current_doc.get("signature") or {}
                if (
                    str(signature.get("invoice_ref") or "").strip()
                    and str(signature.get("invoice_ref") or "").strip() == str(current_signature.get("invoice_ref") or "").strip()
                    and str(signature.get("supplier_name") or "").strip() == str(current_signature.get("supplier_name") or "").strip()
                ):
                    current_doc["pages"].append(entry["page_number"])
                    current_doc["raw_text_parts"].append(raw_text)
                    current_doc["fixed_text_parts"].append(fixed_text)
                    continue
                groups.append(current_doc)
            current_doc = {
                "pages": [entry["page_number"]],
                "raw_text_parts": [raw_text],
                "fixed_text_parts": [fixed_text],
                "signature": signature,
            }
            continue
        if current_doc and _finance_is_bundle_continuation_page(raw_text, fixed_text, current_doc):
            current_doc["pages"].append(entry["page_number"])
            current_doc["raw_text_parts"].append(raw_text)
            current_doc["fixed_text_parts"].append(fixed_text)
            continue
        if current_doc:
            groups.append(current_doc)
            current_doc = None
    if current_doc:
        groups.append(current_doc)
    return [group for group in groups if group.get("pages")]


def _ensure_finance_invoice_storage_dirs() -> None:
    FINANCE_INVOICE_UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
    FINANCE_INVOICE_ACTIVE_DIR.mkdir(parents=True, exist_ok=True)
    FINANCE_INVOICE_SOURCE_DIR.mkdir(parents=True, exist_ok=True)
    FINANCE_INVOICE_SPLIT_DIR.mkdir(parents=True, exist_ok=True)
    FINANCE_INVOICE_ARCHIVE_DIR.mkdir(parents=True, exist_ok=True)


def _finance_invoice_upload_target(original_name: str) -> Path:
    _ensure_finance_invoice_storage_dirs()
    suffix = Path(original_name).suffix
    safe_stem = _safe_folder_name(Path(original_name).stem) or "invoice"
    safe_name = f"{safe_stem}{suffix}" if suffix else safe_stem
    return FINANCE_INVOICE_SOURCE_DIR / f"{datetime.now().strftime('%Y%m%d-%H%M%S')}-{safe_name}"


def _finance_invoice_split_root(original_name: str) -> Path:
    _ensure_finance_invoice_storage_dirs()
    return FINANCE_INVOICE_SPLIT_DIR / f"{_safe_folder_name(Path(original_name).stem) or 'bundle'}-split"


def _finance_archive_path(source_path: Path, bucket: str = "orphaned") -> Path:
    _ensure_finance_invoice_storage_dirs()
    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    bucket_dir = FINANCE_INVOICE_ARCHIVE_DIR / bucket / timestamp
    bucket_dir.mkdir(parents=True, exist_ok=True)
    target = bucket_dir / source_path.name
    if not target.exists():
        return target
    stem = source_path.stem
    suffix = source_path.suffix
    counter = 2
    while True:
        candidate = bucket_dir / f"{stem}-{counter}{suffix}"
        if not candidate.exists():
            return candidate
        counter += 1


def _archive_finance_path(source_path: Path, bucket: str = "orphaned") -> Path | None:
    try:
        if not source_path.exists():
            return None
        target = _finance_archive_path(source_path, bucket=bucket)
        shutil.move(str(source_path), str(target))
        return target
    except Exception as exc:
        log_handled_error("archive finance path failed", exc)
        return None


def _finance_referenced_local_paths(rows: list[dict] | None = None) -> set[Path]:
    referenced: set[Path] = set()
    source_rows = rows if rows is not None else _dedupe_finance_invoice_rows(load_marketing_rows("finance_invoices"))
    for row in source_rows or []:
        raw_path = str((row or {}).get("source_file_path") or "").strip()
        if not raw_path:
            continue
        try:
            path = Path(raw_path).resolve()
        except Exception:
            continue
        referenced.add(path)
        for parent in path.parents:
            if parent == FINANCE_INVOICE_UPLOAD_DIR.resolve():
                referenced.add(parent)
                break
    return referenced


def _finance_cleanup_uploads_dir() -> dict:
    _ensure_finance_invoice_storage_dirs()
    rows = _dedupe_finance_invoice_rows(load_marketing_rows("finance_invoices"))
    referenced_paths = _finance_referenced_local_paths(rows)
    archived_files = 0
    archived_dirs = 0
    archived_items: list[str] = []
    upload_root = FINANCE_INVOICE_UPLOAD_DIR.resolve()
    protected_roots = {
        FINANCE_INVOICE_ACTIVE_DIR.resolve(),
        FINANCE_INVOICE_ARCHIVE_DIR.resolve(),
    }

    for child in sorted(FINANCE_INVOICE_UPLOAD_DIR.iterdir(), key=lambda item: item.name.lower()):
        child_resolved = child.resolve()
        if child_resolved in protected_roots:
            continue
        if child.is_file():
            if child_resolved in referenced_paths:
                continue
            archived_target = _archive_finance_path(child, bucket="orphaned-files")
            if archived_target:
                archived_files += 1
                archived_items.append(str(archived_target))
            continue
        if child.is_dir():
            child_files = [path.resolve() for path in child.rglob("*") if path.is_file()]
            if any(file_path in referenced_paths for file_path in child_files):
                continue
            archived_target = _archive_finance_path(child, bucket="orphaned-folders")
            if archived_target:
                archived_dirs += 1
                archived_items.append(str(archived_target))

    return {
        "referenced_rows": len(rows),
        "archived_files": archived_files,
        "archived_dirs": archived_dirs,
        "archived_items": archived_items,
        "active_root": str(FINANCE_INVOICE_ACTIVE_DIR),
        "archive_root": str(FINANCE_INVOICE_ARCHIVE_DIR),
        "upload_root": str(upload_root),
    }


def _finance_export_split_pdf(source_file: Path, pages: list[int], target_path: Path) -> None:
    from PyPDF2 import PdfReader, PdfWriter

    reader = PdfReader(str(source_file))
    writer = PdfWriter()
    for page_number in pages:
        if 1 <= int(page_number) <= len(reader.pages):
            writer.add_page(reader.pages[int(page_number) - 1])
    target_path.parent.mkdir(parents=True, exist_ok=True)
    with target_path.open("wb") as file_obj:
        writer.write(file_obj)


def _finance_export_split_pdf_regions(source_file: Path, regions: list[dict], target_path: Path) -> None:
    import fitz

    source_doc = fitz.open(str(source_file))
    output_doc = fitz.open()
    try:
        for region in regions or []:
            try:
                page_number = int(region.get("page") or region.get("page_number") or 1)
            except Exception:
                page_number = 1
            rect_values = region.get("rect") or region.get("clip") or []
            if len(rect_values) != 4:
                continue
            try:
                clip_rect = fitz.Rect(*[float(value) for value in rect_values])
            except Exception:
                continue
            if page_number < 1 or page_number > source_doc.page_count:
                continue
            source_page = source_doc.load_page(page_number - 1)
            pixmap = source_page.get_pixmap(matrix=fitz.Matrix(2.5, 2.5), clip=clip_rect, alpha=False)
            output_page = output_doc.new_page(width=clip_rect.width, height=clip_rect.height)
            output_page.insert_image(output_page.rect, stream=pixmap.tobytes("png"))
        if output_doc.page_count <= 0:
            raise RuntimeError("לא נמצאו אזורי חיתוך תקינים לפיצול החשבונית.")
        target_path.parent.mkdir(parents=True, exist_ok=True)
        output_doc.save(str(target_path))
    finally:
        try:
            output_doc.close()
        except Exception:
            pass
        source_doc.close()


class _FinanceHTMLTextExtractor(HTMLParser):
    def __init__(self) -> None:
        super().__init__()
        self._parts: list[str] = []
        self._skip_depth = 0

    def handle_starttag(self, tag: str, attrs) -> None:
        tag_name = str(tag or "").lower()
        if tag_name in {"style", "script", "head", "title"}:
            self._skip_depth += 1
            return
        if tag_name in {"br", "p", "div", "li", "tr", "table", "section", "h1", "h2", "h3", "h4"}:
            self._parts.append("\n")

    def handle_endtag(self, tag: str) -> None:
        tag_name = str(tag or "").lower()
        if tag_name in {"style", "script", "head", "title"}:
            self._skip_depth = max(0, self._skip_depth - 1)
            return
        if tag_name in {"p", "div", "li", "tr", "table", "section", "h1", "h2", "h3", "h4"}:
            self._parts.append("\n")

    def handle_data(self, data: str) -> None:
        if self._skip_depth <= 0 and data:
            self._parts.append(data)

    def get_text(self) -> str:
        return html.unescape("".join(self._parts))


def _finance_html_to_text(content: str) -> str:
    parser = _FinanceHTMLTextExtractor()
    try:
        parser.feed(content or "")
        parser.close()
    except Exception:
        return html.unescape(re.sub(r"<[^>]+>", " ", str(content or "")))
    return parser.get_text()


def _finance_read_eml_payload(file_path: Path) -> dict:
    try:
        with file_path.open("rb") as file_obj:
            message = BytesParser(policy=policy.default).parse(file_obj)
    except Exception:
        return {
            "subject": "",
            "sender": "",
            "plain_text": "",
            "html_text": "",
            "combined_text": "",
        }

    plain_parts: list[str] = []
    html_parts: list[str] = []
    for part in message.walk():
        if part.is_multipart():
            continue
        if str(part.get_content_disposition() or "").lower() == "attachment":
            continue
        content_type = str(part.get_content_type() or "").lower()
        try:
            payload = part.get_content()
        except Exception:
            try:
                raw_bytes = part.get_payload(decode=True) or b""
                charset = part.get_content_charset() or "utf-8"
                payload = raw_bytes.decode(charset, errors="replace")
            except Exception:
                payload = ""
        payload_text = str(payload or "")
        if content_type == "text/plain":
            plain_parts.append(payload_text)
        elif content_type == "text/html":
            html_parts.append(payload_text)

    subject = normalize_ws(str(message.get("subject") or ""))
    sender = normalize_ws(str(message.get("from") or ""))
    plain_text = "\n\n".join(part.strip() for part in plain_parts if str(part or "").strip())
    html_text = "\n\n".join(_finance_html_to_text(part) for part in html_parts if str(part or "").strip())
    combined_text = "\n\n".join(
        part
        for part in [
            f"Subject: {subject}" if subject else "",
            f"From: {sender}" if sender else "",
            plain_text,
            html_text,
        ]
        if str(part or "").strip()
    ).strip()
    return {
        "subject": subject,
        "sender": sender,
        "plain_text": plain_text.strip(),
        "html_text": html_text.strip(),
        "combined_text": combined_text,
    }


def _finance_extract_eml_text(file_path: Path) -> str:
    payload = _finance_read_eml_payload(file_path)
    return str(payload.get("combined_text") or "").strip()


def _finance_render_eml_to_pdf(file_path: Path) -> Path:
    _ensure_finance_invoice_storage_dirs()
    payload = _finance_read_eml_payload(file_path)
    pdf_path = file_path.with_suffix(".pdf")
    title_style = ParagraphStyle(
        "finance-eml-title",
        parent=getSampleStyleSheet()["Heading2"],
        alignment=TA_LEFT,
        fontName="Helvetica-Bold",
        fontSize=16,
        leading=20,
        textColor=colors.HexColor("#1f2937"),
    )
    body_style = ParagraphStyle(
        "finance-eml-body",
        parent=getSampleStyleSheet()["BodyText"],
        alignment=TA_LEFT,
        fontName="Helvetica",
        fontSize=9.5,
        leading=13,
        textColor=colors.black,
    )
    story: list = [Paragraph("Email Invoice Copy", title_style), Spacer(1, 10)]
    for raw_line in str(payload.get("combined_text") or "").splitlines():
        line = str(raw_line or "").rstrip()
        if not line:
            story.append(Spacer(1, 6))
            continue
        story.append(Paragraph(html.escape(line), body_style))
        story.append(Spacer(1, 3))
    if len(story) <= 2:
        story.append(Paragraph("No readable invoice content was found in this email.", body_style))
    document = SimpleDocTemplate(
        str(pdf_path),
        pagesize=A4,
        leftMargin=30,
        rightMargin=30,
        topMargin=30,
        bottomMargin=30,
    )
    document.build(story)
    return pdf_path


def _finance_extract_uploaded_invoice_text(file_path: Path) -> str:
    suffix = file_path.suffix.lower()
    text = ""
    try:
        if suffix == ".pdf":
            text = extract_text_pdfplumber(file_path)
            if len(normalize_ws(text)) < 80:
                text = ocr_pdf(file_path)
        elif suffix == ".eml":
            text = _finance_extract_eml_text(file_path)
        elif suffix in {".jpg", ".jpeg", ".png", ".bmp", ".tif", ".tiff", ".webp", ".heic"}:
            from services.ocr_service import ocr_image_file
            text = ocr_image_file(file_path)
    except Exception:
        text = ""
    cleaned = fix_hebrew_text(text or "").strip()
    return cleaned or (text or "").strip()


