def _finance_ocr_google_ads_summary_text(file_path: Path) -> str:
    import fitz
    from PIL import Image
    from services.ocr_service import _ocr_image_bytes_via_vision

    if file_path.suffix.lower() != ".pdf":
        return ""
    try:
        pdf = fitz.open(str(file_path))
    except Exception:
        return ""
    try:
        if pdf.page_count <= 0:
            return ""
        page = pdf.load_page(0)
        pixmap = page.get_pixmap(matrix=fitz.Matrix(3, 3), alpha=False)
        image = Image.frombytes("RGB", [pixmap.width, pixmap.height], pixmap.samples)
        width, height = image.size
        crop_box = (
            int(width * 0.37),
            int(height * 0.22),
            int(width * 0.93),
            int(height * 0.50),
        )
        cropped = image.crop(crop_box)
        img_bytes = io.BytesIO()
        cropped.save(img_bytes, format="PNG")
        result = _ocr_image_bytes_via_vision(img_bytes.getvalue())
        if result:
            return result.strip()
        # fallback to pytesseract if Vision not available
        try:
            import pytesseract
            texts = []
            for psm in (11, 6):
                try:
                    texts.append(pytesseract.image_to_string(cropped, lang="eng", config=f"--psm {psm}"))
                except Exception:
                    continue
            return "\n".join(t for t in texts if t).strip()
        except Exception:
            return ""
    finally:
        pdf.close()


def _finance_detect_pazomat_invoice(raw_text: str, fixed_text: str, original_name: str) -> bool:
    haystack = "\n".join([raw_text or "", fixed_text or "", original_name or ""]).lower()
    return (
        "pazomat" in haystack
        or "pazomat.co.il" in haystack
        or "invoice_summary_" in haystack
        or "פז קמעונאות" in haystack
        or "שירות@פזומט".lower() in haystack
    )


def _finance_detect_paz_aviation_invoice(raw_text: str, fixed_text: str, original_name: str) -> bool:
    haystack = "\n".join([raw_text or "", fixed_text or "", original_name or ""]).lower()
    return (
        "שירותי תעופה" in haystack
        or "aviation_services@paz.co.il" in haystack
        or "בנזין תעופתי" in haystack
    )


def _finance_find_labeled_amount(text: str, patterns: list[str]) -> float | None:
    for pattern in patterns:
        match = re.search(pattern, text, re.IGNORECASE | re.MULTILINE)
        if not match:
            continue
        amount = normalize_amount(match.group(1))
        if amount is not None:
            return float(amount)
    return None


def _finance_guess_invoice_totals(text: str) -> tuple[str, str, str]:
    subtotal = _finance_first_amount_after_label(
        text,
        [
            r"סה[\"״]כ\s*לפני\s*מע[\"״]מ",
            r"סכום\s*לפני\s*מע[\"״]מ",
            r"subtotal",
            r"before\s*vat",
            r"amount\s*before\s*vat",
        ],
        max_gap=120,
    )
    if subtotal is None:
        subtotal = _finance_last_amount_before_label(text, [r"סה[\"״]כ\s*לפני\s*מע[\"״]מ"], max_gap=80)

    vat = _finance_first_amount_after_label(
        text,
        [
            r"מע[\"״]מ",
            r"vat",
            r"tax",
        ],
        max_gap=80,
    )

    total = _finance_first_amount_after_label(
        text,
        [
            r"סה[\"״]כ\s*לתשלום",
            r"סה[\"״]כ\s*כולל\s*מע[\"״]מ",
            r"total",
            r"amount\s*due",
            r"סה[\"״]כ\s*שולם",
            r"סה[\"״]כ\s*אחרי\s*מע[\"״]מ",
        ],
        max_gap=120,
    )
    if total is None:
        total = _finance_last_amount_before_label(text, [r"סה[\"״]כ\s*לתשלום", r"amount\s*due"], max_gap=80)
    if subtotal is None and total is not None and vat is not None:
        subtotal = round(max(0.0, total - vat), 2)
    if total is None and subtotal is not None and vat is not None:
        total = round(subtotal + vat, 2)
    if vat is None and subtotal is not None and total is not None:
        vat = round(max(0.0, total - subtotal), 2)
    if subtotal is None and total is not None:
        subtotal = total
    if vat is None and subtotal is not None and total is not None and abs(total - subtotal) < 0.01:
        vat = 0.0
    return (
        f"{subtotal:.2f}" if subtotal is not None else "",
        f"{vat:.2f}" if vat is not None else "",
        f"{total:.2f}" if total is not None else "",
    )


def _finance_guess_invoice_date(text: str) -> str:
    english_date = _finance_parse_english_date(text)
    if english_date:
        return english_date
    patterns = [
        r"(?:תאריך\s*חשבונית|תאריך\s*הפקה|תאריך|invoice\s*date|date)\D{0,10}(\d{2}[./-]\d{2}[./-]\d{2,4})",
        r"(\d{2}[./-]\d{2}[./-]\d{4})",
        r"(\d{2}[./-]\d{2}[./-]\d{2})",
    ]
    for pattern in patterns:
        match = re.search(pattern, text, re.IGNORECASE | re.MULTILINE)
        if not match:
            continue
        normalized = normalize_date(match.group(1).replace(".", "/").replace("-", "/"))
        if normalized:
            return normalized
    return date.today().strftime("%d/%m/%Y")


def _finance_guess_invoice_date_from_raw(raw_text: str) -> str:
    english_date = _finance_parse_english_date(raw_text)
    if english_date:
        return english_date
    for pattern in (
        r"(\d{2}/\d{2}/\d{4})\s*:ךיראת",
        r":ךיראת\s*(\d{2}/\d{2}/\d{4})",
        r"(\d{2}/\d{2}/\d{4})",
        r"(\d{2}[.-]\d{2}[.-]\d{4})",
    ):
        match = re.search(pattern, raw_text or "")
        if not match:
            continue
        normalized = normalize_date(match.group(1).replace(".", "/").replace("-", "/"))
        if normalized:
            return normalized
    return date.today().strftime("%d/%m/%Y")


def _finance_guess_supplier_name(text: str, original_name: str) -> str:
    known_supplier = _finance_guess_supplier_from_known_patterns(text, original_name)
    if known_supplier:
        return known_supplier
    lines = [normalize_ws(line) for line in fix_hebrew_text(text or "").splitlines()]
    candidates: list[str] = []
    for line in lines[:20]:
        clean = normalize_ws(line)
        if not clean or len(clean) < 3 or len(clean) > 80:
            continue
        lowered = clean.lower()
        if any(token in lowered for token in FINANCE_INVOICE_SUPPLIER_SKIP_PATTERNS):
            continue
        if re.search(r"\d{5,}", clean):
            continue
        if clean.count(" ") > 9:
            continue
        candidates.append(clean)
    if candidates:
        return candidates[0]
    return normalize_ws(Path(original_name).stem.replace("_", " ").replace("-", " "))


def _finance_guess_service_or_product(text: str, original_name: str) -> str:
    known_service = _finance_extract_line_item_service(text)
    if known_service:
        return known_service
    patterns = [
        r"(?:תיאור\s*(?:שירות|מוצר|עסקה)|עבור|פרטי\s*עסקה|description)\D{0,10}([^\n]{3,120})",
    ]
    for pattern in patterns:
        match = re.search(pattern, text, re.IGNORECASE | re.MULTILINE)
        if not match:
            continue
        candidate = normalize_ws(match.group(1))
        if candidate and len(candidate) <= 120:
            return candidate
    stem = normalize_ws(Path(original_name).stem.replace("_", " ").replace("-", " "))
    return stem or "חשבונית שהועלתה"


def _finance_detect_google_ads_invoice(raw_text: str, fixed_text: str, original_name: str) -> bool:
    _raw, lowered = _finance_text_haystacks(raw_text, fixed_text, original_name)
    return "google ads" in lowered and "summary for" in lowered


def _finance_parse_google_ads_invoice(raw_text: str, fixed_text: str, original_name: str, file_path: Path) -> dict:
    combined = "\n".join([fixed_text or "", raw_text or ""])
    period_match = re.search(r"Summary\s+for\s+([A-Za-z]{3,9}\s+\d{1,2},\s+\d{4}\s*-\s*[A-Za-z]{3,9}\s+\d{1,2},\s+\d{4})", combined, re.IGNORECASE)
    issue_match = re.search(r"Statement\s+issue\s+date[^\n]*?([A-Za-z]{3,9}\s+\d{1,2},\s+\d{4})", combined, re.IGNORECASE)
    issue_date = _finance_parse_english_date(issue_match.group(0) if issue_match else combined) or _finance_guess_invoice_date(combined)
    total = _finance_first_amount_after_label(combined, [r"Total\s+new\s+activity"], max_gap=40)
    starting_balance = _finance_first_amount_after_label(combined, [r"Starting\s+balance"], max_gap=25)
    ending_balance = _finance_first_amount_after_label(combined, [r"Ending\s+balance\s+in\s+ILS"], max_gap=25)
    payments_received = _finance_first_amount_after_label(combined, [r"Total\s+payments\s+received"], max_gap=25)
    if ending_balance is None or payments_received is None or (total is not None and total >= 1000):
        summary_ocr = _finance_ocr_google_ads_summary_text(file_path)
        if summary_ocr:
            total = _finance_first_amount_after_label(summary_ocr, [r"Total\s+new\s+activity"], max_gap=30) or total
            starting_balance = _finance_first_amount_after_label(summary_ocr, [r"Starting\s+balance"], max_gap=20) or starting_balance
            ending_balance = _finance_first_amount_after_label(summary_ocr, [r"Ending\s+balance\s+in\s+ILS"], max_gap=20) or ending_balance
            payments_match = re.search(r"Total\s+payments\s+received[^\d-]*(-?\d[\d,]*\.\d{2})", summary_ocr, re.IGNORECASE)
            if payments_match:
                try:
                    payments_received = float(str(payments_match.group(1)).replace(",", ""))
                except Exception:
                    pass
    inferred_total = None
    if ending_balance is not None and starting_balance is not None and payments_received is not None:
        inferred_total = round(max(0.0, ending_balance - starting_balance + abs(payments_received)), 2)
    if inferred_total is not None:
        if total is None:
            total = inferred_total
        elif ending_balance is not None and (
            total > ending_balance * 1.4
            or abs(total - inferred_total) > 0.01
        ):
            total = inferred_total
    elif ending_balance is not None and (total is None or (total and total < ending_balance * 0.5)):
        total = ending_balance
    total_value = round(total or 0.0, 2)
    service = "Google Ads"
    if period_match:
        service = f"Google Ads ({normalize_ws(period_match.group(1))})"
    return _normalize_finance_invoice_row_app(
        {
            "row_id": f"finance-upload-{uuid.uuid4().hex}",
            "invoice_date": issue_date or date.today().strftime("%d/%m/%Y"),
            "supplier_name": "Google Ads",
            "service_or_product": service,
            "subtotal": f"{total_value:.2f}" if total_value else "",
            "vat": "0.00" if total_value else "",
            "total": f"{total_value:.2f}" if total_value else "",
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": _finance_due_date_display(issue_date),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )


