def _finance_detect_infinitech_invoice(raw_text: str, fixed_text: str, original_name: str) -> bool:
    raw_haystack, lowered = _finance_text_haystacks(raw_text, fixed_text, original_name)
    return (
        "infinitech" in lowered
        or "infinitechlabs" in lowered
        or "אינפיניטק" in lowered
        or "טיניפניא" in (raw_haystack or "")
    )


def _finance_parse_infinitech_invoice(raw_text: str, fixed_text: str, original_name: str, file_path: Path) -> dict:
    raw_source = raw_text or ""
    fixed_source = fixed_text or ""
    combined = "\n".join([raw_source, fixed_source, original_name or ""]).strip()

    supplier_name_match = (
        re.search(r"א\.\s*כ\s*אינפיניטק", fixed_source, re.IGNORECASE)
        or re.search(r"ק\s*טיניפניא\s*אכ\.א", raw_source)
    )
    supplier_name = "א.כ אינפיניטק" if supplier_name_match else "Infinitech Ltd."

    invoice_date_match = (
        re.search(r"([0-9]{2}/[0-9]{2}/[0-9]{4})\s*:\s*ךיראת", raw_source)
        or re.search(r"תאריך[:\s]*([0-9]{2}/[0-9]{2}/[0-9]{4})", fixed_source)
    )
    invoice_date = normalize_date(invoice_date_match.group(1)) if invoice_date_match else _finance_guess_invoice_date(combined)

    invoice_number_match = (
        re.search(r"\(רוקמ\)\s*([0-9]{3,})\s+הלבק\s+סמ\s+תינובשח", raw_source)
        or re.search(r"חשבונית\s*מס\s*קבלה\s*[(/-]?\s*([0-9]{3,})", fixed_source, re.IGNORECASE)
        or re.search(r"\b([0-9]{3,})\b", Path(original_name).stem)
    )
    invoice_number = normalize_ws(invoice_number_match.group(1)) if invoice_number_match else ""

    item_match = (
        re.search(r"(MacBook\s+Pro\s+14\"[^\n]+)", fixed_source, re.IGNORECASE)
        or re.search(r"(MacBook\s+Pro\s+14\"[^\n]+)", combined, re.IGNORECASE)
    )
    service_or_product = normalize_ws(item_match.group(1)) if item_match else "MacBook Pro 14\" 2023 - M2 Pro 16 / 1TB"

    subtotal_match = (
        re.search(r"₪\s*([\d,]+\.\d{2})\s*מ[\"״']?עמ\s+ינפל\s+כ[\"״']?הס", raw_source)
        or re.search(r"סה[\"״']?כ\s*לפנ[י|י]\s*מע[\"״']?מ\s*₪?\s*([\d,]+\.\d{2})", fixed_source)
        or re.search(r"₪\s*([\d,]+\.\d{2})\s*סה\"כ לפנ[י|י] מע\"מ", fixed_source)
    )
    vat_match = (
        re.search(r"₪\s*([\d,]+\.\d{2})\s*18%\s*מ.?ע.?מ", raw_source)
        or re.search(r"מע[\"״']?מ\s*₪?\s*([\d,]+\.\d{2})", fixed_source)
        or re.search(r"₪\s*([\d,]+\.\d{2})\s*18%\s*מע[\"״']?מ", fixed_source)
    )
    total_match = (
        re.search(r"₪\s*([\d,]+\.\d{2})\s*םלוש\s+כ[\"״']?הס", raw_source)
        or re.search(r"סה[\"״']?כ\s*כולל\s*מע[\"״']?מ[:\s]*₪?\s*([\d,]+\.\d{2})", fixed_source)
        or re.search(r"סה[\"״']?כ\s*שולם\s*₪?\s*([\d,]+\.\d{2})", fixed_source)
    )

    subtotal = normalize_amount(subtotal_match.group(1)) if subtotal_match else None
    vat = normalize_amount(vat_match.group(1)) if vat_match else None
    total = normalize_amount(total_match.group(1)) if total_match else None
    if subtotal is None:
        subtotal = _finance_first_amount_after_label(combined, [r"סה[\"״']?כ\s*לפנ[י|י]\s*מע[\"״']?מ"], max_gap=40)
    if vat is None:
        vat = _finance_first_amount_after_label(combined, [r"מע[\"״']?מ"], max_gap=30)
    if total is None:
        total = _finance_first_amount_after_label(combined, [r"סה[\"״']?כ\s*כולל\s*מע[\"״']?מ", r"סה[\"״']?כ\s*שולם"], max_gap=40)
    if subtotal is None and total is not None and vat is not None:
        subtotal = round(max(0.0, total - vat), 2)
    if total is None and subtotal is not None and vat is not None:
        total = round(subtotal + vat, 2)

    row = _normalize_finance_invoice_row_app(
        {
            "row_id": _finance_auto_invoice_row_id("infinitech", invoice_date or "", invoice_number or Path(original_name).stem),
            "invoice_date": invoice_date or date.today().strftime("%d/%m/%Y"),
            "supplier_name": supplier_name,
            "reference_number": invoice_number,
            "service_or_product": service_or_product,
            "subtotal": f"{(subtotal or 0.0):.2f}" if subtotal is not None else "",
            "vat": f"{(vat or 0.0):.2f}" if vat is not None else "",
            "total": f"{(total or 0.0):.2f}" if total is not None else "",
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": _finance_due_date_display(invoice_date),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )
    row["supplier_invoice_number"] = invoice_number
    row["payment_supplier_name"] = supplier_name
    return row


def _finance_detect_provecta_invoice(raw_text: str, fixed_text: str, original_name: str) -> bool:
    raw_haystack, lowered = _finance_text_haystacks(raw_text, fixed_text, original_name)
    return "provecta" in lowered or "פרובקטה" in lowered or "הטקבורפ" in (raw_haystack or "")


def _finance_parse_provecta_invoice(raw_text: str, fixed_text: str, original_name: str, file_path: Path) -> dict:
    raw_source = raw_text or ""
    fixed_source = fixed_text or ""

    invoice_number_match = (
        re.search(r"\(רוקמ\)\s*([0-9]{3,})\s+סמ\s+תינובשח", raw_source)
        or re.search(r"חשבונית\s*מס\s+([0-9]{3,})\s*\)?מקור", fixed_source, re.IGNORECASE)
    )
    invoice_date_match = re.search(r"([0-9]{2}/[0-9]{2}/[0-9]{4})\s*:\s*ךיראת", raw_source)
    due_date_match = re.search(r"([0-9]{2}/[0-9]{2}/[0-9]{4})\s*:\s*דע\s*םולשתל", raw_source)
    supplier_id_match = re.search(r"([0-9]{9})\s*:\s*השרומ\s+קסוע", raw_source)
    supplier_email_match = re.search(r"([A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,})\s*:\s*ל[\"א]וד", raw_source)
    customer_name_match = re.search(r"(.+?)\s*:\s*דובכל", raw_source)

    service_match = re.search(
        r"₪[\d,.]+\s+\d+\s+₪[\d,.]+\s+([0-9]{3}-[0-9]{6})\s+'?סמ\s+תורש\s+חוד\s+יפל\s+(.+)",
        raw_source,
    )
    subtotal_match = re.search(r"₪([\d,.]+)\s+מ\"עמ\s+ינפל\s+כ\"?הס", raw_source)
    vat_match = re.search(r"₪([\d,.]+)\s+18%\s+מ\"עמ", raw_source)
    total_match = re.search(r"₪([\d,.]+)\s*$", raw_source, re.MULTILINE)

    invoice_number = normalize_ws(invoice_number_match.group(1)) if invoice_number_match else ""
    invoice_date = normalize_date(invoice_date_match.group(1)) if invoice_date_match else ""
    payment_due_date = normalize_date(due_date_match.group(1)) if due_date_match else ""
    supplier_id = normalize_ws(supplier_id_match.group(1)[::-1]) if supplier_id_match else ""
    supplier_email = normalize_ws(supplier_email_match.group(1)) if supplier_email_match else ""
    customer_name = normalize_ws(customer_name_match.group(1)[::-1]) if customer_name_match else ""

    service_or_product = "תיקון מכבש"
    if service_match:
        report_number = normalize_ws(service_match.group(1)[::-1])
        service_label = normalize_ws(service_match.group(2)[::-1]).strip(" .")
        service_or_product = f"{service_label} - לפי דוח שירות מס' {report_number}".strip(" -")

    subtotal = _finance_parse_number(subtotal_match.group(1)) if subtotal_match else None
    vat = _finance_parse_number(vat_match.group(1)) if vat_match else None
    total = _finance_parse_number(total_match.group(1)) if total_match else None
    if subtotal is None and total is not None and vat is not None:
        subtotal = round(max(0.0, total - vat), 2)
    if total is None and subtotal is not None and vat is not None:
        total = round(subtotal + vat, 2)

    row = _normalize_finance_invoice_row_app(
        {
            "row_id": f"finance-upload-{uuid.uuid4().hex}",
            "invoice_date": invoice_date or date.today().strftime("%d/%m/%Y"),
            "supplier_name": "פרובקטה",
            "reference_number": invoice_number,
            "allocation_number": "",
            "service_or_product": service_or_product,
            "subtotal": f"{(subtotal or 0.0):.2f}" if subtotal is not None else "",
            "vat": f"{(vat or 0.0):.2f}" if vat is not None else "",
            "total": f"{(total or 0.0):.2f}" if total is not None else "",
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": _finance_due_date_display(invoice_date),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )
    row["supplier_invoice_number"] = invoice_number
    row["payment_due_date"] = payment_due_date
    row["payment_terms_days"] = "0"
    row["payment_supplier_name"] = "פרובקטה"
    row["supplier_email"] = supplier_email
    row["supplier_id"] = supplier_id
    row["customer_name_on_invoice"] = customer_name
    return row


def _finance_parse_office_admin_invoice(raw_text: str, fixed_text: str, original_name: str, file_path: Path) -> dict:
    raw_source = raw_text or ""
    fixed_source = fixed_text or ""
    combined = "\n".join([raw_source, fixed_source, original_name or ""]).strip()

    supplier_name = ""
    supplier_match_fixed = re.search(r"^(.*?)\s+מספר\s+עוסק\s+מורשה", fixed_source, re.MULTILINE)
    if supplier_match_fixed:
        supplier_name = normalize_ws(supplier_match_fixed.group(1))
    if not supplier_name:
        supplier_match = re.search(r"^(.*?)\s*:\s*השרומ\s+קסוע\s+רפסמ", raw_source, re.MULTILINE)
        supplier_name = fix_hebrew_text(supplier_match.group(1)).strip() if supplier_match else ""
        supplier_name = normalize_ws(supplier_name)
    supplier_name = supplier_name or _finance_guess_supplier_from_known_patterns(combined) or "אופיס אדמין"

    invoice_date_match = (
        re.search(r"([0-9]{2}/[0-9]{2}/[0-9]{2,4})\s*:\s*ךיראת", raw_source)
        or re.search(r"תאריך[:\s]*([0-9./-]{8,10})", fixed_source)
        or re.search(r"\b([0-9]{2}/[0-9]{2}/[0-9]{2,4})\b", raw_source)
    )
    invoice_date = normalize_date(invoice_date_match.group(1)) if invoice_date_match else ""

    reference_match = (
        re.search(r"([0-9]{4,})\s+הלבק\s+סמ\s+תינובשח", raw_source)
        or re.search(r"חשבונית\s*מס\s*קבלה\s*([0-9]{4,})", fixed_source)
        or re.search(r"\b([0-9]{4,})\b", Path(original_name).stem)
    )
    reference_number = normalize_ws(reference_match.group(1)) if reference_match else ""

    service_or_product = ""
    raw_service_match = re.search(r'([0-9]{2}/[0-9]{2})\s+ש["״]?חהנה', raw_source)
    if raw_service_match:
        service_or_product = f'הנהח"ש {raw_service_match.group(1)}'
    if not service_or_product:
        service_match = re.search(r'(הנהח["״]?ש\s*[0-9]{2}/[0-9]{2})', fixed_source)
        if service_match:
            service_or_product = normalize_ws(service_match.group(1))
    service_or_product = service_or_product or _finance_guess_service_or_product(combined, original_name)

    subtotal = _finance_find_labeled_amount(
        raw_source,
        [
            r"₪\s*([\d,]+\.\d{2})\s+מ[\"״']?עמב\s+בייח\s+כ[\"״']?הס",
        ],
    )
    vat = _finance_find_labeled_amount(
        raw_source,
        [
            r"₪\s*([\d,]+\.\d{2})\s+%\s*18\.00\s+מ[\"״']?עמ",
            r"₪\s*([\d,]+\.\d{2})\s+מ[\"״']?עמ",
        ],
    )
    total = _finance_find_labeled_amount(
        raw_source,
        [
            r"₪\s*([\d,]+\.\d{2})\s+הלבק.?[\"'/]שח\s+כ[\"״']?הס",
            r"₪\s*([\d,]+\.\d{2})\s+כ[\"״']?הס\s+הלבק",
        ],
    )
    if subtotal is None:
        subtotal = _finance_first_amount_after_label(fixed_source, [r"סה[\"״']?כ\s*חייב\s*במע[\"״']?מ"], max_gap=20)
    if vat is None:
        vat = _finance_first_amount_after_label(fixed_source, [r"מע[\"״']?מ"], max_gap=20)
    if total is None:
        total = _finance_first_amount_after_label(fixed_source, [r"סה[\"״']?כ\s*חש.?/קבלה"], max_gap=20)
    if total is None and subtotal is not None and vat is not None:
        total = round(subtotal + vat, 2)

    return _normalize_finance_invoice_row_app(
        {
            "row_id": f"finance-upload-{uuid.uuid4().hex}",
            "invoice_date": invoice_date or date.today().strftime("%d/%m/%Y"),
            "supplier_name": supplier_name,
            "reference_number": reference_number,
            "service_or_product": service_or_product,
            "subtotal": f"{(subtotal or 0.0):.2f}" if subtotal is not None else "",
            "vat": f"{(vat or 0.0):.2f}" if vat is not None else "",
            "total": f"{(total or 0.0):.2f}" if total is not None else "",
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": _finance_due_date_display(invoice_date),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )


def _finance_detect_zap_invoice(raw_text: str, fixed_text: str, original_name: str) -> bool:
    combined = "\n".join([raw_text or "", fixed_text or "", original_name or ""]).lower()
    return (
        ("zap group" in combined or "זאפ גרופ" in combined)
        and ("icount" in combined or "חשבונית מס קבלה" in combined)
    )


def _finance_parse_zap_invoice(raw_text: str, fixed_text: str, original_name: str, file_path: Path) -> dict:
    raw_source = raw_text or ""
    fixed_source = fixed_text or ""
    combined = "\n".join([raw_source, fixed_source, original_name or ""]).strip()

    invoice_date_match = (
        re.search(r"([0-9]{2}/[0-9]{2}/[0-9]{4})\s*:\s*ךיראת", raw_source)
        or re.search(r"תאריך[:\s]*([0-9./-]{8,10})", fixed_source)
        or re.search(r"\b([0-9]{2}/[0-9]{2}/[0-9]{4})\b", raw_source)
    )
    invoice_date = normalize_date(invoice_date_match.group(1)) if invoice_date_match else ""

    reference_match = (
        re.search(r"\(?רוקמ\)?\s*([0-9]{4,})\s+הלבק\s+סמ\s+תינובשח", raw_source)
        or re.search(r"חשבונית\s*מס\s*קבלה\s*\)?\s*([0-9]{4,})", fixed_source)
        or re.search(r"\b([0-9]{4,})\b", Path(original_name).stem)
    )
    reference_number = normalize_ws(reference_match.group(1)) if reference_match else ""

    supplier_name = "זאפ גרופ בע\"מ"

    subtotal = _finance_find_labeled_amount(
        raw_source,
        [
            r"₪\s*([\d,]+\.\d{2})\s+מ[\"״']?עמ\s+ינפל\s+כ[\"״']?הס",
            r"₪\s*([\d,]+\.\d{2})\s+מ[\"״']?עמ\s+ינפל\s+כ\"הס",
        ],
    )
    vat = _finance_find_labeled_amount(
        raw_source,
        [
            r"₪\s*([\d,]+\.\d{2})\s+18%\s+מ[\"״']?עמ",
        ],
    )
    total = _finance_find_labeled_amount(
        raw_source,
        [
            r"₪\s*([\d,]+\.\d{2})\s+םלוש\s+כ[\"״']?הס",
            r"₪\s*([\d,]+\.\d{2})\s+ללוכ\s+כ[\"״']?הס",
        ],
    )
    if subtotal is None:
        subtotal = _finance_first_amount_after_label(fixed_source, [r"סה[\"״']?כ\s*לפני\s*מע[\"״']?מ"], max_gap=20)
    if vat is None:
        vat = _finance_first_amount_after_label(fixed_source, [r"18%\s*מ[\"״']?ע[\"״']?מ", r"מ[\"״']?ע[\"״']?מ\s*18%"], max_gap=20)
    if total is None:
        total = _finance_first_amount_after_label(
            fixed_source,
            [r"סה[\"״']?כ\s*שולם", r"סה[\"״']?כ\s*כולל", r"סכום"],
            max_gap=20,
        )
    if total is None and subtotal is not None and vat is not None:
        total = round(subtotal + vat, 2)

    raw_lines = [line.strip() for line in raw_source.splitlines() if line.strip()]
    product_line = next(
        (
            line
            for line in raw_lines
            if "210BAR" in line and "2200W" in line and "חולשמ" not in line
        ),
        "",
    )
    service_or_product = "מכונת שטיפה בלחץ - 210BAR - 2200W ASUS LifeStyle"
    if product_line:
        service_or_product = "מכונת שטיפה בלחץ - 210BAR - 2200W ASUS LifeStyle"
        if any("toolsonline" in line.lower().replace(" ", "") for line in raw_lines):
            service_or_product += " נרכש ב-Tools Online"

    return _normalize_finance_invoice_row_app(
        {
            "row_id": f"finance-upload-{uuid.uuid4().hex}",
            "invoice_date": invoice_date or date.today().strftime("%d/%m/%Y"),
            "supplier_name": supplier_name,
            "reference_number": reference_number,
            "allocation_number": "",
            "service_or_product": service_or_product,
            "subtotal": f"{(subtotal or 0.0):.2f}" if subtotal is not None else "",
            "vat": f"{(vat or 0.0):.2f}" if vat is not None else "",
            "total": f"{(total or 0.0):.2f}" if total is not None else "",
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": _finance_due_date_display(invoice_date),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )


def _finance_parse_openai_invoice(raw_text: str, fixed_text: str, original_name: str, file_path: Path) -> dict:
    combined = "\n".join([fixed_text or "", raw_text or ""])
    invoice_date = _finance_parse_english_date(combined) or _finance_guess_invoice_date(combined)
    amount_due_matches = re.findall(r"Amount\s+due[^\d]{0,20}(\d[\d,]*\.\d{2})", combined, re.IGNORECASE)
    total = normalize_amount(amount_due_matches[-1]) if amount_due_matches else None
    if total is None:
        total = _finance_first_amount_after_label(combined, [r"Amount\s+due", r"Total"], max_gap=50)
    if total is None:
        all_amounts = [normalize_amount(match) for match in re.findall(r"\d[\d,]*\.\d{2}", combined)]
        amounts = [float(value) for value in all_amounts if value is not None]
        total = max(amounts) if amounts else 0.0
    total_value = round(total or 0.0, 2)
    service = _finance_extract_line_item_service(combined) or "OpenAI / ChatGPT Plus"
    return _normalize_finance_invoice_row_app(
        {
            "row_id": f"finance-upload-{uuid.uuid4().hex}",
            "invoice_date": invoice_date or date.today().strftime("%d/%m/%Y"),
            "supplier_name": "OpenAI",
            "service_or_product": service,
            "subtotal": f"{total_value:.2f}" if total_value else "",
            "vat": "0.00" if total_value else "",
            "total": f"{total_value:.2f}" if total_value else "",
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": _finance_due_date_display(invoice_date),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )


def _finance_detect_anthropic_receipt(raw_text: str, fixed_text: str, original_name: str) -> bool:
    _raw, lowered = _finance_text_haystacks(raw_text, fixed_text, original_name)
    return "anthropic" in lowered or "claude ai" in lowered


def _finance_parse_anthropic_receipt(raw_text: str, fixed_text: str, original_name: str, file_path: Path) -> dict:
    combined = "\n".join([fixed_text or "", raw_text or ""])
    invoice_date = _finance_parse_english_date(combined) or _finance_guess_invoice_date(combined)
    total = _finance_first_amount_after_label(combined, [r"Subtotal", r"Total", r"paid\s+on"], max_gap=40)
    total_value = round(total or 0.0, 2)
    service = _finance_extract_line_item_service(combined) or "Anthropic / Claude"
    return _normalize_finance_invoice_row_app(
        {
            "row_id": f"finance-upload-{uuid.uuid4().hex}",
            "invoice_date": invoice_date or date.today().strftime("%d/%m/%Y"),
            "supplier_name": "Anthropic",
            "service_or_product": service,
            "subtotal": f"{total_value:.2f}" if total_value else "",
            "vat": "0.00" if total_value else "",
            "total": f"{total_value:.2f}" if total_value else "",
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": _finance_due_date_display(invoice_date),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )


def _finance_detect_partner_statement(raw_text: str, fixed_text: str, original_name: str) -> bool:
    _raw, lowered = _finance_text_haystacks(raw_text, fixed_text, original_name)
    return (
        ("partner" in lowered or "פרטנר" in lowered or "012" in lowered or "mobile" in lowered or "מובייל" in lowered)
        and (
            "חשבון תקופתי" in lowered
            or "תקופת החשבון" in lowered
            or "ןובשחהתפוקת" in lowered
            or "ןובשחתכירעךיראת" in lowered
        )
    )


def _finance_parse_partner_statement(raw_text: str, fixed_text: str, original_name: str, file_path: Path) -> dict:
    combined = "\n".join([fixed_text or "", raw_text or ""])
    raw_or_fixed = "\n".join([raw_text or "", fixed_text or ""])
    def _partner_normalize_short_date(value: str) -> str:
        value = normalize_ws(value).replace(".", "/").replace("-", "/")
        match = re.match(r"^(\d{2})/(\d{2})/(\d{2})$", value)
        if match:
            return f"{match.group(1)}/{match.group(2)}/20{match.group(3)}"
        match = re.match(r"^(\d{2})/(\d{2})/(\d{4})$", value)
        if match:
            return f"{match.group(1)}/{match.group(2)}/{match.group(3)}"
        return normalize_date(value)
    period_match = (
        re.search(r"([0-9]{2}/[0-9]{2}/[0-9]{2})-([0-9]{2}/[0-9]{2}/[0-9]{2})\s*:?[ןת]ובשחהתפוקת", raw_text or "")
        or re.search(r"(\d{2}[./]\d{2}[./]\d{2})\s*-\s*(\d{2}[./]\d{2}[./]\d{2})", combined)
    )
    raw_invoice_date_match = re.search(r"([0-9]{2}/[0-9]{2}/[0-9]{2,4})\s*:?ןובשחתכירעךיראת", raw_text or "")
    invoice_date_match = (
        raw_invoice_date_match
        or re.search(r"תאריך\s*עריכת\s*חשבון[:\s]*([0-9./-]+)", fixed_text or "")
        or re.search(r"תאריך[:\s]*([0-9./-]+)", fixed_text or "")
    )
    invoice_date = _partner_normalize_short_date(invoice_date_match.group(1)) if invoice_date_match else ""
    if not invoice_date and period_match:
        invoice_date = _partner_normalize_short_date(period_match.group(2))

    raw_summary_match = re.search(
        r"\{\s*([\d,]+\.\d{2})\s*\(18%\)\s*מ[\"״]?עמללוכאלןובשחהיבויחכ[\"״]?הס.*?"
        r"\{\s*([\d,]+\.\d{2})\s*18%מ[\"״]?עמ.*?"
        r"\{\s*([\d,]+\.\d{2})\s*מ[\"״]?עמללוכןובשחהתפוקתלםייוכיזוםיבויחכ[\"״]?הס",
        raw_text or "",
        re.DOTALL,
    )
    if raw_summary_match:
        subtotal = normalize_amount(raw_summary_match.group(1))
        vat = normalize_amount(raw_summary_match.group(2))
        total = normalize_amount(raw_summary_match.group(3))
    else:
        subtotal = _finance_first_amount_after_label(
            raw_or_fixed,
            [r"סה[\"״']?כ\s*חיובי\s*החשבון\s*לא\s*כולל\s*מע[\"״']?מ", r"לא\s*כולל\s*מע[\"״']?מ"],
            max_gap=40,
        )
        vat = _finance_first_amount_after_label(
            raw_or_fixed,
            [r"מע[\"״']?מ\s*18%", r"18%\s*מע[\"״']?מ"],
            max_gap=20,
        )
        total = _finance_first_amount_after_label(
            raw_or_fixed,
            [r"סה[\"״']?כ\s*חיובים\s*וזיכויים\s*לתקופת\s*החשבון\s*כולל\s*מע[\"״']?מ", r"סה[\"״']?כ\s*לתשלום"],
            max_gap=30,
        )

    summary_match = re.search(
        r"סה[\"״']?כ\s*חיובי\s*החשבון\s*לא\s*כולל\s*מע[\"״']?מ.*?([\d,]+\.\d{2}).*?מע[\"״']?מ\s*18%.*?([\d,]+\.\d{2}).*?סה[\"״']?כ\s*חיובים\s*וזיכויים\s*לתקופת\s*החשבון\s*כולל\s*מע[\"״']?מ.*?([\d,]+\.\d{2})",
        raw_or_fixed,
        re.DOTALL,
    )
    if summary_match and raw_summary_match is None:
        subtotal = normalize_amount(summary_match.group(1))
        vat = normalize_amount(summary_match.group(2))
        total = normalize_amount(summary_match.group(3))
    if subtotal is None and total is not None and vat is not None:
        subtotal = round(max(0.0, total - vat), 2)
    if total is None and subtotal is not None and vat is not None:
        total = round(subtotal + vat, 2)
    period_label = ""
    if period_match:
        period_label = f"{_partner_normalize_short_date(period_match.group(1))[:10]} - {_partner_normalize_short_date(period_match.group(2))[:10]}"
    service = f"פרטנר / 012 מובייל - חשבון תקופתי ({period_label})" if period_label else "פרטנר / 012 מובייל - חשבון תקופתי"
    return _normalize_finance_invoice_row_app(
        {
            "row_id": f"finance-upload-{uuid.uuid4().hex}",
            "invoice_date": invoice_date or date.today().strftime("%d/%m/%Y"),
            "supplier_name": "פרטנר תקשורת בע״מ",
            "service_or_product": service,
            "subtotal": f"{(subtotal or 0.0):.2f}" if subtotal is not None else "",
            "vat": f"{(vat or 0.0):.2f}" if vat is not None else "",
            "total": f"{(total or 0.0):.2f}" if total is not None else "",
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": _finance_due_date_display(invoice_date),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )


def _finance_detect_cellcom_statement(raw_text: str, fixed_text: str, original_name: str) -> bool:
    raw_haystack, lowered = _finance_text_haystacks(raw_text, fixed_text, original_name)
    return (
        ("סלקום" in lowered or "cellcom" in lowered or "םוקלס" in (raw_haystack or ""))
        and (
            "חשבון תקופתי" in lowered
            or "תקופת החשבון" in lowered
            or "ןובשחה תפוקת" in (raw_text or "")
            or "תאריך החשבון" in lowered
        )
    )


def _finance_parse_cellcom_statement(raw_text: str, fixed_text: str, original_name: str, file_path: Path) -> dict:
    combined = "\n".join([raw_text or "", fixed_text or ""]).strip()
    raw_lines = [normalize_ws(line) for line in str(raw_text or "").splitlines() if normalize_ws(line)]

    def _cellcom_normalize_short_date(value: str) -> str:
        token = normalize_ws(value).replace(".", "/").replace("-", "/")
        match = re.fullmatch(r"(\d{2})/(\d{2})/(\d{2})", token)
        if match:
            return f"{match.group(1)}/{match.group(2)}/20{match.group(3)}"
        return normalize_date(token)

    invoice_date_match = (
        re.search(r"([0-9]{2}[./][0-9]{2}[./][0-9]{2,4})\s*:ןובשחה\s+ךיראת", raw_text or "")
        or re.search(r"([0-9]{2}[./][0-9]{2}[./][0-9]{2,4})\s*תאריך החשבון", combined)
        or re.search(r"תאריך\s*החשבון[:\s]*([0-9./-]+)", combined)
    )
    period_match = (
        re.search(r"([0-9]{2}[./][0-9]{2}[./][0-9]{2,4})\s*-\s*([0-9]{2}[./][0-9]{2}[./][0-9]{2,4})\s*:ןובשחה\s+תפוקת", raw_text or "")
        or re.search(r"([0-9]{2}[./][0-9]{2}[./][0-9]{2,4})\s*-\s*([0-9]{2}[./][0-9]{2}[./][0-9]{2,4})\s*תקופת החשבון", combined)
        or re.search(r"תקופת\s*החשבון[:\s]*([0-9./-]+)\s*-\s*([0-9./-]+)", combined)
    )

    invoice_date = _cellcom_normalize_short_date(invoice_date_match.group(1)) if invoice_date_match else ""
    period_start = _cellcom_normalize_short_date(period_match.group(1)) if period_match else ""
    period_end = _cellcom_normalize_short_date(period_match.group(2)) if period_match else ""

    subtotal = vat = total = None
    for line in raw_lines:
        match = re.match(r"(-?[\d,]+\.\d{2})\s+(.*)$", line)
        if not match:
            continue
        amount = normalize_amount(match.group(1))
        label = match.group(2)
        if subtotal is None and "מ\"עמ ינפל כ\"הס" in label:
            subtotal = amount
            continue
        if vat is None and "18% מ\"עמ כ\"הס" in label:
            vat = amount
            continue
        if total is None and "מ\"עמ ללוכ ח\"שב םולשתל כ\"הס" in label:
            total = amount
            continue

    if subtotal is None:
        subtotal = _finance_first_amount_after_label(combined, [r"סה[\"״']?כ\s+לפני\s+מע[\"״']?מ"], max_gap=25)
    if vat is None:
        vat = _finance_first_amount_after_label(combined, [r"סה[\"״']?כ\s+מע[\"״']?מ"], max_gap=20)
    if total is None:
        total = _finance_first_amount_after_label(combined, [r"סה[\"״']?כ\s+לתשלום"], max_gap=25)
    if subtotal is None and total is not None and vat is not None:
        subtotal = round(max(0.0, total - vat), 2)
    if total is None and subtotal is not None and vat is not None:
        total = round(subtotal + vat, 2)
    if not invoice_date:
        invoice_date = period_end or _finance_guess_invoice_date(combined)

    period_label = ""
    if period_start and period_end:
        period_label = f"{period_start} - {period_end}"
    service = f"סלקום - חשבון תקופתי ({period_label})" if period_label else "סלקום - חשבון תקופתי"
    report_due_source = period_end or invoice_date

    return _normalize_finance_invoice_row_app(
        {
            "row_id": f"finance-upload-{uuid.uuid4().hex}",
            "invoice_date": invoice_date or date.today().strftime("%d/%m/%Y"),
            "supplier_name": "סלקום ישראל בע״מ",
            "service_or_product": service,
            "subtotal": f"{(subtotal or 0.0):.2f}" if subtotal is not None else "",
            "vat": f"{(vat or 0.0):.2f}" if vat is not None else "",
            "total": f"{(total or 0.0):.2f}" if total is not None else "",
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": _finance_due_date_display_or_earliest(report_due_source),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )


def _finance_detect_flaxi_invoice(raw_text: str, fixed_text: str, original_name: str) -> bool:
    raw_haystack, lowered = _finance_text_haystacks(raw_text, fixed_text, original_name)
    return (
        "פלאקסי" in lowered
        or "יסקאלפ" in (raw_haystack or "")
        or "cibus" in lowered
        or "pluxee" in lowered
    )


def _finance_parse_flaxi_invoice(raw_text: str, fixed_text: str, original_name: str, file_path: Path) -> dict:
    combined = "\n".join([fixed_text or "", raw_text or ""])
    invoice_date_match = (
        re.search(r"([0-9]{2}/[0-9]{2}/[0-9]{2,4})\s*:\s*תינובשח\s*ךיראת", raw_text or "")
        or re.search(r"תאריך\s*חשבונית[:\s]*([0-9./-]+)", fixed_text or "")
    )
    due_date_match = (
        re.search(r"([0-9]{2}/[0-9]{2}/[0-9]{2,4})\s*:\s*דע\s*םולשתל", raw_text or "")
        or re.search(r"לתשלום\s*עד[:\s]*([0-9./-]+)", fixed_text or "")
    )
    invoice_number_match = (
        re.search(r"\b(SI\d{6,})\b", raw_text or "")
        or re.search(r"\b(SI\d{6,})\b", fixed_text or "", re.IGNORECASE)
    )
    invoice_date = normalize_date(invoice_date_match.group(1)) if invoice_date_match else ""
    due_date = normalize_date(due_date_match.group(1)) if due_date_match else ""
    invoice_number = normalize_ws(invoice_number_match.group(1)) if invoice_number_match else normalize_ws(Path(original_name).stem)

    subtotal = _finance_find_labeled_amount(
        raw_text or "",
        [
            r"([\d,]+\.\d{2})\s+מ[\"״']?עמב\s+בייח\s+םוכס",
            r"([\d,]+\.\d{2})\s+החנה\s+ירחא\s+ריחמ",
        ],
    )
    vat = _finance_find_labeled_amount(
        raw_text or "",
        [
            r"([\d,]+\.\d{2})\s+\(18\.00%\)\s+מ[\"״']?עמ",
            r"([\d,]+\.\d{2})\s+מ[\"״']?עמ\s+יללכ",
        ],
    )
    total = _finance_find_labeled_amount(
        raw_text or "",
        [
            r"ח[\"״']?ש\s*([\d,]+\.\d{2})\s+ריחמ\s+כ[\"״']?הס",
            r"([\d,]+\.\d{2})\s+ריחמ\s+כ[\"״']?הס",
        ],
    )
    if subtotal is None:
        subtotal = _finance_first_amount_after_label(combined, [r"סכום\s*חייב\s*במע[\"״']?מ"], max_gap=25)
    if vat is None:
        vat = _finance_first_amount_after_label(combined, [r"מע[\"״']?מ\s*\(?%?18"], max_gap=20)
    if total is None:
        total = _finance_first_amount_after_label(combined, [r"סה[\"״']?כ\s*מחיר"], max_gap=20)
    if subtotal is None and total is not None and vat is not None:
        subtotal = round(max(0.0, total - vat), 2)
    if total is None and subtotal is not None and vat is not None:
        total = round(subtotal + vat, 2)

    service = "עסקאות בתי עסק cibus"

    report_due_source = due_date or invoice_date
    return _normalize_finance_invoice_row_app(
        {
            "row_id": _finance_auto_invoice_row_id("flaxi", invoice_date or due_date or "", invoice_number),
            "invoice_date": invoice_date or date.today().strftime("%d/%m/%Y"),
            "supplier_name": "פלאקסי ישראל בע\"מ",
            "reference_number": invoice_number,
            "service_or_product": service,
            "subtotal": f"{(subtotal or 0.0):.2f}" if subtotal is not None else "",
            "vat": f"{(vat or 0.0):.2f}" if vat is not None else "",
            "total": f"{(total or 0.0):.2f}" if total is not None else "",
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": _finance_due_date_display(report_due_source),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )


def _finance_detect_road6_invoice(raw_text: str, fixed_text: str, original_name: str) -> bool:
    _raw, lowered = _finance_text_haystacks(raw_text, fixed_text, original_name)
