    if _finance_detect_elron_car_invoice(raw_text, fixed_text, original_name):
        return _finance_parse_elron_car_invoice(raw_text, fixed_text, original_name, file_path)
    if _finance_detect_proton_invoice(raw_text, fixed_text, original_name):
        return _finance_parse_proton_invoice(raw_text, fixed_text, original_name, file_path)
    if _finance_detect_palziv_invoice(raw_text, fixed_text, original_name):
        return _finance_parse_palziv_invoice(raw_text, fixed_text, original_name, file_path)
    if _finance_detect_gabriel_transport_invoice(raw_text, fixed_text, original_name):
        return _finance_parse_gabriel_transport_invoice(raw_text, fixed_text, original_name, file_path)
    if _finance_detect_pazomat_invoice(raw_text, fixed_text, original_name):
        return _finance_parse_pazomat_invoice_summary(raw_text, fixed_text, original_name, file_path)
    if _finance_detect_tranzila_invoice(raw_text, fixed_text, original_name):
        return _finance_parse_tranzila_invoice(raw_text, fixed_text, original_name, file_path)
    text = "\n".join([fixed_text or "", raw_text or ""]).strip()
    invoice_date = _finance_guess_invoice_date_from_raw(raw_text) or _finance_guess_invoice_date(text)
    supplier_name = _finance_guess_supplier_name(text, original_name)
    service_or_product = _finance_guess_service_or_product(text, original_name)
    if re.search(r"(?:^|\s)tmp(?:\s|$)|\btemp\b", service_or_product, re.IGNORECASE):
        service_or_product = supplier_name or "הוצאה מוכרת"
    subtotal, vat, total = _finance_guess_invoice_totals(text)
    report_due_date = _finance_due_date_display(invoice_date)
    reference_number = _finance_extract_reference_number(text, original_name)
    allocation_number = _finance_extract_allocation_number(text) if _finance_parse_number(total) >= 10000 else ""
    return _normalize_finance_invoice_row_app(
        {
            "row_id": f"finance-upload-{uuid.uuid4().hex}",
            "invoice_date": invoice_date,
            "supplier_name": supplier_name,
            "reference_number": reference_number,
            "allocation_number": allocation_number,
            "service_or_product": service_or_product,
            "subtotal": subtotal,
            "vat": vat,
            "total": total,
            "source_file_name": Path(original_name).name,
            "source_file_path": str(file_path),
            "report_due_date": report_due_date,
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    )


