def _finance_parse_known_bundle_drafts(file_path: Path, original_name: str) -> list[dict]:
    specs = _finance_known_bundle_specs(file_path)
    if not specs:
        return []
    try:
        sha1 = hashlib.sha1(file_path.read_bytes()).hexdigest()
    except Exception:
        sha1 = ""
    split_root = _finance_invoice_split_root(original_name)
    split_root.mkdir(parents=True, exist_ok=True)
    for stale_file in split_root.glob("*.pdf"):
        try:
            stale_file.unlink()
        except Exception:
            continue
    drafts: list[dict] = []
    for index, spec in enumerate(specs, start=1):
        supplier_slug = _safe_folder_name(str(spec.get("supplier_name") or "").strip()) or "invoice"
        invoice_date_slug = str(spec.get("invoice_date") or "").strip().replace("/", "-") or datetime.now().strftime("%Y-%m-%d")
        target_path = split_root / f"{index:03d}-{supplier_slug}-{invoice_date_slug}.pdf"
        if target_path.exists():
            target_path.unlink()
        if spec.get("regions"):
            _finance_export_split_pdf_regions(file_path, spec.get("regions") or [], target_path)
        else:
            _finance_export_split_pdf(file_path, spec.get("pages") or [], target_path)
        row = _normalize_finance_invoice_row_app(
            {
                "row_id": f"finance-bundle-{sha1[:12]}-{index:03d}",
                "invoice_date": spec.get("invoice_date") or "",
                "supplier_name": spec.get("supplier_name") or "",
                "reference_number": spec.get("reference_number") or "",
                "allocation_number": spec.get("allocation_number") or "",
                "service_or_product": spec.get("service_or_product") or "",
                "subtotal": spec.get("subtotal") or "",
                "vat": spec.get("vat") or "",
                "total": spec.get("total") or "",
                "source_file_name": target_path.name,
                "source_file_path": str(target_path),
                "report_due_date": str(spec.get("report_due_date") or "").strip() or _finance_due_date_display(spec.get("invoice_date") or ""),
                "updated_at": datetime.now().isoformat(timespec="seconds"),
            }
        )
        drafts.append(row)
    return drafts


def _finance_parse_uploaded_invoice_drafts(file_path: Path, original_name: str) -> list[dict]:
    known_bundle_drafts = _finance_parse_known_bundle_drafts(file_path, original_name)
    if known_bundle_drafts:
        return known_bundle_drafts
    if file_path.suffix.lower() == ".pdf":
        raw_text, fixed_text = _finance_extract_uploaded_invoice_texts(file_path)
        if _finance_detect_flaxi_invoice(raw_text, fixed_text, original_name):
            return [_finance_parse_flaxi_invoice(raw_text, fixed_text, original_name, file_path)]
        if _finance_detect_bezeq_invoice(raw_text, fixed_text, original_name):
            return [_finance_parse_bezeq_invoice(raw_text, fixed_text, original_name, file_path)]
        if _finance_detect_birman_invoice(raw_text, fixed_text, original_name):
            return [_finance_parse_birman_invoice(raw_text, fixed_text, original_name, file_path)]
        if _finance_detect_elron_car_invoice(raw_text, fixed_text, original_name):
            return [_finance_parse_elron_car_invoice(raw_text, fixed_text, original_name, file_path)]
        if _finance_detect_proton_invoice(raw_text, fixed_text, original_name):
            return [_finance_parse_proton_invoice(raw_text, fixed_text, original_name, file_path)]
        if _finance_detect_palziv_invoice(raw_text, fixed_text, original_name):
            return [_finance_parse_palziv_invoice(raw_text, fixed_text, original_name, file_path)]
        if _finance_detect_infinitech_invoice(raw_text, fixed_text, original_name):
            return [_finance_parse_infinitech_invoice(raw_text, fixed_text, original_name, file_path)]
    if file_path.suffix.lower() != ".pdf":
        return [_finance_parse_uploaded_invoice_draft(file_path, original_name)]
    bundle_groups = _finance_split_invoice_bundle(file_path)
    if len(bundle_groups) <= 1:
        return [_finance_parse_uploaded_invoice_draft(file_path, original_name)]

    split_root = _finance_invoice_split_root(original_name)
    split_root.mkdir(parents=True, exist_ok=True)
    for stale_file in split_root.glob("*.pdf"):
        try:
            stale_file.unlink()
        except Exception:
            continue
    drafts: list[dict] = []
    for index, group in enumerate(bundle_groups, start=1):
        temp_target = split_root / f"{index:03d}-temp.pdf"
        _finance_export_split_pdf(file_path, group.get("pages") or [], temp_target)
        draft = _finance_parse_uploaded_invoice_draft(temp_target, temp_target.name)
        supplier_slug = _safe_folder_name(str(draft.get("supplier_name") or "").strip()) or "invoice"
        invoice_date_slug = str(draft.get("invoice_date") or "").strip().replace("/", "-") or datetime.now().strftime("%Y-%m-%d")
        final_target = split_root / f"{index:03d}-{supplier_slug}-{invoice_date_slug}.pdf"
        if final_target.exists():
            final_target.unlink()
        temp_target.rename(final_target)
        draft["source_file_name"] = final_target.name
        draft["source_file_path"] = str(final_target)
        drafts.append(_normalize_finance_invoice_row_app(draft))
    return drafts or [_finance_parse_uploaded_invoice_draft(file_path, original_name)]


def _finance_due_dates() -> list[date]:
    return [
        date(2026, 1, 15),
        date(2026, 3, 15),
        date(2026, 5, 15),
        date(2026, 7, 15),
        date(2026, 9, 15),
        date(2026, 11, 15),
        date(2027, 1, 15),
    ]


def _finance_due_date_for_invoice_date(value) -> date | None:
    invoice_day = value if isinstance(value, date) else _finance_parse_date_value(value)
    if not invoice_day:
        return None
    for due_date in _finance_due_dates():
        period_start, period_end, _effective_end = _finance_period_for_due_date(due_date)
        if period_start <= invoice_day <= period_end:
            return due_date
    return None


def _finance_due_date_display(value) -> str:
    target = value if isinstance(value, date) else _finance_parse_date_value(value)
    if not target:
        return ""
    if target in _finance_due_dates():
        return target.strftime("%d/%m/%Y")
    matched_due_date = _finance_due_date_for_invoice_date(target)
    if matched_due_date:
        return matched_due_date.strftime("%d/%m/%Y")
    return ""


def _finance_due_date_display_or_earliest(value) -> str:
    target = value if isinstance(value, date) else _finance_parse_date_value(value)
    if not target:
        return ""
    due_dates = _finance_due_dates()
    if due_dates and target <= due_dates[0]:
        return _finance_format_display_date(due_dates[0])
    direct = _finance_due_date_display(value)
    if direct:
        return direct
    return ""


def _ensure_finance_drive_root_folder() -> str:
    parent_id = _ensure_admin_drive_root_folder()
    parent_id = ensure_child_folder(parent_id, "כספים")
    return ensure_child_folder(parent_id, "חשבוניות")


def _finance_drive_folder_name(due_date_value) -> str:
    label = _finance_due_date_display(due_date_value)
    return f"חשבוניות {label}" if label else "חשבוניות ללא מועד דיווח"


def _finance_target_drive_folder_id(due_date_value) -> tuple[str, str]:
    parent_id = _ensure_finance_drive_root_folder()
    target_due_date = _finance_due_date_display(due_date_value)
    folder_id = ensure_child_folder(parent_id, _finance_drive_folder_name(target_due_date))
    return folder_id, target_due_date


def _drive_get_file_record(file_id: str) -> dict:
    service = _google_drive_service()
    record = service.files().get(
        fileId=file_id,
        fields="id,name,parents,webViewLink,webContentLink",
        supportsAllDrives=True,
    ).execute()
    return {
        "id": str(record.get("id") or "").strip(),
        "name": str(record.get("name") or "").strip(),
        "parents": [str(item or "").strip() for item in (record.get("parents") or []) if str(item or "").strip()],
        "web_view_link": str(record.get("webViewLink") or "").strip(),
        "web_content_link": str(record.get("webContentLink") or "").strip(),
    }


def _move_drive_file_to_folder(file_id: str, target_folder_id: str) -> dict:
    current = _drive_get_file_record(file_id)
    current_parents = current.get("parents") or []
    remove_parents = ",".join(parent for parent in current_parents if parent and parent != target_folder_id)
    service = _google_drive_service()
    updated = service.files().update(
        fileId=file_id,
        addParents=target_folder_id if target_folder_id not in current_parents else None,
        removeParents=remove_parents or None,
        fields="id,name,webViewLink,webContentLink",
        supportsAllDrives=True,
    ).execute()
    return {
        "id": str(updated.get("id") or "").strip(),
        "name": str(updated.get("name") or "").strip(),
        "web_view_link": str(updated.get("webViewLink") or "").strip(),
        "web_content_link": str(updated.get("webContentLink") or "").strip(),
    }


def _finance_cleanup_duplicate_drive_files(file_id: str, file_name: str, keep_folder_id: str) -> None:
    root_id = _ensure_finance_drive_root_folder()
    service = _google_drive_service()
    safe_name = str(file_name or "").strip()
    if not safe_name:
        return
    for folder in list_child_folders(root_id):
        folder_id = str(folder.get("id") or "").strip()
        if not folder_id:
            continue
        duplicate = _find_file_in_folder(service, folder_id, safe_name)
        duplicate_id = str((duplicate or {}).get("id") or "").strip()
        if not duplicate_id or duplicate_id == file_id:
            continue
        if folder_id == keep_folder_id:
            delete_drive_file(duplicate_id)
            continue
        delete_drive_file(duplicate_id)


def _finance_sync_invoice_file_to_drive(local_path: Path | None, due_date_value, existing_file_id: str = "", drive_name: str = "") -> dict:
    target_folder_id, primary_due_date = _finance_target_drive_folder_id(due_date_value)
    uploaded: dict = {}
    effective_name = str(drive_name or (local_path.name if local_path else "")).strip()
    if existing_file_id:
        try:
            uploaded = _move_drive_file_to_folder(existing_file_id, target_folder_id)
        except Exception:
            uploaded = {}
    if not uploaded:
        if not (local_path and local_path.exists()):
            raise FileNotFoundError("קובץ החשבונית לא נמצא לצורך סנכרון ל-Google Drive.")
        uploaded = ensure_file_in_folder(target_folder_id, local_path, drive_name=effective_name or local_path.name)
    drive_file_id = str(uploaded.get("id") or "").strip()
    if drive_file_id and effective_name:
        try:
            _finance_cleanup_duplicate_drive_files(drive_file_id, effective_name, target_folder_id)
        except Exception as cleanup_exc:
            log_handled_error("finance duplicate drive cleanup failed", cleanup_exc)
    drive_file_id = str(uploaded.get("id") or "").strip()
    drive_url = str(uploaded.get("web_view_link") or uploaded.get("webViewLink") or "").strip()
    if not drive_url and drive_file_id:
        drive_url = _drive_file_view_link(drive_file_id)
    return {
        "drive_file_id": drive_file_id,
        "drive_url": drive_url,
        "drive_folder_id": target_folder_id,
        "report_due_date": primary_due_date,
        "linked_folders": [
            {
                "report_due_date": primary_due_date,
                "drive_folder_id": target_folder_id,
                "drive_file_id": drive_file_id,
                "drive_url": drive_url,
            }
        ],
    }


def _xlsx_col_name(index: int) -> str:
    label = ""
    value = max(1, int(index))
    while value:
        value, remainder = divmod(value - 1, 26)
        label = chr(65 + remainder) + label
    return label


def _finance_vat_summary_line(row: dict) -> str:
    due_date = _finance_format_display_date(str((row or {}).get("due_date") or "").strip())
    vat_payable = _finance_parse_number((row or {}).get("vat_payable"))
    vat_credit = _finance_parse_number((row or {}).get("vat_credit"))
    vat_due = _finance_parse_number((row or {}).get("vat_due"))
    return (
        f"בתקופת הדיווח: {due_date}, "
        f"סה״כ המע״מ לתשלום בגין עסקות הוא: ₪ {vat_payable:,.2f}, "
        f"וסה״כ המע״מ המוכר להפחתה הוא: ₪ {vat_credit:,.2f}, "
        f"סה״כ מע״מ לתשלום לתקופת דיווח זו, הוא: ₪ {vat_due:,.2f}"
    )


async def _finance_vat_summary_rows_for_due_dates(due_dates: list[str]) -> list[dict]:
    normalized_due_dates = _finance_normalize_due_dates(due_dates)
    if not normalized_due_dates:
        return []
    payload = _get_cached_finance_state()
    if not isinstance(payload, dict) or not isinstance(payload.get("vat_rows"), list):
        payload = await _build_finance_payload(force_refresh=False)
    vat_rows = payload.get("vat_rows") or []
    vat_map: dict[str, dict] = {}
    for row in vat_rows:
        due_date = _finance_format_display_date(str((row or {}).get("due_date") or "").strip())
        if not due_date:
            continue
        vat_payable = round(_finance_parse_number((row or {}).get("vat_payable")), 2)
        vat_credit = round(_finance_parse_number((row or {}).get("vat_credit")), 2)
        vat_map[due_date] = {
            "due_date": due_date,
            "vat_payable": vat_payable,
            "vat_credit": vat_credit,
            "vat_due": round(vat_payable - vat_credit, 2),
        }
    return [
        vat_map.get(
            due_date,
            {
                "due_date": due_date,
                "vat_payable": 0.0,
                "vat_credit": 0.0,
                "vat_due": 0.0,
            },
        )
        for due_date in normalized_due_dates
    ]


def _build_finance_invoices_xlsx(rows: list[dict], vat_summary_rows: list[dict] | None = None) -> bytes:
    headers = ["תאריך", "ספק", "מספר אסמכתא", "מספר הקצאה", "שירות / מוצר", "סה״כ (לפני מע״מ)", "מע״מ", "סה״כ (כולל מע״מ)"]
    normalized_rows = [_normalize_finance_invoice_row_app(row or {}) for row in rows or []]

    def cell_xml(row_number: int, col_number: int, value, *, numeric: bool = False) -> str:
        ref = f"{_xlsx_col_name(col_number)}{row_number}"
        if numeric:
            number = _finance_parse_number(value)
            return f'<c r="{ref}"><v>{number:.2f}</v></c>'
        text = str(value or "")
        return f'<c r="{ref}" t="inlineStr"><is><t>{xml_escape(text)}</t></is></c>'

    rows_xml: list[str] = []
    header_cells = "".join(cell_xml(1, index + 1, title) for index, title in enumerate(headers))
    rows_xml.append(f'<row r="1">{header_cells}</row>')
    for offset, row in enumerate(normalized_rows, start=2):
        row_cells = "".join([
            cell_xml(offset, 1, _finance_format_display_date(row.get("invoice_date"))),
            cell_xml(offset, 2, row.get("supplier_name")),
            cell_xml(offset, 3, row.get("reference_number")),
            cell_xml(offset, 4, row.get("allocation_number")),
            cell_xml(offset, 5, row.get("service_or_product")),
            cell_xml(offset, 6, row.get("subtotal"), numeric=True),
            cell_xml(offset, 7, row.get("vat"), numeric=True),
            cell_xml(offset, 8, row.get("total"), numeric=True),
        ])
        rows_xml.append(f'<row r="{offset}">{row_cells}</row>')
    next_row_number = len(normalized_rows) + 2
    effective_vat_rows = [row for row in (vat_summary_rows or []) if isinstance(row, dict)]
    if effective_vat_rows:
        rows_xml.append(f'<row r="{next_row_number}">{cell_xml(next_row_number, 1, "")}</row>')
        next_row_number += 1
        for vat_row in effective_vat_rows:
            summary_cells = "".join([
                cell_xml(next_row_number, 1, f"תקופת דיווח: {str(vat_row.get('due_date') or '').strip()}"),
                cell_xml(next_row_number, 2, f"מע״מ לתשלום בגין עסקות: ₪ {_finance_parse_number(vat_row.get('vat_payable')):,.2f}"),
                cell_xml(next_row_number, 3, f"מע״מ מוכר להפחתה: ₪ {_finance_parse_number(vat_row.get('vat_credit')):,.2f}"),
                cell_xml(next_row_number, 4, f"מע״מ לתשלום לתקופה זו: ₪ {_finance_parse_number(vat_row.get('vat_due')):,.2f}"),
                cell_xml(next_row_number, 5, ""),
                cell_xml(next_row_number, 6, ""),
                cell_xml(next_row_number, 7, ""),
                cell_xml(next_row_number, 8, ""),
            ])
            rows_xml.append(f'<row r="{next_row_number}">{summary_cells}</row>')
            next_row_number += 1

    dimension = f"A1:H{max(1, next_row_number - 1)}"
    worksheet_xml = f'''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">
  <dimension ref="{dimension}"/>
  <sheetViews><sheetView workbookViewId="0" rightToLeft="1"/></sheetViews>
  <sheetFormatPr defaultRowHeight="18"/>
  <cols>
    <col min="1" max="1" width="14" customWidth="1"/>
    <col min="2" max="2" width="24" customWidth="1"/>
    <col min="3" max="4" width="18" customWidth="1"/>
    <col min="5" max="5" width="42" customWidth="1"/>
    <col min="6" max="8" width="18" customWidth="1"/>
  </cols>
  <sheetData>{''.join(rows_xml)}</sheetData>
</worksheet>'''

    workbook_xml = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">
  <sheets>
    <sheet name="חשבוניות" sheetId="1" r:id="rId1"/>
  </sheets>
</workbook>'''

    workbook_rels_xml = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet1.xml"/>
</Relationships>'''

    root_rels_xml = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>
</Relationships>'''

    content_types_xml = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
  <Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
  <Default Extension="xml" ContentType="application/xml"/>
  <Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>
  <Override PartName="/xl/worksheets/sheet1.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>
</Types>'''

    output = io.BytesIO()
    with zipfile.ZipFile(output, "w", compression=zipfile.ZIP_DEFLATED) as archive:
        archive.writestr("[Content_Types].xml", content_types_xml)
        archive.writestr("_rels/.rels", root_rels_xml)
        archive.writestr("xl/workbook.xml", workbook_xml)
        archive.writestr("xl/_rels/workbook.xml.rels", workbook_rels_xml)
        archive.writestr("xl/worksheets/sheet1.xml", worksheet_xml)
    return output.getvalue()


def _build_finance_invoices_pdf(rows: list[dict], report_due_date: str = "", vat_summary_rows: list[dict] | None = None) -> bytes:
    normalized_rows = [_normalize_finance_invoice_row_app(row or {}) for row in rows or []]
    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        rightMargin=28,
        leftMargin=28,
        topMargin=28,
        bottomMargin=24,
    )
    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        "FinancePdfTitle",
        parent=styles["Heading2"],
        fontName=PDF_HEB_BOLD_FONT or PDF_HEB_FONT,
        fontSize=18,
        leading=24,
        alignment=TA_RIGHT,
        textColor=colors.HexColor("#1f2d3d"),
    )
    meta_style = ParagraphStyle(
        "FinancePdfMeta",
        parent=styles["BodyText"],
        fontName=PDF_HEB_FONT,
        fontSize=10,
        leading=14,
        alignment=TA_RIGHT,
        textColor=colors.HexColor("#4b5563"),
    )
    cell_style = ParagraphStyle(
        "FinancePdfCell",
        parent=styles["BodyText"],
        fontName=PDF_HEB_FONT,
        fontSize=10,
        leading=13,
        alignment=TA_RIGHT,
    )
    header_style = ParagraphStyle(
        "FinancePdfHeader",
        parent=cell_style,
        fontName=PDF_HEB_BOLD_FONT or PDF_HEB_FONT,
        textColor=colors.white,
    )

    subtotal_sum = round(sum(_finance_parse_number(row.get("subtotal")) for row in normalized_rows), 2)
    vat_sum = round(sum(_finance_parse_number(row.get("vat")) for row in normalized_rows), 2)
    total_sum = round(sum(_finance_parse_number(row.get("total")) for row in normalized_rows), 2)

    title = "ייצוא חשבוניות"
    if report_due_date:
        title += f" · מועד דיווח {report_due_date}"
    exported_on = datetime.now().strftime("%d/%m/%Y %H:%M")
    summary_line = (
        f"סה״כ חשבוניות: {len(normalized_rows)} | "
        f"סה״כ לפני מע״מ: ₪ {subtotal_sum:,.2f} | "
        f"מע״מ: ₪ {vat_sum:,.2f} | "
        f"כולל מע״מ: ₪ {total_sum:,.2f}"
    )

    table_data = [
        [Paragraph(pdf_rtl(text), header_style) for text in ["תאריך", "ספק", "מספר אסמכתא", "מספר הקצאה", "שירות / מוצר", "סה״כ (לפני מע״מ)", "מע״מ", "סה״כ (כולל מע״מ)"]]
    ]
    for row in normalized_rows:
        table_data.append(
            [
                Paragraph(pdf_rtl(_finance_format_display_date(row.get("invoice_date"))), cell_style),
                Paragraph(pdf_rtl(str(row.get("supplier_name") or "")), cell_style),
                Paragraph(pdf_rtl(str(row.get("reference_number") or "")), cell_style),
                Paragraph(pdf_rtl(str(row.get("allocation_number") or "")), cell_style),
                Paragraph(pdf_rtl(str(row.get("service_or_product") or "")), cell_style),
                Paragraph(str(f"₪ {_finance_parse_number(row.get('subtotal')):,.2f}"), cell_style),
                Paragraph(str(f"₪ {_finance_parse_number(row.get('vat')):,.2f}"), cell_style),
                Paragraph(str(f"₪ {_finance_parse_number(row.get('total')):,.2f}"), cell_style),
            ]
        )

    table = Table(
        table_data,
        repeatRows=1,
        colWidths=[62, 118, 90, 96, 206, 85, 72, 95],
        hAlign="RIGHT",
    )
    table.setStyle(
        TableStyle(
            [
                ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#f28c28")),
                ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
                ("FONTNAME", (0, 0), (-1, 0), PDF_HEB_BOLD_FONT or PDF_HEB_FONT),
                ("FONTNAME", (0, 1), (-1, -1), PDF_HEB_FONT),
                ("FONTSIZE", (0, 0), (-1, -1), 10),
                ("LEADING", (0, 0), (-1, -1), 13),
                ("ALIGN", (0, 0), (-1, -1), "RIGHT"),
                ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
                ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.whitesmoke, colors.HexColor("#fff7ef")]),
                ("GRID", (0, 0), (-1, -1), 0.6, colors.HexColor("#e6d4c0")),
                ("BOX", (0, 0), (-1, -1), 0.9, colors.HexColor("#d4b89b")),
                ("TOPPADDING", (0, 0), (-1, -1), 7),
                ("BOTTOMPADDING", (0, 0), (-1, -1), 7),
                ("LEFTPADDING", (0, 0), (-1, -1), 8),
                ("RIGHTPADDING", (0, 0), (-1, -1), 8),
            ]
        )
    )

    story = [
        Paragraph(pdf_rtl(title), title_style),
        Spacer(1, 6),
        Paragraph(pdf_rtl(f"נוצר בתאריך {exported_on}"), meta_style),
        Spacer(1, 2),
        Paragraph(pdf_rtl(summary_line), meta_style),
        Spacer(1, 14),
        table,
    ]
    effective_vat_rows = [row for row in (vat_summary_rows or []) if isinstance(row, dict)]
    if effective_vat_rows:
        story.extend([
            Spacer(1, 16),
            Paragraph(pdf_rtl("סיכום מע״מ"), meta_style),
            Spacer(1, 4),
        ])
        for vat_row in effective_vat_rows:
            story.append(Paragraph(pdf_rtl(_finance_vat_summary_line(vat_row)), meta_style))
            story.append(Spacer(1, 4))
    doc.build(story)
    return buffer.getvalue()


def _hr_storage_dir() -> Path:
    HR_UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
    return HR_UPLOAD_DIR


def _hr_drive_root_id() -> str:
    parent_id = managed_storage_root_folder_id()
    return ensure_child_folder(parent_id, "עובדים ושכר")


def _hr_employee_drive_folder(employee_name: str) -> dict:
    root_id = _hr_drive_root_id()
    employee_folder_id = ensure_child_folder(root_id, _safe_folder_name(employee_name or "ללא עובד"))
    return {
        "root_id": root_id,
        "employee_folder_id": employee_folder_id,
        "employee_folder_url": _drive_folder_view_link(employee_folder_id),
    }


def _hr_document_folder(employee_name: str, section: str, month_key: str = "") -> dict:
    employee_folder = _hr_employee_drive_folder(employee_name)
    section_name = {
        "payroll": "תלושים",
        "contributions": "הפרשות",
        "hours": "שעות",
        "sick_notes": "אישורי מחלה",
        "documents": "מסמכים",
    }.get(section, "מסמכים")
    section_folder_id = ensure_child_folder(employee_folder["employee_folder_id"], section_name)
    target_folder_id = section_folder_id
    if month_key:
        target_folder_id = ensure_child_folder(section_folder_id, month_key)
    return {
        **employee_folder,
        "section_folder_id": section_folder_id,
        "target_folder_id": target_folder_id,
        "target_folder_url": _drive_folder_view_link(target_folder_id),
    }


def _hr_upload_file_to_drive(local_path: Path, employee_name: str, section: str, month_key: str = "", drive_name: str = "") -> dict:
    folder_info = _hr_document_folder(employee_name, section, month_key=month_key)
    uploaded = ensure_file_in_folder(folder_info["target_folder_id"], local_path, drive_name=drive_name or local_path.name)
    drive_file_id = str(uploaded.get("id") or "").strip()
    drive_url = str(uploaded.get("web_view_link") or uploaded.get("webViewLink") or "").strip()
    if not drive_url and drive_file_id:
        drive_url = _drive_file_view_link(drive_file_id)
    return {
        **folder_info,
        "drive_file_id": drive_file_id,
        "drive_url": drive_url,
        "drive_name": drive_name or local_path.name,
    }


def _build_simple_xlsx(headers: list[str], rows: list[list[str | int | float]], sheet_name: str) -> bytes:
    def cell_xml(row_number: int, col_number: int, value, *, numeric: bool = False) -> str:
        ref = f"{_xlsx_col_name(col_number)}{row_number}"
        if numeric:
            try:
                return f'<c r="{ref}"><v>{float(value or 0):.2f}</v></c>'
            except Exception:
                pass
        text = str(value or "")
        return f'<c r="{ref}" t="inlineStr"><is><t>{xml_escape(text)}</t></is></c>'

    rows_xml: list[str] = []
    header_cells = "".join(cell_xml(1, index + 1, title) for index, title in enumerate(headers))
    rows_xml.append(f'<row r="1">{header_cells}</row>')
    for row_number, row in enumerate(rows, start=2):
        cells = []
        for col_number, value in enumerate(row, start=1):
            numeric = isinstance(value, (int, float))
            cells.append(cell_xml(row_number, col_number, value, numeric=numeric))
        rows_xml.append(f'<row r="{row_number}">{"".join(cells)}</row>')

    last_col = _xlsx_col_name(max(1, len(headers)))
    dimension = f"A1:{last_col}{max(1, len(rows) + 1)}"
    worksheet_xml = f'''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">
  <dimension ref="{dimension}"/>
  <sheetViews><sheetView workbookViewId="0" rightToLeft="1"/></sheetViews>
  <sheetFormatPr defaultRowHeight="18"/>
  <sheetData>{''.join(rows_xml)}</sheetData>
</worksheet>'''

    workbook_xml = f'''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">
  <sheets>
    <sheet name="{xml_escape(sheet_name)}" sheetId="1" r:id="rId1"/>
  </sheets>
</workbook>'''

    workbook_rels_xml = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet1.xml"/>
</Relationships>'''

    root_rels_xml = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>
</Relationships>'''

    content_types_xml = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
  <Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
  <Default Extension="xml" ContentType="application/xml"/>
  <Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>
  <Override PartName="/xl/worksheets/sheet1.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>
</Types>'''

    output = io.BytesIO()
    with zipfile.ZipFile(output, "w", compression=zipfile.ZIP_DEFLATED) as archive:
        archive.writestr("[Content_Types].xml", content_types_xml)
        archive.writestr("_rels/.rels", root_rels_xml)
        archive.writestr("xl/workbook.xml", workbook_xml)
        archive.writestr("xl/_rels/workbook.xml.rels", workbook_rels_xml)
        archive.writestr("xl/worksheets/sheet1.xml", worksheet_xml)
    return output.getvalue()


def _build_simple_pdf_report(title: str, headers: list[str], rows: list[list[str]]) -> bytes:
    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        rightMargin=28,
        leftMargin=28,
        topMargin=28,
        bottomMargin=24,
    )
    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        "HrPdfTitle",
        parent=styles["Heading2"],
        fontName=PDF_HEB_BOLD_FONT or PDF_HEB_FONT,
        fontSize=18,
        leading=24,
        alignment=TA_RIGHT,
        textColor=colors.HexColor("#1f2d3d"),
    )
    cell_style = ParagraphStyle(
        "HrPdfCell",
        parent=styles["BodyText"],
        fontName=PDF_HEB_FONT,
        fontSize=9,
        leading=12,
        alignment=TA_RIGHT,
    )
    table_rows = [[Paragraph(pdf_rtl(str(cell or "")), cell_style) for cell in headers]]
    for row in rows:
        table_rows.append([Paragraph(pdf_rtl(str(cell or "")), cell_style) for cell in row])
    col_width = 770 / max(1, len(headers))
    table = Table(table_rows, colWidths=[col_width] * len(headers), repeatRows=1)
    table.setStyle(
        TableStyle([
            ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#f4ede4")),
            ("TEXTCOLOR", (0, 0), (-1, 0), colors.HexColor("#7c2d12")),
            ("FONTNAME", (0, 0), (-1, 0), PDF_HEB_BOLD_FONT or PDF_HEB_FONT),
            ("FONTNAME", (0, 1), (-1, -1), PDF_HEB_FONT),
            ("GRID", (0, 0), (-1, -1), 0.5, colors.HexColor("#d6d3d1")),
            ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#fffaf6")]),
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
            ("ALIGN", (0, 0), (-1, -1), "RIGHT"),
            ("RIGHTPADDING", (0, 0), (-1, -1), 8),
            ("LEFTPADDING", (0, 0), (-1, -1), 8),
            ("TOPPADDING", (0, 0), (-1, -1), 6),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 6),
        ])
    )
    story = [Paragraph(pdf_rtl(title), title_style), Spacer(1, 12), table]
    doc.build(story)
    return buffer.getvalue()


def _hr_month_display(month_key: str) -> str:
    raw = str(month_key or "").strip()
    if re.match(r"^\d{4}-\d{2}$", raw):
        month_names = {
            "01": "ינואר",
            "02": "פברואר",
            "03": "מרץ",
            "04": "אפריל",
            "05": "מאי",
            "06": "יוני",
            "07": "יולי",
            "08": "אוגוסט",
            "09": "ספטמבר",
            "10": "אוקטובר",
            "11": "נובמבר",
            "12": "דצמבר",
        }
        year_value, month_value = raw.split("-", 1)
        return f"{month_names.get(month_value, month_value)} {year_value}"
    return raw or "ללא חודש"


def _hr_file_display_name(file_name: str, month_key: str = "", prefix: str = "") -> str:
    raw_name = str(file_name or "").strip()
    suffix = Path(raw_name).suffix or ""
    month_label = _hr_month_display(month_key)
    base_label = prefix.strip() or month_label or Path(raw_name).stem or "קובץ"
    return f"{base_label}{suffix}"


def _hr_local_file_path(employee_id: str, month_key: str, file_name: str) -> Path | None:
    safe_employee_id = str(employee_id or "").strip()
    safe_month_key = str(month_key or "").strip() or "general"
    safe_file_name = Path(str(file_name or "").strip()).name
    if not safe_employee_id or not safe_file_name:
        return None
    candidate = _hr_storage_dir() / safe_employee_id / safe_month_key / safe_file_name
    if candidate.exists():
        return candidate
    fallback = _hr_storage_dir() / safe_employee_id / "general" / safe_file_name
    if fallback.exists():
        return fallback
    return candidate


def _hr_delete_local_file(path_value: Path | None) -> dict:
    if not path_value:
        return {"status": "skipped", "path": ""}
    target = Path(path_value)
    if not target.exists():
        return {"status": "missing", "path": str(target)}
    try:
        target.unlink()
        return {"status": "ok", "path": str(target)}
    except Exception as exc:
        return {"status": "error", "path": str(target), "error": str(exc)}


def _hr_delete_drive_target(drive_id: str, target_label: str) -> dict:
    target_id = str(drive_id or "").strip()
    if not target_id:
        return {"status": "skipped", "target": target_label, "id": ""}
    try:
        delete_drive_file(target_id)
        return {"status": "ok", "target": target_label, "id": target_id}
    except Exception as exc:
        log_handled_error(f"hr drive delete failed ({target_label})", exc)
        return {"status": "error", "target": target_label, "id": target_id, "error": str(exc)}


def _hr_parse_hours_report_rows(file_path: Path) -> list[dict]:
    from openpyxl import load_workbook

    if not file_path.exists():
        return []
    workbook = load_workbook(file_path, data_only=True)
    worksheet = workbook[workbook.sheetnames[0]]
    rows = list(worksheet.iter_rows(values_only=True))
    details: list[dict] = []
    if len(rows) >= 2 and str(rows[1][0] or "").strip() == "מחלקה":
        for row in rows[2:]:
            work_date = str(row[5] or "").strip()
            entry_time = str(row[6] or "").strip()
            exit_time = str(row[9] or "").strip()
            status = str(row[12] or "").strip()
            hours_value = row[11]
            try:
                total_hours = float(hours_value or 0)
            except Exception:
                total_hours = 0.0
            if not work_date:
                continue
            if total_hours <= 0 and not entry_time and not exit_time:
                continue
            details.append(
                {
                    "date": work_date,
                    "day_name": "",
                    "entry_time": entry_time,
                    "exit_time": exit_time,
                    "time_range": f"{entry_time}-{exit_time}".strip("-") if (entry_time or exit_time) else "",
                    "hours": round(total_hours, 2),
                    "status": status or "נוכח",
                }
            )
        return details

    if len(rows) >= 2 and str(rows[1][0] or "").strip() == "תאריך":
        header_row = [str(cell or "").strip() for cell in rows[1]]
        total_hours_index = next(
            (
                index
                for index, value in enumerate(header_row)
                if value == "סך שעות"
            ),
            6,
        )
        time_range_indexes = [index for index in range(2, total_hours_index) if index < len(header_row)]
        for row in rows[2:]:
            work_date = str(row[0] or "").strip()
            day_name = str(row[1] or "").strip()
            time_ranges: list[str] = []
            for index in time_range_indexes:
                if index >= len(row):
                    continue
                value = str(row[index] or "").strip()
                if value:
                    time_ranges.append(value)
            time_range = ""
            for candidate in time_ranges:
                value = str(candidate or "").strip()
                if value:
                    time_range = value
                    break
            try:
                total_hours = float(row[total_hours_index] or 0)
            except Exception:
                total_hours = 0.0
            if not work_date:
                continue
            if total_hours <= 0 and not time_ranges:
                continue
            entry_time = ""
            exit_time = ""
            if "-" in time_range:
                parts = [part.strip() for part in time_range.split("-", 1)]
                if len(parts) == 2:
                    entry_time, exit_time = parts
            details.append(
                {
                    "date": work_date,
                    "day_name": day_name,
                    "entry_time": entry_time,
                    "exit_time": exit_time,
                    "time_range": " | ".join(time_ranges) if time_ranges else time_range,
                    "hours": round(total_hours, 2),
                    "status": "נוכח",
                }
            )
        return details

    return []


def _hr_safe_float(value, default: float = 0.0) -> float:
    raw = str(value or "").strip().replace(",", "")
    if not raw:
        return default
    try:
        return float(raw)
    except Exception:
        return default


def _hr_normalize_text_token(value: str) -> str:
    raw = normalize_ws(str(value or "")).strip().lower()
    raw = raw.replace("׳", "'").replace("״", '"').replace('"', "")
    raw = re.sub(r"[^\w\u0590-\u05FF ]+", " ", raw)
    return re.sub(r"\s+", " ", raw).strip()


def _hr_find_hours_row(employee_id: str, month_key: str, hours_rows: list[dict]) -> dict:
    safe_employee_id = str(employee_id or "").strip()
    safe_month_key = str(month_key or "").strip()
    return next(
        (
            dict(row)
            for row in (hours_rows or [])
            if str(row.get("employee_id") or "").strip() == safe_employee_id
            and str(row.get("month_key") or "").strip() == safe_month_key
        ),
        {},
    ) or {}


def _hr_find_payroll_row(employee_id: str, month_key: str, payroll_rows: list[dict]) -> dict:
    safe_employee_id = str(employee_id or "").strip()
    safe_month_key = str(month_key or "").strip()
    return next(
        (
            dict(row)
            for row in (payroll_rows or [])
            if str(row.get("employee_id") or "").strip() == safe_employee_id
            and str(row.get("month_key") or "").strip() == safe_month_key
        ),
        {},
    ) or {}


