def _hr_extract_text_from_supporting_file(file_path: Path) -> str:
    suffix = file_path.suffix.lower()
    try:
        if suffix == ".pdf":
            text = normalize_ws(str(extract_text_pdfplumber(file_path) or "")).strip()
            if not text:
                text = normalize_ws(str(ocr_pdf(file_path) or "")).strip()
            return text
        from services.ocr_service import ocr_image_file
        return normalize_ws(ocr_image_file(file_path))
    except Exception as exc:
        log_handled_error("hr supporting doc text extraction failed", exc)
        return ""


def _hr_match_employee_name_from_text(text: str, employees: list[dict]) -> str:
    normalized_text = _hr_normalize_text_token(text)
    if not normalized_text:
        return ""
    for employee in employees or []:
        full_name = str(employee.get("full_name") or "").strip()
        normalized_name = _hr_normalize_text_token(full_name)
        if normalized_name and normalized_name in normalized_text:
            return full_name
        name_parts = [part for part in normalized_name.split() if len(part) >= 3]
        if name_parts and all(part in normalized_text for part in name_parts[:2]):
            return full_name
    return ""


def _hr_parse_supporting_doc_summary(file_path: Path, employees: list[dict]) -> dict:
    text = _hr_extract_text_from_supporting_file(file_path)
    employee_name = _hr_match_employee_name_from_text(text, employees)
    file_name = file_path.name
    date_matches = re.findall(r"\b\d{2}/\d{2}/\d{4}\b", text)
    normalized_text = _hr_normalize_text_token(text)

    if "אישור מחלה" in text:
        total_days_match = re.search(r"ימי מחלה[: ]+(\d+)", text)
        from_date_match = re.search(r"מומלץ על מנוחה מתאריך[^\d]{0,12}(\d{2}/\d{2}/\d{4})", text)
        if not from_date_match:
            from_date_match = re.search(r"מתאריך[^\d]{0,12}(\d{2}/\d{2}/\d{4})", text)
        until_date_match = re.search(r"עד תאריך[^\d]{0,12}(\d{2}/\d{2}/\d{4})", text)
        summary_bits = []
        if employee_name:
            summary_bits.append(employee_name)
        summary_bits.append("אישור מחלה")
        if total_days_match:
            summary_bits.append(f"{total_days_match.group(1)} ימי מחלה")
        if from_date_match and until_date_match:
            summary_bits.append(f"{from_date_match.group(1)}-{until_date_match.group(1)}")
        elif date_matches:
            summary_bits.append(", ".join(date_matches[:2]))
        return {
            "file_name": file_name,
            "employee_name": employee_name,
            "category": "אישור מחלה",
            "summary": " · ".join(summary_bits),
            "details": {
                "days": str(total_days_match.group(1) if total_days_match else "").strip(),
                "from_date": str(from_date_match.group(1) if from_date_match else "").strip(),
                "until_date": str(until_date_match.group(1) if until_date_match else "").strip(),
            },
        }

    if "אישור ביקור במרפאת שיניים" in text or ("מרפאת שיניים" in text and "אישור" in text):
        hours_match = re.search(r"בין השעות[: ]+([^\n]+)", text)
        if not hours_match:
            hours_match = re.search(r"טיפול שיניים[^0-9]*(\d+)\s*[בש]?הש", text)
        if not hours_match:
            hours_match = re.search(r"התקיים[^0-9]{0,12}(\d+)", text)
        if not hours_match:
            hours_match = re.search(r"(\d+)\s*שעות", text)
        visit_date = date_matches[-1] if date_matches else ""
        summary_bits = []
        if employee_name:
            summary_bits.append(employee_name)
        summary_bits.append("אישור ביקור במרפאת שיניים")
        if visit_date:
            summary_bits.append(visit_date)
        if hours_match:
            value = hours_match.group(1).strip()
            summary_bits.append(value if "שעות" in value else f"{value} שעות")
        return {
            "file_name": file_name,
            "employee_name": employee_name,
            "category": "אישור ביקור",
            "summary": " · ".join(summary_bits),
            "details": {
                "date": visit_date,
                "hours": str(hours_match.group(1) if hours_match else "").strip(),
            },
        }

    fallback_line = ""
    for chunk in re.split(r"[.\n]", text):
        candidate = normalize_ws(chunk).strip()
        if len(candidate) >= 8:
            fallback_line = candidate
            break
    return {
        "file_name": file_name,
        "employee_name": employee_name,
        "category": "מסמך תומך",
        "summary": " · ".join(
            value for value in [
                employee_name,
                file_name,
                fallback_line or "מסמך צורף למייל",
            ] if value
        ),
        "details": {
            "dates": date_matches[:3],
            "text_hint": fallback_line,
            "normalized_text": normalized_text[:240],
        },
    }


def _hr_build_generated_hours_xlsx(row: dict, details: list[dict], month_key: str, employee_name: str) -> bytes:
    headers = ["עובד", "חודש", "תאריך", "יום", "טווח", "שעות", "סטטוס", "הערה"]
    rows: list[list[str | int | float]] = []
    for detail in details:
        rows.append(
            [
                employee_name,
                _hr_month_display(month_key),
                str(detail.get("date") or ""),
                str(detail.get("day_name") or ""),
                str(detail.get("time_range") or ""),
                float(detail.get("hours") or 0),
                str(detail.get("status") or ""),
                "מהקובץ המקורי",
            ]
        )
    current_regular_hours = round(_hr_safe_float(row.get("regular_hours")), 2)
    current_overtime_hours = round(_hr_safe_float(row.get("overtime_hours")), 2)
    if not rows:
        rows.append([employee_name, _hr_month_display(month_key), "", "", "", current_regular_hours, "ידני", "הוזן ידנית במערכת"])
    rows.append([employee_name, _hr_month_display(month_key), "", "", "", current_regular_hours, "סיכום", "שעות רגילות לאחר עדכון ידני במערכת"])
    if current_overtime_hours > 0:
        rows.append([employee_name, _hr_month_display(month_key), "", "", "", current_overtime_hours, "סיכום", "שעות נוספות לאחר עדכון ידני במערכת"])
    total_hours = round(current_regular_hours + current_overtime_hours, 2)
    rows.append([employee_name, _hr_month_display(month_key), "", "", "", total_hours, "סיכום", "סה״כ שעות לחישוב שכר"])
    return _build_simple_xlsx(headers, rows, "שעות מעודכנות")


def _hr_resolve_hours_attachment(row: dict) -> dict:
    employee_id = str(row.get("employee_id") or "").strip()
    employee_name = str(row.get("employee_name") or "").strip()
    month_key = str(row.get("month_key") or "").strip()
    hours_file_name = str(row.get("hours_file_name") or "").strip()
    if not employee_id or not month_key or not hours_file_name:
        return {"available": False}

    local_path = _hr_local_file_path(employee_id, month_key, hours_file_name)
    if (not local_path or not local_path.exists()) and str(row.get("hours_drive_file_id") or "").strip():
        local_path = _hr_storage_dir() / employee_id / (month_key or "general") / Path(hours_file_name).name
        local_path.parent.mkdir(parents=True, exist_ok=True)
        download_drive_file(str(row.get("hours_drive_file_id") or "").strip(), local_path)
    if not local_path or not local_path.exists():
        return {"available": False}

    details = _hr_parse_hours_report_rows(local_path)
    original_total_hours = round(sum(_hr_safe_float(item.get("hours")) for item in details), 2)
    current_regular_hours = round(_hr_safe_float(row.get("regular_hours")), 2)
    current_overtime_hours = round(_hr_safe_float(row.get("overtime_hours")), 2)
    generated_needed = abs(original_total_hours - current_regular_hours) > 0.01 or current_overtime_hours > 0.01
    if not generated_needed:
        return {
            "available": True,
            "path": str(local_path),
            "generated": False,
            "file_name": local_path.name,
            "original_total_hours": original_total_hours,
            "current_regular_hours": current_regular_hours,
            "current_overtime_hours": current_overtime_hours,
        }

    generated_dir = _hr_generated_hours_dir(employee_id, month_key)
    generated_name = f"{employee_name or employee_id} - {_hr_month_display(month_key)} - שעות מעודכנות.xlsx"
    generated_path = generated_dir / generated_name
    generated_path.write_bytes(_hr_build_generated_hours_xlsx(row, details, month_key, employee_name))
    return {
        "available": True,
        "path": str(generated_path),
        "generated": True,
        "file_name": generated_path.name,
        "original_total_hours": original_total_hours,
        "current_regular_hours": current_regular_hours,
        "current_overtime_hours": current_overtime_hours,
    }


def _hr_is_sick_note_document(row: dict) -> bool:
    return str((row or {}).get("category") or "").strip().lower() == "sick_note"


def _hr_resolve_document_attachment(row: dict, *, section_key: str = "documents") -> dict:
    employee_id = str(row.get("employee_id") or "").strip()
    month_key = str(row.get("month_key") or "").strip()
    file_name = str(row.get("file_name") or "").strip()
    drive_file_id = str(row.get("drive_file_id") or "").strip()
    if not employee_id or not file_name:
        return {"available": False}
    local_path = _hr_local_file_path(employee_id, month_key, file_name)
    if (not local_path or not local_path.exists()) and drive_file_id:
        local_path = _hr_storage_dir() / employee_id / (month_key or "general") / Path(file_name).name
        local_path.parent.mkdir(parents=True, exist_ok=True)
        download_drive_file(drive_file_id, local_path)
    if not local_path or not local_path.exists():
        return {"available": False}
    return {
        "available": True,
        "path": str(local_path),
        "file_name": local_path.name,
        "section": section_key,
    }


def _hr_collect_saved_supporting_docs(month_key: str, document_rows: list[dict], employees: list[dict]) -> tuple[list[dict], list[dict], list[str]]:
    safe_month_key = str(month_key or "").strip()
    matching_rows = [
        dict(row)
        for row in (document_rows or [])
        if _hr_is_sick_note_document(row) and str(row.get("month_key") or "").strip() == safe_month_key
    ]
    attachment_paths: list[str] = []
    summaries: list[dict] = []
    warnings: list[str] = []
    seen_paths: set[str] = set()
    for row in matching_rows:
        resolved = _hr_resolve_document_attachment(row, section_key="sick_notes")
        if resolved.get("available") and resolved.get("path"):
            local_path = str(resolved.get("path") or "").strip()
            if local_path and local_path not in seen_paths:
                attachment_paths.append(local_path)
                seen_paths.add(local_path)
            summary = _hr_parse_supporting_doc_summary(Path(local_path), employees)
            summary["title"] = str(row.get("title") or "").strip()
            summary["employee_name"] = str(row.get("employee_name") or summary.get("employee_name") or "").strip()
            summaries.append(summary)
        else:
            warnings.append(
                f"אישור המחלה {str(row.get('title') or row.get('file_name') or 'ללא שם').strip()} לא נמצא כרגע מקומית."
            )
    return matching_rows, summaries, warnings


def _hr_build_payslip_prep_history_row(
    month_key: str,
    preview_payload: dict,
    send_mode: str,
    recipients: str,
    attachments_count: int,
    supporting_summaries: list[dict],
    notes: str = "",
    sent_at: str | None = None,
) -> dict:
    safe_month_key = str(month_key or "").strip()
    effective_sent_at = str(sent_at or datetime.now().isoformat(timespec="seconds")).strip()
    return {
        "row_id": f"prep_{safe_month_key}_{str(send_mode or 'live').strip().lower()}_{effective_sent_at.replace(':', '').replace('-', '')}",
        "month_key": safe_month_key,
        "month_label": str(preview_payload.get("month_label") or _hr_month_display(safe_month_key)).strip(),
        "send_mode": "test" if str(send_mode or "").strip().lower() == "test" else "live",
        "sent_to": str(recipients or "").strip(),
        "sent_at": effective_sent_at,
        "employees_total": str(preview_payload.get("employees_total") or 0),
        "gross_total_label": str(preview_payload.get("gross_total_label") or "").strip(),
        "attachments_count": str(int(attachments_count or 0)),
        "supporting_summaries_json": json.dumps(supporting_summaries or [], ensure_ascii=False),
        "notes": str(notes or "").strip(),
    }


def _hr_build_payslip_prep_payload(month_key: str) -> dict:
    safe_month_key = str(month_key or "").strip()
    state_payload = _hr_state_payload(force_refresh=False)
    employees = list(state_payload.get("employees") or [])
    hours_rows = list(state_payload.get("hours_rows") or [])
    payroll_rows = list(state_payload.get("payroll_rows") or [])
    document_rows = list(state_payload.get("sick_note_rows") or [])
    preferred_order = {
        "emp_david_ben_yacov": 0,
        "emp_malka_ben_yacov": 1,
        "emp_tawuchao_damlau": 2,
        "emp_solomon_shibshi": 3,
    }
    active_employees = [
        employee
        for employee in employees
        if str(employee.get("active_status") or "active").strip().lower() != "inactive"
    ]
    active_employees.sort(key=lambda item: (preferred_order.get(str(item.get("employee_id") or "").strip(), 99), str(item.get("full_name") or "")))
    stored_supporting_rows, stored_supporting_summaries, stored_supporting_warnings = _hr_collect_saved_supporting_docs(
        safe_month_key,
        document_rows,
        employees,
    )

    preview_rows: list[dict] = []
    total_gross = 0.0
    for employee in active_employees:
        employee_id = str(employee.get("employee_id") or "").strip()
        full_name = str(employee.get("full_name") or "").strip()
        employment_type = str(employee.get("employment_type") or "").strip() or "global"
        base_salary = round(_hr_safe_float(employee.get("base_salary")), 2)
        hourly_rate = round(_hr_safe_float(employee.get("hourly_rate")), 2)
        hours_row = _hr_find_hours_row(employee_id, safe_month_key, hours_rows)
        payroll_row = _hr_find_payroll_row(employee_id, safe_month_key, payroll_rows)
        regular_hours = round(_hr_safe_float(hours_row.get("regular_hours")), 2)
        overtime_hours = round(_hr_safe_float(hours_row.get("overtime_hours")), 2)
        total_hours = round(regular_hours + overtime_hours, 2)
        salary_rule_label = "שכר גלובלי קבוע"
        gross_before_adjustments = base_salary
        warnings: list[str] = []

        if employee_id == "emp_tawuchao_damlau":
            gross_before_adjustments = 6000.0
            salary_rule_label = "גלובלי קבוע 6,000 ש״ח לפני נסיעות וניכוי"
        elif employee_id == "emp_solomon_shibshi":
            gross_before_adjustments = round(total_hours * 50.0, 2)
            salary_rule_label = "50 ש״ח לשעה לפי דוח שעות"
            if total_hours <= 0:
                warnings.append("לא נמצאו שעות לחישוב סלומון בחודש הזה.")
        elif employment_type == "global":
            salary_rule_label = f"שכר גלובלי קבוע {base_salary:,.2f} ש״ח"
        elif employment_type == "hourly":
            gross_before_adjustments = round(total_hours * hourly_rate, 2)
            salary_rule_label = f"{hourly_rate:,.2f} ש״ח לשעה"

        hours_attachment = _hr_resolve_hours_attachment(hours_row) if hours_row else {"available": False}
        if hours_row and hours_attachment.get("generated"):
            warnings.append("קובץ השעות יעודכן לאקסל חדש בגלל עריכה ידנית במערכת.")
        if hours_row and not hours_attachment.get("available"):
            warnings.append("יש שורת שעות אבל קובץ השעות לא נמצא כרגע מקומית.")

        total_gross += gross_before_adjustments
        preview_rows.append(
            {
                "employee_id": employee_id,
                "employee_name": full_name,
                "employment_type": employment_type,
                "salary_rule_label": salary_rule_label,
                "gross_before_adjustments": round(gross_before_adjustments, 2),
                "gross_before_adjustments_label": f"{gross_before_adjustments:,.2f} ₪",
                "regular_hours": regular_hours,
                "overtime_hours": overtime_hours,
                "total_hours": total_hours,
                "hourly_rate": hourly_rate,
                "hourly_rate_label": f"{hourly_rate:,.2f} ₪" if hourly_rate > 0 else "—",
                "hours_file_name": str(hours_row.get("hours_file_name") or "").strip(),
                "hours_file_display_name": _hr_file_display_name(str(hours_row.get("hours_file_name") or ""), safe_month_key, prefix=f"שעות {full_name}") if hours_row else "",
                "hours_file_generated": bool(hours_attachment.get("generated")),
                "hours_file_available": bool(hours_attachment.get("available")),
                "payroll_row_exists": bool(payroll_row),
                "warnings": warnings,
                "stored_supporting_docs_count": sum(
                    1 for item in stored_supporting_summaries
                    if str(item.get("employee_name") or "").strip() == full_name
                ),
            }
        )

    return {
        "month_key": safe_month_key,
        "month_label": _hr_month_display(safe_month_key),
        "rows": preview_rows,
        "employees_total": len(preview_rows),
        "gross_total": round(total_gross, 2),
        "gross_total_label": f"{total_gross:,.2f} ₪",
        "stored_supporting_rows": stored_supporting_rows,
        "stored_supporting_summaries": stored_supporting_summaries,
        "stored_supporting_warnings": stored_supporting_warnings,
    }


def _hr_build_payslip_prep_email_bodies(preview_payload: dict, supporting_summaries: list[dict]) -> tuple[str, str]:
    month_label = str(preview_payload.get("month_label") or "").strip() or "ללא חודש"
    rows = list(preview_payload.get("rows") or [])
    gross_total_label = str(preview_payload.get("gross_total_label") or "0.00 ₪").strip()

    plain_lines = [
        f"חומרי שכר להפקה - {month_label}",
        "",
        f"מצורף ריכוז החומרים להפקת תלושים עבור {month_label}.",
        f"סה\"כ ברוטו לפני נסיעות וניכוי: {gross_total_label}",
        "",
        "פירוט עובדים:",
    ]
    html_rows: list[str] = []
    for row in rows:
        warnings = list(row.get("warnings") or [])
        plain_lines.extend(
            [
                f"- {row.get('employee_name')}: {row.get('gross_before_adjustments_label')} | {row.get('salary_rule_label')}",
                f"  שעות רגילות: {row.get('regular_hours', 0):.2f} | שעות נוספות: {row.get('overtime_hours', 0):.2f} | סה\"כ שעות: {row.get('total_hours', 0):.2f}",
            ]
        )
        if warnings:
            plain_lines.append(f"  הערות: {' | '.join(warnings)}")
        html_warning = ""
        if warnings:
            html_warning = f"<div style=\"margin-top:6px;color:#b45309;font-size:13px;\">{'<br>'.join(html.escape(item) for item in warnings)}</div>"
        html_rows.append(
            f"""
            <div style="border:1px solid #fed7aa;border-radius:16px;padding:14px 16px;margin-bottom:12px;background:#fffaf5;">
              <div style="font-size:17px;font-weight:700;color:#7c2d12;">{html.escape(str(row.get("employee_name") or ""))}</div>
              <div style="margin-top:6px;color:#334155;">{html.escape(str(row.get("salary_rule_label") or ""))}</div>
              <div style="margin-top:4px;color:#111827;font-weight:700;">ברוטו לפני נסיעות וניכוי: {html.escape(str(row.get("gross_before_adjustments_label") or ""))}</div>
              <div style="margin-top:4px;color:#475569;">שעות רגילות: {float(row.get("regular_hours") or 0):.2f} | שעות נוספות: {float(row.get("overtime_hours") or 0):.2f} | סה״כ שעות: {float(row.get("total_hours") or 0):.2f}</div>
              {html_warning}
            </div>
            """
        )

    if supporting_summaries:
        plain_lines.extend(["", "מסמכים תומכים שצורפו:"])
        for item in supporting_summaries:
            plain_lines.append(f"- {item.get('summary')}")
    else:
        plain_lines.extend(["", "לא צורפו מסמכים תומכים נוספים."])

    plain_lines.extend(["", "תודה,", "בן יעקב פתרונות טקסטיל"])

    support_html = ""
    if supporting_summaries:
        support_html = """
        <div style="margin-top:20px;">
          <div style="font-size:17px;font-weight:700;color:#7c2d12;margin-bottom:10px;">מסמכים תומכים שצורפו</div>
          <ul style="margin:0;padding-right:18px;color:#334155;line-height:1.8;">
        """
        for item in supporting_summaries:
            support_html += f"<li>{html.escape(str(item.get('summary') or ''))}</li>"
        support_html += "</ul></div>"
    else:
        support_html = '<div style="margin-top:20px;color:#64748b;">לא צורפו מסמכים תומכים נוספים.</div>'

    html_body = f"""<!doctype html>
<html dir="rtl" lang="he">
  <body dir="rtl" lang="he" style="font-family:Arial,'Helvetica Neue',sans-serif;line-height:1.7;color:#1f2937;direction:rtl;text-align:right;">
    <div style="font-size:22px;font-weight:800;color:#7c2d12;">חומרי שכר להפקה - {html.escape(month_label)}</div>
    <div style="margin-top:10px;">מצורף ריכוז החומרים להפקת תלושים עבור {html.escape(month_label)}.</div>
    <div style="margin-top:6px;font-weight:700;">סה״כ ברוטו לפני נסיעות וניכוי: {html.escape(gross_total_label)}</div>
    <div style="margin-top:18px;">{"".join(html_rows)}</div>
    {support_html}
    <div style="margin-top:22px;">תודה,<br>בן יעקב פתרונות טקסטיל</div>
  </body>
</html>"""
    return "\n".join(plain_lines), html_body


def _hr_parse_iso_date(value: str) -> date | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    for fmt in ("%d/%m/%Y", "%Y-%m-%d"):
        try:
            return datetime.strptime(raw, fmt).date()
        except Exception:
            continue
    return None


def _hr_subtract_tenure(anchor: date, years: int, months: int, days: int) -> date:
    target_year = anchor.year - years
    target_month = anchor.month - months
    while target_month <= 0:
        target_month += 12
        target_year -= 1
    target_day = min(anchor.day, calendar.monthrange(target_year, target_month)[1])
    result = date(target_year, target_month, target_day)
    if days:
        result -= timedelta(days=days)
    return result


def _hr_infer_start_date_from_payslip(file_path: Path, month_key: str = "") -> str:
    try:
        raw_text = extract_text_pdfplumber(file_path)
    except Exception:
        raw_text = ""
    text = " ".join(str(raw_text or "").split())
    if not text:
        return ""

    direct_match = re.search(r"(\d{2}/\d{2}/\d{4})\s*:(?:תחילת עבודה|הדובע תליחת)", text)
    if direct_match:
        direct_date = _hr_parse_iso_date(direct_match.group(1))
        if direct_date:
            return direct_date.isoformat()

    tenure_match = re.search(
        r"([0-9]{2})\.([0-9]{2})\.([0-9]{2})\s*:(?:וותק|קתוו)|:(?:וותק|קתוו)\s*([0-9]{2})\.([0-9]{2})\.([0-9]{2})",
        text,
    )
    if not tenure_match:
        return ""
    parts = [value for value in tenure_match.groups() if value is not None]
    if len(parts) != 3:
        return ""
    years, months, days = (int(value) for value in parts)

    anchor: date | None = None
    month_match = re.search(r"(\d{2})/(\d{4})\s+תלוש שכר לחודש", text)
    if month_match:
        month_number = int(month_match.group(1))
        year_number = int(month_match.group(2))
        next_month = month_number + 1
        next_year = year_number
        if next_month > 12:
            next_month = 1
            next_year += 1
        anchor = date(next_year, next_month, 1)
    elif re.match(r"^\d{4}-\d{2}$", str(month_key or "").strip()):
        month_number = int(month_key[5:7])
        year_number = int(month_key[:4])
        next_month = month_number + 1
        next_year = year_number
        if next_month > 12:
            next_month = 1
            next_year += 1
        anchor = date(next_year, next_month, 1)

    if anchor is None:
        printed_match = re.search(r"(\d{2}/\d{2}/\d{4})\s+הודפס בתאריך", text)
        printed_date = _hr_parse_iso_date(printed_match.group(1)) if printed_match else None
        if printed_date:
            anchor = date(printed_date.year, printed_date.month, 1)

    if anchor is None:
        return ""


def _hr_decimal_string(value) -> str:
    raw = str(value or "").strip().replace(",", "")
    if not raw:
        return ""
    try:
        return f"{float(raw):.2f}"
    except Exception:
        return raw


def _hr_extract_pdf_text(file_path: Path) -> str:
    try:
        raw_text = extract_text_pdfplumber(file_path)
    except Exception:
        raw_text = ""
    return " ".join(str(raw_text or "").split())


def _hr_employee_by_id_number(employees: list[dict]) -> dict[str, dict]:
    return {
        re.sub(r"\D+", "", str(row.get("id_number") or "").strip()): dict(row)
        for row in (employees or [])
        if re.sub(r"\D+", "", str(row.get("id_number") or "").strip())
    }


def _hr_normalize_name_key(value: str) -> str:
    normalized = str(value or "").strip().lower()
    normalized = normalized.replace("״", '"').replace("“", '"').replace("”", '"').replace("׳", "'")
    normalized = normalized.replace("בנייה", "בניה")
    normalized = re.sub(r"[\"'.,()\\-]", " ", normalized)
    normalized = re.sub(r"\s+", "", normalized)
    return normalized


def _hr_match_employee_from_text(text: str, employees: list[dict]) -> dict | None:
    by_id_number = _hr_employee_by_id_number(employees)
    for id_number, employee in by_id_number.items():
        if id_number and id_number in text:
            return dict(employee)
    normalized_text = _hr_normalize_name_key(text)
    for employee in employees or []:
        name_key = _hr_normalize_name_key(str(employee.get("full_name") or ""))
        if name_key and name_key in normalized_text:
            return dict(employee)
    return None


def _hr_parse_month_key_from_text(text: str, patterns: list[str]) -> str:
    for pattern in patterns:
        match = re.search(pattern, text)
        if not match:
            continue
        month_value, year_value = match.group(1), match.group(2)
        if len(month_value) == 2 and len(year_value) == 4:
            return f"{year_value}-{month_value}"
    return ""


def _hr_parse_month_key_from_hebrew_text(text: str) -> str:
    raw_text = str(text or "").strip()
    if not raw_text:
        return ""
    month_names = {
        "ינואר": "01",
        "פברואר": "02",
        "מרץ": "03",
        "אפריל": "04",
        "מאי": "05",
        "יוני": "06",
        "יולי": "07",
        "אוגוסט": "08",
        "ספטמבר": "09",
        "אוקטובר": "10",
        "נובמבר": "11",
        "דצמבר": "12",
    }
    for month_name, month_number in month_names.items():
        match = re.search(rf"{re.escape(month_name)}\s+(\d{{4}})", raw_text)
        if match:
            return f"{match.group(1)}-{month_number}"
        match = re.search(rf"(\d{{4}})\s+{re.escape(month_name)}", raw_text)
        if match:
            return f"{match.group(1)}-{month_number}"
    return ""


def _hr_extract_workbook_text(file_path: Path) -> str:
    from openpyxl import load_workbook

    if not file_path.exists():
        return ""
    try:
        workbook = load_workbook(file_path, data_only=True, read_only=True)
    except Exception:
        return ""
    parts: list[str] = []
    try:
        for worksheet in workbook.worksheets[:1]:
            for row_index, row in enumerate(worksheet.iter_rows(values_only=True)):
                for cell in row:
                    raw = str(cell or "").strip()
                    if raw:
                        parts.append(raw)
                if row_index >= 40 or len(parts) >= 200:
                    break
    finally:
        try:
            workbook.close()
        except Exception:
            pass
    return " ".join(parts)


def _load_hr_israel_holidays_disk_cache() -> dict[str, dict[str, list[dict[str, str]]]]:
    try:
        if HR_ISRAEL_HOLIDAYS_CACHE_FILE.exists():
            payload = json.loads(HR_ISRAEL_HOLIDAYS_CACHE_FILE.read_text())
            if isinstance(payload, dict):
                return {
                    str(key): {
                        "full": [
                            {
                                "date": str((item or {}).get("date") or "").strip(),
                                "title": str((item or {}).get("title") or "").strip(),
                            }
                            for item in (((value or {}) if isinstance(value, dict) else {}).get("full") or [])
                            if str((item or {}).get("date") or "").strip()
                        ],
                        "erev": [
                            {
                                "date": str((item or {}).get("date") or "").strip(),
                                "title": str((item or {}).get("title") or "").strip(),
                            }
                            for item in (((value or {}) if isinstance(value, dict) else {}).get("erev") or [])
                            if str((item or {}).get("date") or "").strip()
                        ],
                    }
                        for key, value in payload.items()
                    }
    except Exception:
        return {}
    return {}


def _save_hr_israel_holidays_disk_cache(cache_payload: dict[str, dict[str, list[dict[str, str]]]]) -> None:
    try:
        HR_ISRAEL_HOLIDAYS_CACHE_FILE.write_text(
            json.dumps(cache_payload, ensure_ascii=False, indent=2, sort_keys=True)
        )
    except Exception:
        pass


def _hr_is_full_day_holiday_item(item: dict) -> bool:
    title = str((item or {}).get("title") or "").strip()
    if bool((item or {}).get("yomtov")):
        return True
    return title in {"Yom HaAtzma’ut", "Yom HaAtzma'ut", "Yom HaAtzmaut"}


def _hr_is_erev_holiday_item(item: dict) -> bool:
    title = str((item or {}).get("title") or "").strip()
    return title.startswith("Erev ")


def _hr_holiday_cache_has_entries(payload: dict | None) -> bool:
    if not isinstance(payload, dict):
        return False
    return bool(payload.get("full") or payload.get("erev"))


def _hr_israel_holidays_for_year(year: int) -> dict[str, dict[date, list[str]]]:
    cached = HR_ISRAEL_HOLIDAYS_CACHE.get(int(year))
    if _hr_holiday_cache_has_entries(cached):
        return {
            "full": {day: list(titles) for day, titles in (cached.get("full") or {}).items()},
            "erev": {day: list(titles) for day, titles in (cached.get("erev") or {}).items()},
        }
    disk_cache = _load_hr_israel_holidays_disk_cache()
    disk_payload = disk_cache.get(str(year))
    if _hr_holiday_cache_has_entries(disk_payload):
        parsed: dict[str, dict[date, list[str]]] = {"full": {}, "erev": {}}
        for bucket in ("full", "erev"):
            for item in disk_payload.get(bucket) or []:
                parsed_value = _finance_parse_date_value(str((item or {}).get("date") or "").strip())
                if parsed_value:
                    parsed[bucket].setdefault(parsed_value, []).append(str((item or {}).get("title") or "").strip())
        HR_ISRAEL_HOLIDAYS_CACHE[int(year)] = {
            "full": {day: list(titles) for day, titles in parsed["full"].items()},
            "erev": {day: list(titles) for day, titles in parsed["erev"].items()},
        }
        return parsed
    try:
        with urlopen(
            f"https://www.hebcal.com/hebcal?cfg=json&v=1&year={int(year)}&i=on&maj=on&mod=on&lg=en",
            timeout=20,
        ) as response:
            payload = json.load(response)
    except Exception:
        fallback_cached = HR_ISRAEL_HOLIDAYS_CACHE.get(int(year))
        if isinstance(fallback_cached, dict):
            return {
                "full": {day: list(titles) for day, titles in (fallback_cached.get("full") or {}).items()},
                "erev": {day: list(titles) for day, titles in (fallback_cached.get("erev") or {}).items()},
            }
        return {"full": {}, "erev": {}}
    full_dates: dict[date, list[str]] = {}
    erev_dates: dict[date, list[str]] = {}
    for item in payload.get("items") or []:
        if not isinstance(item, dict):
            continue
        parsed_value = _finance_parse_date_value(str(item.get("date") or "").strip())
        if not parsed_value:
            continue
        if _hr_is_full_day_holiday_item(item):
            full_dates.setdefault(parsed_value, []).append(str(item.get("hebrew") or item.get("title") or "").strip())
        elif _hr_is_erev_holiday_item(item):
            erev_dates.setdefault(parsed_value, []).append(str(item.get("hebrew") or item.get("title") or "").strip())
    HR_ISRAEL_HOLIDAYS_CACHE[int(year)] = {
        "full": {day: list(titles) for day, titles in full_dates.items()},
        "erev": {day: list(titles) for day, titles in erev_dates.items()},
    }
    disk_cache[str(year)] = {
        "full": [
            {"date": day.isoformat(), "title": title}
            for day, titles in sorted(full_dates.items(), key=lambda item: item[0])
            for title in titles
        ],
        "erev": [
            {"date": day.isoformat(), "title": title}
            for day, titles in sorted(erev_dates.items(), key=lambda item: item[0])
            for title in titles
        ],
    }
    _save_hr_israel_holidays_disk_cache(disk_cache)
    return {"full": full_dates, "erev": erev_dates}


def _hr_month_worktime_reference(month_key: str) -> dict:
    month_match = re.match(r"^(\d{4})-(\d{2})$", str(month_key or "").strip())
    if not month_match:
        return {
            "month_key": str(month_key or "").strip(),
            "full_time_hours": 182.0,
            "weekday_days": 0,
            "working_days": 0,
            "erev_holiday_count": 0,
            "deducted_holiday_days": 0,
            "deducted_erev_hours": 0.0,
            "holiday_names": [],
            "erev_holiday_names": [],
        }
    year = int(month_match.group(1))
    month = int(month_match.group(2))
    holiday_sets = _hr_israel_holidays_for_year(year)
    full_holidays = {
        day: titles for day, titles in (holiday_sets.get("full") or {}).items()
        if day.year == year and day.month == month
    }
    erev_holidays = {
        day: titles for day, titles in (holiday_sets.get("erev") or {}).items()
        if day.year == year and day.month == month
    }
    weekday_days = 0
    working_days = 0
    deducted_holiday_days = 0
    erev_holiday_count = 0
    impacted_holiday_names: list[str] = []
    impacted_erev_holiday_names: list[str] = []
    for day in range(1, calendar.monthrange(year, month)[1] + 1):
        current_day = date(year, month, day)
        if current_day.weekday() in {4, 5}:
            continue
        weekday_days += 1
        if current_day in full_holidays:
            deducted_holiday_days += 1
            impacted_holiday_names.extend(full_holidays.get(current_day) or [])
            continue
        working_days += 1
        if current_day in erev_holidays:
            erev_holiday_count += 1
            impacted_erev_holiday_names.extend(erev_holidays.get(current_day) or [])
    deducted_erev_hours = round(erev_holiday_count * 1.4, 2)
    raw_full_time_hours = round((working_days * 8.4) - deducted_erev_hours, 2)
    full_time_hours = min(182.0, raw_full_time_hours)
    return {
        "month_key": month_key,
        "full_time_hours": max(full_time_hours, 0.0),
        "raw_full_time_hours": max(raw_full_time_hours, 0.0),
        "hours_cap_applied": raw_full_time_hours > 182.0,
        "weekday_days": weekday_days,
        "working_days": working_days,
        "erev_holiday_count": erev_holiday_count,
        "deducted_holiday_days": deducted_holiday_days,
        "deducted_erev_hours": deducted_erev_hours,
        "holiday_names": impacted_holiday_names,
        "erev_holiday_names": impacted_erev_holiday_names,
    }


def _hr_month_key_from_hours_details(details: list[dict]) -> str:
    counts: dict[str, int] = {}
    for detail in details or []:
        raw_date = str((detail or {}).get("date") or "").strip()
        parsed_date = _hr_parse_iso_date(raw_date)
        if not parsed_date:
            continue
        month_key = f"{parsed_date.year:04d}-{parsed_date.month:02d}"
        counts[month_key] = counts.get(month_key, 0) + 1
    if not counts:
        return ""
    return max(counts.items(), key=lambda item: item[1])[0]


def _hr_parse_hours_document(file_path: Path, employees: list[dict]) -> dict | None:
    if str(file_path.suffix or "").lower() not in {".xlsx", ".xlsm", ".xltx", ".xltm"}:
        return None
    details = _hr_parse_hours_report_rows(file_path)
    if not details:
        return None
    workbook_text = _hr_extract_workbook_text(file_path)
    match_context = " ".join(
        part for part in [
            file_path.stem,
            file_path.parent.name,
            file_path.parent.parent.name if file_path.parent.parent else "",
            workbook_text,
        ] if str(part or "").strip()
    )
    employee = _hr_match_employee_from_text(match_context, employees)
    if not employee:
        hourly_employees = [dict(row) for row in (employees or []) if str(row.get("employment_type") or "").strip() == "hourly"]
        if len(hourly_employees) == 1:
            employee = hourly_employees[0]
    month_key = (
        _hr_parse_month_key_from_text(match_context, [
            r"(\d{2})/(\d{4})",
            r"(\d{2})-(\d{4})",
            r"(\d{4})-(\d{2})",
        ])
        or _hr_parse_month_key_from_hebrew_text(match_context)
        or _hr_month_key_from_hours_details(details)
    )
    if re.match(r"^\d{4}-\d{2}$", month_key):
        pass
    elif re.match(r"^\d{2}-\d{4}$", month_key):
        month_key = f"{month_key[3:7]}-{month_key[:2]}"
    elif re.match(r"^\d{2}/\d{4}$", month_key):
        month_key = f"{month_key[3:7]}-{month_key[:2]}"
    else:
        month_key = ""
    if not employee or not month_key:
        return None
    total_hours = round(sum(float((detail or {}).get("hours") or 0) for detail in details), 2)
    return {
        "doc_type": "hours",
        "employee": employee,
        "month_key": month_key,
        "regular_hours": f"{total_hours:.2f}",
        "overtime_hours": "0.00",
        "details": details,
        "text": match_context,
    }


def _hr_extract_first_amount(text: str, patterns: list[str]) -> str:
    for pattern in patterns:
        match = re.search(pattern, text)
        if not match:
            continue
        amount = _hr_decimal_string(match.group(1))
        if amount:
            return amount
    return ""


def _hr_parse_payslip_document(file_path: Path, employees: list[dict]) -> dict | None:
    text = _hr_extract_pdf_text(file_path)
    if not text or ("שולת" not in text and "תלוש" not in text):
        return None
    month_key = _hr_parse_month_key_from_text(text, [
        r"(\d{2})/(\d{4})\s+שדוחל\s+רכש\s+שולת",
        r"(\d{2})/(\d{4})\s+תלוש\s+שכר",
    ])
    employee = _hr_match_employee_from_text(text, employees)
    if not employee or not month_key:
        return None
    gross_amount = _hr_extract_first_amount(text, [
        r"([0-9,]+\.[0-9]{2})\s+םימולשת\s+כ[\"״]הס",
        r"סה[\"״]כ\s+תשלומים\s+([0-9,]+\.[0-9]{2})",
    ])
    net_amount = _hr_extract_first_amount(text, [
        r"([0-9,]+\.[0-9]{2})\s+וטנ\s+רכש",
        r"שכר\s+נטו\s+([0-9,]+\.[0-9]{2})",
    ])
    return {
        "doc_type": "payroll",
        "employee": employee,
        "month_key": month_key,
        "gross_amount": gross_amount,
        "net_amount": net_amount,
        "start_date": _hr_infer_start_date_from_payslip(file_path, month_key=month_key),
        "text": text,
    }


def _hr_parse_contribution_document(file_path: Path, employees: list[dict]) -> dict | None:
    text = _hr_extract_pdf_text(file_path)
    if not text or "למג תופוקל חוד" not in text:
        return None
    month_key = _hr_parse_month_key_from_text(text, [
        r"(\d{2})/(\d{4})\s+תרוכשמ\s+שדוח",
        r"חודש\s+משכורת\s+(\d{2})/(\d{4})",
    ])
    employee = _hr_match_employee_from_text(text, employees)
    if not employee or not month_key:
        return None
    id_number = re.sub(r"\D+", "", str(employee.get("id_number") or ""))
    amount_match = re.search(
        rf"{re.escape(id_number)}\s+([0-9,]+\.[0-9]{{2}})\s+([0-9,]+\.[0-9]{{2}})\s+([0-9,]+\.[0-9]{{2}})\s+([0-9,]+\.[0-9]{{2}})\s*:\S*לכה",
        text,
    )
    if not amount_match:
        amount_match = re.search(
            r"([0-9,]+\.[0-9]{2})\s+([0-9,]+\.[0-9]{2})\s+([0-9,]+\.[0-9]{2})\s+([0-9,]+\.[0-9]{2})\s*:\S*לכה",
            text,
        )
    if not amount_match:
        return None
    _, employee_contribution, employer_contribution, compensation_amount = amount_match.groups()
    return {
        "doc_type": "contributions",
        "employee": employee,
        "month_key": month_key,
        "employee_contribution": _hr_decimal_string(employee_contribution),
        "employer_contribution": _hr_decimal_string(employer_contribution),
        "compensation_amount": _hr_decimal_string(compensation_amount),
        "text": text,
    }


def _hr_parse_contribution_proof_document(file_path: Path, employees: list[dict]) -> dict | None:
    text = _hr_extract_pdf_text(file_path)
    if not text:
        return None
    if "תיאקנב הרבעה" not in text and "העברה בנקאית" not in text and "רושיא ךיראת" not in text and "תאריך אישור" not in text:
        return None
    month_key = _hr_parse_month_key_from_text(text, [
        r"(\d{2})/(\d{4})\s+רכש\s+שדוחל",
        r"(\d{2})/(\d{4})\s+לחודש\s+שכר",
        r"(\d{2})/(\d{4})\s+שדוחל",
    ])
    employee = _hr_match_employee_from_text(text, employees)
    if not employee or not month_key:
        return None

    paid_date = ""
    date_matches = re.findall(r"\b(\d{2}/\d{2}/\d{4})\b", text)
    for raw_date in date_matches:
        parsed = _hr_parse_iso_date(raw_date)
        if parsed:
            paid_date = parsed.isoformat()
            break

    reference_number = ""
    reference_match = re.search(r"(?:\d{2}/\d{4}).*?\b(\d{4,})\s*-\s*", text)
    if reference_match:
        reference_number = str(reference_match.group(1) or "").strip()
    if not reference_number:
        reference_match = re.search(r"\b(\d{4,})\s*-\s*\S*קילס", text)
        if reference_match:
            reference_number = str(reference_match.group(1) or "").strip()

    return {
        "doc_type": "contribution-proof",
        "employee": employee,
        "month_key": month_key,
        "paid": "TRUE",
        "paid_date": paid_date,
        "reference_number": reference_number,
        "text": text,
    }


def _hr_find_any_local_file(employee_ids: list[str], file_name: str) -> Path | None:
    safe_file_name = Path(str(file_name or "").strip()).name
    if not safe_file_name:
        return None
    for employee_id in employee_ids:
        safe_employee_id = str(employee_id or "").strip()
        if not safe_employee_id:
            continue
        base_dir = _hr_storage_dir() / safe_employee_id
        if not base_dir.exists():
            continue
        for candidate in base_dir.rglob(safe_file_name):
            if candidate.is_file():
                return candidate
    return None


def _hr_relocate_local_file(previous_employee_id: str, employee_id: str, file_name: str, month_key: str) -> Path | None:
    safe_file_name = Path(str(file_name or "").strip()).name
    if not safe_file_name:
        return None
    current_path = _hr_local_file_path(employee_id, month_key, safe_file_name)
    if current_path and current_path.exists():
        return current_path
    source_path = _hr_find_any_local_file([previous_employee_id, employee_id], safe_file_name)
    if not source_path or not source_path.exists():
        return current_path
    target_dir = _hr_storage_dir() / str(employee_id or "").strip() / (str(month_key or "").strip() or "general")
    target_dir.mkdir(parents=True, exist_ok=True)
    target_path = target_dir / safe_file_name
    if source_path.resolve() != target_path.resolve():
        shutil.copy2(source_path, target_path)
        try:
            source_path.unlink()
        except Exception:
            pass
    return target_path


def _hr_sync_drive_attachment(
    *,
    section_key: str,
    employee_name: str,
    employee_id: str,
    previous_employee_id: str,
    month_key: str,
    file_name: str,
    drive_file_id: str,
) -> dict:
    safe_file_name = Path(str(file_name or "").strip()).name
    if not safe_file_name:
        return {"drive_file_id": str(drive_file_id or "").strip(), "drive_url": "", "local_path": ""}
    local_path = _hr_relocate_local_file(previous_employee_id, employee_id, safe_file_name, month_key)
    target_folder = _hr_document_folder(employee_name, section_key, month_key=month_key)
    current_drive_id = str(drive_file_id or "").strip()
    if current_drive_id:
        moved = _move_drive_file_to_folder(current_drive_id, target_folder["target_folder_id"])
        drive_url = str(moved.get("web_view_link") or moved.get("web_content_link") or "").strip() or _drive_file_view_link(str(moved.get("id") or current_drive_id).strip())
        return {
            "drive_file_id": str(moved.get("id") or current_drive_id).strip(),
            "drive_url": drive_url,
            "local_path": str(local_path) if local_path else "",
        }
    if local_path and local_path.exists():
        uploaded = _hr_upload_file_to_drive(local_path, employee_name, section_key, month_key=month_key, drive_name=safe_file_name)
        return {
            "drive_file_id": str(uploaded.get("drive_file_id") or "").strip(),
            "drive_url": str(uploaded.get("drive_url") or "").strip(),
            "local_path": str(local_path),
        }
    return {"drive_file_id": "", "drive_url": "", "local_path": str(local_path) if local_path else ""}
    return _hr_subtract_tenure(anchor, years, months, days).isoformat()


FINANCE_BANK_MOVEMENT_FIELDS = [
    "row_id",
    "account_number",
    "account_name",
    "company_name",
    "section_name",
    "transaction_date",
    "value_date",
    "description",
    "operation_type",
    "amount",
    "balance",
    "reference",
    "fee_or_notes",
    "channel",
    "source_file_name",
    "updated_at",
]


def _ensure_finance_bank_movement_storage_dirs() -> None:
    FINANCE_BANK_MOVEMENTS_UPLOAD_DIR.mkdir(parents=True, exist_ok=True)


def _finance_bank_movement_upload_target(original_name: str) -> Path:
    _ensure_finance_bank_movement_storage_dirs()
    safe_stem = _safe_folder_name(Path(str(original_name or "").strip()).stem) or "bank-movements"
    suffix = Path(str(original_name or "").strip()).suffix or ".xlsx"
    return FINANCE_BANK_MOVEMENTS_UPLOAD_DIR / f"{datetime.now().strftime('%Y%m%d-%H%M%S')}-{safe_stem}{suffix}"


def _finance_bank_movement_date_text(value) -> str:
    if not value:
        return ""
    if isinstance(value, datetime):
        return value.strftime("%d/%m/%Y")
    if isinstance(value, date):
        return value.strftime("%d/%m/%Y")
    raw = str(value or "").strip()
    if not raw:
        return ""
    normalized = normalize_date(raw)
    return normalized or raw


def _finance_bank_movement_number_text(value) -> str:
    try:
        return f"{float(value):.2f}"
    except Exception:
        raw = str(value or "").strip().replace(",", "")
        try:
            return f"{float(raw):.2f}" if raw else ""
        except Exception:
            return raw


def _finance_bank_movement_account_digits(value: str) -> str:
    return re.sub(r"\D+", "", str(value or ""))


def _finance_bank_movement_operation_type(description: str) -> str:
    text = str(description or "").strip()
    if not text:
        return ""
    checks = [
        (r"^העברה\s+מ", "העברה נכנסת"),
        (r"^הע\.\s+ל|^העברה\s+ל", "העברה יוצאת"),
        (r"^משיכת שיק", "שיק"),
        (r"^חיוב לכרטיס", "כרטיס אשראי"),
        (r"פירעון הלוואה", "הלוואה"),
        (r"עמל", "עמלה"),
        (r"הפקדה", "הפקדה"),
        (r"חיוב", "חיוב"),
        (r"ויזה", "כרטיס אשראי"),
    ]
    for pattern, label in checks:
        if re.search(pattern, text):
            return label
    compact = re.sub(r"\s+", " ", text)
    return compact.split(" ")[0][:28]


def _finance_bank_movement_row_id(row: dict) -> str:
    parts = [
        _finance_bank_movement_account_digits(row.get("account_number")),
        str(row.get("section_name") or "").strip(),
        str(row.get("transaction_date") or "").strip(),
        str(row.get("value_date") or "").strip(),
        str(row.get("description") or "").strip(),
        str(row.get("amount") or "").strip(),
        str(row.get("balance") or "").strip(),
        str(row.get("reference") or "").strip(),
    ]
    payload = "|".join(parts)
    return hashlib.md5(payload.encode("utf-8")).hexdigest()


def _normalize_finance_bank_movement_row_app(row: dict) -> dict:
    normalized = {field: str((row or {}).get(field, "") or "").strip() for field in FINANCE_BANK_MOVEMENT_FIELDS}
    normalized["account_number"] = _finance_bank_movement_account_digits(normalized.get("account_number"))
    normalized["account_name"] = re.sub(r"\s+", " ", str(normalized.get("account_name") or "").strip())
    normalized["company_name"] = re.sub(r"\s+", " ", str(normalized.get("company_name") or "").strip())
    normalized["section_name"] = re.sub(r"\s+", " ", str(normalized.get("section_name") or "").strip()) or "תנועות אחרונות"
    normalized["transaction_date"] = _finance_bank_movement_date_text(normalized.get("transaction_date"))
    normalized["value_date"] = _finance_bank_movement_date_text(normalized.get("value_date"))
    normalized["description"] = re.sub(r"\s+", " ", str(normalized.get("description") or "").strip())
    normalized["operation_type"] = re.sub(r"\s+", " ", str(normalized.get("operation_type") or "").strip()) or _finance_bank_movement_operation_type(normalized.get("description"))
    normalized["amount"] = _finance_bank_movement_number_text(normalized.get("amount"))
    normalized["balance"] = _finance_bank_movement_number_text(normalized.get("balance"))
    normalized["reference"] = str(normalized.get("reference") or "").strip()
    normalized["fee_or_notes"] = re.sub(r"\s+", " ", str(normalized.get("fee_or_notes") or "").strip())
    normalized["channel"] = re.sub(r"\s+", " ", str(normalized.get("channel") or "").strip())
    normalized["source_file_name"] = str(normalized.get("source_file_name") or "").strip()
    normalized["updated_at"] = str(normalized.get("updated_at") or datetime.now().isoformat(timespec="seconds")).strip()
    normalized["row_id"] = str(normalized.get("row_id") or _finance_bank_movement_row_id(normalized)).strip()
    return normalized


def _finance_bank_movement_sort_date(value: str) -> tuple[int, int, int]:
    parsed = _finance_parse_date_value(value)
    if not parsed:
        return (0, 0, 0)
    return (parsed.year, parsed.month, parsed.day)


def _dedupe_finance_bank_movement_rows(rows: list[dict]) -> list[dict]:
    deduped: dict[str, dict] = {}
    for row in rows or []:
        normalized = _normalize_finance_bank_movement_row_app(row or {})
        deduped[str(normalized.get("row_id") or "").strip()] = normalized
    return sorted(
        deduped.values(),
        key=lambda row: (
            _finance_bank_movement_sort_date(row.get("transaction_date") or ""),
            _finance_bank_movement_sort_date(row.get("value_date") or ""),
            str(row.get("account_number") or ""),
            str(row.get("reference") or ""),
            str(row.get("description") or ""),
        ),
        reverse=True,
    )


def _finance_bank_movement_summary(rows: list[dict]) -> dict:
    normalized_rows = _dedupe_finance_bank_movement_rows(rows or [])
    account_numbers = sorted({
        _finance_bank_movement_account_digits(row.get("account_number"))
        for row in normalized_rows
        if _finance_bank_movement_account_digits(row.get("account_number"))
    })
    dates = [
        _finance_parse_date_value(row.get("transaction_date"))
        for row in normalized_rows
        if _finance_parse_date_value(row.get("transaction_date"))
    ]
    return {
        "count": len(normalized_rows),
        "accounts_count": len(account_numbers),
        "account_numbers": account_numbers,
        "date_from": _finance_format_display_date(min(dates)) if dates else "",
        "date_to": _finance_format_display_date(max(dates)) if dates else "",
    }


def _finance_parse_bank_movement_workbook(file_path: Path) -> dict:
    from openpyxl import load_workbook

    workbook = load_workbook(file_path, data_only=True)
    worksheet = workbook[workbook.sheetnames[0]]
    company_name = ""
    account_name = ""
    account_number = ""
    current_section = "תנועות אחרונות"
    current_header_map: dict[int, str] = {}
    parsed_rows: list[dict] = []

    for row_index, row in enumerate(worksheet.iter_rows(values_only=True), 1):
        values = list(row)
        first_cell = values[0] if values else None
        first_text = str(first_cell or "").strip()
        if row_index == 3 and "חברה:" in first_text:
            company_name = first_text.split("|", 1)[1].strip() if "|" in first_text else first_text.replace("חברה:", "").strip()
            continue
        if row_index == 4 and "חשבון:" in first_text:
            account_part = first_text.split("|", 1)[0].replace("חשבון:", "").strip()
            account_number = _finance_bank_movement_account_digits(account_part)
            account_name = first_text.split("|", 1)[1].strip() if "|" in first_text else ""
            continue
        if first_text in {"תנועות אחרונות", "תנועות עתידיות"}:
            current_section = first_text
            current_header_map = {}
            continue
        if first_text in {"N/A", ""} and not any(values[1:]):
            continue
        if first_text == "תאריך":
            current_header_map = {
                0: "transaction_date",
                1: "value_date",
                2: "description",
                3: "amount",
                4: "balance",
                5: "reference",
                6: "fee_or_notes",
                7: "channel",
            }
            continue
        if not current_header_map:
            continue
        if not isinstance(first_cell, (datetime, date)):
            continue

        movement = {
            "account_number": account_number,
            "account_name": account_name,
            "company_name": company_name,
            "section_name": current_section,
            "source_file_name": file_path.name,
        }
        for index, field in current_header_map.items():
            movement[field] = values[index] if index < len(values) else ""
        movement["transaction_date"] = _finance_bank_movement_date_text(movement.get("transaction_date"))
        movement["value_date"] = _finance_bank_movement_date_text(movement.get("value_date"))
        movement["description"] = re.sub(r"\s+", " ", str(movement.get("description") or "").strip())
        movement["operation_type"] = _finance_bank_movement_operation_type(movement.get("description"))
        movement["amount"] = _finance_bank_movement_number_text(movement.get("amount"))
        movement["balance"] = _finance_bank_movement_number_text(movement.get("balance"))
        movement["reference"] = str(movement.get("reference") or "").strip()
        movement["fee_or_notes"] = re.sub(r"\s+", " ", str(movement.get("fee_or_notes") or "").strip())
        movement["channel"] = re.sub(r"\s+", " ", str(movement.get("channel") or "").strip())
        parsed_rows.append(_normalize_finance_bank_movement_row_app(movement))

    return {
        "account_number": account_number,
        "account_name": account_name,
        "company_name": company_name,
        "rows": _dedupe_finance_bank_movement_rows(parsed_rows),
        "source_file_name": file_path.name,
    }


def _finance_mail_due_dates() -> list[str]:
    return [_finance_format_display_date(item) for item in _finance_due_dates()]


def _finance_normalize_due_dates(values) -> list[str]:
    if not isinstance(values, list):
        values = [values]
    normalized: list[str] = []
    seen: set[str] = set()
    allowed = set(_finance_mail_due_dates())
    for value in values:
        text = _finance_format_display_date(str(value or "").strip())
        if not text or text in seen or text not in allowed:
            continue
        seen.add(text)
        normalized.append(text)
    return normalized


