def _finance_export_filename(format_kind: str, due_dates: list[str]) -> str:
    suffix = "-".join(_finance_safe_due_date_slug(item) for item in _finance_normalize_due_dates(due_dates)) or date.today().strftime("%d-%m-%Y")
    extension = "pdf" if str(format_kind or "").strip().lower() == "pdf" else "xlsx"
    return f"חשבוניות-{suffix}.{extension}"


def _finance_safe_due_date_slug(value: str) -> str:
    return re.sub(r"[^0-9-]+", "", str(value or "").replace("/", "-")) or "all"


def _finance_resolve_invoice_document_to_path(row: dict, target_dir: Path) -> Path | None:
    source_file_path = Path(str(row.get("source_file_path") or "").strip())
    if source_file_path.exists() and source_file_path.is_file():
        return source_file_path
    drive_file_id = str(row.get("drive_file_id") or "").strip()
    if drive_file_id:
        source_name = str(row.get("source_file_name") or source_file_path.name or f"invoice_{row.get('row_id')}.pdf").strip()
        safe_name = _safe_folder_name(source_name) or f"invoice_{row.get('row_id')}.pdf"
        return download_drive_file(drive_file_id, target_dir / safe_name)
    return None


def _finance_build_zip_attachment(rows: list[dict], due_dates: list[str], target_dir: Path) -> Path:
    labels = _finance_normalize_due_dates(due_dates)
    slug = "-".join(_finance_safe_due_date_slug(label) for label in labels) or "all"
    zip_path = target_dir / f"חשבוניות-{slug}.zip"
    source_cache_dir = target_dir / f"files_{slug}"
    source_cache_dir.mkdir(parents=True, exist_ok=True)
    added = 0
    root_folder = zip_path.stem
    used_archive_names: set[str] = set()
    with zipfile.ZipFile(zip_path, "w", compression=zipfile.ZIP_DEFLATED) as archive:
        for row in rows:
            local_path = _finance_resolve_invoice_document_to_path(row, source_cache_dir)
            if not local_path or not local_path.exists():
                continue
            filename = str(row.get("source_file_name") or local_path.name or f"invoice_{row.get('row_id')}.pdf").strip()
            safe_filename = _safe_folder_name(Path(filename).stem) or f"invoice_{row.get('row_id')}"
            suffix = Path(filename).suffix or local_path.suffix or ".pdf"
            candidate_name = f"{safe_filename}{suffix}"
            counter = 2
            while candidate_name in used_archive_names:
                candidate_name = f"{safe_filename}-{counter}{suffix}"
                counter += 1
            used_archive_names.add(candidate_name)
            archive_name = f"{root_folder}/{candidate_name}"
            archive.write(local_path, arcname=archive_name)
            added += 1
    if added <= 0:
        try:
            zip_path.unlink(missing_ok=True)
        except Exception:
            pass
        raise RuntimeError("לא נמצאו קבצי חשבוניות זמינים לצירוף ZIP במועדי הדיווח שבחרת.")
    return zip_path


def _finance_sync_invoice_row_drive_targets(row: dict) -> dict:
    normalized = _normalize_finance_invoice_row_app(row or {})
    local_source_path = Path(str(normalized.get("source_file_path") or "").strip()) if str(normalized.get("source_file_path") or "").strip() else None
    cleanup_path: Path | None = None
    if not (local_source_path and local_source_path.exists()) and str(normalized.get("drive_file_id") or "").strip():
        source_name = str(normalized.get("source_file_name") or "").strip() or f"invoice-{normalized.get('row_id')}.pdf"
        temp_dir = _finance_export_cache_dir() / "_override_sync"
        temp_dir.mkdir(parents=True, exist_ok=True)
        local_source_path = temp_dir / source_name
        cleanup_path = download_drive_file(str(normalized.get("drive_file_id") or "").strip(), local_source_path)
    if not (local_source_path and local_source_path.exists()):
        if not str(normalized.get("drive_file_id") or "").strip():
            return normalized
    drive_sync = _finance_sync_invoice_file_to_drive(
        local_source_path,
        normalized.get("report_due_date"),
        existing_file_id=str(normalized.get("drive_file_id") or "").strip(),
        drive_name=str(normalized.get("source_file_name") or (local_source_path.name if local_source_path else "")).strip(),
    )
    normalized["drive_file_id"] = str(drive_sync.get("drive_file_id") or normalized.get("drive_file_id") or "").strip()
    normalized["drive_url"] = str(drive_sync.get("drive_url") or normalized.get("drive_url") or "").strip()
    if cleanup_path:
        try:
            cleanup_path.unlink(missing_ok=True)
        except Exception:
            pass
    return normalized


def _finance_period_for_due_date(due_date: date) -> tuple[date, date, date]:
    month_anchor = date(due_date.year, due_date.month, 1)
    period_end = month_anchor - timedelta(days=1)
    previous_month_end = date(period_end.year, period_end.month, 1) - timedelta(days=1)
    period_start = date(previous_month_end.year, previous_month_end.month, 1)
    effective_end = min(period_end, date.today())
    return period_start, period_end, effective_end


def _load_finance_income_tax_rate_setting() -> int:
    rows = load_marketing_rows("finance_settings")
    for row in rows:
        if str(row.get("setting_key") or "").strip() != "income_tax_rate_percent":
            continue
        try:
            value = int(float(str(row.get("setting_value") or "").strip()))
        except Exception:
            value = 3
        return min(10, max(1, value))
    return 3


def _save_finance_income_tax_rate_setting(percent: int) -> dict:
    rows = load_marketing_rows("finance_settings")
    normalized_value = str(min(10, max(1, int(percent or 3))))
    updated = False
    for row in rows:
        if str(row.get("setting_key") or "").strip() != "income_tax_rate_percent":
            continue
        row["setting_value"] = normalized_value
        row["updated_at"] = datetime.now().isoformat(timespec="seconds")
        updated = True
        break
    if not updated:
        rows.append(
            {
                "setting_key": "income_tax_rate_percent",
                "setting_value": normalized_value,
                "updated_at": datetime.now().isoformat(timespec="seconds"),
            }
        )
    return save_marketing_rows("finance_settings", rows)


