def _manual_order_customer_lookup_key(customer_guid: str = "", customer_id: str = "", customer_name: str = "") -> str:
    guid_value = str(customer_guid or "").strip()
    if guid_value:
        return f"guid:{guid_value}"
    normalized_id = re.sub(r"\D+", "", str(customer_id or ""))
    if normalized_id:
        return f"tax:{normalized_id}"
    canonical_name = _canonical_income_customer_name(customer_name or "")
    return f"name:{canonical_name}" if canonical_name else ""


def _manual_order_customer_primary_phone(row: dict | None) -> str:
    source = dict(row or {})
    direct = str(source.get("mobile") or source.get("phone") or source.get("customer_phone") or "").strip()
    if direct:
        return direct
    remarks = str(source.get("remarks") or "").strip()
    if remarks:
        match = re.search(r"((?:\+972|0)[0-9\-\s]{8,})", remarks)
        if match:
            return str(match.group(1) or "").strip()
    return ""


def _manual_order_customer_primary_email(row: dict | None) -> str:
    raw = str((row or {}).get("emails") or (row or {}).get("customer_email") or "").strip()
    if not raw:
        return ""
    return next((part.strip() for part in re.split(r"[,\n;]+", raw) if part.strip()), "")


def _manual_order_customer_address_label(row: dict | None) -> str:
    source = dict(row or {})
    return ", ".join(
        part for part in [
            str(source.get("address") or source.get("delivery_address") or "").strip(),
            str(source.get("city") or "").strip(),
            str(source.get("country") or "").strip(),
        ] if part
    )


def _manual_order_normalize_emails_value(value) -> str:
    if isinstance(value, list):
        emails: list[str] = []
        for item in value:
            if isinstance(item, dict):
                email_value = str(item.get("email") or "").strip()
            else:
                email_value = str(item or "").strip()
            if email_value:
                emails.append(email_value)
        return ", ".join(emails)
    return str(value or "").strip()


def _manual_order_apply_customer_overrides(row: dict | None) -> dict:
    merged = dict(row or {})
    guid = str(merged.get("customer_guid") or "").strip()
    if guid and not str(merged.get("customer_id") or "").strip():
        override_customer_id = str(MANUAL_ORDER_CUSTOMER_ID_OVERRIDES_BY_GUID.get(guid) or "").strip()
        if override_customer_id:
            merged["customer_id"] = override_customer_id
    return merged


def _manual_order_history_customer_matches(
    row: dict | None,
    customer_guid: str = "",
    customer_id: str = "",
    customer_name: str = "",
) -> bool:
    source = dict(row or {})
    target_guid = str(customer_guid or "").strip()
    target_id = re.sub(r"\D+", "", str(customer_id or ""))
    target_name = _canonical_income_customer_name(str(customer_name or "").strip())

    row_guid = str(source.get("customer_guid") or source.get("client_id") or "").strip()
    row_id = re.sub(r"\D+", "", str(source.get("customer_id") or ""))
    row_name = _canonical_income_customer_name(str(source.get("customer_name") or "").strip())

    if target_guid and row_guid and target_guid == row_guid:
        return True
    if target_id and row_id and target_id == row_id:
        return True
    if target_name and row_name and target_name == row_name:
        return True
    return False


def _manual_order_history_items_from_row(row: dict | None) -> list[dict]:
    source = dict(row or {})
    candidates = source.get("items")
    if not isinstance(candidates, list):
        raw_items = str(source.get("items_json") or "").strip()
        if raw_items:
            try:
                parsed = json.loads(raw_items)
                if isinstance(parsed, list):
                    candidates = parsed
            except Exception:
                candidates = []
    if not isinstance(candidates, list):
        candidates = []
    normalized_items: list[dict] = []
    for item in candidates:
        if not isinstance(item, dict):
            continue
        description = str(item.get("description") or "").strip()
        if not description:
            continue
        normalized_items.append(
            {
                "description": description,
                "sku": str(item.get("sku") or "").strip(),
                "unit": str(item.get("unit") or "").strip(),
                "quantity": item.get("quantity") or "",
                "unit_price": item.get("unit_price") or "",
                "line_total": item.get("line_total") or "",
            }
        )
    if normalized_items:
        return normalized_items
    fallback_description = str(source.get("item_description") or "").strip()
    if not fallback_description:
        return []
    return [
        {
            "description": fallback_description,
            "sku": str(source.get("item_sku") or "").strip(),
            "unit": str(source.get("item_unit") or "").strip(),
            "quantity": str(source.get("item_quantity") or "").strip(),
            "unit_price": str(source.get("item_unit_price") or "").strip(),
            "line_total": str(source.get("item_line_total") or "").strip(),
        }
    ]


def _manual_order_items_from_greeninvoice_raw(source: dict | None) -> list[dict]:
    def _as_number(value):
        if value is None:
            return 0.0
        if isinstance(value, (int, float)):
            return float(value)
        cleaned = re.sub(r"[^\d.\-]", "", str(value or ""))
        if cleaned in {"", "-", ".", "-."}:
            return 0.0
        try:
            return float(cleaned)
        except Exception:
            return 0.0

    raw = dict(source or {})
    line_collections: list[list] = []
    for key in ("income", "incomeRows", "rows", "items", "products", "lines", "expense", "expenseRows"):
        value = raw.get(key)
        if isinstance(value, list):
            line_collections.append(value)
        elif isinstance(value, dict):
            for nested_key in ("rows", "items", "products", "lines"):
                nested = value.get(nested_key)
                if isinstance(nested, list):
                    line_collections.append(nested)

    items: list[dict] = []
    for collection in line_collections:
        for line in collection:
            if not isinstance(line, dict):
                continue
            description = ""
            for key in ("description", "name", "itemName", "title", "productName"):
                description = re.sub(r"\s+", " ", str(line.get(key) or "").strip())
                if description:
                    break
            if not description:
                continue
            sku = ""
            for key in ("sku", "itemCode", "catalogNum", "catalogNumber", "productSku", "code", "catalogNo"):
                sku = re.sub(r"\s+", " ", str(line.get(key) or "").strip())
                if sku:
                    break
            unit = ""
            for key in ("unit", "unitName", "measureUnit", "measurementUnit"):
                unit = re.sub(r"\s+", " ", str(line.get(key) or "").strip())
                if unit:
                    break
            quantity = 0.0
            for key in ("quantity", "qty", "count", "amount"):
                quantity = _as_number(line.get(key))
                if quantity:
                    break
            unit_price = 0.0
            for key in ("unitPrice", "pricePerUnit", "price"):
                unit_price = _as_number(line.get(key))
                if unit_price:
                    break
            line_total = 0.0
            for key in ("lineTotal", "total", "rowTotal", "amount"):
                line_total = _as_number(line.get(key))
                if line_total:
                    break
            if line_total <= 0 and quantity > 0 and unit_price > 0:
                line_total = quantity * unit_price
            items.append(
                {
                    "description": description,
                    "sku": sku,
                    "unit": unit,
                    "quantity": round(quantity, 4) if quantity else "",
                    "unit_price": round(unit_price, 2) if unit_price else "",
                    "line_total": round(line_total, 2) if line_total else "",
                }
            )
    return items


def _manual_order_template_row_from_greeninvoice_doc(doc: dict | None, source_kind: str) -> dict:
    source = dict(doc or {})
    raw = dict(source.get("raw") or {})
    items = _manual_order_items_from_greeninvoice_raw(raw)
    first_item = items[0] if items else {}
    total = source.get("amount") or raw.get("amount") or raw.get("total") or raw.get("totalAmount") or ""
    return {
        "history_id": "",
        "created_at": str(source.get("date") or "").strip(),
        "input_source": "חשבונית ירוקה",
        "mode": "PROD",
        "customer_name": str(source.get("customer_name") or "").strip(),
        "customer_id": str(source.get("customer_id") or "").strip(),
        "customer_guid": str(source.get("client_id") or "").strip(),
        "customer_email": "",
        "customer_phone": "",
        "delivery_address": "",
        "project": "",
        "contact_name": "",
        "contact_phone": "",
        "payment_terms_days": "",
        "payment_terms_label": "",
        "po_number": "",
        "quote_number": str(source.get("number") or "").strip() if source_kind == "quote" else "",
        "quote_document_id": str(source.get("id") or "").strip() if source_kind == "quote" else "",
        "quote_date": str(source.get("date") or "").strip() if source_kind == "quote" else "",
        "document_mode": "delivery_only" if source_kind == "delivery" else "invoice_only",
        "delivery_document_number": str(source.get("number") or "").strip() if source_kind == "delivery" else "",
        "delivery_document_id": str(source.get("id") or "").strip() if source_kind == "delivery" else "",
        "tax_invoice_number": str(source.get("number") or "").strip() if source_kind == "invoice" else "",
        "tax_invoice_document_id": str(source.get("id") or "").strip() if source_kind == "invoice" else "",
        "item_description": str(first_item.get("description") or source.get("item_name") or "").strip(),
        "item_sku": str(first_item.get("sku") or "").strip(),
        "item_unit": str(first_item.get("unit") or "").strip(),
        "item_quantity": str(first_item.get("quantity") or "").strip(),
        "item_unit_price": str(first_item.get("unit_price") or "").strip(),
        "item_line_total": str(first_item.get("line_total") or "").strip(),
        "subtotal": str(total or "").strip(),
        "vat": "",
        "total": str(total or "").strip(),
        "footer_text": "",
        "items_json": json.dumps(items, ensure_ascii=False),
        "ordered_items_json": json.dumps(items, ensure_ascii=False),
        "document_links": [],
        "label_split_rows_json": "[]",
        "raw_document_id": str(source.get("id") or "").strip(),
        "raw_source_url": str(source.get("source_url") or "").strip(),
        "raw_type": str(source.get("type") or "").strip(),
    }


def _manual_order_history_template_entry(
    row: dict,
    source_kind: str,
    template_type: str,
    section_key: str,
    section_title: str,
    kind_label: str,
    document_number: str,
    secondary_number: str = "",
) -> dict:
    items = _manual_order_history_items_from_row(row)
    preview = ""
    if items:
        first_description = str(items[0].get("description") or "").strip()
        if first_description:
            preview = first_description
    if len(items) > 1:
        preview = f"{preview} + {len(items) - 1} שורות" if preview else f"{len(items)} שורות פריטים"
    return {
        "template_id": f"{source_kind}:{str(row.get('history_id') or '').strip() or secrets.token_hex(4)}:{section_key}",
        "history_id": str(row.get("history_id") or "").strip(),
        "source": source_kind,
        "template_type": template_type,
        "section_key": section_key,
        "section_title": section_title,
        "kind_label": kind_label,
        "document_number": str(document_number or "").strip(),
        "secondary_number": str(secondary_number or "").strip(),
        "po_number": str(row.get("po_number") or "").strip(),
        "created_at": str(row.get("created_at") or row.get("quote_date") or row.get("po_date") or "").strip(),
        "total": str(row.get("total") or "").strip(),
        "customer_name": str(row.get("customer_name") or "").strip(),
        "item_preview": preview,
        "items_count": len(items),
        "row": row,
    }


async def _build_manual_order_recent_templates_payload(
    customer_guid: str = "",
    customer_id: str = "",
    customer_name: str = "",
) -> dict:
    target_guid = str(customer_guid or "").strip()
    target_id = re.sub(r"\D+", "", str(customer_id or ""))
    target_name = str(customer_name or "").strip()
    if not (target_guid or target_id or _canonical_income_customer_name(target_name)):
        return {"status": "ok", "customer_name": target_name, "sections": [], "templates_count": 0}

    order_rows = get_cached_order_history_rows() or load_order_history_rows(force_refresh=False)
    quote_rows = get_cached_quote_history_rows() or load_quote_history_rows(force_refresh=False)

    matched_order_rows = [
        dict(row)
        for row in (order_rows or [])
        if _manual_order_history_customer_matches(row, target_guid, target_id, target_name)
    ]
    matched_quote_rows = [
        dict(row)
        for row in (quote_rows or [])
        if _manual_order_history_customer_matches(row, target_guid, target_id, target_name)
    ]

    section_templates: dict[str, list[dict]] = {
        "delivery_only": [],
        "invoice_only": [],
        "full": [],
        "quote": [],
    }

    for row in matched_order_rows:
        document_mode = _normalize_order_document_mode(str(row.get("document_mode") or ""))
        if document_mode == "invoice_only":
            section_key = "invoice_only"
            section_title = "חשבוניות אחרונות"
            kind_label = "חשבונית"
            document_number = str(row.get("tax_invoice_number") or "").strip()
        elif document_mode == "full":
            section_key = "full"
            section_title = "משלוח + חשבונית אחרונים"
            kind_label = "משלוח + חשבונית"
            document_number = str(row.get("delivery_document_number") or row.get("tax_invoice_number") or "").strip()
        else:
            section_key = "delivery_only"
            section_title = "תעודות משלוח אחרונות"
            kind_label = "תעודת משלוח"
            document_number = str(row.get("delivery_document_number") or "").strip()
        if len(section_templates[section_key]) >= 3:
            continue
        section_templates[section_key].append(
            _manual_order_history_template_entry(
                row=row,
                source_kind="order",
                template_type=document_mode,
                section_key=section_key,
                section_title=section_title,
                kind_label=kind_label,
                document_number=document_number,
                secondary_number=str(row.get("tax_invoice_number") or "").strip()
                if section_key in {"delivery_only", "full"} else str(row.get("delivery_document_number") or "").strip(),
            )
        )

    for row in matched_quote_rows:
        if len(section_templates["quote"]) >= 3:
            continue
        has_items = bool(_manual_order_history_items_from_row(row))
        if not has_items:
            try:
                items = await _resolve_quote_history_items(row)
            except Exception as exc:
                log_handled_error("manual recent quote template items resolve failed", exc)
                items = []
            if items:
                row["items_json"] = json.dumps(items, ensure_ascii=False)
        section_templates["quote"].append(
            _manual_order_history_template_entry(
                row=row,
                source_kind="quote",
                template_type="quote",
                section_key="quote",
                section_title="הצעות מחיר אחרונות",
                kind_label="הצעת מחיר",
                document_number=str(row.get("quote_number") or "").strip(),
                secondary_number=str(row.get("po_number") or "").strip(),
            )
        )

    sections: list[dict] = []
    for section_key in ("delivery_only", "invoice_only", "full", "quote"):
        templates = section_templates.get(section_key) or []
        if not templates:
            continue
        sections.append(
            {
                "key": section_key,
                "title": templates[0].get("section_title") or section_key,
                "templates": templates,
                "count": len(templates),
            }
        )

    needs_greeninvoice_fallback = any(len(section_templates.get(section_key) or []) < 3 for section_key in ("delivery_only", "invoice_only", "quote"))
    if needs_greeninvoice_fallback:
        try:
            cfg = get_mode_config("prod")
            client = GreenInvoiceClient(
                base_url=cfg["base_url"],
                api_key=cfg["api_key"],
                api_secret=cfg["api_secret"],
            )
            date_from = date(2025, 5, 1).isoformat()
            date_to = date.today().isoformat()
            delivery_docs, invoice_docs, quote_docs = await asyncio.gather(
                client.get_delivery_documents(date_from=date_from, date_to=date_to, page_size=100, max_pages=100),
                client.get_invoice_documents(date_from=date_from, date_to=date_to, page_size=100, max_pages=100),
                client.get_quote_documents(date_from=date_from, date_to=date_to, page_size=100, max_pages=60),
            )

            def _doc_matches(doc: dict) -> bool:
                return _manual_order_history_customer_matches(
                    {
                        "customer_guid": str(doc.get("client_id") or "").strip(),
                        "customer_id": str(doc.get("customer_id") or "").strip(),
                        "customer_name": str(doc.get("customer_name") or "").strip(),
                    },
                    target_guid,
                    target_id,
                    target_name,
                )

            existing_numbers = {
                section_key: {
                    str(template.get("document_number") or "").strip()
                    for template in (section_templates.get(section_key) or [])
                    if str(template.get("document_number") or "").strip()
                }
                for section_key in ("delivery_only", "invoice_only", "quote")
            }

            for doc in sorted((doc for doc in delivery_docs if _doc_matches(doc)), key=lambda item: str(item.get("date") or ""), reverse=True):
                if len(section_templates["delivery_only"]) >= 3:
                    break
                number = str(doc.get("number") or "").strip()
                if number and number in existing_numbers["delivery_only"]:
                    continue
                row = _manual_order_template_row_from_greeninvoice_doc(doc, "delivery")
                section_templates["delivery_only"].append(
                    _manual_order_history_template_entry(
                        row=row,
                        source_kind="order",
                        template_type="delivery_only",
                        section_key="delivery_only",
                        section_title="תעודות משלוח אחרונות",
                        kind_label="תעודת משלוח",
                        document_number=number,
                    )
                )
                if number:
                    existing_numbers["delivery_only"].add(number)

            for doc in sorted((doc for doc in invoice_docs if _doc_matches(doc)), key=lambda item: str(item.get("date") or ""), reverse=True):
                if len(section_templates["invoice_only"]) >= 3:
                    break
                number = str(doc.get("number") or "").strip()
                if number and number in existing_numbers["invoice_only"]:
                    continue
                row = _manual_order_template_row_from_greeninvoice_doc(doc, "invoice")
                section_templates["invoice_only"].append(
                    _manual_order_history_template_entry(
                        row=row,
                        source_kind="order",
                        template_type="invoice_only",
                        section_key="invoice_only",
                        section_title="חשבוניות אחרונות",
                        kind_label="חשבונית",
                        document_number=number,
                    )
                )
                if number:
                    existing_numbers["invoice_only"].add(number)

            for doc in sorted((doc for doc in quote_docs if _doc_matches(doc)), key=lambda item: str(item.get("date") or ""), reverse=True):
                if len(section_templates["quote"]) >= 3:
                    break
                number = str(doc.get("number") or "").strip()
                if number and number in existing_numbers["quote"]:
                    continue
                row = _manual_order_template_row_from_greeninvoice_doc(doc, "quote")
                if not _manual_order_history_items_from_row(row):
                    continue
                section_templates["quote"].append(
                    _manual_order_history_template_entry(
                        row=row,
                        source_kind="quote",
                        template_type="quote",
                        section_key="quote",
                        section_title="הצעות מחיר אחרונות",
                        kind_label="הצעת מחיר",
                        document_number=number,
                    )
                )
                if number:
                    existing_numbers["quote"].add(number)
        except Exception as exc:
            log_handled_error("manual recent templates greeninvoice fallback failed", exc)

        sections = []
        for section_key in ("delivery_only", "invoice_only", "full", "quote"):
            templates = section_templates.get(section_key) or []
            if not templates:
                continue
            sections.append(
                {
                    "key": section_key,
                    "title": templates[0].get("section_title") or section_key,
                    "templates": templates[:3],
                    "count": min(len(templates), 3),
                }
            )

    return {
        "status": "ok",
        "customer_name": target_name,
        "sections": sections,
        "templates_count": sum(section.get("count", 0) for section in sections),
    }


async def _build_manual_order_recent_customers_payload(force_refresh: bool = False) -> dict:
    if not force_refresh:
        cached = _get_cached_manual_order_customers()
        if cached and _manual_order_customers_cache_is_fresh():
            return cached

    cfg = get_mode_config("prod")
    client = GreenInvoiceClient(
        base_url=cfg["base_url"],
        api_key=cfg["api_key"],
        api_secret=cfg["api_secret"],
    )
    date_from = date(2025, 5, 1).isoformat()
    date_to = date.today().isoformat()
    docs_results = await asyncio.gather(
        client.get_income_documents(date_from=date_from, date_to=date_to, page_size=100, max_pages=120),
        client.get_quote_documents(date_from=date_from, date_to=date_to, page_size=100, max_pages=120),
        client.get_delivery_documents(date_from=date_from, date_to=date_to, page_size=100, max_pages=120),
        client.get_purchase_order_documents(date_from=date_from, date_to=date_to, page_size=100, max_pages=120),
        return_exceptions=True,
    )
    customers_catalog = await client.list_all_clients(page_size=100, max_pages=60)

    docs: list[dict] = []
    warnings: list[str] = []
    for label, result in zip(
        ("income", "quotes", "deliveries", "purchase_orders"),
        docs_results,
    ):
        if isinstance(result, Exception):
            log_handled_error(f"manual order customers {label} fetch failed", result)
            warnings.append(label)
            continue
        docs.extend(dict(item) for item in (result or []) if isinstance(item, dict))

    customers_by_guid: dict[str, dict] = {}
    customers_by_id: dict[str, dict] = {}
    customers_by_name: dict[str, dict] = {}
    for item in customers_catalog or []:
        if not isinstance(item, dict):
            continue
        guid = str(item.get("customer_guid") or item.get("client_id") or "").strip()
        customer_id = re.sub(r"\D+", "", str(item.get("customer_id") or ""))
        canonical_name = _canonical_income_customer_name(str(item.get("customer_name") or ""))
        if guid:
            customers_by_guid[guid] = dict(item)
        if customer_id:
            customers_by_id[customer_id] = dict(item)
        if canonical_name:
            customers_by_name[canonical_name] = dict(item)

    customer_details_by_guid: dict[str, dict] = {}

    recent_customers: dict[str, dict] = {}
    for doc in docs:
        customer_guid = str(doc.get("client_id") or doc.get("customer_guid") or "").strip()
        customer_id = re.sub(r"\D+", "", str(doc.get("customer_id") or ""))
        customer_name = str(doc.get("customer_name") or "").strip()
        customer_key = _manual_order_customer_lookup_key(customer_guid, customer_id, customer_name)
        if not customer_key:
            continue
        matched_customer = (
            customers_by_guid.get(customer_guid)
            or customers_by_id.get(customer_id)
            or customers_by_name.get(_canonical_income_customer_name(customer_name))
            or {}
        )
        if not matched_customer and not customer_guid and not customer_id:
            continue
        resolved_guid = str(matched_customer.get("customer_guid") or customer_guid or "").strip()
        needs_customer_detail = bool(
            resolved_guid and (
                not str(matched_customer.get("customer_id") or "").strip()
                or not str(matched_customer.get("payment_terms_days") or "").strip()
                or not _manual_order_customer_primary_phone(matched_customer)
                or not str(matched_customer.get("contact_person") or "").strip()
            )
        )
        if needs_customer_detail:
            detail_row = customer_details_by_guid.get(resolved_guid)
            if detail_row is None:
                try:
                    detail = await client.get_client_by_guid(resolved_guid)
                except Exception as exc:
                    log_handled_error(f"manual order customer detail fetch failed for {resolved_guid}", exc)
                    detail = {}
                detail_row = {
                    "customer_guid": str((detail or {}).get("id") or (detail or {}).get("guid") or resolved_guid).strip(),
                    "customer_id": re.sub(
                        r"\D+",
                        "",
                        str(
                            (detail or {}).get("taxId")
                            or (detail or {}).get("idNumber")
                            or (detail or {}).get("vatNumber")
                            or (detail or {}).get("companyNumber")
                            or (detail or {}).get("companyId")
                            or ""
                        ),
                    ),
                    "customer_name": str((detail or {}).get("name") or (detail or {}).get("fullName") or customer_name or "").strip(),
                    "emails": _manual_order_normalize_emails_value((detail or {}).get("emails")),
                    "phone": str((detail or {}).get("phone") or "").strip(),
                    "mobile": str((detail or {}).get("mobile") or "").strip(),
                    "contact_person": str((detail or {}).get("contactPerson") or "").strip(),
                    "address": str((detail or {}).get("address") or "").strip(),
                    "city": str((detail or {}).get("city") or "").strip(),
                    "country": str((detail or {}).get("country") or "").strip(),
                    "payment_terms_days": str(client._extract_payment_days_from_customer(detail or {}) or "").strip(),
                    "remarks": str((detail or {}).get("remarks") or "").strip(),
                }
                customer_details_by_guid[resolved_guid] = detail_row
            if detail_row:
                merged_customer = dict(matched_customer or {})
                for key, value in detail_row.items():
                    if str(merged_customer.get(key) or "").strip():
                        continue
                    if str(value or "").strip():
                        merged_customer[key] = value
                matched_customer = merged_customer
        matched_customer = _manual_order_apply_customer_overrides(matched_customer)
        existing = recent_customers.get(customer_key) or {}
        doc_date = str(doc.get("date") or "").strip()
        documents_count = int(existing.get("documents_count") or 0) + 1
        merged = {
            "customer_key": customer_key,
            "customer_guid": str(matched_customer.get("customer_guid") or customer_guid or "").strip(),
            "customer_id": str(matched_customer.get("customer_id") or customer_id or "").strip(),
            "customer_name": str(matched_customer.get("customer_name") or customer_name or "").strip(),
            "emails": str(matched_customer.get("emails") or "").strip(),
            "phone": str(matched_customer.get("phone") or "").strip(),
            "mobile": str(matched_customer.get("mobile") or "").strip(),
            "contact_person": str(matched_customer.get("contact_person") or "").strip(),
            "address": str(matched_customer.get("address") or "").strip(),
            "city": str(matched_customer.get("city") or "").strip(),
            "country": str(matched_customer.get("country") or "").strip(),
            "payment_terms_days": str(matched_customer.get("payment_terms_days") or "").strip(),
            "source_mode": "PROD",
            "documents_count": documents_count,
            "last_document_date": max(str(existing.get("last_document_date") or "").strip(), doc_date),
            "primary_email": _manual_order_customer_primary_email(matched_customer),
            "primary_phone": _manual_order_customer_primary_phone(matched_customer),
            "address_label": _manual_order_customer_address_label(matched_customer),
        }
        if not merged["customer_name"]:
            merged["customer_name"] = customer_name or "ללא שם"
        recent_customers[customer_key] = merged

    rows = sorted(
        recent_customers.values(),
        key=lambda row: (
            _canonical_income_customer_name(row.get("customer_name") or ""),
            str(row.get("customer_id") or ""),
        ),
    )
    payload = {
        "status": "ok",
        "customers": rows,
        "count": len(rows),
        "source": "greeninvoice-prod-documents-since-2025-05-01",
        "date_from": "2025-05-01",
        "generated_at": datetime.now().isoformat(timespec="seconds"),
        "warning": ("חלק מסוגי המסמכים לא נטענו כרגע, אבל הרשימה הוכנה מהנתונים שכן חזרו." if warnings else ""),
    }
    return _store_manual_order_customers_cache(payload)

def _store_finance_state_cache(payload: dict) -> dict:
    global FINANCE_STATE_CACHE, FINANCE_STATE_CACHE_TS
    FINANCE_STATE_CACHE = copy.deepcopy(payload)
    FINANCE_STATE_CACHE_TS = time.time()
    _save_finance_state_disk_cache(FINANCE_STATE_CACHE)
    return copy.deepcopy(FINANCE_STATE_CACHE)


def _get_cached_finance_state() -> dict | None:
    if FINANCE_STATE_CACHE is not None:
        return copy.deepcopy(FINANCE_STATE_CACHE)
    return _load_finance_state_disk_cache()


def _finance_state_cache_is_fresh() -> bool:
    return (
        FINANCE_STATE_CACHE is not None
        and (time.time() - FINANCE_STATE_CACHE_TS) <= FINANCE_STATE_CACHE_TTL_SECONDS
    )


def _invalidate_finance_state_cache(schedule_refresh: bool = True) -> None:
    global FINANCE_STATE_CACHE, FINANCE_STATE_CACHE_TS
    FINANCE_STATE_CACHE = None
    FINANCE_STATE_CACHE_TS = 0.0
    try:
        FINANCE_STATE_CACHE_FILE.unlink(missing_ok=True)
    except Exception:
        pass
    if schedule_refresh:
        _ensure_finance_state_refresh_started(force_refresh=True)


async def _fetch_finance_prod_invoice_documents() -> list[dict]:
    cfg = get_mode_config("prod")
    client = GreenInvoiceClient(
        base_url=cfg["base_url"],
        api_key=cfg["api_key"],
        api_secret=cfg["api_secret"],
    )
    return await client.get_invoice_documents(
        date_from="2025-01-01",
        date_to=date.today().isoformat(),
        page_size=100,
        max_pages=48,
    )


async def _build_finance_payload(force_refresh: bool = False) -> dict:
    invoice_rows = _finance_backfill_stored_rows(
        load_marketing_rows("finance_invoices", force_refresh=force_refresh),
        persist=True,
    )
    bank_movement_rows = _dedupe_finance_bank_movement_rows(
        load_marketing_rows("finance_bank_movements", force_refresh=force_refresh)
    )
    customer_withholding_rows = _dedupe_finance_customer_withholding_rows(
        load_marketing_rows("finance_customer_withholdings", force_refresh=force_refresh)
    )
    settings_rows = load_marketing_rows("finance_settings", force_refresh=force_refresh)
    income_tax_rate = _load_finance_income_tax_rate_setting()
    documents = await _fetch_finance_prod_invoice_documents()
    document_entries: list[dict] = []
    for document in documents:
        doc_date = _finance_parse_date_value(document.get("date"))
        totals = _finance_document_totals(document)
        document_entries.append(
            {
                "date": doc_date,
                "date_text": str(document.get("date") or "").strip(),
                "subtotal": totals["subtotal"],
                "vat": totals["vat"],
                "total": totals["total"],
                "number": str(document.get("number") or "").strip(),
            }
        )

    vat_credit_rows = []
    income_tax_rows = []
    for due_date in _finance_due_dates():
        period_start, period_end, effective_end = _finance_period_for_due_date(due_date)
        if period_start > date.today():
            payable_vat = 0.0
            income_subtotal = 0.0
        else:
            payable_vat = round(
                sum(
                    float(item.get("vat") or 0)
                    for item in document_entries
                    if item.get("date") and period_start <= item["date"] <= effective_end
                ),
                2,
            )
            income_subtotal = round(
                sum(
                    float(item.get("subtotal") or 0)
                    for item in document_entries
                    if item.get("date") and period_start <= item["date"] <= effective_end
                ),
                2,
            )
        deductible_vat = round(
            sum(
                _finance_parse_number(row.get("vat"))
                for row in invoice_rows
                if (parsed := _finance_parse_date_value(row.get("invoice_date"))) and period_start <= parsed <= effective_end
            ),
            2,
        )
        vat_credit_rows.append(
            {
                "due_date": _finance_format_display_date(due_date),
                "period_start": _finance_format_display_date(period_start),
                "period_end": _finance_format_display_date(period_end),
                "effective_end": _finance_format_display_date(effective_end),
                "vat_payable": payable_vat,
                "vat_credit": deductible_vat,
            }
        )
        income_tax_rows.append(
            {
                "due_date": _finance_format_display_date(due_date),
                "period_start": _finance_format_display_date(period_start),
                "period_end": _finance_format_display_date(period_end),
                "effective_end": _finance_format_display_date(effective_end),
                "income_subtotal": income_subtotal,
                "rate_percent": income_tax_rate,
                "income_tax_due": round(income_subtotal * (income_tax_rate / 100), 2),
            }
        )

    invoice_summary = {
        "count": len(invoice_rows),
        "subtotal_sum": round(sum(_finance_parse_number(row.get("subtotal")) for row in invoice_rows), 2),
        "vat_sum": round(sum(_finance_parse_number(row.get("vat")) for row in invoice_rows), 2),
        "total_sum": round(sum(_finance_parse_number(row.get("total")) for row in invoice_rows), 2),
    }
    bank_movement_summary = _finance_bank_movement_summary(bank_movement_rows)
    return {
        "invoice_rows": invoice_rows,
        "invoice_summary": invoice_summary,
        "bank_movement_rows": bank_movement_rows,
        "bank_movement_summary": bank_movement_summary,
        "vat_rows": vat_credit_rows,
        "income_tax_rows": income_tax_rows,
        "customer_withholding_rows": customer_withholding_rows,
        "income_tax_rate_percent": income_tax_rate,
        "settings_rows": settings_rows,
        "prod_invoice_documents_count": len(document_entries),
    }


async def _refresh_finance_state_cache(force_refresh: bool = False) -> dict:
    async with FINANCE_STATE_REFRESH_LOCK:
        payload = await _build_finance_payload(force_refresh=force_refresh)
        return _store_finance_state_cache(payload)


async def _run_finance_state_refresh(force_refresh: bool = False) -> None:
    global FINANCE_STATE_REFRESH_TASK
    try:
        await _refresh_finance_state_cache(force_refresh=force_refresh)
    except Exception as exc:
        log_handled_error("finance state refresh failed", exc)
    finally:
        FINANCE_STATE_REFRESH_TASK = None


def _ensure_finance_state_refresh_started(force_refresh: bool = False) -> None:
    global FINANCE_STATE_REFRESH_TASK
    if FINANCE_STATE_REFRESH_TASK and not FINANCE_STATE_REFRESH_TASK.done():
        return
    FINANCE_STATE_REFRESH_TASK = asyncio.create_task(_run_finance_state_refresh(force_refresh=force_refresh))


def _render_work_managers_mail_html(message: str) -> str:
    lines = [html.escape(part) for part in str(message or "").splitlines()]
    return "<div dir='rtl' style='font-family:Arial,sans-serif;font-size:15px;line-height:1.8;'>" + "<br>".join(lines) + "</div>"


def _send_work_managers_email(recipients: list[str], subject: str, message: str) -> None:
    recipient_list = [item.strip() for item in recipients if str(item or "").strip()]
    if not recipient_list:
        raise RuntimeError("לא נמצאו כתובות מייל תקינות לשליחה.")
    plain_body = str(message or "").strip()
    html_body = _render_work_managers_mail_html(plain_body)
    smtp_from_email = str(settings.smtp_from_email or "office@ben-yacov.com").strip() or "office@ben-yacov.com"
    smtp_from_name = str(settings.smtp_from_name or "בן יעקב פתרונות טקסטיל").strip() or "בן יעקב פתרונות טקסטיל"
    gmail_status = gmail_connection_status()
    if gmail_status.get("can_send"):
        visible = recipient_list[:1] if len(recipient_list) == 1 else []
        hidden = recipient_list[1:] if len(recipient_list) > 1 else []
        if len(recipient_list) > 1:
            hidden = recipient_list
        send_mail_via_gmail_api(
            visible,
            subject,
            plain_body,
            html_body,
            [],
            sender_address=smtp_from_email,
            sender_name=smtp_from_name,
            inline_gif_path=DELIVERY_MAIL_GIF_PATH,
            bcc_recipients=hidden,
        )
        return
    gmail_send_status = gmail_oauth_send_status()
    if gmail_send_status == "revoked_or_expired":
        raise RuntimeError("טוקן Gmail OAuth של office@ben-yacov.com פג או בוטל. צריך להיכנס ל־/gmail-oauth/start ולחבר מחדש את Gmail.")
    if gmail_status.get("token_present") and gmail_send_status == "missing_scope":
        raise RuntimeError("Gmail OAuth מחובר בלי הרשאת שליחה. צריך לחבר מחדש את Gmail עם scope של gmail.send.")
    if gmail_status.get("oauth_ready"):
        raise RuntimeError("Gmail OAuth מחובר, אבל אין כרגע הרשאת שליחה. צריך לחבר מחדש את Gmail ולא לחזור ל-SMTP.")
    smtp_host = str(settings.smtp_host or "").strip()
    smtp_user = str(settings.smtp_username or "").strip()
    smtp_password = str(settings.smtp_password or "").strip()
    if not (smtp_host and smtp_user and smtp_password):
        raise RuntimeError("לא הוגדר חיבור Gmail OAuth או SMTP לשליחת המייל.")
    msg = EmailMessage()
    msg["Subject"] = subject
    msg["From"] = formataddr((smtp_from_name, smtp_from_email))
    msg["To"] = recipient_list[0] if len(recipient_list) == 1 else "undisclosed-recipients:;"
    if len(recipient_list) > 1:
        msg["Bcc"] = ", ".join(recipient_list)
    msg.set_content(plain_body)
    msg.add_alternative(html_body, subtype="html")
    if settings.smtp_use_ssl:
        with smtplib.SMTP_SSL(smtp_host, settings.smtp_port, context=ssl.create_default_context()) as server:
            server.login(smtp_user, smtp_password)
            server.send_message(msg)
    else:
        with smtplib.SMTP(smtp_host, settings.smtp_port) as server:
            server.starttls(context=ssl.create_default_context())
            server.login(smtp_user, smtp_password)
            server.send_message(msg)


def _update_marketing_pipeline_comm_status(customer_key: str, status: str, sent_at: str = "") -> dict | None:
    target_key = str(customer_key or "").strip()
    if not target_key:
        return None
    rows = load_marketing_rows("pipeline")
    updated_row = None
    for index, row in enumerate(rows):
        if str(row.get("customer_key") or "").strip() != target_key:
            continue
        merged = dict(row)
        merged["comm_status"] = str(status or "").strip().lower()
        merged["comm_sent_at"] = str(sent_at or datetime.now().isoformat(timespec="seconds")).strip()
        merged["updated_at"] = datetime.now().isoformat(timespec="seconds")
        rows[index] = merged
        updated_row = merged
        break
    if updated_row:
        save_marketing_rows("pipeline", rows)
    return updated_row


