def _send_marketing_email_message(
    *,
    recipients: str = "",
    subject: str = "",
    plain_body: str = "",
    html_body: str = "",
    customer_key: str = "",
    customer_guid: str = "",
    customer_id: str = "",
    customer_name: str = "",
    reminder_id: str = "",
    test_send: bool = False,
    doc_asset_keys: list[str] | None = None,
    extra_attachment_paths: list[Path] | None = None,
) -> dict:
    recipient_list = _customer_email_list(recipients)
    if test_send:
        recipient_list = ["asafbeny@gmail.com"]
    if not recipient_list:
        raise ValueError("חסרה כתובת מייל לשליחה.")
    if not str(subject or "").strip():
        raise ValueError("חסר נושא למייל.")

    stored_files: list[Path] = []
    for asset_key in doc_asset_keys or []:
        spec = MARKETING_DRIVE_ASSETS.get(asset_key)
        if not spec:
            continue
        local_path = Path(spec["local_path"])
        if local_path.exists() and local_path.is_file():
            stored_files.append(local_path)
        try:
            _ensure_marketing_drive_asset(asset_key)
        except Exception as drive_exc:
            log_handled_error(f"marketing email drive sync failed for {asset_key}", drive_exc)
    for attachment_path in extra_attachment_paths or []:
        path_obj = Path(attachment_path)
        if path_obj.exists() and path_obj.is_file():
            stored_files.append(path_obj)

    final_plain = _customer_mail_plain_text(html_body, plain_body)
    final_html = _delivery_confirmation_mail_html_from_editor_html(html_body, final_plain)
    _send_delivery_confirmation_mail(
        ", ".join(recipient_list),
        str(subject or "").strip(),
        final_plain,
        final_html,
        [str(path) for path in stored_files],
    )
    history_row = append_marketing_history_row(
        {
            "created_at": datetime.now().isoformat(timespec="seconds"),
            "customer_key": str(customer_key or "").strip(),
            "customer_guid": str(customer_guid or "").strip(),
            "customer_id": str(customer_id or "").strip(),
            "customer_name": str(customer_name or "").strip(),
            "action_type": MARKETING_HISTORY_ACTION_EMAIL,
            "channel": "email_test" if test_send else "email",
            "subject": str(subject or "").strip(),
            "details_json": json.dumps(
                {
                    "recipients": recipient_list,
                    "doc_asset_keys": [item for item in (doc_asset_keys or []) if item],
                    "attachments_count": len(stored_files),
                },
                ensure_ascii=False,
            ),
            "result": "ok",
        }
    ).get("row")

    updated_row = None
    if not test_send:
        sent_at = datetime.now().isoformat(timespec="seconds")
        updated_row = _update_marketing_pipeline_comm_status(
            str(customer_key or "").strip(),
            "email",
            sent_at,
        )
        if not updated_row and str(reminder_id or "").strip():
            updated_row = _update_marketing_reminder_comm_status(
                str(reminder_id or "").strip(),
                "email",
                sent_at,
            )
    return {
        "recipients": recipient_list,
        "attachments_count": len(stored_files),
        "test_send": test_send,
        "row": updated_row,
        "history_row": history_row,
    }


def _marketing_reminder_due_dt(row: dict) -> datetime | None:
    due_date = str(row.get("due_date") or "").strip()
    due_time = str(row.get("due_time") or "09:00").strip() or "09:00"
    if not due_date:
        return None
    parsed_date = None
    for fmt in ("%Y-%m-%d", "%d/%m/%Y"):
        try:
            parsed_date = datetime.strptime(due_date, fmt).date()
            break
        except Exception:
            continue
    if parsed_date is None:
        return None
    try:
        parsed_time = datetime.strptime(due_time, "%H:%M").time()
    except Exception:
        parsed_time = datetime.strptime("09:00", "%H:%M").time()
    return datetime.combine(parsed_date, parsed_time)


async def _process_due_marketing_reminders() -> None:
    async with MARKETING_REMINDER_AUTOSEND_LOCK:
        rows = load_marketing_rows("reminders", force_refresh=True)
        now = datetime.now()
        for row in rows:
            if str(row.get("status") or "").strip().lower() in {"done", "טופל"}:
                continue
            if str(row.get("auto_whatsapp_status") or "").strip().lower() == "sent":
                continue
            due_dt = _marketing_reminder_due_dt(row)
            if not due_dt or now < due_dt:
                continue
            customer_name = str(row.get("customer_name") or "לקוח").strip()
            contact_name = str(row.get("contact_name") or "").strip()
            note_text = str(row.get("note_text") or "").strip()
            message = str(row.get("message") or "").strip() or f"תזכורת שיווקית עבור {customer_name}"
            due_label = due_dt.strftime("%d/%m/%Y %H:%M")
            lines = [
                "תזכורת שיווקית אוטומטית",
                "",
                f"חברה: {customer_name}",
            ]
            if contact_name:
                lines.append(f"איש קשר: {contact_name}")
            if note_text:
                lines.append(f"הערות: {note_text}")
            lines.extend([
                f"מועד שנקבע: {due_label}",
                "",
                message,
            ])
            try:
                await send_files_via_whatsapp(
                    phone=MARKETING_REMINDER_TARGET_PHONE,
                    message="\n".join(lines).strip(),
                    file_paths=[],
                )
                sent_at = datetime.now().isoformat(timespec="seconds")
                _update_marketing_reminder_auto_status(str(row.get("reminder_id") or ""), "sent", sent_at)
                append_marketing_history_row(
                    {
                        "created_at": sent_at,
                        "customer_key": str(row.get("customer_key") or "").strip(),
                        "customer_guid": str(row.get("customer_guid") or "").strip(),
                        "customer_id": str(row.get("customer_id") or "").strip(),
                        "customer_name": customer_name,
                        "action_type": MARKETING_HISTORY_ACTION_WHATSAPP,
                        "channel": "whatsapp_auto",
                        "subject": "נשלחה תזכורת אוטומטית בוואטסאפ",
                        "details_json": json.dumps({"reminder_id": row.get("reminder_id"), "due_at": due_label}, ensure_ascii=False),
                        "result": "ok",
                    }
                )
            except Exception as exc:
                log_handled_error("marketing reminder auto whatsapp failed", exc)
                _update_marketing_reminder_auto_status(str(row.get("reminder_id") or ""), "failed", datetime.now().isoformat(timespec="seconds"))


async def _marketing_reminder_autosend_loop() -> None:
    await asyncio.sleep(5)
    while True:
        try:
            await _process_due_marketing_reminders()
        except Exception as exc:
            log_handled_error("marketing reminder autosend loop failed", exc)
        await asyncio.sleep(60)


