def _month_start_months_ago(months_back: int) -> date:
    today = date.today()
    year = today.year
    month = today.month - (months_back - 1)
    while month <= 0:
        month += 12
        year -= 1
    return date(year, month, 1)


def _payments_transfer_status_snapshot() -> dict:
    return {
        "active": bool(PAYMENTS_TRANSFER_REFRESH_STATUS.get("active")),
        "percent": int(PAYMENTS_TRANSFER_REFRESH_STATUS.get("percent") or 0),
        "label": str(PAYMENTS_TRANSFER_REFRESH_STATUS.get("label") or ""),
        "error": str(PAYMENTS_TRANSFER_REFRESH_STATUS.get("error") or ""),
        "cache_ready": bool(PAYMENTS_TRANSFER_CACHE is not None),
        "updated_at": PAYMENTS_TRANSFER_CACHE_TS,
    }


def _set_payments_transfer_status(*, active: bool, percent: int, label: str, error: str = "") -> None:
    PAYMENTS_TRANSFER_REFRESH_STATUS["active"] = active
    PAYMENTS_TRANSFER_REFRESH_STATUS["percent"] = max(0, min(100, int(percent)))
    PAYMENTS_TRANSFER_REFRESH_STATUS["label"] = label
    PAYMENTS_TRANSFER_REFRESH_STATUS["error"] = error
    PAYMENTS_TRANSFER_REFRESH_STATUS["cache_ready"] = PAYMENTS_TRANSFER_CACHE is not None
    PAYMENTS_TRANSFER_REFRESH_STATUS["updated_at"] = PAYMENTS_TRANSFER_CACHE_TS


def _store_payments_transfer_cache(payload: dict) -> dict:
    global PAYMENTS_TRANSFER_CACHE, PAYMENTS_TRANSFER_CACHE_TS
    PAYMENTS_TRANSFER_CACHE = copy.deepcopy(payload)
    PAYMENTS_TRANSFER_CACHE_TS = time.time()
    PAYMENTS_TRANSFER_REFRESH_STATUS["cache_ready"] = True
    PAYMENTS_TRANSFER_REFRESH_STATUS["updated_at"] = PAYMENTS_TRANSFER_CACHE_TS
    return copy.deepcopy(PAYMENTS_TRANSFER_CACHE)


def _payments_transfer_cache_payload() -> dict | None:
    global PAYMENTS_TRANSFER_CACHE, PAYMENTS_TRANSFER_CACHE_TS
    if PAYMENTS_TRANSFER_CACHE is None:
        disk_cached = _get_cached_payments_transfer_state()
        if disk_cached:
            PAYMENTS_TRANSFER_CACHE = copy.deepcopy(disk_cached)
            PAYMENTS_TRANSFER_CACHE_TS = time.time()
            PAYMENTS_TRANSFER_REFRESH_STATUS["cache_ready"] = True
            PAYMENTS_TRANSFER_REFRESH_STATUS["updated_at"] = PAYMENTS_TRANSFER_CACHE_TS
    if PAYMENTS_TRANSFER_CACHE is None:
        return None
    payload = copy.deepcopy(PAYMENTS_TRANSFER_CACHE)
    payload["_cache_ts"] = PAYMENTS_TRANSFER_CACHE_TS
    return payload


