class PaymentsRowConflictError(Exception):
    def __init__(self, current_row: dict | None, current_hash: str, state: dict | None = None):
        super().__init__("הרשומה השתנתה מאז שפתחת אותה. טען מחדש ונסה שוב.")
        self.current_row = copy.deepcopy(current_row or {})
        self.current_hash = str(current_hash or "").strip()
        self.state = copy.deepcopy(state or {})


