def _payments_current_user_identity(request: Request | None) -> tuple[str, str]:
    state = load_auth_state()
    fallback_user = get_auth_user(state, state.get("default_user_id"))
    user_id = authenticated_user_id(request) if request is not None else ""
    user = get_auth_user(state, user_id)
    resolved_user_id = str(user.get("id") or fallback_user.get("id") or "asaf").strip()
    user_name = str(user.get("display_name") or fallback_user.get("display_name") or resolved_user_id).strip() or resolved_user_id
    return resolved_user_id, user_name


def _payments_cleanup_edit_presence_unlocked(now_ts: float | None = None) -> None:
    now_ts = float(now_ts or time.time())
    stale_keys = [
        key for key, value in PAYMENTS_EDIT_PRESENCE.items()
        if float(value.get("expires_at") or 0) <= now_ts
    ]
    for key in stale_keys:
        PAYMENTS_EDIT_PRESENCE.pop(key, None)


def _payments_presence_snapshot_unlocked() -> dict[str, dict]:
    _payments_cleanup_edit_presence_unlocked()
    snapshot: dict[str, dict] = {}
    for key, value in PAYMENTS_EDIT_PRESENCE.items():
        snapshot[key] = {
            "user_id": str(value.get("user_id") or "").strip(),
            "user_name": str(value.get("user_name") or "").strip(),
            "session_id": str(value.get("session_id") or "").strip(),
            "updated_at": float(value.get("updated_at") or 0),
            "expires_at": float(value.get("expires_at") or 0),
        }
    return snapshot


async def _payments_presence_snapshot() -> dict[str, dict]:
    async with PAYMENTS_EDIT_PRESENCE_LOCK:
        return _payments_presence_snapshot_unlocked()


def _payments_row_snapshot_hash(row: dict | None) -> str:
    row = dict(row or {})
    payload = {
        field: str(row.get(field) or "").strip()
        for field in PAYMENTS_ROW_SNAPSHOT_FIELDS
    }
    payload["_sheet_title"] = str(row.get("_sheet_title") or "").strip()
    payload["_sheet_row"] = int(row.get("_sheet_row") or 0)
    encoded = json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(encoded.encode("utf-8")).hexdigest()[:20]


def _payments_state_payload(state: dict | None, request: Request | None = None, presence_snapshot: dict | None = None) -> dict:
    payload = copy.deepcopy(state or {})
    row_hashes: dict[str, str] = {}
    all_rows = payload.get("all_rows") if isinstance(payload, dict) else None
    if isinstance(all_rows, list):
        for row in all_rows:
            if not isinstance(row, dict):
                continue
            row_hash = _payments_row_snapshot_hash(row)
            row["_snapshot_hash"] = row_hash
            row_hashes[_payments_presence_key(row.get("_sheet_title", ""), row.get("_sheet_row", 0))] = row_hash
    for bucket_name in ("payments_2026_collection", "payments_2026_payment"):
        bucket = payload.get(bucket_name) if isinstance(payload, dict) else None
        if not isinstance(bucket, list):
            continue
        for row in bucket:
            if not isinstance(row, dict):
                continue
            row_key = _payments_presence_key(row.get("_sheet_title", ""), row.get("_sheet_row", 0))
            row["_snapshot_hash"] = row_hashes.get(row_key) or _payments_row_snapshot_hash(row)
    if presence_snapshot is None:
        now_ts = time.time()
        presence_snapshot = {}
        for key, value in list(PAYMENTS_EDIT_PRESENCE.items()):
            expires_at = float((value or {}).get("expires_at") or 0)
            if expires_at <= now_ts:
                continue
            presence_snapshot[key] = {
                "user_id": str((value or {}).get("user_id") or "").strip(),
                "user_name": str((value or {}).get("user_name") or "").strip(),
                "session_id": str((value or {}).get("session_id") or "").strip(),
                "updated_at": float((value or {}).get("updated_at") or 0),
                "expires_at": expires_at,
            }
    payload["edit_presence"] = copy.deepcopy(presence_snapshot or {})
    current_user_id, current_user_name = _payments_current_user_identity(request)
    payload["current_user_id"] = current_user_id
    payload["current_user_name"] = current_user_name
    return payload


def _payments_find_current_row(sheet_title: str, row_number: int) -> tuple[dict | None, dict]:
    state = load_payment_transfer_rows(force_refresh=True, repair_schema=False)
    current_row = next(
        (
            row for row in ((state or {}).get("all_rows") or [])
            if str(row.get("_sheet_title") or "").strip() == str(sheet_title or "").strip()
            and int(row.get("_sheet_row") or 0) == int(row_number or 0)
        ),
        None,
    )
    return current_row, state


def _payments_assert_snapshot_matches(sheet_title: str, row_number: int, expected_snapshot_hash: str = "") -> tuple[dict | None, dict]:
    current_row, state = _payments_find_current_row(sheet_title, row_number)
    if not current_row:
        raise FileNotFoundError("לא הצלחתי למצוא את השורה שביקשת לעדכן.")
    expected_hash = str(expected_snapshot_hash or "").strip()
    current_hash = _payments_row_snapshot_hash(current_row)
    if expected_hash and expected_hash != current_hash:
        raise PaymentsRowConflictError(current_row, current_hash, state)
    return current_row, state


async def _run_payments_receipt_sync_followup(since_date: str = "") -> None:
    global PAYMENTS_TRANSFER_RECEIPT_SYNC_TASK
    try:
        sync_result = await _sync_missing_payment_receipts_with_greeninvoice(since_date=since_date)
        payload = sync_result.get("state") or load_payment_transfer_rows(force_refresh=True, repair_schema=False)
        _store_payments_transfer_cache(payload)
        _complete_payments_receipt_sync_check()
    except Exception as exc:
        log_handled_error("payments receipt sync followup failed", exc)
    finally:
        PAYMENTS_TRANSFER_RECEIPT_SYNC_TASK = None


def _start_payments_receipt_sync_followup(since_date: str = "") -> None:
    global PAYMENTS_TRANSFER_RECEIPT_SYNC_TASK
    if PAYMENTS_TRANSFER_RECEIPT_SYNC_TASK and not PAYMENTS_TRANSFER_RECEIPT_SYNC_TASK.done():
        return
    PAYMENTS_TRANSFER_RECEIPT_SYNC_TASK = asyncio.create_task(_run_payments_receipt_sync_followup(since_date=since_date))


async def _refresh_payments_transfer_cache() -> dict:
    async with PAYMENTS_TRANSFER_REFRESH_LOCK:
        _set_payments_transfer_status(active=True, percent=18, label="שלב 1 מתוך 2: טוען את נתוני התשלומים וההעברות מגוגל שיט…")
        try:
            meta = _load_payments_receipt_sync_meta()
            pending_sync = bool(meta.get("pending_sync"))
            since_date = str(meta.get("last_checked_date") or "").strip()
            payload = load_payment_transfer_rows(force_refresh=True, repair_schema=False)
            _set_payments_transfer_status(active=True, percent=88, label="שלב 2 מתוך 2: בונה סיכומים ומכין את הטבלאות…")
            cached = _store_payments_transfer_cache(payload)
            if pending_sync:
                _start_payments_receipt_sync_followup(since_date=since_date)
                _set_payments_transfer_status(active=False, percent=100, label="נתוני התשלומים נטענו. סנכרון קבלות חסרות יושלם ברקע.", error="")
            else:
                _set_payments_transfer_status(active=False, percent=100, label="נתוני התשלומים נטענו", error="")
            return cached
        except Exception as exc:
            log_handled_error("payments transfer refresh failed", exc)
            _set_payments_transfer_status(active=False, percent=100, label="טעינת נתוני התשלומים נכשלה", error=str(exc))
            raise


async def _ensure_payments_transfer_refresh_started() -> dict:
    global PAYMENTS_TRANSFER_REFRESH_TASK
    if PAYMENTS_TRANSFER_REFRESH_TASK and not PAYMENTS_TRANSFER_REFRESH_TASK.done():
        return _payments_transfer_status_snapshot()
    PAYMENTS_TRANSFER_REFRESH_TASK = asyncio.create_task(_refresh_payments_transfer_cache())
    return _payments_transfer_status_snapshot()


async def _startup_prewarm_state() -> None:
    global STARTUP_PREWARM_TASK
    try:
        await asyncio.to_thread(warm_local_caches_from_disk)
    except Exception as exc:
        log_handled_error("startup disk cache prewarm failed", exc)
    try:
        _payments_transfer_cache_payload()
    except Exception as exc:
        log_handled_error("startup payments cache bootstrap failed", exc)
    try:
        _get_cached_finance_state()
    except Exception as exc:
        log_handled_error("startup finance cache bootstrap failed", exc)
    try:
        await asyncio.sleep(0.35)
        if _get_cached_finance_state() is None:
            _ensure_finance_state_refresh_started(force_refresh=False)
    except Exception as exc:
        log_handled_error("startup finance refresh scheduling failed", exc)
    finally:
        STARTUP_PREWARM_TASK = None


@app.on_event("startup")
async def startup_background_tasks() -> None:
    global MARKETING_REMINDER_AUTOSEND_TASK, STARTUP_PREWARM_TASK
    if MARKETING_REMINDER_AUTOSEND_TASK is None or MARKETING_REMINDER_AUTOSEND_TASK.done():
        MARKETING_REMINDER_AUTOSEND_TASK = asyncio.create_task(_marketing_reminder_autosend_loop())
    if STARTUP_PREWARM_TASK is None or STARTUP_PREWARM_TASK.done():
        STARTUP_PREWARM_TASK = asyncio.create_task(_startup_prewarm_state())

def _extract_brosh_site_details(text: str):
    import re

    text = text or ""

    # לוקחים רק את הבלוק שבין כתובת למשלוח ללכבוד
    m_block = re.search(r"כתובת למשלוח:\s*(.*?)\s*לכבוד:", text, re.DOTALL)
    if not m_block:
        return {"delivery_address": "", "contact_name": "", "contact_phone": ""}

    block = m_block.group(1)

    delivery_address = ""
    contact_name = ""
    contact_phone = ""

    lines = [ln.strip() for ln in block.splitlines() if ln.strip()]

    # שתי השורות הראשונות הן הכתובת, אצל ברוש הן זהות
    if len(lines) >= 2:
        line1 = lines[0]
        line2 = lines[1]
        delivery_address = line1 if line1 == line2 else f"{line1} / {line2}"

    m_contact = re.search(r"לידי:\s*([^\n]+)", block)
    if m_contact:
        contact_name = m_contact.group(1).strip()

    m_phone = re.search(r"טלפון:\s*(0\d{1,2}-\d{7})", block)
    if m_phone:
        contact_phone = m_phone.group(1).strip()

    return {
        "delivery_address": delivery_address,
        "contact_name": contact_name,
        "contact_phone": contact_phone,
    }



