def _find_delivery_contact_email(company: str) -> str:
    target = _normalize_company_name(company)
    for row in load_delivery_contact_rows():
        if _normalize_company_name(row.get("company", "")) != target:
            continue
        return str(row.get("email") or "").strip()
    return _default_delivery_contact_email(company)


def _default_delivery_contact_email(company: str) -> str:
    target = _normalize_company_name(company)
    for raw_company, email in DELIVERY_CONTACT_EMAIL_OVERRIDES_BY_COMPANY.items():
        if _normalize_company_name(raw_company) == target and str(email or "").strip():
            return str(email or "").strip()
    return ""


def _mark_customer_bank_details_updated(company: str) -> bool:
    raw_target = str(company or "").strip()
    target_name = _canonical_income_customer_name(raw_target) or raw_target
    target_normalized = _normalize_company_name(raw_target)
    if not target_name and not target_normalized:
        return False

    updated_any = False
    now_iso = datetime.now().isoformat(timespec="seconds")

    def _apply(rows: list[dict]) -> tuple[list[dict], bool]:
        changed = False
        updated_rows: list[dict] = []
        for row in rows or []:
            current = dict(row)
            row_name_raw = str(current.get("customer_name") or "").strip()
            row_name = _canonical_income_customer_name(row_name_raw) or row_name_raw
            row_name_normalized = _normalize_company_name(row_name_raw)
            if (
                (target_normalized and row_name_normalized and row_name_normalized == target_normalized)
                or (target_name and row_name == target_name)
            ):
                if str(current.get("bank_details_updated_sent") or "").strip().upper() != "TRUE":
                    changed = True
                current["bank_details_updated_sent"] = "TRUE"
                current["synced_at"] = now_iso
            updated_rows.append(current)
        return updated_rows, changed

    active_rows, active_changed = _apply(load_customer_rows())
    inactive_rows, inactive_changed = _apply(load_inactive_customer_rows())
    if active_changed:
        save_customer_rows(active_rows)
        updated_any = True
    if inactive_changed:
        save_inactive_customer_rows(inactive_rows)
        updated_any = True
    return updated_any


