def _payment_reminder_plain_text_with_spacers(body: str) -> str:
    raw = str(body or "").replace("\r\n", "\n").replace("\r", "\n").strip()
    if not raw:
        return ""
    paragraphs: list[str] = []
    for paragraph in re.split(r"\n\s*\n", raw):
        lines = [line.rstrip() for line in paragraph.splitlines() if line.strip()]
        if not lines:
            continue
        paragraphs.append("\n".join(lines))
    if not paragraphs:
        return raw
    return "\n \n".join(paragraphs).strip() + "\n"


