def _send_delivery_confirmation_mail(
    recipients: str,
    subject: str,
    body: str,
    html_body: str,
    attachments: list[str],
    sender_address: str = "office@ben-yacov.com",
) -> None:
    recipient_list = [part.strip() for part in re.split(r"[;,]+", recipients or "") if part.strip()]
    if not recipient_list:
        raise RuntimeError("לא נמצאו נמענים לשליחה.")

    smtp_host = str(settings.smtp_host or "").strip()
    smtp_user = str(settings.smtp_username or "").strip()
    smtp_password = str(settings.smtp_password or "").strip()
    smtp_from_email = str(settings.smtp_from_email or sender_address).strip() or sender_address
    smtp_from_name = str(settings.smtp_from_name or "בן יעקב פתרונות טקסטיל").strip() or "בן יעקב פתרונות טקסטיל"

    gmail_status = gmail_connection_status()
    if gmail_status.get("can_send"):
        send_mail_via_gmail_api(
            recipient_list,
            subject,
            body,
            html_body,
            attachments,
            sender_address=smtp_from_email,
            sender_name=smtp_from_name,
            inline_gif_path=DELIVERY_MAIL_GIF_PATH,
        )
        return
    gmail_send_status = gmail_oauth_send_status()
    if gmail_send_status == "revoked_or_expired":
        raise RuntimeError("טוקן Gmail OAuth של office@ben-yacov.com פג או בוטל. צריך להיכנס ל־/gmail-oauth/start ולחבר מחדש את Gmail.")
    if gmail_status.get("token_present") and gmail_send_status == "missing_scope":
        raise RuntimeError("Gmail OAuth מחובר בלי הרשאת שליחה. צריך לחבר מחדש את Gmail עם scope של gmail.send.")
    if gmail_status.get("oauth_ready"):
        raise RuntimeError("Gmail OAuth מחובר, אבל אין כרגע הרשאת שליחה. צריך לחבר מחדש את Gmail ולא לחזור ל-SMTP.")

    if smtp_host and smtp_user and smtp_password:
        try:
            msg = EmailMessage()
            msg["Subject"] = subject
            msg["From"] = formataddr((smtp_from_name, smtp_from_email))
            msg["To"] = ", ".join(recipient_list)
            msg.set_content(body)
            msg.add_alternative(html_body, subtype="html")

            html_part = msg.get_payload()[-1]
            if DELIVERY_MAIL_GIF_PATH.exists():
                html_part.add_related(
                    DELIVERY_MAIL_GIF_PATH.read_bytes(),
                    maintype="image",
                    subtype="gif",
                    cid="<ben_yacov_logo>",
                    filename=DELIVERY_MAIL_GIF_PATH.name,
                    disposition="inline",
                )

            for attachment_path in attachments:
                attachment_file = Path(attachment_path)
                if not attachment_file.exists() or not attachment_file.is_file():
                    continue
                mime_type, _ = mimetypes.guess_type(str(attachment_file))
                maintype, subtype = (mime_type.split("/", 1) if mime_type else ("application", "octet-stream"))
                msg.add_attachment(
                    attachment_file.read_bytes(),
                    maintype=maintype,
                    subtype=subtype,
                    filename=attachment_file.name,
                )

            if settings.smtp_use_ssl:
                with smtplib.SMTP_SSL(smtp_host, settings.smtp_port, context=ssl.create_default_context()) as server:
                    server.login(smtp_user, smtp_password)
                    server.send_message(msg)
            else:
                with smtplib.SMTP(smtp_host, settings.smtp_port) as server:
                    server.starttls(context=ssl.create_default_context())
                    server.login(smtp_user, smtp_password)
                    server.send_message(msg)
            return
        except Exception as exc:
            log_handled_error("delivery confirmation smtp send failed", exc)
            raise RuntimeError(
                "שליחת המייל נכשלה דרך ה-backend. צריך לתקן את Gmail OAuth או את הגדרות ה-SMTP של office@ben-yacov.com."
            ) from exc

    raise RuntimeError(
        "לא הוגדר חיבור backend תקין לשליחת מיילים. צריך לחבר Gmail OAuth עם הרשאת שליחה או SMTP עבור office@ben-yacov.com."
    )


def _guess_customer_folder_name(company: str) -> str:
    name = _normalize_company_name(company)
    return re.sub(r"[/:]+", "-", name) or "לקוח ללא שם"


def _guess_order_folder_name(po_number: str, order_date: str) -> str:
    parts = [str(po_number or "").strip(), str(order_date or "").strip()]
    value = " - ".join([part for part in parts if part])
    return re.sub(r"[/:]+", "-", value) or f"order-{uuid.uuid4().hex[:8]}"


def _sandbox_output_folder_name(name: str, is_sandbox: bool) -> str:
    base_name = str(name or "").strip()
    if not base_name:
        return base_name
    if not is_sandbox:
        return base_name
    if base_name.endswith("-sandbox"):
        return base_name
    return f"{base_name}-sandbox"


def _generated_docs_root_for_mode(mode_value: str) -> Path:
    normalized = str(mode_value or "").strip().upper()
    target = SANDBOX_DOCS_DIR if normalized == "SB" else PRODUCTION_DOCS_DIR
    target.mkdir(parents=True, exist_ok=True)
    return target


def _generated_docs_root_for_sandbox_flag(is_sandbox: bool) -> Path:
    return _generated_docs_root_for_mode("SB" if is_sandbox else "PROD")


def _order_output_dir_from_history_row(row: dict) -> Path | None:
    if not isinstance(row, dict):
        return None
    customer_name = str(row.get("customer_name") or "").strip()
    po_number = str(row.get("po_number") or "").strip()
    mode_value = str(row.get("mode") or row.get("source_mode") or "").strip().upper()
    if not customer_name or not po_number:
        return None
    folder_name = f"{_safe_folder_name(customer_name.split(' - ח.פ')[0])} - {_safe_folder_name(po_number)}"
    folder_name = _sandbox_output_folder_name(folder_name, mode_value == "SB")
    output_root = _generated_docs_root_for_mode(mode_value)
    target_candidates = [
        (output_root / folder_name).resolve(),
        (OUTPUT_DIR / folder_name).resolve(),
    ]
    for target_dir in target_candidates:
        try:
            target_dir.relative_to(OUTPUT_DIR.resolve())
        except Exception:
            continue
        if target_dir.exists() and target_dir.is_dir():
            return target_dir
    fallback_dir = target_candidates[0]
    try:
        fallback_dir.relative_to(OUTPUT_DIR.resolve())
    except Exception:
        return None
    return fallback_dir


def _delete_local_order_output_dir(row: dict) -> dict:
    target_dir = _order_output_dir_from_history_row(row)
    if not target_dir:
        return {"status": "skipped", "reason": "output_folder_unresolved"}
    if not target_dir.exists() or not target_dir.is_dir():
        return {"status": "skipped", "reason": "output_folder_missing", "path": str(target_dir)}
    shutil.rmtree(target_dir)
    return {"status": "ok", "path": str(target_dir)}


def _matching_order_history_rows_for_payment_row(payment_row: dict) -> list[dict]:
    if not isinstance(payment_row, dict):
        return []
    rows = load_order_history_rows(force_refresh=True)
    target_po = str(payment_row.get("po_number") or "").strip()
    target_invoice = str(payment_row.get("tax_invoice_number") or "").strip()
    target_delivery = str(payment_row.get("delivery_number") or "").strip()
    target_mode = str(payment_row.get("source_mode") or "").strip().upper()
    target_customer = _canonical_income_customer_name(payment_row.get("customer_name", ""))
    matches: list[dict] = []
    for row in rows:
        row_po = str(row.get("po_number") or "").strip()
        row_invoice = str(row.get("tax_invoice_number") or "").strip()
        row_delivery = str(row.get("delivery_document_number") or "").strip()
        row_mode = str(row.get("mode") or row.get("source_mode") or "").strip().upper()
        row_customer = _canonical_income_customer_name(row.get("customer_name", ""))
        if target_po and row_po != target_po:
            continue
        if target_mode and row_mode != target_mode:
            continue
        if target_invoice and row_invoice != target_invoice:
            continue
        if target_delivery and row_delivery != target_delivery:
            continue
        if target_customer and row_customer != target_customer:
            continue
        matches.append(row)
    return matches


def _quote_item_descriptions(po: PurchaseOrderData) -> list[str]:
    descriptions: list[str] = []
    seen: set[str] = set()
    for item in list(po.items or []):
        description = re.sub(r"\s+", " ", str(getattr(item, "description", "") or "").strip())
        if not description:
            continue
        key = description.lower()
        if key in seen:
            continue
        seen.add(key)
        descriptions.append(description)
    return descriptions


def _quote_item_summary_text(po: PurchaseOrderData) -> str:
    descriptions = _quote_item_descriptions(po)
    if not descriptions:
        return "הפריטים שבהצעה"
    if len(descriptions) == 1:
        return descriptions[0]
    return " | ".join(descriptions)


