def _parse_quote_history_number(value) -> float:
    raw = str(value or "").strip().replace(",", "")
    if not raw:
        return 0.0
    try:
        return float(raw)
    except Exception:
        return 0.0


def _extract_quote_history_items_from_document(document: dict | None) -> list[dict]:
    raw = (document or {}).get("raw") or {}
    if not isinstance(raw, dict):
        return []

    collections: list[list] = []
    for key in ("income", "incomeRows", "rows", "items", "products", "lines"):
        value = raw.get(key)
        if isinstance(value, list):
            collections.append(value)
        elif isinstance(value, dict):
            for nested_key in ("rows", "items", "products", "lines"):
                nested = value.get(nested_key)
                if isinstance(nested, list):
                    collections.append(nested)

    items: list[dict] = []
    for collection in collections:
        for line in collection:
            if not isinstance(line, dict):
                continue
            description = ""
            for key in ("description", "name", "itemName", "title", "productName"):
                description = str(line.get(key) or "").strip()
                if description:
                    break
            if not description:
                continue
            sku = ""
            for key in ("sku", "itemCode", "catalogNum", "catalogNumber", "productSku", "code", "catalogNo"):
                sku = str(line.get(key) or "").strip()
                if sku:
                    break
            unit = ""
            for key in ("unit", "unitName", "measureUnit", "measurementUnit"):
                unit = str(line.get(key) or "").strip()
                if unit:
                    break
            quantity = _parse_quote_history_number(
                next((line.get(key) for key in ("quantity", "qty", "count", "amount") if line.get(key) is not None), 0)
            )
            unit_price = _parse_quote_history_number(
                next((line.get(key) for key in ("unitPrice", "pricePerUnit", "price") if line.get(key) is not None), 0)
            )
            line_total = _parse_quote_history_number(
                next((line.get(key) for key in ("lineTotal", "total", "rowTotal", "amount") if line.get(key) is not None), 0)
            )
            if line_total <= 0 and quantity > 0 and unit_price > 0:
                line_total = quantity * unit_price
            items.append(
                {
                    "description": description,
                    "sku": sku,
                    "unit": unit,
                    "quantity": quantity if quantity else "",
                    "unit_price": unit_price if unit_price else "",
                    "line_total": round(line_total, 2) if line_total else "",
                }
            )
    return items


async def _resolve_quote_history_items(row: dict) -> list[dict]:
    items_json = str((row or {}).get("items_json") or "[]").strip() or "[]"
    try:
        parsed = json.loads(items_json)
        if isinstance(parsed, list) and parsed:
            expected_subtotal = round(_parse_quote_history_number((row or {}).get("subtotal")), 2)
            parsed_subtotal = round(
                sum(_parse_quote_history_number(item.get("line_total")) for item in parsed if isinstance(item, dict)),
                2,
            )
            if not expected_subtotal or abs(parsed_subtotal - expected_subtotal) < 0.01:
                return parsed
    except Exception:
        pass

    mode = "sandbox" if str((row or {}).get("mode") or "").strip().upper() == "SB" else "prod"
    cfg = get_mode_config(mode)
    client = GreenInvoiceClient(
        base_url=cfg["base_url"],
        api_key=cfg["api_key"],
        api_secret=cfg["api_secret"],
    )
    quote_date_raw = str((row or {}).get("quote_date") or "").strip()
    try:
        quote_date_obj = datetime.strptime(quote_date_raw, "%d/%m/%Y").date()
    except Exception:
        quote_date_obj = date.today()
    date_from = (quote_date_obj - timedelta(days=31)).isoformat()
    date_to = (quote_date_obj + timedelta(days=31)).isoformat()
    documents = await client.get_quote_documents(date_from=date_from, date_to=date_to, max_pages=24)
    target_document_id = str((row or {}).get("quote_document_id") or "").strip()
    target_quote_number = str((row or {}).get("quote_number") or "").strip()
    target_doc = None
    if target_document_id:
        target_doc = next((doc for doc in documents if str(doc.get("id") or "").strip() == target_document_id), None)
    if not target_doc and target_quote_number:
        target_doc = next((doc for doc in documents if str(doc.get("number") or "").strip() == target_quote_number), None)
    if not target_doc:
        return []
    return _extract_quote_history_items_from_document(target_doc)


def _customer_mode_label(mode: str) -> str:
    lowered = str(mode or "").strip().lower()
    if lowered in {"sb", "sandbox", "test", "טסט"}:
        return "SB"
    if lowered in {"drive", "drv"}:
        return "DRIVE"
    return "PROD"


def _quote_document_links_payload(
    *,
    quote_number: str,
    quote_relative_file: str,
    quote_drive_url: str = "",
    quote_drive_folder_url: str = "",
) -> str:
    links: list[dict] = []
    if quote_relative_file:
        links.append(
            {
                "name": f"הצעת מחיר {quote_number or ''}".strip(),
                "url": f"/files/{quote(quote_relative_file)}".replace("%2F", "/"),
                "kind": "local",
            }
        )
    if quote_drive_url:
        links.append(
            {
                "name": f"הצעת מחיר {quote_number or ''} ב-Drive".strip(),
                "url": quote_drive_url,
                "kind": "drive_file",
            }
        )
    if quote_drive_folder_url:
        links.append(
            {
                "name": "תיקיית Drive",
                "url": quote_drive_folder_url,
                "kind": "drive_folder",
            }
        )
    return json.dumps(links, ensure_ascii=False)


def _extract_drive_folder_id(folder_url: str) -> str:
    match = re.search(r"/folders/([A-Za-z0-9_-]+)", str(folder_url or "").strip())
    return str(match.group(1) or "").strip() if match else ""


def _quote_history_local_path_from_url(url: str) -> Path | None:
    raw_url = str(url or "").strip()
    if not raw_url.startswith("/files/"):
        return None
    relative_value = unquote(raw_url[len("/files/"):].lstrip("/"))
    if not relative_value:
        return None
    try:
        full_path = (OUTPUT_DIR / relative_value).resolve()
        output_root = OUTPUT_DIR.resolve()
        if output_root not in full_path.parents and full_path != output_root:
            return None
        return full_path
    except Exception:
        return None


def _resolve_quote_history_primary_link(row: dict) -> str:
    links = _normalize_order_history_links((row or {}).get("document_links_json"))
    if not links:
        return ""

    def _is_quote_link(link: dict) -> bool:
        name = str(link.get("name") or "").strip()
        url = str(link.get("url") or "").strip()
        if not url:
            return False
        return bool(re.search(r"הצעת\s*מחיר|quote", name, re.IGNORECASE) or "quote" in url.lower())

    def _is_signed_quote(link: dict) -> bool:
        name = str(link.get("name") or "").strip()
        url = str(link.get("url") or "").strip()
        return bool(re.search(r"הצעה\s*חתומה|signed", name, re.IGNORECASE) or "signed" in url.lower())

    quote_links = [link for link in links if _is_quote_link(link) and not _is_signed_quote(link)]
    local_quote_links = [link for link in quote_links if str(link.get("url") or "").strip().startswith("/files/")]
    for link in local_quote_links:
        target_path = _quote_history_local_path_from_url(str(link.get("url") or "").strip())
        if target_path and target_path.exists() and target_path.is_file():
            return str(link.get("url") or "").strip()

    drive_quote_link = next(
        (
            str(link.get("url") or "").strip()
            for link in quote_links
            if str(link.get("url") or "").strip() and not str(link.get("url") or "").strip().startswith("/files/")
        ),
        "",
    )
    if drive_quote_link:
        return drive_quote_link

    for link in links:
        url = str(link.get("url") or "").strip()
        name = str(link.get("name") or "").strip()
        if not url or _is_signed_quote(link) or "תיקיית Drive" in name:
            continue
        if url.startswith("/files/"):
            target_path = _quote_history_local_path_from_url(url)
            if target_path and target_path.exists() and target_path.is_file():
                return url
            continue
        return url
    return ""


def _find_local_delivery_confirmation_invoice_pdf(row: dict) -> Path | None:
    po_number = str(row.get("po_number") or "").strip()
    invoice_number = str(row.get("tax_invoice_number") or "").strip()
    if not po_number and not invoice_number:
        return None

    patterns: list[str] = []
    if po_number and invoice_number:
        patterns.append(f"*{po_number}*invoice*{invoice_number}*.pdf")
        patterns.append(f"*{po_number}*_invoice_{invoice_number}.pdf")
    if invoice_number:
        patterns.append(f"*_invoice_{invoice_number}.pdf")
        patterns.append(f"*invoice*{invoice_number}*.pdf")
    if po_number:
        patterns.append(f"{po_number}_invoice_*.pdf")

    seen: set[str] = set()
    for pattern in patterns:
        if pattern in seen:
            continue
        seen.add(pattern)
        for candidate in OUTPUT_DIR.rglob(pattern):
            if candidate.exists() and candidate.is_file():
                return candidate.resolve()
    return None


def _find_local_delivery_confirmation_coc_pdf(row: dict) -> Path | None:
    po_number = str(row.get("po_number") or "").strip()
    if not po_number:
        return None
    patterns = [
        f"coc_{po_number}.pdf",
        f"*{po_number}*coc*.pdf",
        f"*coc*{po_number}*.pdf",
    ]
    seen: set[str] = set()
    for pattern in patterns:
        if pattern in seen:
            continue
        seen.add(pattern)
        for candidate in OUTPUT_DIR.rglob(pattern):
            if candidate.exists() and candidate.is_file():
                return candidate.resolve()
    return None


async def _resolve_delivery_confirmation_coc_attachment(row: dict, mode: str) -> Path:
    updated_row = await _ensure_delivery_confirmation_drive_assets(row, mode)
    po_number = str(updated_row.get("po_number") or row.get("po_number") or "").strip() or "order"
    coc_drive_file_id = str(updated_row.get("coc_drive_file_id") or "").strip()
    if coc_drive_file_id:
        coc_name = str(updated_row.get("coc_name") or f"coc_{po_number}.pdf").strip() or f"coc_{po_number}.pdf"
        coc_target = OUTPUT_DIR / "_delivery_confirmation_cache" / coc_name
        return download_drive_file(coc_drive_file_id, coc_target).resolve()

    local_coc_pdf = _find_local_delivery_confirmation_coc_pdf(updated_row)
    if local_coc_pdf and local_coc_pdf.exists():
        return local_coc_pdf.resolve()

    raise RuntimeError("ללקוח פלסן סאסא צריך לצרף מסמך COC לפני שליחת המייל.")


@app.middleware("http")
async def log_unhandled_errors(request: Request, call_next):
    try:
        return await call_next(request)
    except Exception as exc:
        logger.exception("UNHANDLED REQUEST ERROR | %s %s", request.method, request.url.path)
        raise


@app.middleware("http")
async def add_security_headers(request: Request, call_next):
    response = await call_next(request)
    response.headers.setdefault("X-Frame-Options", "DENY")
    response.headers.setdefault("X-Content-Type-Options", "nosniff")
    response.headers.setdefault("Referrer-Policy", "same-origin")
    response.headers.setdefault("Permissions-Policy", "camera=(), microphone=(self), geolocation=()")
    response.headers.setdefault(
        "Content-Security-Policy",
        "default-src 'self' data: blob:; img-src 'self' data: blob:; style-src 'self' 'unsafe-inline'; "
        "script-src 'self' 'unsafe-inline'; connect-src 'self' ws: wss:; frame-ancestors 'none'; "
        "base-uri 'self'; form-action 'self'",
    )
    if not request.url.path.startswith("/static/"):
        response.headers.setdefault("Cache-Control", "no-store")
    return response


AUTH_PUBLIC_PREFIXES = ("/static/", "/auth", "/gmail-oauth/", "/google-drive/oauth/")
AUTH_PUBLIC_PATHS = {"/", "/mobile/bootstrap", "/mobile/auth/bootstrap"}


@app.middleware("http")
async def auth_gate(request: Request, call_next):
    path = request.url.path
    if path in AUTH_PUBLIC_PATHS or any(path.startswith(prefix) for prefix in AUTH_PUBLIC_PREFIXES):
        return await call_next(request)
    if is_request_authenticated(request):
        return await call_next(request)
    return JSONResponse({"error": "נדרשת הזדהות לפני שימוש באפליקציה."}, status_code=401)


@app.get("/files/{file_path:path}")
async def get_file(file_path: str):
    full_path = (OUTPUT_DIR / file_path).resolve()
    output_root = OUTPUT_DIR.resolve()

    if output_root not in full_path.parents and full_path != output_root:
        return JSONResponse({"error": "forbidden"}, status_code=403)

    if not full_path.exists() or not full_path.is_file():
        return JSONResponse({"error": "file not found"}, status_code=404)

    return FileResponse(str(full_path))


