@app.get("/marketing-doc-preview/{asset_key}")
async def marketing_doc_preview(asset_key: str):
    try:
        spec = MARKETING_DRIVE_ASSETS.get(asset_key)
        if not spec:
            return JSONResponse({"error": "מסמך השיווק לא הוגדר."}, status_code=404)
        local_path = Path(spec["local_path"])
        if not local_path.exists() or not local_path.is_file():
            # Vercel: proxy Drive thumbnail via service account (browser can't auth directly)
            try:
                cached = MARKETING_DRIVE_ASSET_CACHE.get(asset_key) or {}
                file_id = str(cached.get("id") or "").strip()
                if not file_id:
                    # trigger lookup
                    _marketing_drive_thumbnail_url(asset_key)
                    cached = MARKETING_DRIVE_ASSET_CACHE.get(asset_key) or {}
                    file_id = str(cached.get("id") or "").strip()
                if not file_id:
                    return JSONResponse({"error": "מסמך לא נמצא ב-Drive"}, status_code=404)
                service = _google_drive_service()
                meta = service.files().get(fileId=file_id, fields="thumbnailLink", supportsAllDrives=True).execute()
                thumb_url = meta.get("thumbnailLink", "").replace("=s220", "=s480")
                if thumb_url:
                    import httpx as _httpx
                    async with _httpx.AsyncClient(follow_redirects=True, timeout=15) as client:
                        r = await client.get(thumb_url)
                    if r.status_code == 200:
                        from fastapi.responses import Response as _Resp
                        return _Resp(content=r.content, media_type=r.headers.get("content-type", "image/jpeg"),
                                     headers={"Cache-Control": "public, max-age=3600"})
            except Exception as thumb_exc:
                log_handled_error("marketing preview proxy failed", thumb_exc)
            return JSONResponse({"error": f"מסמך שיווק לא נמצא מקומית: {local_path.name}"}, status_code=404)
        suffix = local_path.suffix.lower()
        if suffix in {".jpg", ".jpeg", ".png", ".webp", ".gif"}:
            media_type, _ = mimetypes.guess_type(str(local_path))
            return FileResponse(local_path, media_type=media_type or "image/*")

        preview_path = MARKETING_PREVIEW_CACHE_DIR / f"{asset_key}.png"
        source_mtime = local_path.stat().st_mtime
        if not preview_path.exists() or preview_path.stat().st_mtime < source_mtime:
            generated = False
            # Try qlmanage (macOS local)
            try:
                with tempfile.TemporaryDirectory(prefix="marketing-preview-") as temp_dir:
                    subprocess.run(
                        ["qlmanage", "-t", "-s", "480", "-o", temp_dir, str(local_path)],
                        check=True,
                        stdout=subprocess.DEVNULL,
                        stderr=subprocess.DEVNULL,
                    )
                    gen = Path(temp_dir) / f"{local_path.name}.png"
                    if gen.exists():
                        shutil.copyfile(gen, preview_path)
                        generated = True
            except Exception:
                pass
            # Fallback: PyMuPDF (works on Vercel/Linux)
            if not generated:
                import fitz
                doc = fitz.open(str(local_path))
                page = doc.load_page(0)
                pix = page.get_pixmap(matrix=fitz.Matrix(1.5, 1.5), alpha=False)
                pix.save(str(preview_path))
                doc.close()
        return FileResponse(preview_path, media_type="image/png")
    except Exception as exc:
        log_handled_error("marketing_doc_preview failed", exc)
        return JSONResponse({"error": f"לא הצלחתי להציג תצוגה מקדימה למסמך השיווק: {exc}"}, status_code=500)

