def _set_auth_cookie_on_response(response, remember_me: bool, user_id: str, request: Request | None = None):
    state = load_auth_state()
    token = issue_auth_token(state["cookie_secret"], remember_me=remember_me, user_id=user_id)
    cookie_settings = auth_cookie_settings(remember_me)
    if request and request.url.scheme == "https":
        cookie_settings["secure"] = True
    response.set_cookie(AUTH_COOKIE_NAME, token, **cookie_settings)
    return response


def _auth_template_context(request: Request):
    state = load_auth_state()
    requested_user_id = str(request.query_params.get("user") or state.get("default_user_id") or "asaf").strip()
    users = list_auth_users(state)
    selected_user = next((user for user in users if str(user.get("id") or "") == requested_user_id), None) or (users[0] if users else {})
    selected_user_id = str(selected_user.get("id") or state.get("default_user_id") or "asaf").strip() or "asaf"
    methods = get_enabled_methods(state, selected_user_id)
    setup_required = not has_any_enabled_method(state, selected_user_id)
    totp_setup = build_totp_setup_payload(state, selected_user_id) if (setup_required or not methods["totp"]) else None
    return {
        "request": request,
        "methods": methods,
        "setup_required": setup_required,
        "email_address": selected_user.get("email_address", ""),
        "selected_user_id": selected_user_id,
        "selected_user_name": selected_user.get("display_name", ""),
        "auth_users": [
            {
                "id": str(user.get("id") or ""),
                "display_name": str(user.get("display_name") or user.get("username") or user.get("id") or ""),
                "methods": get_enabled_methods(state, str(user.get("id") or "")),
                "setup_required": not has_any_enabled_method(state, str(user.get("id") or "")),
            }
            for user in users
        ],
        "totp_qr_data_uri": (totp_setup or {}).get("qr_data_uri", ""),
        "totp_secret": (totp_setup or {}).get("secret", ""),
    }


def _is_mobile_request(request: Request) -> bool:
    ui_hint = str(request.query_params.get("ui") or "").strip().lower()
    if ui_hint in {"desktop", "web", "full"}:
        return False
    if ui_hint in {"mobile", "ios"}:
        return True
    mobile_hint = str(request.query_params.get("mobile") or "").strip().lower()
    if mobile_hint in {"1", "true", "yes", "mobile"}:
        return True
    if mobile_hint in {"0", "false", "no", "desktop"}:
        return False
    if (request.headers.get("x-po-client") or "").strip().lower() == "ios-app":
        return True
    user_agent = (request.headers.get("user-agent") or "").lower()
    mobile_markers = ["iphone", "android", "ipad", "ipod", "mobile", "windows phone"]
    return any(marker in user_agent for marker in mobile_markers)


def _localhost_hostname(value: str) -> bool:
    host = str(value or "").strip().lower()
    return host in {"localhost", "127.0.0.1", "::1"}


def _private_debug_hostname(value: str) -> bool:
    host = str(value or "").strip().lower()
    if _localhost_hostname(host):
        return True
    try:
        parsed = ipaddress.ip_address(host)
        return parsed.is_private or parsed.is_loopback
    except ValueError:
        return host.endswith(".local")


def _allow_dev_mobile_auth(request: Request) -> bool:
    host = str(request.url.hostname or "").strip().lower()
    debug_header = str(request.headers.get("x-po-debug-auth") or "").strip().lower()
    if debug_header not in {"1", "true", "yes", "debug"}:
        return False
    if _localhost_hostname(host):
        return True
    allow_private_debug_auth = str(os.getenv("PO_ALLOW_PRIVATE_DEBUG_AUTH") or "").strip().lower() in {"1", "true", "yes", "on"}
    return allow_private_debug_auth and _private_debug_hostname(host)


def get_mode_config(mode: str):
    if mode == "prod":
        return {
            "mode": "production",
            "api_key": settings.greeninvoice_prod_api_key,
            "api_secret": settings.greeninvoice_prod_api_secret,
            "base_url": settings.greeninvoice_prod_base_url,
        }

    return {
        "mode": "sandbox",
        "api_key": settings.greeninvoice_sandbox_api_key,
        "api_secret": settings.greeninvoice_sandbox_api_secret,
        "base_url": settings.greeninvoice_sandbox_base_url,
    }


def _normalize_customer_mode(value: str) -> str:
    mode = str(value or "prod").strip().lower()
    return "sandbox" if mode == "sandbox" else "prod"


CUSTOMER_DOMAIN_CONSTRUCTION = "construction"
CUSTOMER_DOMAIN_TEXTILE = "textile"
CUSTOMER_DOMAIN_SUPPLIER = "supplier"
CUSTOMER_DOMAIN_GRAPHIC_WEB = "graphic_web"


def _normalize_customer_domain_value(value: str) -> str:
    lowered = str(value or "").strip().lower()
    if lowered in {CUSTOMER_DOMAIN_CONSTRUCTION, "building", "תחום הבנייה", "בנייה", "הבניה"}:
        return CUSTOMER_DOMAIN_CONSTRUCTION
    if lowered in {CUSTOMER_DOMAIN_TEXTILE, "technical_textile", "textile_processing", "עיבוד טכני בטקסטיל"}:
        return CUSTOMER_DOMAIN_TEXTILE
    if lowered in {CUSTOMER_DOMAIN_SUPPLIER, "vendor", "ספק", "ספקים"}:
        return CUSTOMER_DOMAIN_SUPPLIER
    if lowered in {CUSTOMER_DOMAIN_GRAPHIC_WEB, "graphic_design", "web_design", "design_web", "עיצוב גרפי ואינטרנט", "עיצוב גרפי", "אינטרנט"}:
        return CUSTOMER_DOMAIN_GRAPHIC_WEB
    return ""


def _customer_identity_tokens(row: dict | None) -> tuple[str, str, str, str]:
    source = row or {}
    source_mode = _customer_mode_label(source.get("source_mode") or "")
    guid = str(source.get("customer_guid") or "").strip()
    customer_id = str(source.get("customer_id") or "").strip()
    customer_name = _canonical_income_customer_name(source.get("customer_name") or "")
    return source_mode, guid, customer_id, customer_name


def _customer_row_matches(left: dict | None, right: dict | None) -> bool:
    left_mode, left_guid, left_id, left_name = _customer_identity_tokens(left)
    right_mode, right_guid, right_id, right_name = _customer_identity_tokens(right)
    if left_mode and right_mode and left_mode != right_mode:
        return False
    return (
        (left_guid and right_guid and left_guid == right_guid)
        or (left_id and right_id and left_id == right_id)
        or (left_name and right_name and left_name == right_name)
    )


def _customer_rows_without_selected(rows: list[dict], selected_rows: list[dict]) -> list[dict]:
    filtered: list[dict] = []
    for row in rows or []:
        if any(_customer_row_matches(row, selected_row) for selected_row in selected_rows or []):
            continue
        filtered.append(row)
    return filtered


def _filter_out_inactive_customer_rows(rows: list[dict], inactive_rows: list[dict]) -> list[dict]:
    return _customer_rows_without_selected(rows, inactive_rows)


def _customer_sync_timestamp() -> str:
    return datetime.now().isoformat(timespec="seconds")


async def _fetch_greeninvoice_customers(mode: str = "prod") -> list[dict]:
    safe_mode = _normalize_customer_mode(mode)
    cfg = get_mode_config(safe_mode)
    client = GreenInvoiceClient(
        base_url=cfg["base_url"],
        api_key=cfg["api_key"],
        api_secret=cfg["api_secret"],
    )
    customers = await client.list_all_clients(page_size=100, max_pages=40)
    synced_at = _customer_sync_timestamp()
    rows: list[dict] = []
    for row in customers or []:
        if not isinstance(row, dict):
            continue
        normalized = dict(row)
        normalized["source_mode"] = _customer_mode_label(safe_mode)
        normalized["synced_at"] = synced_at
        rows.append(normalized)
    return rows


async def _fetch_all_greeninvoice_customers() -> list[dict]:
    results = await asyncio.gather(
        _fetch_greeninvoice_customers("prod"),
        _fetch_greeninvoice_customers("sandbox"),
        return_exceptions=True,
    )
    combined: list[dict] = []
    for result in results:
        if isinstance(result, Exception):
            log_handled_error("fetch all customers mode failed", result)
            continue
        combined.extend(dict(row) for row in (result or []) if isinstance(row, dict))
    return _sort_customer_rows(combined)


async def _enrich_customer_rows_with_source_mode(rows: list[dict]) -> tuple[list[dict], bool]:
    normalized_rows = [dict(row) for row in (rows or [])]
    valid_modes = {"PROD", "SB", "DRIVE"}
    if not normalized_rows or all(str(row.get("source_mode") or "").strip().upper() in valid_modes for row in normalized_rows):
        return normalized_rows, False
    remote_rows = await _fetch_all_greeninvoice_customers()
    remote_by_guid: dict[str, str] = {}
    remote_by_id_and_name: dict[tuple[str, str], str] = {}
    for row in remote_rows:
        source_mode = _customer_mode_label(row.get("source_mode") or "")
        guid = str(row.get("customer_guid") or "").strip()
        customer_id = re.sub(r"\D+", "", str(row.get("customer_id") or ""))
        customer_name = _canonical_income_customer_name(row.get("customer_name") or "")
        if guid:
            remote_by_guid[guid] = source_mode
        if customer_id or customer_name:
            remote_by_id_and_name[(customer_id, customer_name)] = source_mode
    changed = False
    for row in normalized_rows:
        current_mode = str(row.get("source_mode") or "").strip().upper()
        if current_mode in valid_modes:
            continue
        guid = str(row.get("customer_guid") or "").strip()
        customer_id = re.sub(r"\D+", "", str(row.get("customer_id") or ""))
        customer_name = _canonical_income_customer_name(row.get("customer_name") or "")
        source_mode = remote_by_guid.get(guid) or remote_by_id_and_name.get((customer_id, customer_name)) or ""
        if source_mode:
            row["source_mode"] = source_mode
            changed = True
    return _sort_customer_rows(normalized_rows), changed


def _merge_customer_row_with_payload(base_row: dict | None, payload: dict | None) -> dict:
    merged = dict(base_row or {})
    source = dict(payload or {})
    editable_fields = (
        "customer_guid",
        "customer_name",
        "customer_id",
        "source_mode",
        "active",
        "send",
        "department",
        "accounting_key",
        "payment_terms_days",
        "phone",
        "mobile",
        "emails",
        "contact_person",
        "address",
        "city",
        "zip",
        "country",
        "remarks",
        "customer_domain",
    )
    for field in editable_fields:
        if field in source:
            merged[field] = source.get(field, "")
    merged["customer_domain"] = _normalize_customer_domain_value(merged.get("customer_domain") or "")
    merged["synced_at"] = _customer_sync_timestamp()
    return merged


def _upsert_customer_row(rows: list[dict], row: dict) -> list[dict]:
    target_mode = _customer_mode_label((row or {}).get("source_mode") or "")
    target_guid = str((row or {}).get("customer_guid") or "").strip()
    target_id = str((row or {}).get("customer_id") or "").strip()
    target_name = _normalize_company_name((row or {}).get("customer_name") or "")
    updated_rows: list[dict] = []
    replaced = False
    for existing in rows or []:
        existing_mode = _customer_mode_label(existing.get("source_mode") or "")
        existing_guid = str(existing.get("customer_guid") or "").strip()
        existing_id = str(existing.get("customer_id") or "").strip()
        existing_name = _normalize_company_name(existing.get("customer_name") or "")
        if (
            (target_mode and existing_mode and target_mode != existing_mode)
        ):
            updated_rows.append(dict(existing))
            continue
        if (
            (target_guid and existing_guid == target_guid)
            or (target_id and existing_id and existing_id == target_id)
            or (target_name and existing_name == target_name)
        ):
            updated_rows.append(dict(row))
            replaced = True
        else:
            updated_rows.append(dict(existing))
    if not replaced:
        updated_rows.append(dict(row))
    return updated_rows


def _overlay_customer_rows(base_rows: list[dict], overlay_rows: list[dict]) -> list[dict]:
    merged = [dict(row) for row in base_rows or []]
    for row in overlay_rows or []:
        merged = _upsert_customer_row(merged, row)
    return merged


def _preserve_customer_custom_fields(incoming_rows: list[dict], reference_rows: list[dict]) -> list[dict]:
    preserved_rows: list[dict] = []
    reference_pool = [dict(row) for row in (reference_rows or []) if isinstance(row, dict)]
    for row in incoming_rows or []:
        current = dict(row) if isinstance(row, dict) else {}
        matched = next((candidate for candidate in reference_pool if _customer_row_matches(candidate, current)), None)
        if matched:
            matched_domain = _normalize_customer_domain_value(matched.get("customer_domain") or "")
            if matched_domain:
                current["customer_domain"] = matched_domain
        preserved_rows.append(current)
    return _sort_customer_rows(preserved_rows)


def _sort_customer_rows(rows: list[dict]) -> list[dict]:
    return sorted(
        rows or [],
        key=lambda row: (
            _canonical_income_customer_name(row.get("customer_name") or ""),
            str(row.get("customer_id") or ""),
            _customer_mode_label(row.get("source_mode") or ""),
        ),
    )


def _is_obviously_placeholder_customer_id(value: str) -> bool:
    digits = re.sub(r"\D+", "", str(value or "").strip())
    if not digits:
        return True
    if digits in {"012345678", "123456789", "000000000", "999999999", "111111111"}:
        return True
    if len(set(digits)) == 1:
        return True
    return False


def _customer_can_skip_tax_id(po: PurchaseOrderData) -> bool:
    normalized_name = _normalize_company_name(po.customer_name or "")
    if not normalized_name:
        return False
    skip_markers = (
        "ועד הבית",
        "ועד בית",
        "וועד הבית",
        "בית משותף",
        "דיירי ",
    )
    return any(marker in normalized_name for marker in skip_markers)


def _pick_existing_customer_candidate_without_tax_id(candidates: list[dict], customer_name: str) -> dict | None:
    normalized_target = _canonical_income_customer_name(customer_name or "")
    if not normalized_target:
        return None
    exact_candidates: list[dict] = []
    exact_without_tax: list[dict] = []
    for candidate in candidates or []:
        candidate_name = str(candidate.get("name") or candidate.get("title") or "").strip()
        if _canonical_income_customer_name(candidate_name) != normalized_target:
            continue
        exact_candidates.append(candidate)
        candidate_tax = re.sub(
            r"\D+",
            "",
            str(
                candidate.get("taxId")
                or candidate.get("idNumber")
                or candidate.get("vatNumber")
                or candidate.get("companyNumber")
                or ""
            ).strip(),
        )
        if not candidate_tax:
            exact_without_tax.append(candidate)
    if exact_without_tax:
        return exact_without_tax[0]
    if exact_candidates:
        return exact_candidates[0]
    return None


def _fetch_drive_customers() -> list[dict]:
    root_id = managed_storage_root_folder_id()
    folders = list_child_folders(root_id)
    existing_rows = load_customer_rows()
    existing_by_name = {
        _normalize_company_name(row.get("customer_name") or ""): dict(row)
        for row in existing_rows
        if _normalize_company_name(row.get("customer_name") or "")
    }
    synced_at = _customer_sync_timestamp()
    drive_rows: list[dict] = []
    seen_names: set[str] = set()
    for folder in folders:
        folder_name = str(folder.get("name") or "").strip()
        if not folder_name:
            continue
        normalized_name = _normalize_company_name(folder_name)
        if not normalized_name or normalized_name in seen_names:
            continue
        seen_names.add(normalized_name)
        existing = existing_by_name.get(normalized_name, {})
        drive_rows.append(
            {
                **existing,
                "customer_name": str(existing.get("customer_name") or folder_name).strip(),
                "synced_at": synced_at,
            }
        )
    return _sort_customer_rows(_overlay_customer_rows(existing_rows, drive_rows))


def _build_manual_customer_payload(po: PurchaseOrderData, allow_missing_id_number: bool = False) -> dict:
    customer_id = re.sub(r"\D+", "", str(po.customer_id or "").strip())
    if _is_obviously_placeholder_customer_id(customer_id):
        customer_id = ""
    if not customer_id and not allow_missing_id_number:
        raise ValueError("חסר ח.פ / ע.מ ללקוח החדש.")

    emails = _customer_email_list(po.customer_email or "")
    extra = po.extra or {}
    payload = {
        "name": str(po.customer_name or "").strip(),
        "phone": str(po.customer_phone or "").strip(),
        "mobile": str(po.customer_phone or "").strip(),
        "contactPerson": str(extra.get("contact_name") or "").strip(),
        "address": str(po.delivery_address or "").strip(),
        "remarks": str(extra.get("footer_text") or "").strip(),
        "emails": emails,
        "active": True,
        "send": True,
    }
    if customer_id:
        payload["idNumber"] = customer_id
    if allow_missing_id_number:
        payload["allowMissingIdNumber"] = True
    # GreenInvoice rejects some order-derived payment term strings during
    # customer creation. We do not need payment terms on the customer card
    # to proceed with invoice/document generation, so omit them here.
    return payload


async def _ensure_finalize_customer(po: PurchaseOrderData, mode: str, client: GreenInvoiceClient) -> dict:
    raw_tax_id = re.sub(r"\D+", "", str(po.customer_id or "").strip())
    allow_missing_id_number = _customer_can_skip_tax_id(po)
    tax_id = raw_tax_id
    if allow_missing_id_number and _is_obviously_placeholder_customer_id(raw_tax_id):
        tax_id = ""
    if not tax_id:
        po.customer_id = ""
    if not tax_id:
        existing_customer_candidates = await client.get_existing_customer_candidates_by_name(str(po.customer_name or "").strip())
        existing_customer = _pick_existing_customer_candidate_without_tax_id(
            existing_customer_candidates,
            str(po.customer_name or "").strip(),
        )
        if existing_customer:
            return {
                "status": "existing",
                "missing_before": True,
                "customer_guid": str(existing_customer.get("id") or "").strip(),
                "customer_name": str(existing_customer.get("name") or po.customer_name or "").strip(),
            }

        payload = _build_manual_customer_payload(po, allow_missing_id_number=True)
        if not payload.get("name"):
            raise RuntimeError("חסר שם לקוח, ולכן אי אפשר להקים לקוח חדש בחשבונית ירוקה.")
        try:
            await client.create_client(payload)
        except Exception as exc:
            refreshed_candidates = await client.get_existing_customer_candidates_by_name(str(po.customer_name or "").strip())
            created_or_existing_customer = _pick_existing_customer_candidate_without_tax_id(
                refreshed_candidates,
                str(po.customer_name or "").strip(),
            )
            if created_or_existing_customer:
                return {
                    "status": "created",
                    "missing_before": True,
                    "customer_guid": str(created_or_existing_customer.get("id") or "").strip(),
                    "customer_name": str(created_or_existing_customer.get("name") or payload.get("name") or "").strip(),
                }
            if not allow_missing_id_number:
                raise RuntimeError(
                    "לא נמצא ח.פ / ע.מ ללקוח, וגם יצירת לקוח בלי ח.פ בחשבונית ירוקה לא הצליחה: "
                    f"{exc}"
                ) from exc
            raise RuntimeError(f"לא הצלחתי ליצור לקוח חדש בחשבונית ירוקה: {exc}") from exc

        fetched_rows = await _fetch_greeninvoice_customers(mode)
        save_customer_rows(_sort_customer_rows(fetched_rows))
        refreshed_candidates = await client.get_existing_customer_candidates_by_name(str(po.customer_name or "").strip())
        created_customer = _pick_existing_customer_candidate_without_tax_id(
            refreshed_candidates,
            str(po.customer_name or "").strip(),
        )
        return {
            "status": "created",
            "missing_before": True,
            "customer_guid": str((created_customer or {}).get("id") or "").strip(),
            "customer_name": str((created_customer or {}).get("name") or payload.get("name") or po.customer_name or "").strip(),
        }

    po.customer_id = tax_id
    existing_customer = await client.get_existing_customer_details(tax_id)
    if existing_customer:
        return {
            "status": "existing",
            "missing_before": False,
            "customer_guid": str(existing_customer.get("id") or "").strip(),
            "customer_name": str(existing_customer.get("name") or po.customer_name or "").strip(),
        }

    existing_customer_candidates = await client.get_existing_customer_candidates_by_name(str(po.customer_name or "").strip())
    exact_tax_match = None
    missing_tax_match = None
    conflicting_tax_matches: list[dict] = []
    for candidate in existing_customer_candidates:
        candidate_tax_id = re.sub(
            r"\D+",
            "",
            str(
                candidate.get("taxId")
                or candidate.get("idNumber")
                or candidate.get("vatNumber")
                or candidate.get("companyNumber")
                or ""
            ).strip(),
        )
        if candidate_tax_id == tax_id:
            exact_tax_match = candidate
            break
        if not candidate_tax_id:
            if missing_tax_match is None:
                missing_tax_match = candidate
            continue
        conflicting_tax_matches.append(candidate)

    if exact_tax_match:
        return {
            "status": "existing",
            "missing_before": False,
            "customer_guid": str(exact_tax_match.get("id") or "").strip(),
            "customer_name": str(exact_tax_match.get("name") or po.customer_name or "").strip(),
        }

    if conflicting_tax_matches:
        conflicting_ids = ", ".join(
            sorted(
                {
                    re.sub(
                        r"\D+",
                        "",
                        str(
                            item.get("taxId")
                            or item.get("idNumber")
                            or item.get("vatNumber")
                            or item.get("companyNumber")
                            or ""
                        ).strip(),
                    )
                    for item in conflicting_tax_matches
                    if str(
                        item.get("taxId")
                        or item.get("idNumber")
                        or item.get("vatNumber")
                        or item.get("companyNumber")
                        or ""
                    ).strip()
                }
            )
        )
        raise RuntimeError(
            f"נמצא בחשבונית ירוקה לקוח עם אותו שם אבל עם ח.פ אחר ({conflicting_ids}). "
            "המערכת עצרה כדי לא ליצור כפילות או לשייך מסמך ללקוח שגוי."
        )

    if missing_tax_match:
        payload = _build_manual_customer_payload(po)
        payload["name"] = str(missing_tax_match.get("name") or po.customer_name or "").strip()
        await client.update_client(str(missing_tax_match.get("id") or "").strip(), payload)
        updated_customer = await client.get_existing_customer_details(tax_id)
        if not updated_customer:
            raise RuntimeError("הלקוח נמצא לפי שם, אבל עדכון הח.פ שלו בחשבונית ירוקה לא אומת בהצלחה.")
        return {
            "status": "existing",
            "missing_before": False,
            "customer_guid": str(updated_customer.get("id") or "").strip(),
            "customer_name": str(updated_customer.get("name") or po.customer_name or "").strip(),
        }

    payload = _build_manual_customer_payload(po)
    if not payload.get("name"):
        raise RuntimeError("חסר שם לקוח, ולכן אי אפשר להקים לקוח חדש בחשבונית ירוקה.")

    try:
        await client.create_client(payload)
    except Exception as exc:
        # GreenInvoice sometimes returns a generic 400 even when the customer
        # was actually created or already exists by the time we retry lookup.
        created_or_existing_customer = await client.get_existing_customer_details(tax_id)
        if created_or_existing_customer:
            return {
                "status": "created",
                "missing_before": True,
                "customer_guid": str(created_or_existing_customer.get("id") or "").strip(),
                "customer_name": str(created_or_existing_customer.get("name") or payload.get("name") or "").strip(),
            }
        raise RuntimeError(f"לא הצלחתי ליצור לקוח חדש בחשבונית ירוקה: {exc}") from exc

    fetched_rows = await _fetch_greeninvoice_customers(mode)
    save_customer_rows(_sort_customer_rows(fetched_rows))

    created_customer = await client.get_existing_customer_details(tax_id)
    if not created_customer:
        raise RuntimeError("הלקוח נוצר לכאורה, אבל לא נמצא אחר כך לפי ח.פ בחשבונית ירוקה.")
    return {
        "status": "created",
        "missing_before": True,
        "customer_guid": str((created_customer or {}).get("id") or "").strip(),
        "customer_name": str((created_customer or {}).get("name") or payload.get("name") or "").strip(),
    }


def _customer_email_list(value: str | list[str] | None) -> list[str]:
    if isinstance(value, list):
        raw_parts = value
    else:
        raw_parts = re.split(r"[;,]+", str(value or ""))
    emails: list[str] = []
    seen: set[str] = set()
    for part in raw_parts:
        email = str(part or "").strip()
        lowered = email.lower()
        if not email or lowered in seen:
            continue
        seen.add(lowered)
        emails.append(email)
    return emails


def _greeninvoice_customer_email_text(customer: dict | None) -> str:
    source = customer or {}
    collected: list[str] = []
    for key in ("emails", "email", "mail"):
        value = source.get(key)
        if isinstance(value, list):
            for item in value:
                if isinstance(item, dict):
                    collected.extend(
                        [
                            str(item.get("email") or "").strip(),
                            str(item.get("mail") or "").strip(),
                            str(item.get("address") or "").strip(),
                            str(item.get("value") or "").strip(),
                        ]
                    )
                else:
                    collected.append(str(item or "").strip())
        elif isinstance(value, dict):
            collected.extend(
                [
                    str(value.get("email") or "").strip(),
                    str(value.get("mail") or "").strip(),
                    str(value.get("address") or "").strip(),
                    str(value.get("value") or "").strip(),
                ]
            )
        else:
            collected.append(str(value or "").strip())
    normalized = _customer_email_list([entry for entry in collected if str(entry or "").strip()])
    return ", ".join(normalized)


async def _enrich_quote_history_row_customer_email(row: dict) -> tuple[dict, bool]:
    normalized_row = dict(row or {})
    existing_email = ", ".join(_customer_email_list(normalized_row.get("customer_email") or ""))
    if existing_email:
        normalized_row["customer_email"] = existing_email
        return normalized_row, False
    mode = str(normalized_row.get("mode") or "PROD").strip().upper()
    customer_id = re.sub(r"\D+", "", str(normalized_row.get("customer_id") or ""))
    customer_name = str(normalized_row.get("customer_name") or "").strip()
    if not customer_id and not customer_name:
        return normalized_row, False
    cfg = get_mode_config(mode)
    client = GreenInvoiceClient(
        base_url=cfg["base_url"],
        api_key=cfg["api_key"],
        api_secret=cfg["api_secret"],
    )
    customer: dict | None = None
    try:
        if customer_id:
            customer = await client.get_existing_customer_details(customer_id)
        if not customer and customer_name:
            customer = await client.get_existing_customer_details_by_name(customer_name)
    except Exception as exc:
        log_handled_error("quote history customer email lookup failed", exc)
        return normalized_row, False
    customer_email = _greeninvoice_customer_email_text(customer)
    if not customer_email:
        return normalized_row, False
    normalized_row["customer_email"] = customer_email
    normalized_row["updated_at"] = datetime.now().isoformat(timespec="seconds")
    return normalized_row, True


def _customer_mail_plain_text(html: str, fallback: str = "") -> str:
    raw = str(html or "").strip()
    if not raw:
        return str(fallback or "").strip()
    raw = re.sub(r"(?i)<br\\s*/?>", "\n", raw)
    raw = re.sub(r"(?i)</p>", "\n\n", raw)
    raw = re.sub(r"<[^>]+>", "", raw)
    raw = raw.replace("&nbsp;", " ").replace("&amp;", "&")
    raw = re.sub(r"\n{3,}", "\n\n", raw)
    return raw.strip() or str(fallback or "").strip()


def _normalize_contact_phone(value: str) -> str:
    raw = (value or "").strip()
    if not raw:
        return ""
    digits = "".join(ch for ch in raw if ch.isdigit())
    if len(digits) == 10 and digits.startswith("0"):
        return f"{digits[:3]}-{digits[3:]}"
    if len(digits) == 9 and digits.startswith("5"):
        return f"0{digits[:2]}-{digits[2:]}"
    return raw


def _income_range_from_preset(preset: str, custom_start: str = "", custom_end: str = "") -> tuple[str, str, str]:
    today = date.today()
    preset = (preset or "last_30_days").strip().lower()

    if preset == "current_year":
        start = date(today.year, 1, 1)
        end = today
        label = f"{today.year}"
    elif preset == "last_12_months":
        start = today - timedelta(days=365)
        end = today
        label = "12 החודשים האחרונים"
    elif preset == "previous_year":
        previous_year = today.year - 1
        start = date(previous_year, 1, 1)
        end = date(previous_year, 12, 31)
        label = f"{previous_year}"
    elif preset == "custom":
        try:
            start = date.fromisoformat((custom_start or "").strip())
            end = date.fromisoformat((custom_end or "").strip())
        except Exception:
            raise ValueError("טווח התאריכים הידני לא תקין.")
        if end < start:
            raise ValueError("תאריך הסיום לא יכול להיות לפני תאריך ההתחלה.")
        label = f"{start.strftime('%d/%m/%Y')}–{end.strftime('%d/%m/%Y')}"
    else:
        start = today - timedelta(days=30)
        end = today
        label = "30 הימים האחרונים"

    return start.isoformat(), end.isoformat(), label


def _payment_rows_missing_receipts(rows: list[dict]) -> list[dict]:
    candidates: list[dict] = []
    seen: set[tuple[str, str, str, str]] = set()
    for row in rows or []:
        payment_direction = str(row.get("payment_direction") or "").strip()
        invoice_number = str(row.get("tax_invoice_number") or "").strip()
        receipt_number = str(row.get("receipt_number") or "").strip()
        if payment_direction != "גביה" or receipt_number or not invoice_number:
            continue
        key = (
            invoice_number,
            str(row.get("po_number") or "").strip(),
            str(row.get("_sheet_title") or ""),
            str(row.get("_sheet_row") or ""),
        )
        if key in seen:
            continue
        seen.add(key)
        candidates.append(row)
    return candidates


def _normalize_name_for_receipt_match(value: str) -> str:
    value = re.sub(r"\s+", " ", str(value or "").strip()).lower()
    value = value.replace("״", '"').replace("”", '"').replace("“", '"').replace("׳", "'")
    value = re.sub(r"[\"'`]", "", value)
    value = value.replace("פרוייקטים", "פרויקטים")
    value = value.replace("ייזום", "יזום")
    return value.strip()


def _normalize_money_for_receipt_match(value) -> float:
    try:
        text = str(value or "").replace("₪", "").replace(",", "").strip()
        return round(float(text), 2)
    except Exception:
        return 0.0


def _pick_receipt_for_payment_row(row: dict, receipt_links: list[dict]) -> dict | None:
    payment_direction = str(row.get("payment_direction") or "").strip()
    invoice_number = str(row.get("tax_invoice_number") or "").strip()
    po_number = str(row.get("po_number") or "").strip()
    customer_name = _normalize_name_for_receipt_match(row.get("customer_name") or "")
    row_amount = _normalize_money_for_receipt_match(row.get("amount"))

    if payment_direction != "גביה" or not invoice_number:
        return None

    invoice_matches = [
        link for link in receipt_links
        if str(link.get("linked_invoice_number") or "").strip() == invoice_number
    ]
    if invoice_matches:
        return sorted(invoice_matches, key=lambda link: str(link.get("document_date") or ""), reverse=True)[0]

    po_matches = [
        link for link in receipt_links
        if po_number and str(link.get("linked_po_number") or "").strip() == po_number
    ]
    if not po_matches:
        return None

    strong_matches = []
    for link in po_matches:
        link_name = _normalize_name_for_receipt_match(link.get("customer_name") or "")
        link_amount = _normalize_money_for_receipt_match(link.get("amount"))
        same_customer = bool(customer_name and link_name and customer_name == link_name)
        amount_close = bool(row_amount and link_amount and abs(row_amount - link_amount) <= 0.05)
        if same_customer or amount_close:
            strong_matches.append(link)

    if len(strong_matches) == 1:
        return strong_matches[0]
    if strong_matches:
        return sorted(strong_matches, key=lambda link: str(link.get("document_date") or ""), reverse=True)[0]
    return None


def _receipt_link_matches_row(row: dict, link: dict | None) -> bool:
    if not link:
        return False
    payment_direction = str(row.get("payment_direction") or "").strip()
    invoice_number = str(row.get("tax_invoice_number") or "").strip()
    po_number = str(row.get("po_number") or "").strip()
    customer_name = _normalize_name_for_receipt_match(row.get("customer_name") or "")
    row_amount = _normalize_money_for_receipt_match(row.get("amount"))
    linked_invoice = str(link.get("linked_invoice_number") or "").strip()
    linked_po = str(link.get("linked_po_number") or "").strip()
    link_name = _normalize_name_for_receipt_match(link.get("customer_name") or "")
    link_amount = _normalize_money_for_receipt_match(link.get("amount"))

    if payment_direction != "גביה" or not invoice_number:
        return False
    if linked_invoice == invoice_number:
        return True
    if po_number and linked_po == po_number and (
        (customer_name and link_name and customer_name == link_name)
        or (row_amount and link_amount and abs(row_amount - link_amount) <= 0.05)
    ):
        return True
    return False


async def _sync_missing_payment_receipts_with_greeninvoice(since_date: str = "") -> dict:
    state = load_payment_transfer_rows(force_refresh=True, repair_schema=False)
    all_rows = state.get("all_rows") or []
    since_dt = _parse_payment_sync_date(since_date)

    if since_dt:
        candidate_rows = [
            row for row in all_rows
            if (_payment_row_invoice_date(row) or since_dt) >= since_dt
        ]
    else:
        candidate_rows = list(all_rows)

    cfg = get_mode_config("prod")
    client = GreenInvoiceClient(
        base_url=cfg["base_url"],
        api_key=cfg["api_key"],
        api_secret=cfg["api_secret"],
    )
    receipt_links = await client.list_receipt_links(
        date_from=since_dt.isoformat() if since_dt else "2022-01-01",
        date_to=date.today().isoformat(),
        page_size=100,
        max_pages=100,
    )
    receipt_by_number = {
        str(link.get("receipt_number") or "").strip(): link
        for link in receipt_links
        if str(link.get("receipt_number") or "").strip()
    }

    cleanup_updates: list[dict] = []
    for row in candidate_rows:
        receipt_number = str(row.get("receipt_number") or "").strip()
        if not receipt_number:
            continue
        link = receipt_by_number.get(receipt_number)
        if _receipt_link_matches_row(row, link):
            continue
        sheet_title = str(row.get("_sheet_title") or "").strip()
        row_number = int(row.get("_sheet_row") or 0)
        if not sheet_title or row_number <= 0:
            continue
        cleanup_updates.append(
            {
                "sheet_title": sheet_title,
                "row_number": row_number,
                "receipt_number": "",
                "paid": row.get("paid") or "",
            }
        )

    synced_count = 0
    if cleanup_updates:
        cleanup_result = batch_update_payment_transfer_receipts(cleanup_updates)
        synced_count += int(cleanup_result.get("updated_rows") or 0)
        state = load_payment_transfer_rows(repair_schema=False)
        all_rows = state.get("all_rows") or []
        if since_dt:
            candidate_rows = [
                row for row in all_rows
                if (_payment_row_invoice_date(row) or since_dt) >= since_dt
            ]
        else:
            candidate_rows = list(all_rows)

    missing_rows = _payment_rows_missing_receipts(candidate_rows)
    if not missing_rows:
        return {"state": state, "synced_count": synced_count, "performed": True, "since_date": since_dt.isoformat() if since_dt else ""}

    batched_updates: list[dict] = []
    for row in missing_rows:
        match = _pick_receipt_for_payment_row(row, receipt_links)
        if not match:
            continue
        receipt_number = str(match.get("receipt_number") or "").strip()
        if not receipt_number:
            continue
        sheet_title = str(row.get("_sheet_title") or "").strip()
        row_number = int(row.get("_sheet_row") or 0)
        if not sheet_title or row_number <= 0:
            invoice_number = str(row.get("tax_invoice_number") or "").strip()
            result = sync_payment_transfer_receipt_by_invoice_number(
                invoice_number=invoice_number,
                receipt_number=receipt_number,
                paid=True,
            )
            synced_count += int(result.get("updated_rows") or 0)
            continue
        batched_updates.append(
            {
                "sheet_title": sheet_title,
                "row_number": row_number,
                "receipt_number": receipt_number,
                "paid": True,
            }
        )

    if batched_updates:
        result = batch_update_payment_transfer_receipts(batched_updates)
        synced_count += int(result.get("updated_rows") or 0)

    if synced_count:
        state = load_payment_transfer_rows(repair_schema=False)
    return {"state": state, "synced_count": synced_count, "performed": True, "since_date": since_dt.isoformat() if since_dt else ""}


def _extract_additional_contacts(text: str, excluded_numbers: set[str] | None = None) -> list[tuple[str, str]]:
    import re

    excluded_numbers = excluded_numbers or set()
    source = text or ""
    results: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()
    patterns = [
        re.compile(r"(?:איש קשר|לידי)\s*[:\-]?\s*([^\n,|]+?)\s+(?:טלפון|נייד)?\s*[:\-]?\s*(05\d[-\s]?\d{7}|0\d{1,2}-\d{7})"),
        re.compile(r"([א-ת\"'׳\-\s]{2,40}?)\s*[-–:]\s*(05\d[-\s]?\d{7}|0\d{1,2}-\d{7})"),
    ]
    for pattern in patterns:
        for match in pattern.finditer(source):
            name = re.sub(r"\s+", " ", (match.group(1) or "").strip(" -:\n\t"))
            phone = _normalize_contact_phone(match.group(2) or "")
            if not name or not phone or phone in excluded_numbers:
                continue
            key = (name, phone)
            if key in seen:
                continue
            seen.add(key)
            results.append(key)
    return results


def _split_contact_candidates(name_value: str, phone_value: str) -> list[tuple[str, str]]:
    name_value = re.sub(r"\s+", " ", str(name_value or "").strip())
    phone_matches = re.findall(r"0\d{1,2}[-\s]?\d{7}|05\d[-\s]?\d{7}", str(phone_value or ""))
    if not phone_matches:
        cleaned_name, cleaned_phone = sanitize_contact_pair(name_value, phone_value)
        return [(cleaned_name, cleaned_phone)] if cleaned_phone else []

    names = [
        re.sub(r"\s+", " ", chunk.strip(" -/|,"))
        for chunk in re.split(r"\s*/\s*|\s*\|\s*|,|;", name_value)
        if re.sub(r"\s+", " ", chunk.strip(" -/|,"))
    ]
    contacts: list[tuple[str, str]] = []
    for idx, raw_phone in enumerate(phone_matches):
        candidate_name = names[idx] if idx < len(names) else (names[0] if len(names) == 1 else "")
        clean_name, clean_phone = sanitize_contact_pair(candidate_name, raw_phone)
        if clean_phone:
            contacts.append((clean_name, clean_phone))
    return contacts


def _project_manager_entries_from_po(po: PurchaseOrderData) -> list[dict]:
    extra = po.extra or {}
    excluded_numbers = {
        _normalize_contact_phone(po.customer_phone or ""),
        _normalize_contact_phone("0547720142"),
        _normalize_contact_phone("0505204010"),
        _normalize_contact_phone("0503011503"),
    }
    company = po.customer_name or ""
    tax_id = str(po.customer_id or "").strip()
    site_address = po.delivery_address or extra.get("delivery_address", "")
    order_date = po.po_date or ""
    item = po.items[0].description if po.items else (extra.get("item_description") or "")

    if not re.sub(r"\s+", " ", company).strip():
        return []
    if not re.sub(r"\s+", " ", site_address).strip():
        return []

    contacts_by_phone: dict[str, tuple[str, str]] = {}

    def register_contact(name: str, phone: str):
        clean_name, clean_phone = sanitize_contact_pair(name, phone, customer_phone=po.customer_phone or "")
        clean_phone = _normalize_contact_phone(clean_phone)
        if not clean_phone or clean_phone in excluded_numbers:
            return
        current = contacts_by_phone.get(clean_phone)
        if current:
            current_name = re.sub(r"\s+", " ", str(current[0] or "").strip())
            if clean_name and not current_name:
                contacts_by_phone[clean_phone] = (clean_name, clean_phone)
            return
        contacts_by_phone[clean_phone] = (clean_name, clean_phone)

    for name, phone in _split_contact_candidates(
        str(extra.get("contact_name") or "").strip(),
        str(extra.get("contact_phone") or "").strip(),
    ):
        register_contact(name, phone)

    for name, phone in _extract_additional_contacts(
        "\n".join(filter(None, [po.raw_text or "", extra.get("footer_text", ""), site_address])),
        excluded_numbers=excluded_numbers,
    ):
        register_contact(name, phone)

    rows = []
    for phone, (name, normalized_phone) in contacts_by_phone.items():
        rows.append(
            {
                "company": company,
                "tax_id": tax_id,
                "site_address": site_address,
                "contact_name": name,
                "order_date": order_date,
                "item": item,
                "contact_phone": normalized_phone,
            }
        )
    return rows


async def _enrich_po_for_process(po: PurchaseOrderData, cfg: dict) -> PurchaseOrderData:
    customer_data = None
    # 🔥 override מ-GI רק לימי אשראי / תנאי תשלום
    try:
        client = GreenInvoiceClient(
            base_url=cfg["base_url"],
            api_key=cfg["api_key"],
            api_secret=cfg["api_secret"],
        )

        if po.customer_id:
            customer_data = await client.get_existing_customer_details(po.customer_id)

            if customer_data:
                days = client._resolve_payment_days_for_customer(
                    customer_data=customer_data,
                    customer_id=po.customer_id or "",
                    customer_name=po.customer_name or "",
                )
                if days is not None:
                    po.payment_terms_days = days
                    po.payment_terms_label = f"שוטף + {days}"

        extra = po.extra or {}

        # ברוש - כתובת ואיש קשר תמיד מה-PO, לא מ-GI
        if "ברוש ניר עבודות הנדסה" in (po.raw_text or ""):
            import re
            flat = re.sub(r"\s+", " ", po.raw_text or "").strip()

            m = re.search(
                r"כתובת למשלוח:\s*(?P<addr>.+?)\s+(?P=addr)\s+לידי:\s*(?P<contact>.+?)\s+טלפון:\s*(?P<phone>0\d{1,2}-\d{7})\s+לכבוד:",
                flat
            )

            if m:
                po.delivery_address = m.group("addr").strip()
                extra["contact_name"] = m.group("contact").strip()
                extra["contact_phone"] = m.group("phone").strip()
            else:
                if 'לואי מרשל 2-4 ת"א' in flat:
                    po.delivery_address = 'לואי מרשל 2-4 ת"א'
                if 'לידי: עמית פרץ' in flat:
                    extra["contact_name"] = 'עמית פרץ'
                if '054-4847360' in flat:
                    extra["contact_phone"] = '054-4847360'

            footer_parts = []
            if po.po_number:
                footer_parts.append(f"הזמנת רכש {po.po_number}")
            if extra.get("project"):
                footer_parts.append(f"פרויקט: {extra.get('project')}")
            if po.delivery_address:
                footer_parts.append(f"כתובת לאספקה: {po.delivery_address}")
            if extra.get("contact_name"):
                footer_parts.append(f"איש קשר: {extra.get('contact_name')}")
            if extra.get("contact_phone"):
                footer_parts.append(f"טל': {extra.get('contact_phone')}")
            extra["footer_text"] = " | ".join(footer_parts)

        po.extra = extra

        text = po.raw_text or ""
        if "ברוש ניר עבודות הנדסה" in text:
            m_block = re.search(
                r"כתובת למשלוח:\s*(.*?)\s*לכבוד:",
                text,
                re.DOTALL
            )

            if m_block:
                block = m_block.group(1)

                m_addr = re.search(
                    r"^\s*([^\n]+)\n\s*([^\n]+)",
                    block,
                    re.MULTILINE
                )
                if m_addr:
                    line1 = m_addr.group(1).strip()
                    line2 = m_addr.group(2).strip()
                    po.delivery_address = line1 if line1 == line2 else f"{line1} / {line2}"

                m_contact = re.search(r"לידי:\s*([^\n]+)", block)
                if m_contact:
                    extra["contact_name"] = m_contact.group(1).strip()

                m_phone = re.search(r"טלפון:\s*(0\d{1,2}-\d{7})", block)
                if m_phone:
                    extra["contact_phone"] = m_phone.group(1).strip()

            if not po.delivery_address and 'לואי מרשל 2-4 ת"א' in text:
                po.delivery_address = 'לואי מרשל 2-4 ת"א'
            if not extra.get("contact_name") and "לידי: עמית פרץ" in text:
                extra["contact_name"] = "עמית פרץ"
            if not extra.get("contact_phone") and "054-4847360" in text:
                extra["contact_phone"] = "054-4847360"

            footer_parts = []
            if po.po_number:
                footer_parts.append(f"הזמנת רכש {po.po_number}")
            if extra.get("project"):
                footer_parts.append(f"פרויקט: {extra.get('project')}")
            if po.delivery_address:
                footer_parts.append(f"כתובת לאספקה: {po.delivery_address}")
            if extra.get("contact_name"):
                footer_parts.append(f"איש קשר: {extra.get('contact_name')}")
            if extra.get("contact_phone"):
                footer_parts.append(f"טל': {extra.get('contact_phone')}")
            extra["footer_text"] = " | ".join(footer_parts)

        po.extra = extra

    except Exception as e:
        print("FINAL OVERRIDE ERROR:", repr(e))

    try:
        if customer_data:
            client = GreenInvoiceClient(
                base_url=cfg["base_url"],
                api_key=cfg["api_key"],
                api_secret=cfg["api_secret"],
            )
            keep_delivery = po.delivery_address
            keep_contact_name = (po.extra or {}).get("contact_name", "")
            keep_contact_phone = (po.extra or {}).get("contact_phone", "")

            po = client._merge_customer_data_into_po(po, customer_data)

            po.extra = po.extra or {}
            po.delivery_address = keep_delivery or po.delivery_address
            po.extra["contact_name"] = keep_contact_name or po.extra.get("contact_name", "")
            po.extra["contact_phone"] = keep_contact_phone or po.extra.get("contact_phone", "")

            footer_parts = []
            if po.po_number:
                footer_parts.append(f"הזמנת רכש {po.po_number}")
            if po.extra.get("project"):
                footer_parts.append(f"פרויקט: {po.extra.get('project')}")
            if po.delivery_address:
                footer_parts.append(f"כתובת לאספקה: {po.delivery_address}")
            if po.extra.get("contact_name"):
                footer_parts.append(f"איש קשר: {po.extra.get('contact_name')}")
            if po.extra.get("contact_phone"):
                footer_parts.append(f"טל': {po.extra.get('contact_phone')}")
            po.extra["footer_text"] = " | ".join(footer_parts)
    except Exception as e:
        print("GI ENRICH DURING PROCESS FAILED:", repr(e))

    return po


def _sync_project_managers_from_pdf_sync(file_path: Path, po: PurchaseOrderData) -> None:
    try:
        upsert_project_manager_rows(
            extract_project_manager_entries_from_pdf(file_path, parsed_po=po)
        )
    except Exception as e:
        print("PROJECT MANAGERS SYNC ERROR:", repr(e))


async def _sync_project_managers_from_pdf_background(file_path: Path, po: PurchaseOrderData) -> None:
    try:
        await asyncio.to_thread(_sync_project_managers_from_pdf_sync, file_path, po)
    except Exception as exc:
        log_handled_error("project_managers_process_background_sync failed", exc)


