@app.get("/mobile/auth/bootstrap")
async def mobile_auth_bootstrap(request: Request):
    try:
        state = load_auth_state()
        users = list_auth_users(state)
        authenticated = is_request_authenticated(request)
        selected_user_id = (
            authenticated_user_id(request)
            or str(request.query_params.get("user") or state.get("default_user_id") or "asaf").strip()
            or "asaf"
        )
        selected_user = next((user for user in users if str(user.get("id") or "").strip() == selected_user_id), None) or (users[0] if users else {})
        selected_user_id = str(selected_user.get("id") or selected_user_id or state.get("default_user_id") or "asaf").strip() or "asaf"
        methods = get_enabled_methods(state, selected_user_id)
        return JSONResponse(
            {
                "status": "ok",
                "authenticated": authenticated,
                "selected_user_id": selected_user_id,
                "selected_user_name": str(selected_user.get("display_name") or selected_user.get("username") or selected_user_id),
                "methods": methods,
                "auth_users": [
                    {
                        "id": str(user.get("id") or ""),
                        "display_name": str(user.get("display_name") or user.get("username") or user.get("id") or ""),
                        "email_address": str(user.get("email_address") or "").strip(),
                        "methods": get_enabled_methods(state, str(user.get("id") or "")),
                        "setup_required": not has_any_enabled_method(state, str(user.get("id") or "")),
                    }
                    for user in users
                ],
                "source_label": f"backend:{settings.data_backend}",
            }
        )
    except Exception as exc:
        log_handled_error("mobile_auth_bootstrap failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לטעון כרגע את מצב ההתחברות למובייל: {exc}"}, status_code=500)


@app.get("/mobile/domains/{domain}")
async def mobile_domain_rows(domain: str, force_refresh: bool = False, limit: int = 0):
    try:
        rows = _load_mobile_domain_rows(domain, force_refresh=force_refresh)
        if limit > 0:
            rows = rows[:limit]
        return JSONResponse(
            {
                "status": "ok",
                "domain": str(domain or "").strip().lower().replace("-", "_"),
                "count": len(rows),
                "source_label": f"backend:{settings.data_backend}",
                "rows": rows,
            }
        )
    except KeyError:
        return JSONResponse({"error": f"דומיין mobile לא נתמך: {domain}"}, status_code=404)
    except Exception as exc:
        log_handled_error("mobile_domain_rows failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לטעון כרגע את הדומיין {domain}: {exc}"}, status_code=500)


