def _quote_file_relative_to_output(path: Path | str | None) -> str:
    if not path:
        return ""
    try:
        return str(Path(path).resolve().relative_to(OUTPUT_DIR.resolve()))
    except Exception:
        return ""


def _label_unit_text(value: str) -> str:
    raw = str(value or "").strip()
    if not raw:
        return "יח׳"
    if raw in {"יחידה", "יחידות", "יח׳", "יח'"}:
        return "יח׳"
    return raw


def _sync_quote_pdf_to_drive(po: PurchaseOrderData, quote_pdf_path: Path) -> dict:
    root_id = managed_storage_root_folder_id()
    customer_folder_id = ensure_child_folder(root_id, _guess_customer_folder_name(po.customer_name))
    order_folder_id = ensure_child_folder(customer_folder_id, _guess_order_folder_name(po.po_number, po.po_date))
    drive_name = quote_pdf_path.name
    uploaded = ensure_file_in_folder(order_folder_id, quote_pdf_path, drive_name=drive_name)
    return {
        "status": "ok",
        "customer_folder_id": customer_folder_id,
        "order_folder_id": order_folder_id,
        "uploaded": uploaded,
        "quote_drive_file_id": str(uploaded.get("id") or "").strip(),
        "quote_drive_url": str(uploaded.get("web_view_link") or uploaded.get("webViewLink") or "").strip(),
        "quote_drive_folder_url": f"https://drive.google.com/drive/folders/{order_folder_id}",
    }


def _sync_inventory_purchase_order_pdf_to_drive(supplier_name: str, po_number: str, po_date: str, pdf_path: Path) -> dict:
    root_id = managed_storage_root_folder_id()
    inventory_root_id = ensure_child_folder(root_id, "הזמנות רכש ספקים")
    supplier_folder_id = ensure_child_folder(inventory_root_id, _guess_customer_folder_name(supplier_name or "ספק"))
    order_folder_id = ensure_child_folder(supplier_folder_id, _guess_order_folder_name(po_number or "PO", po_date))
    uploaded = ensure_file_in_folder(order_folder_id, pdf_path, drive_name=pdf_path.name)
    return {
        "status": "ok",
        "root_folder_id": inventory_root_id,
        "supplier_folder_id": supplier_folder_id,
        "order_folder_id": order_folder_id,
        "uploaded": uploaded,
        "po_drive_file_id": str(uploaded.get("id") or "").strip(),
        "po_drive_url": str(uploaded.get("web_view_link") or uploaded.get("webViewLink") or "").strip(),
        "drive_folder_url": f"https://drive.google.com/drive/folders/{order_folder_id}",
    }


def _inventory_purchase_order_file_relative_to_output(path: Path | str | None) -> str:
    return _quote_file_relative_to_output(path)


def _inventory_purchase_order_display_description(value: str, row: dict | None = None) -> str:
    base = str(value or "").strip()
    source = row or {}
    if not base:
        base = str(source.get("product") or source.get("material") or "").strip()
    length = str(source.get("length") or "").strip()
    width = str(source.get("width") or "").strip()
    thickness = str(source.get("thickness") or "").strip()
    dims = [part for part in (length, width, thickness) if part]
    if not base:
        return "—"
    if not dims:
        return base
    return f"{base} | {' / '.join(dims)}"


def _inventory_purchase_order_row_send_status(row: dict | None = None) -> str:
    return str((row or {}).get("send_status") or "").strip().lower()


def _inventory_purchase_order_hidden_keys() -> set[str]:
    try:
        supabase_payload = _load_supabase_app_state("app_inventory_purchase_order_hidden_keys")
        if isinstance(supabase_payload, dict):
            items = supabase_payload.get("hidden_keys") or []
            if isinstance(items, list):
                return {str(item or "").strip() for item in items if str(item or "").strip()}
        if not INVENTORY_PURCHASE_ORDERS_HIDDEN_FILE.exists():
            return set()
        payload = json.loads(INVENTORY_PURCHASE_ORDERS_HIDDEN_FILE.read_text(encoding="utf-8"))
        if isinstance(payload, list):
            return {str(item or "").strip() for item in payload if str(item or "").strip()}
    except Exception as exc:
        log_handled_error("inventory purchase order hidden keys load failed", exc)
    return set()


def _save_inventory_purchase_order_hidden_keys(keys: set[str]) -> None:
    payload = {"hidden_keys": sorted(str(key or "").strip() for key in keys if str(key or "").strip())}
    _save_supabase_app_state("app_inventory_purchase_order_hidden_keys", payload)
    try:
        INVENTORY_PURCHASE_ORDERS_HIDDEN_FILE.write_text(
            json.dumps(payload["hidden_keys"], ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
    except Exception as exc:
        log_handled_error("inventory purchase order hidden keys save failed", exc)


def _inventory_purchase_order_hidden_key(row: dict | None = None, *, mode: str = "", po_number: str = "", po_document_id: str = "") -> str:
    document_id = str(po_document_id or (row or {}).get("po_document_id") or "").strip()
    if document_id:
        return f"doc::{document_id}"
    normalized_mode = str(mode or (row or {}).get("mode") or "").strip().lower() or "production"
    normalized_number = str(po_number or (row or {}).get("po_number") or "").strip()
    if not normalized_number:
        return ""
    return f"{normalized_mode}::{normalized_number}"


async def _sync_recent_greeninvoice_purchase_orders(limit: int = 5) -> tuple[list[dict], str]:
    rows = load_inventory_purchase_order_rows()
    hidden_keys = _inventory_purchase_order_hidden_keys()
    cfg = get_mode_config("prod")
    if not cfg.get("api_key") or not cfg.get("api_secret"):
        return rows, ""

    client = GreenInvoiceClient(
        base_url=cfg["base_url"],
        api_key=cfg["api_key"],
        api_secret=cfg["api_secret"],
    )
    token = await client._get_token()
    date_to = date.today().strftime("%Y-%m-%d")
    date_from = (date.today() - timedelta(days=730)).strftime("%Y-%m-%d")
    documents = await client.get_purchase_order_documents(date_from=date_from, date_to=date_to, max_pages=24)
    if not documents:
        return rows, ""

    rows_by_document_id = {
        str(row.get("po_document_id") or "").strip(): row
        for row in rows
        if str(row.get("po_document_id") or "").strip()
    }
    rows_by_number = {
        f"{str(row.get('mode') or '').strip().lower()}::{str(row.get('po_number') or '').strip()}": row
        for row in rows
        if str(row.get("po_number") or "").strip()
    }
    changed = False
    for doc in documents[: max(0, limit)]:
        po_document_id = str(doc.get("id") or "").strip()
        po_number = str(doc.get("number") or "").strip()
        po_date = str(doc.get("date") or "").strip()
        hidden_key = _inventory_purchase_order_hidden_key(mode="production", po_number=po_number, po_document_id=po_document_id)
        if hidden_key and hidden_key in hidden_keys:
            continue
        row = rows_by_document_id.get(po_document_id) or rows_by_number.get(f"production::{po_number}")
        raw_item = doc.get("raw") if isinstance(doc.get("raw"), dict) else {}
        client_info = raw_item.get("client") if isinstance(raw_item.get("client"), dict) else {}
        supplier_name = _canonical_income_customer_name(doc.get("customer_name") or "") or str(doc.get("customer_name") or "").strip()
        supplier_id = str(doc.get("customer_id") or "").strip()
        supplier_email = str(doc.get("customer_email") or client_info.get("email") or "").strip()
        supplier_phone = str(doc.get("customer_phone") or client_info.get("phone") or client_info.get("mobile") or "").strip()
        item_description = str(doc.get("item_name") or "").strip()
        item_sku = str(doc.get("item_sku") or "").strip()
        item_quantity = _normalize_inventory_numeric_text(doc.get("item_quantity"))
        item_unit = str(doc.get("item_unit") or "").strip()
        item_unit_price = _normalize_inventory_numeric_text(doc.get("item_unit_price"))
        source_url = str(doc.get("source_url") or "").strip()
        subtotal_text = _normalize_inventory_numeric_text(doc.get("subtotal"))
        vat_text = _normalize_inventory_numeric_text(doc.get("vat"))
        total_text = _normalize_inventory_numeric_text(doc.get("total"))

        local_file_rel = str(row.get("po_local_file") or "").strip() if row else ""
        po_drive_file_id = str(row.get("po_drive_file_id") or "").strip() if row else ""
        po_drive_url = str(row.get("po_drive_url") or "").strip() if row else ""
        drive_folder_id = str(row.get("drive_folder_id") or "").strip() if row else ""
        drive_folder_url = str(row.get("drive_folder_url") or "").strip() if row else ""

        if source_url and not (local_file_rel or po_drive_url):
            try:
                customer_folder_name = _guess_customer_folder_name(supplier_name or "ספק")
                order_folder_name = _guess_order_folder_name(po_number or "PO", po_date)
                local_dir = OUTPUT_DIR / "supplier_purchase_orders" / customer_folder_name / order_folder_name
                local_dir.mkdir(parents=True, exist_ok=True)
                safe_po_name = _safe_folder_name(po_number or po_document_id or "purchase_order") or "purchase_order"
                pdf_path = local_dir / f"{safe_po_name}_purchase_order.pdf"
                await client.download_pdf(token, source_url, pdf_path)
                if pdf_path.exists():
                    local_file_rel = _inventory_purchase_order_file_relative_to_output(pdf_path)
                    try:
                        drive_sync_result = _sync_inventory_purchase_order_pdf_to_drive(supplier_name, po_number, po_date, pdf_path)
                    except Exception as exc:
                        log_handled_error("inventory purchase order historical drive sync failed", exc)
                        drive_sync_result = {}
                    po_drive_file_id = str(drive_sync_result.get("po_drive_file_id") or po_drive_file_id).strip()
                    po_drive_url = str(drive_sync_result.get("po_drive_url") or po_drive_url).strip()
                    drive_folder_id = str(drive_sync_result.get("order_folder_id") or drive_folder_id).strip()
                    drive_folder_url = str(drive_sync_result.get("drive_folder_url") or drive_folder_url).strip()
            except Exception as exc:
                log_handled_error("inventory purchase order historical download failed", exc)

        if not po_drive_url:
            po_drive_url = source_url

        normalized_row = {
            "history_id": str(row.get("history_id") or uuid.uuid4().hex).strip() if row else uuid.uuid4().hex,
            "created_at": str(row.get("created_at") or f"{po_date}T12:00:00").strip() if row else f"{po_date}T12:00:00",
            "mode": "production",
            "supplier_name": supplier_name,
            "supplier_id": supplier_id,
            "supplier_email": supplier_email,
            "supplier_phone": supplier_phone,
            "po_number": po_number,
            "po_document_id": po_document_id,
            "po_date": po_date,
            "item_description": item_description,
            "item_sku": item_sku,
            "item_quantity": item_quantity or (str(row.get("item_quantity") or "").strip() if row else ""),
            "item_unit": item_unit or (str(row.get("item_unit") or "").strip() if row else ""),
            "item_unit_price": item_unit_price or (str(row.get("item_unit_price") or "").strip() if row else ""),
            "subtotal": subtotal_text or str(row.get("subtotal") or "").strip() if row else subtotal_text,
            "vat": vat_text or str(row.get("vat") or "").strip() if row else vat_text,
            "total": total_text or str(row.get("total") or "").strip() if row else total_text,
            "remarks": str(row.get("remarks") or "").strip() if row else "",
            "po_local_file": local_file_rel,
            "po_drive_file_id": po_drive_file_id,
            "po_drive_url": po_drive_url,
            "drive_folder_id": drive_folder_id,
            "drive_folder_url": drive_folder_url,
            "send_status": str(row.get("send_status") or "").strip() if row else "",
            "sent_at": str(row.get("sent_at") or "").strip() if row else "",
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
        if row:
            current_normalized = {key: str(row.get(key) or "") for key in normalized_row.keys()}
            incoming_normalized = {key: str(normalized_row.get(key) or "") for key in normalized_row.keys()}
            if current_normalized != incoming_normalized:
                row.update(normalized_row)
                changed = True
        else:
            rows.append(normalized_row)
            rows_by_document_id[po_document_id] = normalized_row
            rows_by_number[f"production::{po_number}"] = normalized_row
            changed = True

    rows.sort(key=lambda entry: str(entry.get("created_at") or ""), reverse=True)
    if changed:
        save_inventory_purchase_order_rows(rows)
    return rows, ""


def _inventory_supplier_contact_match(supplier_name: str) -> dict:
    target = _normalize_company_name(supplier_name)
    if not target:
        return {}
    for row in load_inventory_rows("contacts"):
        company = _normalize_company_name(str((row or {}).get("company") or ""))
        if company == target:
            return dict(row)
    lowered_target = target.lower()
    for row in load_inventory_rows("contacts"):
        company = _normalize_company_name(str((row or {}).get("company") or ""))
        if company.lower() == lowered_target or lowered_target in company.lower() or company.lower() in lowered_target:
            return dict(row)
    return {}


def _inventory_supplier_phone_match(supplier_name: str) -> str:
    match = _inventory_supplier_contact_match(supplier_name)
    return str(match.get("direct_phone") or match.get("company_phone") or "").strip()


def _inventory_supplier_email_match(supplier_name: str) -> str:
    match = _inventory_supplier_contact_match(supplier_name)
    return str(match.get("email") or "").strip()


