def _normalize_inventory_numeric_text(value) -> str:
    raw = str(value or "").strip().replace(",", "")
    if not raw:
        return ""
    try:
        amount = float(raw)
    except Exception:
        return raw
    if amount.is_integer():
        return str(int(amount))
    return f"{amount:.2f}".rstrip("0").rstrip(".")


def _inventory_numeric_value(value) -> float:
    raw = str(value or "").strip().replace(",", "")
    if not raw:
        return 0.0
    try:
        return float(raw)
    except Exception:
        return 0.0


def _canonical_supplier_name(value: str) -> str:
    clean = str(value or "").strip()
    if not clean:
        return ""
    if "פלציב" in clean:
        return "פלציב"
    if "אשקלון" in clean and "פולימרים" in clean:
        return "אשקלון פולימרים"
    return clean


def _raw_inventory_match_score(row: dict, item: dict, supplier_name: str) -> int:
    score = 0
    row_supplier = _canonical_supplier_name(row.get("supplier", ""))
    item_supplier = _canonical_supplier_name(supplier_name)
    if row_supplier and item_supplier and row_supplier == item_supplier:
        score += 4
    if str(row.get("supplier_sku") or "").strip() and str(item.get("supplier_sku") or "").strip():
        if str(row.get("supplier_sku") or "").strip() == str(item.get("supplier_sku") or "").strip():
            score += 10
    for field in ("product", "material", "length", "width", "thickness", "unit"):
        row_value = str(row.get(field) or "").strip()
        item_value = str(item.get(field) or "").strip()
        if row_value and item_value and row_value == item_value:
            score += 2
    return score


def _apply_supplier_delivery_note_to_inventory(raw_rows: list[dict], note_rows: list[dict], multiplier: float = 1.0) -> list[dict]:
    updated_rows = [dict(row) for row in (raw_rows or [])]
    for note_row in note_rows:
        quantity = _inventory_numeric_value(note_row.get("quantity")) * multiplier
        if quantity <= 0:
            if quantity == 0:
                continue
        supplier_name = str(note_row.get("supplier_name") or "").strip()
        best_index = -1
        best_score = 0
        for index, raw_row in enumerate(updated_rows):
            score = _raw_inventory_match_score(raw_row, note_row, supplier_name)
            if score > best_score:
                best_score = score
                best_index = index
        if best_index >= 0 and best_score >= 8:
            current_qty = _inventory_numeric_value(updated_rows[best_index].get("actual_quantity"))
            next_qty = current_qty + quantity
            updated_rows[best_index]["actual_quantity"] = _normalize_inventory_numeric_text(max(next_qty, 0))
            updated_rows[best_index]["updated_at"] = date.today().strftime("%d/%m/%Y")
            previous_notes = str(updated_rows[best_index].get("notes") or "").strip()
            note_tag = f"עודכן מתעודת משלוח {note_row.get('delivery_note_number', '')}".strip()
            if note_tag and note_tag not in previous_notes:
                updated_rows[best_index]["notes"] = " | ".join(part for part in [previous_notes, note_tag] if part)
            continue

        if quantity < 0:
            continue
        updated_rows.append(
            {
                "supplier": supplier_name,
                "supplier_sku": str(note_row.get("supplier_sku") or "").strip(),
                "product": str(note_row.get("product") or "").strip() or str(note_row.get("item_description") or "").strip(),
                "material": str(note_row.get("material") or "").strip(),
                "length": str(note_row.get("length") or "").strip(),
                "width": str(note_row.get("width") or "").strip(),
                "thickness": str(note_row.get("thickness") or "").strip(),
                "price": "",
                "unit": str(note_row.get("unit") or "").strip(),
                "actual_quantity": _normalize_inventory_numeric_text(quantity),
                "updated_at": date.today().strftime("%d/%m/%Y"),
                "notes": f"נוצר מתעודת משלוח {note_row.get('delivery_note_number', '')}".strip(),
            }
        )
    return updated_rows


def _supplier_delivery_note_summary_rows(rows: list[dict]) -> list[dict]:
    grouped: dict[tuple[str, str, str, str], dict] = {}
    for row in rows:
        key = (
            str(row.get("supplier_name") or "").strip(),
            str(row.get("product") or "").strip(),
            str(row.get("material") or "").strip(),
            str(row.get("unit") or "").strip(),
        )
        entry = grouped.setdefault(
            key,
            {
                "supplier_name": key[0],
                "product": key[1],
                "material": key[2],
                "unit": key[3],
                "quantity_total": 0.0,
                "delivery_dates": set(),
                "delivery_notes": set(),
            },
        )
        entry["quantity_total"] += _inventory_numeric_value(row.get("quantity"))
        if str(row.get("delivery_date") or "").strip():
            entry["delivery_dates"].add(str(row.get("delivery_date") or "").strip())
        if str(row.get("delivery_note_number") or "").strip():
            entry["delivery_notes"].add(str(row.get("delivery_note_number") or "").strip())
    output = []
    for entry in grouped.values():
        output.append(
            {
                "supplier_name": entry["supplier_name"],
                "product": entry["product"],
                "material": entry["material"],
                "unit": entry["unit"],
                "quantity_total": _normalize_inventory_numeric_text(entry["quantity_total"]),
                "delivery_dates": ", ".join(sorted(entry["delivery_dates"], reverse=True)),
                "delivery_notes": ", ".join(sorted(entry["delivery_notes"], reverse=True)),
            }
        )
    output.sort(key=lambda row: (row["supplier_name"], row["material"], row["product"]))
    return output


