@app.post("/pricing-bom-state")
async def save_pricing_bom_state(request: Request):
    body = await request.json()
    item_rows = body.get("items") or []
    component_rows = body.get("components") or []
    if not isinstance(item_rows, list) or not isinstance(component_rows, list):
        return JSONResponse({"error": "מבנה תמחור לא תקין."}, status_code=400)
    try:
        items_result = save_pricing_rows("items", item_rows)
        components_result = save_pricing_rows("components", component_rows)
        payload = _pricing_payload(force_refresh=True)
        return JSONResponse(
            {
                "status": "ok",
                "items_result": items_result,
                "components_result": components_result,
                **payload,
            }
        )
    except Exception as exc:
        log_handled_error("pricing_bom_state save failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשמור את תמחור ועצי המוצר: {exc}"}, status_code=500)


