@app.post("/inventory-purchase-orders-create")
async def inventory_purchase_orders_create(request: Request):
    try:
        body = await request.json()
        mode = str((body or {}).get("mode") or "sandbox").strip().lower()
        cfg = get_mode_config("prod" if mode in {"production", "prod"} else "sandbox")
        supplier_name = str((body or {}).get("supplier_name") or "").strip()
        supplier_id = str((body or {}).get("supplier_id") or "").strip()
        supplier_email = str((body or {}).get("supplier_email") or "").strip()
        supplier_phone = str((body or {}).get("supplier_phone") or "").strip()
        po_date = str((body or {}).get("po_date") or "").strip() or datetime.now().strftime("%Y-%m-%d")
        item_description = str((body or {}).get("item_description") or "").strip()
        item_sku = str((body or {}).get("item_sku") or "").strip()
        item_unit = str((body or {}).get("item_unit") or "").strip() or "יח׳"
        remarks = str((body or {}).get("remarks") or "").strip()
        quantity = float((body or {}).get("item_quantity") or 0)
        unit_price = float((body or {}).get("item_unit_price") or 0)
        subtotal = float((body or {}).get("subtotal") or 0)
        vat = float((body or {}).get("vat") or 0)
        total = float((body or {}).get("total") or 0)
        raw_items = (body or {}).get("items") or []
        normalized_items: list[dict] = []
        if isinstance(raw_items, list):
            for raw_item in raw_items:
                if not isinstance(raw_item, dict):
                    continue
                line_description = str(raw_item.get("description") or "").strip()
                line_sku = str(raw_item.get("sku") or "").strip()
                line_unit = str(raw_item.get("unit") or "").strip() or item_unit or "יח׳"
                try:
                    line_quantity = float(raw_item.get("quantity") or 0)
                except Exception:
                    line_quantity = 0
                try:
                    line_unit_price = float(raw_item.get("unit_price") or 0)
                except Exception:
                    line_unit_price = 0
                if not line_description or line_quantity <= 0:
                    continue
                normalized_items.append(
                    {
                        "description": line_description,
                        "sku": line_sku,
                        "unit": line_unit,
                        "quantity": line_quantity,
                        "unit_price": line_unit_price,
                        "line_total": round(line_quantity * line_unit_price, 2),
                    }
                )
        if not supplier_name:
            return JSONResponse({"error": "חסר שם ספק ליצירת הזמנת רכש."}, status_code=400)
        if not item_description and not normalized_items:
            return JSONResponse({"error": "חסר תיאור פריט להזמנת הרכש."}, status_code=400)
        if quantity <= 0 and not normalized_items:
            return JSONResponse({"error": "כמות חייבת להיות גדולה מאפס."}, status_code=400)
        if unit_price < 0:
            return JSONResponse({"error": "מחיר יחידה לא יכול להיות שלילי."}, status_code=400)
        if normalized_items:
            quantity = normalized_items[0]["quantity"]
            unit_price = normalized_items[0]["unit_price"]
            item_description = item_description or normalized_items[0]["description"]
            item_sku = item_sku or normalized_items[0]["sku"]
            item_unit = item_unit or normalized_items[0]["unit"]
            subtotal = round(sum(item["line_total"] for item in normalized_items), 2)
            vat = round(subtotal * 0.18, 2)
            total = round(subtotal + vat, 2)
        if subtotal <= 0:
            subtotal = quantity * unit_price
        if vat < 0:
            vat = round(subtotal * 0.18, 2)
        if total <= 0:
            total = subtotal + vat

        po_items = [
            POItem(
                description=item["description"],
                sku=item["sku"],
                quantity=item["quantity"],
                unit_price=item["unit_price"],
                line_total=item["line_total"],
            )
            for item in normalized_items
        ] or [
            POItem(
                description=item_description,
                sku=item_sku,
                quantity=quantity,
                unit_price=unit_price,
                line_total=subtotal,
            )
        ]

        po = PurchaseOrderData(
            po_number=str((body or {}).get("po_number") or "").strip(),
            po_date=po_date,
            customer_name=supplier_name,
            customer_id=supplier_id or None,
            customer_email=supplier_email,
            customer_phone=supplier_phone,
            delivery_address="ההסתדרות 228, חיפה",
            subtotal=subtotal,
            vat=vat,
            total=total,
            items=po_items,
            raw_text="",
            extra={
                "item_unit": item_unit,
                "footer_text": remarks,
            },
        )

        client = GreenInvoiceClient(
            base_url=cfg["base_url"],
            api_key=cfg["api_key"],
            api_secret=cfg["api_secret"],
        )
        token = await client._get_token()
        po_rows = client._rows_for_invoice(po)
        client_payload = {
            "name": supplier_name,
            "idNumber": supplier_id,
            "email": supplier_email,
            "phone": supplier_phone,
        }
        base_payload = {
            "type": 500,
            "lang": "he",
            "currency": "ILS",
            "vatType": 0,
            "client": client_payload,
            "description": item_description if len(po_items) == 1 else f"{po_items[0].description} + {len(po_items) - 1} נוספים",
            "remarks": remarks,
            "bottomText": remarks,
        }

        create_attempt_errors: list[str] = []
        created_doc = None
        for attempt_payload in (
            {**base_payload, "income": po_rows, "incomeRows": po_rows},
            {**base_payload, "expense": po_rows, "expenseRows": po_rows},
            {**base_payload, "recipient": client_payload, "expense": po_rows, "expenseRows": po_rows},
        ):
            try:
                created_doc = await client.create_document(token, attempt_payload)
                break
            except Exception as exc:
                create_attempt_errors.append(str(exc))
                log_handled_error("inventory_purchase_orders_create attempt failed", exc)
        if created_doc is None:
            raise RuntimeError(" | ".join(create_attempt_errors) or "GreenInvoice rejected purchase order creation.")

        created_po_number = str(getattr(created_doc, "number", "") or po.po_number or "").strip()
        customer_folder_name = _guess_customer_folder_name(supplier_name)
        order_folder_name = _guess_order_folder_name(created_po_number or "PO", po_date)
        local_dir = OUTPUT_DIR / "supplier_purchase_orders" / customer_folder_name / order_folder_name
        local_dir.mkdir(parents=True, exist_ok=True)
        safe_created_po_name = _safe_folder_name(created_po_number or "purchase_order") or "purchase_order"
        po_pdf_path = local_dir / f"{safe_created_po_name}_purchase_order.pdf"
        if getattr(created_doc, "url", ""):
            await client.download_pdf(token, created_doc.url, po_pdf_path)

        drive_sync_result = {"status": "skipped", "reason": "missing_pdf"}
        if po_pdf_path.exists():
            try:
                drive_sync_result = _sync_inventory_purchase_order_pdf_to_drive(supplier_name, created_po_number, po_date, po_pdf_path)
            except Exception as exc:
                log_handled_error("inventory purchase order drive sync failed", exc)
                drive_sync_result = {"status": "error", "error": str(exc)}

        row = {
            "history_id": uuid.uuid4().hex,
            "created_at": datetime.now().isoformat(timespec="seconds"),
            "mode": "production" if mode in {"production", "prod"} else "sandbox",
            "supplier_name": supplier_name,
            "supplier_id": supplier_id,
            "supplier_email": supplier_email,
            "supplier_phone": supplier_phone,
            "po_number": created_po_number,
            "po_document_id": str(getattr(created_doc, "document_id", "") or "").strip(),
            "po_date": po_date,
            "item_description": item_description if len(po_items) == 1 else f"{po_items[0].description} + {len(po_items) - 1} נוספים",
            "item_sku": item_sku,
            "item_quantity": _normalize_inventory_numeric_text(quantity) if len(po_items) == 1 else f"{len(po_items)} שורות",
            "item_unit": item_unit if len(po_items) == 1 else "מעורב",
            "item_unit_price": _normalize_inventory_numeric_text(unit_price) if len(po_items) == 1 else "",
            "subtotal": _normalize_inventory_numeric_text(subtotal),
            "vat": _normalize_inventory_numeric_text(vat),
            "total": _normalize_inventory_numeric_text(total),
            "remarks": remarks,
            "po_local_file": _inventory_purchase_order_file_relative_to_output(po_pdf_path if po_pdf_path.exists() else None),
            "po_drive_file_id": str(drive_sync_result.get("po_drive_file_id") or "").strip(),
            "po_drive_url": str(drive_sync_result.get("po_drive_url") or "").strip(),
            "drive_folder_id": str(drive_sync_result.get("order_folder_id") or "").strip(),
            "drive_folder_url": str(drive_sync_result.get("drive_folder_url") or "").strip(),
            "send_status": "",
            "sent_at": "",
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
        history_result = append_inventory_purchase_order_row(row)
        rows = load_inventory_purchase_order_rows(force_refresh=True)
        return JSONResponse(
            {
                "status": "ok",
                "row": history_result.get("row") or row,
                "rows": rows,
                "drive_sync_result": drive_sync_result,
            }
        )
    except Exception as exc:
        log_handled_error("inventory_purchase_orders_create failed", exc)
        return JSONResponse({"error": f"לא הצלחתי ליצור את הזמנת הרכש: {exc}"}, status_code=500)


@app.post("/inventory-purchase-orders-delete")
async def inventory_purchase_orders_delete(request: Request):
    try:
        body = await request.json()
        history_id = str((body or {}).get("history_id") or "").strip()
        if not history_id:
            return JSONResponse({"error": "חסר מזהה שורת היסטוריה למחיקה."}, status_code=400)
        rows = load_inventory_purchase_order_rows()
        target_row = next((row for row in rows if str(row.get("history_id") or "").strip() == history_id), None)
        if not target_row:
            return JSONResponse({"error": "לא נמצאה שורת הזמנת רכש מתאימה."}, status_code=404)
        local_file = str(target_row.get("po_local_file") or "").strip().lstrip("/")
        if local_file:
            try:
                local_path = (OUTPUT_DIR / local_file).resolve()
                if local_path.exists() and local_path.is_file():
                    local_path.unlink()
            except Exception as exc:
                log_handled_error("inventory purchase order local file delete failed", exc)
        drive_file_id = str(target_row.get("po_drive_file_id") or "").strip()
        if drive_file_id:
            try:
                delete_drive_file(drive_file_id)
            except Exception as exc:
                log_handled_error("inventory purchase order drive file delete failed", exc)
        hidden_key = _inventory_purchase_order_hidden_key(target_row)
        if hidden_key:
            hidden_keys = _inventory_purchase_order_hidden_keys()
            hidden_keys.add(hidden_key)
            _save_inventory_purchase_order_hidden_keys(hidden_keys)
        delete_result = delete_inventory_purchase_order_row(history_id)
        return JSONResponse({"status": "ok", **delete_result})
    except Exception as exc:
        log_handled_error("inventory_purchase_orders_delete failed", exc)
        return JSONResponse({"error": f"לא הצלחתי למחוק את הזמנת הרכש: {exc}"}, status_code=500)


@app.post("/inventory-purchase-orders-send-email")
async def inventory_purchase_orders_send_email(
    history_id: str = Form(""),
    recipients: str = Form(""),
    subject: str = Form(""),
    plain_body: str = Form(""),
    html_body: str = Form(""),
    po_file: str = Form(""),
    test_send: str = Form("false"),
    attachments: list[UploadFile] | None = File(None),
):
    recipient_list = _customer_email_list(recipients)
    is_test_send = str(test_send or "").strip().lower() == "true"
    if is_test_send:
        recipient_list = ["asafbeny@gmail.com"]
    if not recipient_list:
        return JSONResponse({"error": "חסרה כתובת מייל לשליחה."}, status_code=400)
    if not str(subject or "").strip():
        return JSONResponse({"error": "חסר נושא למייל."}, status_code=400)

    stored_files: list[Path] = []
    upload_dir = BASE_DIR / "output" / "purchase-order-mails"
    try:
        po_relative = str(po_file or "").strip().lstrip("/")
        if po_relative:
            po_path = (OUTPUT_DIR / po_relative).resolve()
            if not po_path.exists() or not po_path.is_file():
                return JSONResponse({"error": "קובץ הזמנת הרכש לא נמצא."}, status_code=404)
            stored_files.append(po_path)

        for file in attachments or []:
            stored_path, _ = await _store_uploaded_attachment(file, upload_dir, fallback_name="purchase-order-mail-attachment.pdf")
            stored_files.append(stored_path)

        final_plain = _customer_mail_plain_text(html_body, plain_body)
        final_html = _delivery_confirmation_mail_html_from_editor_html(html_body, final_plain)
        _send_delivery_confirmation_mail(
            ", ".join(recipient_list),
            str(subject or "").strip(),
            final_plain,
            final_html,
            [str(path) for path in stored_files],
        )
        updated_row = None
        if str(history_id or "").strip():
            try:
                status_result = update_inventory_purchase_order_send_status(
                    history_id,
                    "test-only" if is_test_send else "sent",
                    datetime.now().isoformat(timespec="seconds"),
                )
                updated_row = status_result.get("row")
            except Exception as status_exc:
                log_handled_error("inventory_purchase_orders_send_email status update failed", status_exc)
        return JSONResponse(
            {
                "status": "ok",
                "recipients": recipient_list,
                "attachments_count": len(stored_files),
                "test_send": is_test_send,
                "row": updated_row,
            }
        )
    except Exception as exc:
        log_handled_error("inventory_purchase_orders_send_email failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשלוח את מייל הזמנת הרכש: {exc}"}, status_code=500)


