@app.post("/supplier-delivery-notes-parse")
async def supplier_delivery_notes_parse(file: UploadFile = File(...)):
    try:
        original_name = str(file.filename or "").strip() or "supplier_delivery_note.pdf"
        safe_name = FILENAME_SAFE_PATTERN.sub("_", original_name)
        suffix = Path(safe_name).suffix or ".pdf"
        if suffix.lower() != ".pdf":
            return JSONResponse({"error": "אפשר להעלות כרגע רק קבצי PDF של תעודות משלוח ספקים."}, status_code=400)
        SUPPLIER_DELIVERY_UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
        target_path = SUPPLIER_DELIVERY_UPLOAD_DIR / f"{datetime.now().strftime('%Y%m%d%H%M%S')}_{uuid.uuid4().hex[:8]}{suffix.lower()}"
        contents = await file.read()
        target_path.write_bytes(contents)
        parsed = parse_supplier_delivery_note(target_path)
        parsed["source_local_path"] = str(target_path)
        return JSONResponse({"status": "ok", "parsed": parsed})
    except Exception as exc:
        log_handled_error("supplier_delivery_notes_parse failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לפרסר את תעודת המשלוח: {exc}"}, status_code=500)


@app.post("/supplier-delivery-notes-save")
async def supplier_delivery_notes_save(request: Request):
    try:
        body = await request.json()
        note = body.get("note") if isinstance(body, dict) else None
        items = body.get("items") if isinstance(body, dict) else None
        if not isinstance(note, dict) or not isinstance(items, list) or not items:
            return JSONResponse({"error": "מבנה תעודת משלוח לא תקין לשמירה."}, status_code=400)

        base_note = {
            "supplier_name": str(note.get("supplier_name") or "").strip(),
            "parser_name": str(note.get("parser_name") or "").strip(),
            "source_document_name": str(note.get("source_document_name") or "").strip(),
            "delivery_note_number": str(note.get("delivery_note_number") or "").strip(),
            "delivery_date": str(note.get("delivery_date") or "").strip(),
            "customer_name": str(note.get("customer_name") or "").strip(),
            "customer_id": str(note.get("customer_id") or "").strip(),
            "delivery_address": str(note.get("delivery_address") or "").strip(),
            "contact_name": str(note.get("contact_name") or "").strip(),
            "contact_phone": str(note.get("contact_phone") or "").strip(),
            "source_local_path": str(note.get("source_local_path") or "").strip(),
        }
        if not base_note["supplier_name"] or not base_note["delivery_note_number"]:
            return JSONResponse({"error": "חסר שם ספק או מספר תעודת משלוח."}, status_code=400)

        timestamp = datetime.now().isoformat(timespec="seconds")
        saved_rows = load_supplier_delivery_note_rows()
        note_key = (
            base_note["supplier_name"],
            base_note["delivery_note_number"],
            base_note["delivery_date"],
        )
        filtered_rows = [
            row
            for row in saved_rows
            if (
                str(row.get("supplier_name") or "").strip(),
                str(row.get("delivery_note_number") or "").strip(),
                str(row.get("delivery_date") or "").strip(),
            ) != note_key
        ]
        existing_note_rows = [row for row in saved_rows if row not in filtered_rows]

        normalized_rows = []
        source_drive_file_id = ""
        source_drive_url = ""
        try:
            source_local_path = Path(base_note["source_local_path"]) if base_note["source_local_path"] else None
            if source_local_path and source_local_path.exists():
                supplier_folder_id = _ensure_supplier_delivery_drive_folder(base_note["supplier_name"])
                uploaded = ensure_file_in_folder(supplier_folder_id, source_local_path, drive_name=source_local_path.name)
                source_drive_file_id = str(uploaded.get("id") or "").strip()
                source_drive_url = str(uploaded.get("web_view_link") or uploaded.get("webViewLink") or "").strip()
                if not source_drive_url and source_drive_file_id:
                    source_drive_url = _drive_file_view_link(source_drive_file_id)
        except Exception as exc:
            log_handled_error("supplier delivery note source drive sync failed", exc)

        for index, item in enumerate(items, start=1):
            normalized_rows.append(
                {
                    "record_id": str(item.get("record_id") or uuid.uuid4().hex),
                    **base_note,
                    "item_index": str(item.get("item_index") or index),
                    "supplier_sku": str(item.get("supplier_sku") or "").strip(),
                    "item_description": str(item.get("item_description") or "").strip(),
                    "product": str(item.get("product") or "").strip(),
                    "material": str(item.get("material") or "").strip(),
                    "length": str(item.get("length") or "").strip(),
                    "width": str(item.get("width") or "").strip(),
                    "thickness": str(item.get("thickness") or "").strip(),
                    "quantity": _normalize_inventory_numeric_text(item.get("quantity")),
                    "unit": str(item.get("unit") or "").strip(),
                    "notes": str(item.get("notes") or "").strip(),
                    "source_drive_file_id": source_drive_file_id,
                    "source_drive_url": source_drive_url,
                    "updated_at": timestamp,
                }
            )
        rows_to_save = filtered_rows + normalized_rows
        save_result = save_supplier_delivery_note_rows(rows_to_save)

        raw_rows = load_inventory_rows("raw")
        raw_rows_without_existing = _apply_supplier_delivery_note_to_inventory(raw_rows, existing_note_rows, multiplier=-1.0)
        updated_raw_rows = _apply_supplier_delivery_note_to_inventory(raw_rows_without_existing, normalized_rows)
        inventory_save_result = save_inventory_rows("raw", updated_raw_rows)

        return JSONResponse(
            {
                "status": "ok",
                "rows": rows_to_save,
                "summary_rows": _supplier_delivery_note_summary_rows(rows_to_save),
                "raw_rows": updated_raw_rows,
                "save_result": save_result,
                "inventory_save_result": inventory_save_result,
            }
        )
    except Exception as exc:
        log_handled_error("supplier_delivery_notes_save failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשמור את תעודת המשלוח: {exc}"}, status_code=500)


@app.get("/supplier-delivery-note-source/{record_id}")
async def supplier_delivery_note_source(record_id: str):
    try:
        target_id = str(record_id or "").strip()
        if not target_id:
            return JSONResponse({"error": "חסר מזהה שורה של תעודת המשלוח."}, status_code=400)
        rows = load_supplier_delivery_note_rows()
        row = next((item for item in rows if str(item.get("record_id") or "").strip() == target_id), None)
        if not row:
            return JSONResponse({"error": "לא נמצאה שורת תעודת משלוח מתאימה."}, status_code=404)

        source_local_path = Path(str(row.get("source_local_path") or "").strip()) if str(row.get("source_local_path") or "").strip() else None
        if source_local_path and source_local_path.exists():
            return FileResponse(str(source_local_path))

        source_drive_file_id = str(row.get("source_drive_file_id") or "").strip()
        if source_drive_file_id:
            return RedirectResponse(_drive_file_view_link(source_drive_file_id))

        source_drive_url = str(row.get("source_drive_url") or "").strip()
        if source_drive_url:
            return RedirectResponse(source_drive_url)

        return JSONResponse({"error": "לא נמצא קובץ מקור זמין לתעודת המשלוח."}, status_code=404)
    except Exception as exc:
        log_handled_error("supplier_delivery_note_source failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לפתוח את קובץ המקור: {exc}"}, status_code=500)


