@app.post("/supplier-delivery-notes-delete-row")
async def supplier_delivery_notes_delete_row(request: Request):
    try:
        body = await request.json()
        record_id = str((body or {}).get("record_id") or "").strip()
        if not record_id:
            return JSONResponse({"error": "חסר מזהה שורה למחיקה."}, status_code=400)

        rows = load_supplier_delivery_note_rows()
        target_row = next((row for row in rows if str(row.get("record_id") or "").strip() == record_id), None)
        if not target_row:
            return JSONResponse({"error": "לא נמצאה שורת תעודת משלוח מתאימה."}, status_code=404)

        remaining_rows = [row for row in rows if str(row.get("record_id") or "").strip() != record_id]
        save_result = save_supplier_delivery_note_rows(remaining_rows)

        raw_rows = load_inventory_rows("raw")
        updated_raw_rows = _apply_supplier_delivery_note_to_inventory(raw_rows, [target_row], multiplier=-1.0)
        inventory_save_result = save_inventory_rows("raw", updated_raw_rows)

        return JSONResponse(
            {
                "status": "ok",
                "rows": remaining_rows,
                "summary_rows": _supplier_delivery_note_summary_rows(remaining_rows),
                "raw_rows": updated_raw_rows,
                "save_result": save_result,
                "inventory_save_result": inventory_save_result,
            }
        )
    except Exception as exc:
        log_handled_error("supplier_delivery_notes_delete_row failed", exc)
        return JSONResponse({"error": f"לא הצלחתי למחוק את שורת תעודת המשלוח: {exc}"}, status_code=500)


@app.post("/supplier-delivery-notes-delete-summary")
async def supplier_delivery_notes_delete_summary(request: Request):
    try:
        body = await request.json()
        summary = body.get("summary") if isinstance(body, dict) else None
        if not isinstance(summary, dict):
            return JSONResponse({"error": "חסרים פרטי שורת הסיכום למחיקה."}, status_code=400)

        supplier_name = str(summary.get("supplier_name") or "").strip()
        product = str(summary.get("product") or "").strip()
        material = str(summary.get("material") or "").strip()
        unit = str(summary.get("unit") or "").strip()
        if not supplier_name:
            return JSONResponse({"error": "חסר שם ספק למחיקת שורת הסיכום."}, status_code=400)

        rows = load_supplier_delivery_note_rows()
        matching_rows = [
            row for row in rows
            if str(row.get("supplier_name") or "").strip() == supplier_name
            and str(row.get("product") or "").strip() == product
            and str(row.get("material") or "").strip() == material
            and str(row.get("unit") or "").strip() == unit
        ]
        if not matching_rows:
            return JSONResponse({"error": "לא נמצאו פריטי תעודת משלוח תואמים לשורת הסיכום."}, status_code=404)

        remaining_rows = [row for row in rows if row not in matching_rows]
        save_result = save_supplier_delivery_note_rows(remaining_rows)

        raw_rows = load_inventory_rows("raw")
        updated_raw_rows = _apply_supplier_delivery_note_to_inventory(raw_rows, matching_rows, multiplier=-1.0)
        inventory_save_result = save_inventory_rows("raw", updated_raw_rows)

        return JSONResponse(
            {
                "status": "ok",
                "rows": remaining_rows,
                "summary_rows": _supplier_delivery_note_summary_rows(remaining_rows),
                "raw_rows": updated_raw_rows,
                "save_result": save_result,
                "inventory_save_result": inventory_save_result,
            }
        )
    except Exception as exc:
        log_handled_error("supplier_delivery_notes_delete_summary failed", exc)
        return JSONResponse({"error": f"לא הצלחתי למחוק את שורת הסיכום: {exc}"}, status_code=500)


