@app.post("/project-managers-upload")
async def project_managers_upload(
    file: UploadFile = File(...),
    mode: str = Form("sandbox"),
):
    try:
        file_path, _ = await _store_uploaded_pdf(file, UPLOADS_DIR, fallback_name="project-managers-upload.pdf")
    except ValueError as exc:
        return JSONResponse({"error": str(exc)}, status_code=400)

    cfg = {
        "base_url": settings.greeninvoice_sandbox_base_url if mode == "sandbox" else settings.greeninvoice_prod_base_url,
        "api_key": settings.greeninvoice_sandbox_api_key if mode == "sandbox" else settings.greeninvoice_prod_api_key,
        "api_secret": settings.greeninvoice_sandbox_api_secret if mode == "sandbox" else settings.greeninvoice_prod_api_secret,
        "mode": mode,
    }

    try:
        po = parse_purchase_order(file_path)
        po = await _enrich_po_for_process(po, cfg)
        rows = extract_project_manager_entries_from_pdf(file_path, parsed_po=po)
        result = upsert_project_manager_rows(rows)
        latest_rows = get_cached_project_manager_rows()
        return JSONResponse(
            {
                "status": "ok",
                "rows_added": len(rows),
                "sync_result": result,
                "rows": latest_rows,
                "po_number": po.po_number or "",
            }
        )
    except Exception as exc:
        log_handled_error("project_managers_upload failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לעדכן מנהלי פרויקטים מהקובץ: {exc}"}, status_code=500)


@app.get("/delivery-confirmations-state")
async def delivery_confirmations_state():
    try:
        return JSONResponse({"status": "ok", **_build_delivery_confirmation_payload()})
    except Exception as exc:
        log_handled_error("delivery_confirmations_state failed", exc)
        cached_rows = get_cached_delivery_confirmation_rows()
        cached_contacts = get_cached_delivery_contact_rows()
        if cached_rows or cached_contacts:
            threshold = _delivery_confirmation_threshold()
            filtered_rows = [
                row for row in cached_rows
                if (_parse_order_display_date(row.get("order_date", "")) or threshold) >= threshold
            ]
            sent_rows = [row for row in filtered_rows if str(row.get("sent", "")).strip().upper() == "TRUE"]
            unsent_rows = [row for row in filtered_rows if str(row.get("sent", "")).strip().upper() != "TRUE"]
            return JSONResponse(
                {
                    "status": "ok",
                    "rows": filtered_rows,
                    "sent_rows": sent_rows,
                    "unsent_rows": unsent_rows,
                    "contacts_rows": cached_contacts,
                    "threshold_date": threshold.strftime("%d/%m/%Y"),
                    "warning": "הוצגו נתוני אישורי המסירה האחרונים שנשמרו, כי Google Sheets מגביל כרגע את קצב הקריאות.",
                }
            )
        return JSONResponse({"error": f"לא הצלחתי לטעון את אישורי המסירה: {exc}"}, status_code=500)


