@app.post("/order-history-delete")
async def order_history_delete(request: Request):
    try:
        body = await request.json()
        history_id = str(body.get("history_id") or "").strip()
        if not history_id:
            return JSONResponse({"error": "חסר מזהה היסטוריה למחיקה."}, status_code=400)
        history_rows = load_order_history_rows(force_refresh=True)
        target_row = next((row for row in history_rows if str(row.get("history_id") or "").strip() == history_id), None)
        fallback_row = target_row or {
            "history_id": history_id,
            "fulfillment_id": str(body.get("fulfillment_id") or "").strip(),
            "po_number": str(body.get("po_number") or "").strip(),
            "source_mode": str(body.get("source_mode") or body.get("mode") or "").strip(),
            "customer_name": str(body.get("customer_name") or body.get("company") or "").strip(),
            "delivery_number": str(body.get("delivery_number") or body.get("delivery_document_number") or "").strip(),
            "tax_invoice_number": str(body.get("tax_invoice_number") or "").strip(),
        }
        add_delivery_confirmation_suppression(
            company=str(fallback_row.get("customer_name") or "").strip(),
            po_number=str(fallback_row.get("po_number") or "").strip(),
            source_mode=str(fallback_row.get("source_mode") or "").strip(),
            tax_invoice_number=str(fallback_row.get("tax_invoice_number") or "").strip(),
            delivery_document_number=str(fallback_row.get("delivery_number") or "").strip(),
        )
        result = delete_order_history_row(history_id)
        delivery_result = {"status": "skipped", "reason": "order_history_row_missing"}
        if any(
            str((fallback_row or {}).get(key) or "").strip()
            for key in ("history_id", "fulfillment_id", "po_number", "delivery_number", "tax_invoice_number")
        ):
            delivery_result = delete_delivery_confirmation_rows(
                history_id=history_id,
                fulfillment_id=str(fallback_row.get("fulfillment_id") or "").strip(),
                po_number=str(fallback_row.get("po_number") or "").strip(),
                source_mode=str(fallback_row.get("source_mode") or "").strip(),
                company=str(fallback_row.get("customer_name") or "").strip(),
                delivery_document_number=str(fallback_row.get("delivery_number") or "").strip(),
                tax_invoice_number=str(fallback_row.get("tax_invoice_number") or "").strip(),
            )
        return JSONResponse(
            {
                "status": "ok",
                "delivery_confirmation_cleanup": delivery_result,
                **_build_order_history_payload(result.get("rows") or []),
            }
        )
    except Exception as exc:
        log_handled_error("order_history_delete failed", exc)
        return JSONResponse({"error": f"לא הצלחתי למחוק את השורה מההיסטוריה: {exc}"}, status_code=500)


