@app.post("/quote-history-upload-signed")
async def quote_history_upload_signed(history_id: str = Form(...), file: UploadFile = File(...)):
    temp_path: Path | None = None
    try:
        target_history_id = str(history_id or "").strip()
        if not target_history_id:
            return JSONResponse({"error": "חסר מזהה היסטוריה לשיוך ההצעה החתומה."}, status_code=400)
        rows = load_quote_history_rows(force_refresh=True)
        row = next((item for item in rows if str(item.get("history_id") or "").strip() == target_history_id), None)
        if not row:
            return JSONResponse({"error": "לא נמצאה שורת היסטוריית הצעת מחיר מתאימה."}, status_code=404)

        folder_id = str(row.get("quote_drive_folder_id") or "").strip() or _extract_drive_folder_id(row.get("quote_drive_folder_url") or "")
        if not folder_id:
            return JSONResponse({"error": "לא נמצאה תיקיית Drive לשיוך ההצעה החתומה."}, status_code=400)

        temp_path, _ = await _store_uploaded_attachment(file, QUOTE_HISTORY_SIGNED_UPLOADS_DIR, fallback_name="signed-quote.pdf")
        suffix = Path(temp_path.name).suffix.lower() or ".pdf"
        quote_number = str(row.get("quote_number") or "").strip()
        drive_name = f"הצעה חתומה {quote_number}".strip() if quote_number else "הצעה חתומה"
        uploaded = upload_file_to_folder(folder_id, temp_path, drive_name=f"{drive_name}{suffix}")
        drive_url = str(uploaded.get("web_view_link") or uploaded.get("webViewLink") or "").strip()
        if not drive_url:
            file_id = str(uploaded.get("id") or "").strip()
            if file_id:
                drive_url = f"https://drive.google.com/file/d/{file_id}/view"

        existing_links = _normalize_order_history_links(row.get("document_links_json"))
        filtered_links = [
            link for link in existing_links
            if str(link.get("name") or "").strip() not in {"הצעה חתומה", "הצעה חתומה ב-Drive"}
        ]
        if drive_url:
            filtered_links.append({"name": "הצעה חתומה", "url": drive_url})
        row["document_links_json"] = json.dumps(filtered_links, ensure_ascii=False)
        row["updated_at"] = datetime.now().isoformat(timespec="seconds")
        save_quote_history_rows(rows)
        return JSONResponse(
            {
                "status": "ok",
                "message": "ההצעה החתומה הועלתה לתיקיית ה-Drive של ההצעה.",
                "uploaded_url": drive_url,
                **_build_quote_history_payload(rows),
            }
        )
    except Exception as exc:
        log_handled_error("quote_history_upload_signed failed", exc)
        return JSONResponse({"error": f"לא הצלחתי להעלות את ההצעה החתומה: {exc}"}, status_code=500)
    finally:
        if temp_path and temp_path.exists():
            try:
                temp_path.unlink()
            except Exception:
                pass


