@app.post("/delivery-confirmations-upload")
async def delivery_confirmations_upload(request: Request, file: UploadFile = File(...)):
    try:
        fulfillment_id = str(request.query_params.get("fulfillment_id") or "").strip()
        po_number = _normalize_delivery_confirmation_po_number(request.query_params.get("po_number") or "")
        tax_invoice_number = str(request.query_params.get("tax_invoice_number") or "").strip()
        source_mode = str(request.query_params.get("source_mode") or "").strip().upper()
        if not po_number and not fulfillment_id:
            return JSONResponse({"error": "חסר מזהה מימוש או מספר הזמנה לשיוך אישור המסירה."}, status_code=400)
        file_path, _ = await _store_uploaded_attachment(file, DELIVERY_CONFIRMATION_UPLOADS_DIR, fallback_name="signed-delivery.pdf")
        rows = load_delivery_confirmation_rows()
        target = next(
            (
                row
                for row in rows
                if (fulfillment_id and str(row.get("fulfillment_id") or "").strip() == fulfillment_id)
                or (
                    not fulfillment_id
                    and _normalize_delivery_confirmation_po_number(row.get("po_number") or "") == po_number
                    and (not tax_invoice_number or str(row.get("tax_invoice_number") or "").strip() == tax_invoice_number)
                    and (not source_mode or str(row.get("source_mode") or "").strip().upper() == source_mode)
                )
            ),
            None,
        )
        if not target and not fulfillment_id:
            target = next(
                (
                    row
                    for row in rows
                    if _normalize_delivery_confirmation_po_number(row.get("po_number") or "") == po_number
                ),
                None,
            )
        if not target:
            return JSONResponse({"error": "לא נמצאה שורת אישור מסירה להזמנה הזו."}, status_code=404)
        resolved_po_number = str(target.get("po_number") or po_number or "").strip()
        resolved_fulfillment_id = str(target.get("fulfillment_id") or fulfillment_id or "").strip()
        canonical_name = _delivery_confirmation_storage_name(
            resolved_po_number,
            file.filename or file_path.name,
            resolved_fulfillment_id,
        )
        canonical_path = file_path.with_name(canonical_name)
        if canonical_path != file_path:
            canonical_path.unlink(missing_ok=True)
            file_path.rename(canonical_path)
            file_path = canonical_path
        po_number = resolved_po_number
        related_indexes = _delivery_confirmation_related_indexes(rows, target) or [rows.index(target)]
        for row_index in related_indexes:
            rows[row_index]["signed_delivery_local_path"] = str(file_path)
            rows[row_index]["signed_delivery_name"] = file_path.name
            rows[row_index]["updated_at"] = datetime.now().isoformat(timespec="seconds")
        save_delivery_confirmation_rows(rows)
        updated_row = dict(rows[related_indexes[0]])
        drive_warning = ""
        try:
            updated_row = await _ensure_delivery_confirmation_signed_drive_asset(target)
            for row_index in related_indexes:
                rows[row_index]["signed_delivery_local_path"] = str(updated_row.get("signed_delivery_local_path") or str(file_path)).strip()
                rows[row_index]["signed_delivery_name"] = str(updated_row.get("signed_delivery_name") or file_path.name).strip()
                rows[row_index]["signed_delivery_drive_file_id"] = str(updated_row.get("signed_delivery_drive_file_id") or "").strip()
                if str(updated_row.get("order_drive_folder_id") or "").strip():
                    rows[row_index]["order_drive_folder_id"] = str(updated_row.get("order_drive_folder_id") or "").strip()
                rows[row_index]["updated_at"] = datetime.now().isoformat(timespec="seconds")
            save_delivery_confirmation_rows(rows)
            updated_row = dict(rows[related_indexes[0]])
        except Exception as drive_exc:
            log_handled_error("delivery_confirmations_upload drive sync failed", drive_exc)
            drive_warning = _google_drive_sync_warning(drive_exc)
        response_payload = {
            "status": "ok",
            "row": updated_row,
            "upload_complete": True,
            **_build_delivery_confirmation_payload(),
        }
        if drive_warning:
            response_payload["warning"] = drive_warning
        return JSONResponse(response_payload)
    except ValueError as exc:
        return JSONResponse({"error": str(exc)}, status_code=400)
    except Exception as exc:
        log_handled_error("delivery_confirmations_upload failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשמור את אישור המסירה: {exc}"}, status_code=500)


@app.post("/delivery-confirmations-send")
async def delivery_confirmations_send(request: Request):
    uploaded_attachment_paths: list[Path] = []
    try:
        content_type = str(request.headers.get("content-type") or "").lower()
        uploaded_files: list[UploadFile] = []
        if "multipart/form-data" in content_type:
            form = await request.form()
            fulfillment_id = str(form.get("fulfillment_id") or "").strip()
            po_number = _normalize_delivery_confirmation_po_number(form.get("po_number") or "")
            tax_invoice_number = str(form.get("tax_invoice_number") or "").strip()
            source_mode = str(form.get("source_mode") or "").strip().upper()
            mode = str(form.get("mode") or "prod").strip().lower()
            test_send = str(form.get("test_send") or "").strip().lower() in {"1", "true", "yes", "on"}
            subject = str(form.get("subject") or "").strip()
            message = str(form.get("message") or "").strip()
            recipients = str(form.get("recipients") or "").strip()
            send_new_bank_details = str(form.get("send_new_bank_details") or "").strip().lower() in {"1", "true", "yes", "on"}
            html_body = str(form.get("html_body") or "").strip()
            uploaded_files = [
                item
                for item in form.getlist("attachments")
                if getattr(item, "filename", None) and callable(getattr(item, "read", None))
            ]
        else:
            body = await request.json()
            fulfillment_id = str(body.get("fulfillment_id") or "").strip()
            po_number = _normalize_delivery_confirmation_po_number(body.get("po_number") or "")
            tax_invoice_number = str(body.get("tax_invoice_number") or "").strip()
            source_mode = str(body.get("source_mode") or "").strip().upper()
            mode = str(body.get("mode") or "prod").strip().lower()
            test_send = bool(body.get("test_send"))
            subject = str(body.get("subject") or "").strip()
            message = str(body.get("message") or "").strip()
            recipients = str(body.get("recipients") or "").strip()
            send_new_bank_details = bool(body.get("send_new_bank_details"))
            html_body = str(body.get("html_body") or "").strip()
        if not po_number and not fulfillment_id:
            return JSONResponse({"error": "חסר מזהה מימוש או מספר הזמנה."}, status_code=400)

        rows = load_delivery_confirmation_rows()
        row = next(
            (
                candidate
                for candidate in rows
                if (fulfillment_id and str(candidate.get("fulfillment_id") or "").strip() == fulfillment_id)
                or (
                    not fulfillment_id
                    and _normalize_delivery_confirmation_po_number(candidate.get("po_number") or "") == po_number
                    and (not tax_invoice_number or str(candidate.get("tax_invoice_number") or "").strip() == tax_invoice_number)
                    and (not source_mode or str(candidate.get("source_mode") or "").strip().upper() == source_mode)
                )
            ),
            None,
        )
        if not row and not fulfillment_id:
            row = next(
                (
                    candidate
                    for candidate in rows
                    if _normalize_delivery_confirmation_po_number(candidate.get("po_number") or "") == po_number
                ),
                None,
            )
        if not row:
            return JSONResponse({"error": "לא נמצאה שורת אישור מסירה מתאימה."}, status_code=404)

        row = await _ensure_delivery_confirmation_drive_assets(row, mode)
        if not recipients:
            company_key = _normalize_company_name(row.get("company", ""))
            delivery_contacts = load_delivery_contact_rows()
            contact = next(
                (item for item in delivery_contacts if _normalize_company_name(item.get("company", "")) == company_key),
                None,
            )
            recipients = str((contact or {}).get("email") or row.get("target_email") or "").strip()
        if test_send:
            recipients = "asafbeny@gmail.com"
        if not recipients:
            return JSONResponse({"error": "לא נמצא דואר אלקטרוני יעד. עדכן אותו בטבלת אנשי הקשר."}, status_code=400)

        subject = subject or _build_delivery_confirmation_mail_subject(row)
        message = message or _build_delivery_confirmation_mail_body(row)

        attachments: list[str] = []
        invoice_drive_file_id = str(row.get("invoice_drive_file_id") or "").strip()
        if invoice_drive_file_id:
            invoice_target = OUTPUT_DIR / "_delivery_confirmation_cache" / f"invoice_{po_number}.pdf"
            attachments.append(str(download_drive_file(invoice_drive_file_id, invoice_target)))
        else:
            local_invoice_pdf = _find_local_delivery_confirmation_invoice_pdf(row)
            if local_invoice_pdf:
                attachments.append(str(local_invoice_pdf))
                order_folder_id = str(row.get("order_drive_folder_id") or "").strip()
                if order_folder_id:
                    try:
                        uploaded = upload_file_to_folder(order_folder_id, local_invoice_pdf, drive_name=local_invoice_pdf.name)
                        row["invoice_drive_file_id"] = uploaded.get("id", "")
                    except Exception as drive_exc:
                        log_handled_error("delivery confirmation local invoice drive sync failed", drive_exc)
            elif str(row.get("tax_invoice_number") or "").strip():
                invoice_doc, invoice_mode = await _find_greeninvoice_invoice_document_any_mode(mode, row.get("tax_invoice_number", ""))
                if invoice_doc:
                    raw = invoice_doc.get("raw") or {}
                    url_payload = raw.get("url") or {}
                    invoice_url = ""
                    if isinstance(url_payload, dict):
                        invoice_url = str(url_payload.get("origin") or url_payload.get("he") or "").strip()
                    if invoice_url:
                        cfg = get_mode_config(invoice_mode or mode)
                        client = GreenInvoiceClient(
                            base_url=cfg["base_url"],
                            api_key=cfg["api_key"],
                            api_secret=cfg["api_secret"],
                        )
                        token = await client._get_token()
                        invoice_target = OUTPUT_DIR / "_delivery_confirmation_cache" / f"invoice_{po_number}.pdf"
                        attachments.append(str(await client.download_pdf(token, invoice_url, invoice_target)))
                        order_folder_id = str(row.get("order_drive_folder_id") or "").strip()
                        if order_folder_id and attachments:
                            try:
                                uploaded = upload_file_to_folder(order_folder_id, Path(attachments[-1]), drive_name=Path(attachments[-1]).name)
                                row["invoice_drive_file_id"] = uploaded.get("id", "")
                            except Exception as drive_exc:
                                log_handled_error("delivery confirmation invoice fallback drive sync failed", drive_exc)

        signed_local = str(row.get("signed_delivery_local_path") or "").strip()
        signed_drive_file_id = str(row.get("signed_delivery_drive_file_id") or "").strip()
        if signed_local and Path(signed_local).exists():
            attachments.append(str(Path(signed_local).resolve()))
        elif signed_drive_file_id:
            signed_name = str(row.get("signed_delivery_name") or f"signed_{po_number}.pdf")
            signed_target = OUTPUT_DIR / "_delivery_confirmation_cache" / signed_name
            attachments.append(str(download_drive_file(signed_drive_file_id, signed_target)))

        if _is_plasan_delivery_confirmation_row(row):
            coc_path = ""
            coc_drive_file_id = str(row.get("coc_drive_file_id") or "").strip()
            if coc_drive_file_id:
                coc_name = str(row.get("coc_name") or f"coc_{po_number}.pdf").strip() or f"coc_{po_number}.pdf"
                coc_target = OUTPUT_DIR / "_delivery_confirmation_cache" / coc_name
                coc_path = str(download_drive_file(coc_drive_file_id, coc_target))
            else:
                local_coc_pdf = _find_local_delivery_confirmation_coc_pdf(row)
                if local_coc_pdf:
                    coc_path = str(local_coc_pdf)
                    order_folder_id = str(row.get("order_drive_folder_id") or "").strip()
                    if order_folder_id:
                        try:
                            uploaded = upload_file_to_folder(order_folder_id, local_coc_pdf, drive_name=local_coc_pdf.name)
                            row["coc_drive_file_id"] = uploaded.get("id", "")
                            row["coc_name"] = uploaded.get("name", "") or local_coc_pdf.name
                        except Exception as drive_exc:
                            log_handled_error("delivery confirmation coc drive sync failed", drive_exc)
            if coc_path:
                attachments.append(coc_path)
            else:
                return JSONResponse({"error": "ללקוח פלסן סאסא צריך לצרף גם מסמך COC לפני שליחת המייל."}, status_code=400)

        minimum_attachments = 3 if _is_plasan_delivery_confirmation_row(row) else 2
        if len(attachments) < minimum_attachments:
            return JSONResponse({"error": "צריך גם חשבונית מס וגם ת. משלוח חתומה לפני שליחת המייל."}, status_code=400)

        if uploaded_files:
            upload_dir = OUTPUT_DIR / "_delivery_confirmation_uploaded"
            for index, uploaded_file in enumerate(uploaded_files, start=1):
                stored_path, _ = await _store_uploaded_attachment(
                    uploaded_file,
                    upload_dir,
                    fallback_name=f"delivery_confirmation_attachment_{index}.pdf",
                )
                uploaded_attachment_paths.append(stored_path)
                attachments.append(str(stored_path.resolve()))

        if send_new_bank_details:
            bank_attachment_path = _materialize_admin_business_doc_attachment(
                "bank-discount-confirmation",
                OUTPUT_DIR / "_delivery_confirmation_uploaded",
            )
            uploaded_attachment_paths.append(bank_attachment_path)
            attachments.append(str(bank_attachment_path.resolve()))

        html_message = (
            _delivery_confirmation_mail_html_from_editor_html(html_body, message)
            if html_body
            else _delivery_confirmation_mail_html_from_text(message)
        )
        _send_delivery_confirmation_mail(
            recipients,
            subject,
            message,
            html_message,
            attachments,
            sender_address="office@ben-yacov.com",
        )
        warning_messages: list[str] = []
        if test_send:
            response_payload = {
                "status": "ok",
                "test_send": True,
                "test_recipient": recipients,
                "send_new_bank_details": send_new_bank_details,
            }
            try:
                response_payload.update(_build_delivery_confirmation_payload())
            except Exception as exc:
                log_handled_error("delivery confirmation test send payload refresh failed", exc)
                warning_messages.append("מייל הטסט נשלח, אבל לא הצלחתי כרגע לרענן את טבלת אישורי המסירה.")
            if warning_messages:
                response_payload["warning"] = " ".join(warning_messages)
            return JSONResponse(response_payload)
        related_indexes = _delivery_confirmation_related_indexes(rows, row) or [rows.index(row)]
        sent_at_display = date.today().strftime("%d/%m/%Y")
        for row_index in related_indexes:
            rows[row_index]["target_email"] = recipients
            rows[row_index]["sent"] = "TRUE"
            rows[row_index]["sent_at"] = sent_at_display
            rows[row_index]["updated_at"] = datetime.now().isoformat(timespec="seconds")
        try:
            save_delivery_confirmation_rows(rows)
        except Exception as exc:
            log_handled_error("delivery confirmation sent status sync failed", exc)
            warning_messages.append("המייל נשלח, אבל לא הצלחתי כרגע לשמור את סטטוס השליחה בשיט.")
        try:
            missing_history_updates = 0
            for row_index in related_indexes:
                related_row = rows[row_index]
                history_id = str(related_row.get("history_id") or "").strip()
                if history_id:
                    order_history_rows = load_order_history_rows()
                    target_history_row = next((item for item in order_history_rows if str(item.get("history_id") or "").strip() == history_id), None)
                    if target_history_row:
                        target_history_row["delivery_confirmation_sent"] = "כן"
                        target_history_row["updated_at"] = datetime.now().isoformat(timespec="seconds")
                        upsert_order_history_row(target_history_row)
                    else:
                        missing_history_updates += 1
                else:
                    history_sync = update_order_history_delivery_sent(
                        po_number=related_row.get("po_number", ""),
                        tax_invoice_number=related_row.get("tax_invoice_number", ""),
                        sent=True,
                        source_mode=related_row.get("source_mode", ""),
                        customer_name=related_row.get("company", ""),
                    )
                    if history_sync.get("status") == "skipped":
                        missing_history_updates += 1
            if missing_history_updates:
                warning_messages.append("המייל נשלח, אבל לא הצלחתי לעדכן את כל שורות ההיסטוריה הרלוונטיות.")
        except Exception as exc:
            log_handled_error("delivery confirmation history sent status sync failed", exc)
            warning_messages.append("המייל נשלח, אבל לא הצלחתי כרגע לעדכן את ההיסטוריה.")
        if send_new_bank_details:
            try:
                if not _mark_customer_bank_details_updated(str(row.get("company") or "").strip()):
                    warning_messages.append("המייל נשלח, אבל לא מצאתי שורת לקוח לעדכון תגית פרטי החשבון.")
            except Exception as exc:
                log_handled_error("delivery confirmation bank details customer flag failed", exc)
                warning_messages.append("המייל נשלח, אבל לא הצלחתי לעדכן את תגית פרטי החשבון אצל הלקוח.")
        response_payload = {"status": "ok"}
        try:
            response_payload.update(_build_delivery_confirmation_payload())
        except Exception as exc:
            log_handled_error("delivery confirmation send payload refresh failed", exc)
            warning_messages.append("המייל נשלח, אבל לא הצלחתי כרגע לרענן את טבלת אישורי המסירה.")
        response_payload["send_new_bank_details"] = send_new_bank_details
        response_payload["customer_name"] = str(row.get("company") or "").strip()
        if warning_messages:
            response_payload["warning"] = " ".join(warning_messages)
        return JSONResponse(response_payload)
    except Exception as exc:
        log_handled_error("delivery_confirmations_send failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשלוח את אישור המסירה: {exc}"}, status_code=500)
    finally:
        for uploaded_path in uploaded_attachment_paths:
            try:
                uploaded_path.unlink(missing_ok=True)
            except Exception:
                pass


@app.post("/delivery-confirmations-send-coc")
async def delivery_confirmations_send_coc(request: Request):
    try:
        body = await request.json()
        fulfillment_id = str(body.get("fulfillment_id") or "").strip()
        po_number = _normalize_delivery_confirmation_po_number(body.get("po_number") or "")
        tax_invoice_number = str(body.get("tax_invoice_number") or "").strip()
        source_mode = str(body.get("source_mode") or "").strip().upper()
        mode = str(body.get("mode") or "prod").strip().lower()
        recipients = str(body.get("recipients") or "").strip()
        if not po_number and not fulfillment_id:
            return JSONResponse({"error": "חסר מזהה מימוש או מספר הזמנה."}, status_code=400)
        if not recipients:
            return JSONResponse({"error": "יש להזין כתובת דוא״ל לשליחת מסמך ה־COC."}, status_code=400)

        rows = load_delivery_confirmation_rows()
        row = next(
            (
                candidate
                for candidate in rows
                if (fulfillment_id and str(candidate.get("fulfillment_id") or "").strip() == fulfillment_id)
                or (
                    not fulfillment_id
                    and _normalize_delivery_confirmation_po_number(candidate.get("po_number") or "") == po_number
                    and (not tax_invoice_number or str(candidate.get("tax_invoice_number") or "").strip() == tax_invoice_number)
                    and (not source_mode or str(candidate.get("source_mode") or "").strip().upper() == source_mode)
                )
            ),
            None,
        )
        if not row and not fulfillment_id:
            row = next(
                (
                    candidate
                    for candidate in rows
                    if _normalize_delivery_confirmation_po_number(candidate.get("po_number") or "") == po_number
                ),
                None,
            )
        if not row:
            return JSONResponse({"error": "לא נמצאה שורת אישור מסירה מתאימה."}, status_code=404)
        if not _is_plasan_delivery_confirmation_row(row):
            return JSONResponse({"error": "כפתור שלח COC זמין רק ללקוחות פלסן."}, status_code=400)

        coc_path = await _resolve_delivery_confirmation_coc_attachment(row, mode)
        company_name = str(row.get("company") or "לקוח יקר").strip() or "לקוח יקר"
        row_po_number = str(row.get("po_number") or "—").strip() or "—"
        row_invoice_number = str(row.get("tax_invoice_number") or "").strip()
        invoice_fragment = f", חשבונית {row_invoice_number}" if row_invoice_number else ""
        subject = f"מצורף מסמך COC להזמנה {row_po_number}"
        message = (
            f"שלום {company_name},\n\n"
            f"מצורף מסמך COC עבור הזמנת רכש {row_po_number}{invoice_fragment}.\n\n"
            "בברכה,\n"
            "בן יעקב פתרונות טקסטיל\n"
            "0547720142\n"
        )
        html_message = _delivery_confirmation_mail_html_from_text(message)
        _send_delivery_confirmation_mail(
            recipients,
            subject,
            message,
            html_message,
            [str(coc_path)],
            sender_address="office@ben-yacov.com",
        )
        return JSONResponse(
            {
                "status": "ok",
                "message": "מסמך ה־COC נשלח בהצלחה.",
                "row_key": fulfillment_id or po_number,
            }
        )
    except Exception as exc:
        log_handled_error("delivery_confirmations_send_coc failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשלוח את מסמך ה־COC: {exc}"}, status_code=500)


