@app.post("/customers-set-active")
async def customers_set_active(request: Request):
    body = await request.json()
    activate = bool(body.get("active"))
    selected = body.get("rows") if isinstance(body.get("rows"), list) else []
    selected_rows = [row for row in selected if isinstance(row, dict)]
    if not selected_rows:
        return JSONResponse({"error": "לא נבחרו לקוחות לעדכון."}, status_code=400)
    try:
        active_rows = load_customer_rows()
        inactive_rows = load_inactive_customer_rows()
        if activate:
            moving_rows = [row for row in inactive_rows if any(_customer_row_matches(row, selected_row) for selected_row in selected_rows)]
            updated_inactive_rows = _customer_rows_without_selected(inactive_rows, moving_rows)
            updated_active_rows = active_rows[:]
            for row in moving_rows:
                restored_row = dict(row)
                restored_row["active"] = "TRUE"
                updated_active_rows = _upsert_customer_row(updated_active_rows, restored_row)
            active_rows = _sort_customer_rows(updated_active_rows)
            inactive_rows = _sort_customer_rows(updated_inactive_rows)
        else:
            moving_rows = [row for row in active_rows if any(_customer_row_matches(row, selected_row) for selected_row in selected_rows)]
            updated_active_rows = _customer_rows_without_selected(active_rows, moving_rows)
            updated_inactive_rows = inactive_rows[:]
            for row in moving_rows:
                disabled_row = dict(row)
                disabled_row["active"] = "FALSE"
                updated_inactive_rows = _upsert_customer_row(updated_inactive_rows, disabled_row)
            active_rows = _sort_customer_rows(updated_active_rows)
            inactive_rows = _sort_customer_rows(updated_inactive_rows)

        active_save_result = save_customer_rows(active_rows)
        inactive_save_result = save_inactive_customer_rows(inactive_rows)
        return JSONResponse(
            {
                "status": "ok",
                "rows": active_rows,
                "inactive_rows": inactive_rows,
                "active_save_result": active_save_result,
                "inactive_save_result": inactive_save_result,
                "updated_count": len(moving_rows),
                "active": activate,
            }
        )
    except Exception as exc:
        log_handled_error("customers_set_active failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לעדכן את סטטוס הלקוחות: {exc}"}, status_code=500)


