@app.post("/customers-assign-domain")
async def customers_assign_domain(request: Request):
    body = await request.json()
    selected = body.get("rows") if isinstance(body.get("rows"), list) else []
    selected_rows = [row for row in selected if isinstance(row, dict)]
    if not selected_rows:
        return JSONResponse({"error": "לא נבחרו לקוחות לשיוך."}, status_code=400)
    domain = _normalize_customer_domain_value(body.get("customer_domain") or "")
    if not domain:
        return JSONResponse({"error": "לא נבחר תחום תקין לשיוך."}, status_code=400)
    try:
        active_rows = load_customer_rows()
        inactive_rows = load_inactive_customer_rows()
        updated_count = 0

        def _apply(rows: list[dict]) -> list[dict]:
            nonlocal updated_count
            updated_rows: list[dict] = []
            for row in rows or []:
                current = dict(row)
                if any(_customer_row_matches(current, selected_row) for selected_row in selected_rows):
                    if _normalize_customer_domain_value(current.get("customer_domain") or "") != domain:
                        updated_count += 1
                    current["customer_domain"] = domain
                    current["synced_at"] = _customer_sync_timestamp()
                updated_rows.append(current)
            return _sort_customer_rows(updated_rows)

        active_rows = _apply(active_rows)
        inactive_rows = _apply(inactive_rows)
        active_save_result = save_customer_rows(active_rows)
        inactive_save_result = save_inactive_customer_rows(inactive_rows)
        return JSONResponse(
            {
                "status": "ok",
                "rows": active_rows,
                "inactive_rows": inactive_rows,
                "updated_count": updated_count,
                "customer_domain": domain,
                "active_save_result": active_save_result,
                "inactive_save_result": inactive_save_result,
            }
        )
    except Exception as exc:
        log_handled_error("customers_assign_domain failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשייך את הלקוחות לתחום: {exc}"}, status_code=500)


@app.post("/customers-update")
async def customers_update(request: Request):
    body = await request.json()
    payload = body.get("customer") if isinstance(body.get("customer"), dict) else body
    mode = _normalize_customer_mode(body.get("mode") or "prod")
    cfg = get_mode_config(mode)
    try:
        client_guid = str((payload or {}).get("customer_guid") or "").strip()
        if not client_guid:
            raise ValueError("חסר מזהה פנימי של הלקוח לעדכון.")
        existing_rows = load_customer_rows()
        existing_row = next((row for row in existing_rows if str(row.get("customer_guid") or "").strip() == client_guid), None)
        client = GreenInvoiceClient(
            base_url=cfg["base_url"],
            api_key=cfg["api_key"],
            api_secret=cfg["api_secret"],
        )
        updated = await client.update_client(
            client_guid,
            {
                "name": (payload or {}).get("customer_name"),
                "idNumber": (payload or {}).get("customer_id"),
                "active": (payload or {}).get("active"),
                "send": (payload or {}).get("send"),
                "department": (payload or {}).get("department"),
                "accountingKey": (payload or {}).get("accounting_key"),
                "paymentTerms": (payload or {}).get("payment_terms_days"),
                "phone": (payload or {}).get("phone"),
                "mobile": (payload or {}).get("mobile"),
                "emails": (payload or {}).get("emails"),
                "contactPerson": (payload or {}).get("contact_person"),
                "address": (payload or {}).get("address"),
                "city": (payload or {}).get("city"),
                "zip": (payload or {}).get("zip"),
                "country": (payload or {}).get("country"),
                "remarks": (payload or {}).get("remarks"),
                "sourceMode": (payload or {}).get("source_mode"),
            },
        )
        updated_row = _merge_customer_row_with_payload(existing_row, payload)
        rows = _upsert_customer_row(existing_rows, updated_row)
        save_result = save_customer_rows(_sort_customer_rows(rows))
        warning = ""
        try:
            fetched_rows = await _fetch_all_greeninvoice_customers()
            rows = _overlay_customer_rows(fetched_rows, [updated_row])
            rows = _filter_hidden_customer_rows(rows)
            save_result = save_customer_rows(_sort_customer_rows(rows))
        except Exception as refresh_exc:
            log_handled_error("customers_update refresh from greeninvoice failed", refresh_exc)
            rows = _filter_hidden_customer_rows(load_customer_rows())
            warning = "הלקוח נשמר, אבל הרענון המלא מחשבונית ירוקה לא הושלם כרגע."
        return JSONResponse(
            {
                "status": "ok",
                "updated": updated,
                "rows": rows,
                "mode": mode,
                "save_result": save_result,
                "warning": warning,
            }
        )
    except ValueError as exc:
        return JSONResponse({"error": str(exc)}, status_code=400)
    except Exception as exc:
        log_handled_error("customers_update failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לעדכן את הלקוח בחשבונית ירוקה: {exc}"}, status_code=500)


@app.post("/customers-delete")
async def customers_delete(request: Request):
    body = await request.json()
    row = body.get("customer") if isinstance(body.get("customer"), dict) else body
    if not isinstance(row, dict):
        return JSONResponse({"error": "לא נשלח לקוח למחיקה."}, status_code=400)

    source_mode = _customer_mode_label(row.get("source_mode") or "")
    hidden_keys = _load_hidden_customer_keys()
    hidden_key = _customer_hidden_key(row)
    warning = ""
    deleted_from_api = False

    try:
        if source_mode == "SB":
            client_guid = str(row.get("customer_guid") or "").strip()
            if client_guid:
                cfg = get_mode_config("sandbox")
                client = GreenInvoiceClient(
                    base_url=cfg["base_url"],
                    api_key=cfg["api_key"],
                    api_secret=cfg["api_secret"],
                )
                try:
                    await client.delete_client(client_guid)
                    deleted_from_api = True
                except Exception as api_exc:
                    log_handled_error("customers_delete sandbox api delete failed", api_exc)
                    warning = (
                        "הלקוח הוסר מהאפליקציה, אבל מחיקה מחשבונית ירוקה בסביבת הסנדבוקס נכשלה. "
                        "לרוב זה קורה אם כבר קיימים עליו מסמכים או תנועה במערכת הטסט."
                    )
            else:
                warning = "הלקוח הוסר מהאפליקציה, אבל לא היה מזהה פנימי למחיקה מחשבונית ירוקה בסביבת הסנדבוקס."

        active_rows = _customer_rows_without_selected(load_customer_rows(), [row])
        inactive_rows = _customer_rows_without_selected(load_inactive_customer_rows(), [row])
        if hidden_key:
            hidden_keys.add(hidden_key)
            _save_hidden_customer_keys(hidden_keys)
        active_rows = _filter_hidden_customer_rows(active_rows)
        inactive_rows = _filter_hidden_customer_rows(inactive_rows)
        active_save_result = save_customer_rows(_sort_customer_rows(active_rows))
        inactive_save_result = save_inactive_customer_rows(_sort_customer_rows(inactive_rows))
        return JSONResponse(
            {
                "status": "ok",
                "rows": active_rows,
                "inactive_rows": inactive_rows,
                "deleted_from_api": deleted_from_api,
                "source_mode": source_mode,
                "active_save_result": active_save_result,
                "inactive_save_result": inactive_save_result,
                "warning": warning,
            }
        )
    except Exception as exc:
        log_handled_error("customers_delete failed", exc)
        return JSONResponse({"error": f"לא הצלחתי למחוק את הלקוח: {exc}"}, status_code=500)


@app.post("/customers-send-email")
async def customers_send_email(
    recipients: str = Form(""),
    subject: str = Form(""),
    plain_body: str = Form(""),
    html_body: str = Form(""),
    attachments: list[UploadFile] | None = File(None),
):
    recipient_list = _customer_email_list(recipients)
    if not recipient_list:
        return JSONResponse({"error": "חסרה כתובת מייל לשליחה."}, status_code=400)
    if not str(subject or "").strip():
        return JSONResponse({"error": "חסר נושא למייל."}, status_code=400)

    upload_dir = (BASE_DIR / "output" / "customer-mails")
    stored_files: list[Path] = []
    try:
        for file in attachments or []:
            stored_path, _ = await _store_uploaded_attachment(file, upload_dir, fallback_name="customer-attachment.pdf")
            stored_files.append(stored_path)
        final_html = str(html_body or "").strip()
        final_plain = _customer_mail_plain_text(final_html, plain_body)
        final_rendered_html = _delivery_confirmation_mail_html_from_editor_html(final_html, final_plain)
        _send_delivery_confirmation_mail(
            ", ".join(recipient_list),
            str(subject or "").strip(),
            final_plain,
            final_rendered_html,
            [str(path) for path in stored_files],
        )
        return JSONResponse({"status": "ok", "recipients": recipient_list, "attachments_count": len(stored_files)})
    except Exception as exc:
        log_handled_error("customers_send_email failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשלוח את המייל: {exc}"}, status_code=500)


