@app.post("/quote-send-email")
async def quote_send_email(
    recipients: str = Form(""),
    subject: str = Form(""),
    plain_body: str = Form(""),
    html_body: str = Form(""),
    quote_file: str = Form(""),
    history_id: str = Form(""),
    test_send: str = Form("false"),
    attachments: list[UploadFile] | None = File(None),
):
    recipient_list = _customer_email_list(recipients)
    is_test_send = str(test_send or "").strip().lower() == "true"
    if is_test_send:
        recipient_list = ["asafbeny@gmail.com"]
    if not recipient_list:
        return JSONResponse({"error": "חסרה כתובת מייל לשליחה."}, status_code=400)
    if not str(subject or "").strip():
        return JSONResponse({"error": "חסר נושא למייל."}, status_code=400)

    stored_files: list[Path] = []
    upload_dir = BASE_DIR / "output" / "quote-mails"
    try:
        quote_relative = str(quote_file or "").strip().lstrip("/")
        if quote_relative:
            quote_path = (OUTPUT_DIR / quote_relative).resolve()
            if not quote_path.exists() or not quote_path.is_file():
                return JSONResponse({"error": "קובץ הצעת המחיר לא נמצא."}, status_code=404)
            stored_files.append(quote_path)

        for file in attachments or []:
            stored_path, _ = await _store_uploaded_attachment(file, upload_dir, fallback_name="quote-mail-attachment.pdf")
            stored_files.append(stored_path)

        final_plain = _customer_mail_plain_text(html_body, plain_body)
        final_html = _delivery_confirmation_mail_html_from_editor_html(html_body, final_plain)
        _send_delivery_confirmation_mail(
            ", ".join(recipient_list),
            str(subject or "").strip(),
            final_plain,
            final_html,
            [str(path) for path in stored_files],
        )
        updated_row = None
        target_history_id = str(history_id or "").strip()
        if target_history_id and not is_test_send:
            rows = load_quote_history_rows(force_refresh=True)
            row_index = next((index for index, item in enumerate(rows) if str(item.get("history_id") or "").strip() == target_history_id), -1)
            if row_index >= 0:
                row = dict(rows[row_index])
                row["customer_email"] = ", ".join(_customer_email_list(recipients)) or str(row.get("customer_email") or "").strip()
                row["quote_mail_status"] = "sent"
                row["quote_mail_sent_at"] = datetime.now().strftime("%d/%m/%Y")
                row["updated_at"] = datetime.now().isoformat(timespec="seconds")
                rows[row_index] = row
                save_quote_history_rows(rows)
                payload = _build_quote_history_payload([row])
                updated_row = payload.get("rows", [{}])[0] if payload.get("rows") else {}
        return JSONResponse(
            {
                "status": "ok",
                "recipients": recipient_list,
                "attachments_count": len(stored_files),
                "test_send": is_test_send,
                "row": updated_row,
            }
        )
    except Exception as exc:
        log_handled_error("quote_send_email failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשלוח את מייל הצעת המחיר: {exc}"}, status_code=500)


