@app.post("/marketing-work-managers-save")
async def marketing_work_managers_save(request: Request):
    body = await request.json()
    incoming = body.get("row") or {}
    if not isinstance(incoming, dict):
        return JSONResponse({"error": "מבנה מנהל העבודה לא תקין."}, status_code=400)
    normalized = _normalize_work_manager_row_app(incoming)
    if not normalized["full_name"]:
        return JSONResponse({"error": "חסר שם מלא."}, status_code=400)
    try:
        rows = load_marketing_rows("work_managers")
        pm_phone_digits = {
            _work_manager_phone_digits(str(item.get("contact_phone") or ""))
            for item in load_project_manager_rows()
            if _work_manager_phone_digits(str(item.get("contact_phone") or ""))
        }
        row_phones = {
            _work_manager_phone_digits(normalized.get("phone_1", "")),
            _work_manager_phone_digits(normalized.get("phone_2", "")),
            _work_manager_phone_digits(normalized.get("phone_3", "")),
        }
        row_phones.discard("")
        normalized["project_manager_match"] = "true" if row_phones & pm_phone_digits else "false"
        normalized["project_manager_checked_at"] = datetime.now().isoformat(timespec="seconds")
        replaced = False
        for index, row in enumerate(rows):
            if str(row.get("row_id") or "").strip() != normalized["row_id"]:
                continue
            normalized["updated_at"] = datetime.now().isoformat(timespec="seconds")
            rows[index] = normalized
            replaced = True
            break
        if not replaced:
            normalized["updated_at"] = datetime.now().isoformat(timespec="seconds")
            rows.insert(0, normalized)
        rows = _dedupe_work_manager_rows(rows)
        save_result = save_marketing_rows("work_managers", rows)
        saved_row = next((row for row in rows if str(row.get("row_id") or "") == normalized["row_id"]), normalized)
        return JSONResponse({"status": "ok", "row": saved_row, "save_result": save_result})
    except Exception as exc:
        log_handled_error("marketing_work_managers_save failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשמור את מנהל העבודה: {exc}"}, status_code=500)


