@app.post("/marketing-construction-companies-import-xlsx")
async def marketing_construction_companies_import_xlsx(file: UploadFile = File(...)):
    filename = str(file.filename or "").strip()
    if not filename.lower().endswith(".xlsx"):
        return JSONResponse({"error": "יש להעלות קובץ אקסל מסוג .xlsx"}, status_code=400)
    try:
        from openpyxl import load_workbook

        content = await file.read()
        workbook = load_workbook(io.BytesIO(content), data_only=True)
        sheet = workbook.active
        rows_iter = list(sheet.iter_rows(values_only=True))
        if not rows_iter:
            return JSONResponse({"error": "קובץ האקסל ריק."}, status_code=400)

        header_row = [str(cell or "").strip() for cell in rows_iter[0]]
        header_index = {value: idx for idx, value in enumerate(header_row) if value}

        imported_rows: list[dict] = []
        for row_values in rows_iter[1:]:
            row_values = list(row_values or [])
            mapped = {
                "row_id": str(row_values[header_index.get("מזהה רשומה", -1)] or "").strip() if header_index.get("מזהה רשומה", -1) >= 0 and header_index.get("מזהה רשומה", -1) < len(row_values) else "",
                "company_name": str(row_values[header_index.get("חברה", -1)] or "").strip() if header_index.get("חברה", -1) >= 0 and header_index.get("חברה", -1) < len(row_values) else "",
                "company_id": str(row_values[header_index.get("ח.פ", -1)] or "").strip() if header_index.get("ח.פ", -1) >= 0 and header_index.get("ח.פ", -1) < len(row_values) else "",
                "phone": str(row_values[header_index.get("טלפון", -1)] or "").strip() if header_index.get("טלפון", -1) >= 0 and header_index.get("טלפון", -1) < len(row_values) else "",
                "address": str(row_values[header_index.get("כתובת", -1)] or "").strip() if header_index.get("כתובת", -1) >= 0 and header_index.get("כתובת", -1) < len(row_values) else "",
                "email": str(row_values[header_index.get("דוא\"ל", -1)] or "").strip() if header_index.get("דוא\"ל", -1) >= 0 and header_index.get("דוא\"ל", -1) < len(row_values) else "",
                "details_url": str(row_values[header_index.get("אתר אינטרנט", -1)] or "").strip() if header_index.get("אתר אינטרנט", -1) >= 0 and header_index.get("אתר אינטרנט", -1) < len(row_values) else "",
                "notes": str(row_values[header_index.get("הערות", -1)] or "").strip() if header_index.get("הערות", -1) >= 0 and header_index.get("הערות", -1) < len(row_values) else "",
            }
            if not any(str(value or "").strip() for value in mapped.values()):
                continue
            if not mapped["company_name"]:
                continue
            imported_rows.append(mapped)

        if not imported_rows:
            return JSONResponse({"error": "לא נמצאו רשומות תקינות לייבוא בקובץ."}, status_code=400)

        existing_rows = load_marketing_rows("construction_companies", force_refresh=False)
        merged_rows = _merge_marketing_construction_companies_import(existing_rows, imported_rows)
        save_result = save_marketing_rows("construction_companies", merged_rows)
        payload = _build_marketing_construction_companies_payload(force_refresh=False)
        return JSONResponse({
            "status": "ok",
            "imported_count": len(imported_rows),
            "rows": payload.get("rows") or [],
            "summary": payload.get("summary") or {},
            "save_result": save_result,
        })
    except Exception as exc:
        log_handled_error("marketing_construction_companies_import_xlsx failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לייבא את קובץ האקסל: {exc}"}, status_code=500)


