@app.get("/finance-state")
async def finance_state():
    try:
        cached_payload = _get_cached_finance_state()
        if cached_payload:
            if not _finance_state_cache_is_fresh():
                _ensure_finance_state_refresh_started(force_refresh=False)
            return JSONResponse(
                {
                    "status": "ok",
                    **cached_payload,
                    "source": "cache",
                    "refreshing": bool(FINANCE_STATE_REFRESH_TASK and not FINANCE_STATE_REFRESH_TASK.done()),
                }
            )
        payload = await _refresh_finance_state_cache(force_refresh=False)
        return JSONResponse({"status": "ok", **payload, "source": "sheet"})
    except Exception as exc:
        log_handled_error("finance_state failed", exc)
        cached_payload = _get_cached_finance_state()
        if cached_payload:
            return JSONResponse(
                {
                    "status": "stale",
                    **cached_payload,
                    "warning": f"נטען cache מקומי של טאב הכספים כי הרענון המלא נכשל זמנית: {exc}",
                    "source": "cache",
                }
            )
        cached_rows = get_cached_marketing_rows("finance_invoices")
        if cached_rows:
            invoice_rows = _dedupe_finance_invoice_rows(cached_rows)
            bank_movement_rows = _dedupe_finance_bank_movement_rows(get_cached_marketing_rows("finance_bank_movements"))
            income_tax_rate = _load_finance_income_tax_rate_setting()
            try:
                customer_withholding_rows = _dedupe_finance_customer_withholding_rows(
                    load_marketing_rows("finance_customer_withholdings")
                )
            except Exception:
                customer_withholding_rows = []
            return JSONResponse(
                {
                    "status": "stale",
                    "invoice_rows": invoice_rows,
                    "invoice_summary": {
                        "count": len(invoice_rows),
                        "subtotal_sum": round(sum(_finance_parse_number(row.get("subtotal")) for row in invoice_rows), 2),
                        "vat_sum": round(sum(_finance_parse_number(row.get("vat")) for row in invoice_rows), 2),
                        "total_sum": round(sum(_finance_parse_number(row.get("total")) for row in invoice_rows), 2),
                    },
                    "bank_movement_rows": bank_movement_rows,
                    "bank_movement_summary": _finance_bank_movement_summary(bank_movement_rows),
                    "vat_rows": [],
                    "income_tax_rows": [],
                    "customer_withholding_rows": customer_withholding_rows,
                    "income_tax_rate_percent": income_tax_rate,
                    "warning": f"נטען כרגע cache מקומי של טבלת החשבוניות כי חישובי GreenInvoice נכשלו זמנית: {exc}",
                    "source": "cache",
                }
            )
        return JSONResponse({"error": f"לא הצלחתי לטעון את טאב הכספים: {exc}"}, status_code=500)


@app.post("/finance-bank-movements-upload")
async def finance_bank_movements_upload(files: list[UploadFile] = File(...)):
    if not files:
        return JSONResponse({"error": "לא נבחר קובץ עו״ש לייבוא."}, status_code=400)
    imported_rows: list[dict] = []
    imported_files: list[str] = []
    try:
        _ensure_finance_bank_movement_storage_dirs()
        existing_rows = _dedupe_finance_bank_movement_rows(load_marketing_rows("finance_bank_movements"))
        for file in files:
            original_name = Path(str(file.filename or "").strip()).name or f"bank-movements-{int(time.time())}.xlsx"
            if Path(original_name).suffix.lower() not in {".xlsx", ".xlsm"}:
                return JSONResponse({"error": f"הקובץ {original_name} אינו קובץ אקסל נתמך."}, status_code=400)
            target = _finance_bank_movement_upload_target(original_name)
            target.write_bytes(await file.read())
            parsed = _finance_parse_bank_movement_workbook(target)
            rows = parsed.get("rows") or []
            if not rows:
                return JSONResponse({"error": f"לא הצלחתי לחלץ תנועות עו״ש מתוך {original_name}."}, status_code=400)
            imported_rows.extend(rows)
            imported_files.append(target.name)

        all_rows = _dedupe_finance_bank_movement_rows([*existing_rows, *imported_rows])
        save_result = save_marketing_rows("finance_bank_movements", all_rows)
        _invalidate_finance_state_cache(schedule_refresh=False)
        return JSONResponse(
            {
                "status": "ok",
                "rows": all_rows,
                "summary": _finance_bank_movement_summary(all_rows),
                "imported_count": len(imported_rows),
                "files": imported_files,
                "save_result": save_result,
            }
        )
    except Exception as exc:
        log_handled_error("finance_bank_movements_upload failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לייבא את תנועות העו״ש: {exc}"}, status_code=500)


