        log_handled_error("finance_customer_withholdings_state failed", exc)
        cached_rows = get_cached_marketing_rows("finance_customer_withholdings") or []
        if cached_rows:
            customer_withholding_rows = _dedupe_finance_customer_withholding_rows(cached_rows)
            return JSONResponse(
                {
                    "status": "stale",
                    "customer_withholding_rows": customer_withholding_rows,
                    "warning": f"נטען כרגע cache מקומי של ניכויי המס כי טעינת השיט נכשלה זמנית: {exc}",
                    "source": "cache",
                }
            )
        return JSONResponse({"error": f"לא הצלחתי לטעון את טבלת ניכויי המס: {exc}"}, status_code=500)


