@app.post("/finance-invoices-save")
async def finance_invoices_save(request: Request):
    body = await request.json()
    incoming = body.get("row") or {}
    if not isinstance(incoming, dict):
        return JSONResponse({"error": "מבנה החשבונית לא תקין."}, status_code=400)
    create_payable_row_raw = str(incoming.get("create_payable_row") or "").strip().lower()
    create_payable_row = create_payable_row_raw in {"1", "true", "yes", "on", "כן"}
    supplier_invoice_number = str(
        incoming.get("supplier_invoice_number")
        or incoming.get("invoice_number")
        or incoming.get("supplier_invoice_id")
        or ""
    ).strip()
    payment_due_date = str(incoming.get("payment_due_date") or incoming.get("due_date") or "").strip()
    payment_terms_days = str(incoming.get("payment_terms_days") or "").strip()
    payment_supplier_name = str(incoming.get("payment_supplier_name") or "").strip()
    source_mode = str(incoming.get("source_mode") or "PROD").strip().upper() or "PROD"
    normalized = _normalize_finance_invoice_row_app(incoming)
    normalized = _finance_impute_vat_from_total_if_needed(normalized)
    normalized["report_due_date"] = _finance_due_date_display(normalized.get("invoice_date"))
    try:
        normalized = _finance_sync_invoice_row_drive_targets(normalized)
    except Exception as drive_exc:
        log_handled_error("finance_invoices_save drive sync failed", drive_exc)
    if not normalized["supplier_name"]:
        return JSONResponse({"error": "חסר שם ספק."}, status_code=400)
    if not normalized["service_or_product"]:
        return JSONResponse({"error": "חסר שירות / מוצר."}, status_code=400)
    try:
        rows = _dedupe_finance_invoice_rows(load_marketing_rows("finance_invoices"))
        replaced = False
        for index, row in enumerate(rows):
            if str(row.get("row_id") or "").strip() != normalized["row_id"]:
                continue
            normalized["updated_at"] = datetime.now().isoformat(timespec="seconds")
            rows[index] = normalized
            replaced = True
            break
        if not replaced:
            normalized["updated_at"] = datetime.now().isoformat(timespec="seconds")
            rows.insert(0, normalized)
        rows = _dedupe_finance_invoice_rows(rows)
        save_result = save_marketing_rows("finance_invoices", rows)
        saved_row = next((row for row in rows if str(row.get("row_id") or "").strip() == normalized["row_id"]), normalized)
        payments_sync = None
        if supplier_invoice_number and (create_payable_row or _finance_find_payable_row_for_invoice(supplier_invoice_number)):
            payments_sync = _finance_upsert_payable_row_for_invoice(
                saved_row,
                supplier_invoice_number=supplier_invoice_number,
                payment_terms_days=payment_terms_days,
                payment_due_date=payment_due_date,
                payment_supplier_name=payment_supplier_name,
                source_mode=source_mode,
            )
        return JSONResponse({"status": "ok", "row": saved_row, "save_result": save_result, "payments_sync": payments_sync})
    except Exception as exc:
        log_handled_error("finance_invoices_save failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשמור את החשבונית: {exc}"}, status_code=500)


@app.post("/finance-invoices-override-due-dates")
async def finance_invoices_override_due_dates(request: Request):
    body = await request.json()
    row_id = str(body.get("row_id") or "").strip()
    selected_due_dates = _finance_normalize_due_dates(body.get("due_dates") or [])
    preferred_due_date = _finance_due_date_display(str(body.get("preferred_due_date") or "").strip())
    if not row_id:
        return JSONResponse({"error": "חסר מזהה רשומה."}, status_code=400)
    if not selected_due_dates:
        return JSONResponse({"error": "יש לבחור לפחות מועד דיווח אחד."}, status_code=400)
    try:
        rows = _dedupe_finance_invoice_rows(load_marketing_rows("finance_invoices"))
        target_index = next((index for index, row in enumerate(rows) if str(row.get("row_id") or "").strip() == row_id), -1)
        if target_index < 0:
            return JSONResponse({"error": "לא נמצאה חשבונית תואמת."}, status_code=404)
        normalized = _normalize_finance_invoice_row_app(rows[target_index])
        target_due_date = preferred_due_date if preferred_due_date and preferred_due_date in selected_due_dates else selected_due_dates[0]
        normalized["report_due_date"] = target_due_date
        normalized["report_due_overrides"] = ""
        normalized["updated_at"] = datetime.now().isoformat(timespec="seconds")
        try:
            normalized = _finance_sync_invoice_row_drive_targets(normalized)
        except Exception as drive_exc:
            log_handled_error("finance_invoices_override_due_dates drive sync failed", drive_exc)
        rows[target_index] = normalized
        rows = _dedupe_finance_invoice_rows(rows)
        save_result = save_marketing_rows("finance_invoices", rows)
        saved_row = next((row for row in rows if str(row.get("row_id") or "").strip() == row_id), normalized)
        return JSONResponse({"status": "ok", "row": saved_row, "save_result": save_result})
    except Exception as exc:
        log_handled_error("finance_invoices_override_due_dates failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לעדכן את מועדי הדיווח לחשבונית: {exc}"}, status_code=500)


@app.post("/finance-invoices-delete")
async def finance_invoices_delete(request: Request):
    body = await request.json()
    row_id = str(body.get("row_id") or "").strip()
    if not row_id:
        return JSONResponse({"error": "חסר מזהה רשומה למחיקה."}, status_code=400)
    try:
        rows = _dedupe_finance_invoice_rows(load_marketing_rows("finance_invoices"))
        remaining = [row for row in rows if str(row.get("row_id") or "").strip() != row_id]
        if len(remaining) == len(rows):
            return JSONResponse({"error": "לא נמצאה רשומה תואמת."}, status_code=404)
        save_result = save_marketing_rows("finance_invoices", remaining)
        return JSONResponse({"status": "ok", "deleted_row_id": row_id, "save_result": save_result})
    except Exception as exc:
        log_handled_error("finance_invoices_delete failed", exc)
        return JSONResponse({"error": f"לא הצלחתי למחוק את החשבונית: {exc}"}, status_code=500)


@app.post("/finance-invoices-delete-many")
async def finance_invoices_delete_many(request: Request):
    body = await request.json()
    row_ids = [str(item or "").strip() for item in (body.get("row_ids") or []) if str(item or "").strip()]
    if not row_ids:
        return JSONResponse({"error": "לא נבחרו רשומות למחיקה."}, status_code=400)
    try:
        row_id_set = set(row_ids)
        rows = _dedupe_finance_invoice_rows(load_marketing_rows("finance_invoices"))
        remaining = [row for row in rows if str(row.get("row_id") or "").strip() not in row_id_set]
        deleted_count = len(rows) - len(remaining)
        if deleted_count <= 0:
            return JSONResponse({"error": "לא נמצאו רשומות למחיקה."}, status_code=404)
        save_result = save_marketing_rows("finance_invoices", remaining)
        return JSONResponse({"status": "ok", "deleted_count": deleted_count, "save_result": save_result})
    except Exception as exc:
        log_handled_error("finance_invoices_delete_many failed", exc)
        return JSONResponse({"error": f"לא הצלחתי למחוק את הרשומות שנבחרו: {exc}"}, status_code=500)


@app.post("/finance-invoices-export")
async def finance_invoices_export(request: Request):
    body = await request.json()
    rows = body.get("rows") or []
    report_due_date = str(body.get("report_due_date") or "").strip()
    vat_due_dates = _finance_normalize_due_dates(body.get("vat_due_dates") or [])
    include_vat_summary = bool(body.get("include_vat_summary"))
    if not isinstance(rows, list) or not rows:
        return JSONResponse({"error": "אין כרגע רשומות לייצוא."}, status_code=400)
    if include_vat_summary and not vat_due_dates:
        return JSONResponse({"error": "כדי להוסיף נתוני מע״מ צריך לבחור לפחות תקופת דיווח אחת."}, status_code=400)
    try:
        vat_summary_rows = await _finance_vat_summary_rows_for_due_dates(vat_due_dates) if include_vat_summary else []
        workbook_bytes = _build_finance_invoices_xlsx(rows, vat_summary_rows=vat_summary_rows)
        date_suffix = report_due_date.replace("/", "-") if report_due_date else date.today().strftime("%d-%m-%Y")
        filename = f"חשבוניות-{date_suffix}.xlsx"
        headers = {
            "Content-Disposition": f"attachment; filename*=UTF-8''{quote(filename)}"
        }
        return Response(
            content=workbook_bytes,
            media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            headers=headers,
        )
    except Exception as exc:
        log_handled_error("finance_invoices_export failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לייצא את הטבלה לאקסל: {exc}"}, status_code=500)


