@app.post("/finance-invoices-send-email")
async def finance_invoices_send_email(request: Request):
    body = await request.json()
    selected_due_dates = _finance_normalize_due_dates(body.get("report_due_dates") or [])
    if not selected_due_dates:
        return JSONResponse({"error": "יש לבחור לפחות מועד דיווח אחד."}, status_code=400)
    include_zip = bool(body.get("include_zip"))
    include_pdf = bool(body.get("include_pdf"))
    include_xlsx = bool(body.get("include_xlsx"))
    include_vat_summary = bool(body.get("include_vat_summary"))
    if not any([include_zip, include_pdf, include_xlsx]):
        return JSONResponse({"error": "יש לבחור לפחות סוג צרופה אחד."}, status_code=400)
    recipients = _customer_email_list(body.get("recipients") or "")
    is_test_send = bool(body.get("test_send"))
    if is_test_send:
        recipients = ["asafbeny@gmail.com"]
    if not recipients:
        return JSONResponse({"error": "חסרה כתובת מייל לשליחה."}, status_code=400)

    subject = str(body.get("subject") or "").strip() or _finance_mail_subject(selected_due_dates)
    message = str(body.get("message") or "").strip() or _finance_mail_body(selected_due_dates)

    try:
        all_rows = _finance_backfill_stored_rows(load_marketing_rows("finance_invoices"), persist=True)
        filtered_rows = _finance_rows_for_due_dates(all_rows, selected_due_dates)
        if not filtered_rows:
            return JSONResponse({"error": "לא נמצאו חשבוניות עבור מועדי הדיווח שבחרת."}, status_code=404)

        export_dir = _finance_export_cache_dir() / f"mail_{datetime.now().strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:6]}"
        export_dir.mkdir(parents=True, exist_ok=True)
        vat_summary_rows = await _finance_vat_summary_rows_for_due_dates(selected_due_dates) if include_vat_summary else []
        attachments: list[str] = []
        if include_zip:
            attachments.append(str(_finance_build_zip_attachment(filtered_rows, selected_due_dates, export_dir)))
        if include_pdf:
            pdf_path = export_dir / f"חשבוניות-{ '-'.join(_finance_safe_due_date_slug(item) for item in selected_due_dates) or 'all' }.pdf"
            pdf_path.write_bytes(
                _build_finance_invoices_pdf(
                    filtered_rows,
                    report_due_date=_finance_mail_dates_label(selected_due_dates),
                    vat_summary_rows=vat_summary_rows,
                )
            )
            attachments.append(str(pdf_path))
        if include_xlsx:
            xlsx_path = export_dir / f"חשבוניות-{ '-'.join(_finance_safe_due_date_slug(item) for item in selected_due_dates) or 'all' }.xlsx"
            xlsx_path.write_bytes(_build_finance_invoices_xlsx(filtered_rows, vat_summary_rows=vat_summary_rows))
            attachments.append(str(xlsx_path))

        html_body = _delivery_confirmation_mail_html_from_text(message)
        _send_delivery_confirmation_mail(
            ", ".join(recipients),
            subject,
            message,
            html_body,
            attachments,
        )
        return JSONResponse(
            {
                "status": "ok",
                "recipients": recipients,
                "test_send": is_test_send,
                "attachments": [Path(path).name for path in attachments],
                "rows_count": len(filtered_rows),
                "due_dates": selected_due_dates,
            }
        )
    except Exception as exc:
        log_handled_error("finance_invoices_send_email failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשלוח את החשבוניות: {exc}"}, status_code=500)


@app.post("/finance-invoices-export-deliver")
async def finance_invoices_export_deliver(request: Request):
    body = await request.json()
    format_kind = str(body.get("format") or "").strip().lower()
    channel = str(body.get("channel") or "").strip().lower()
    rows = body.get("rows") or []
    selected_due_dates = _finance_normalize_due_dates(body.get("report_due_dates") or [])
    include_vat_summary = bool(body.get("include_vat_summary"))
    is_test_send = bool(body.get("test_send"))
    if format_kind not in {"pdf", "xlsx"}:
        return JSONResponse({"error": "סוג הייצוא לא תקין."}, status_code=400)
    if channel not in {"email", "whatsapp"}:
        return JSONResponse({"error": "ערוץ השליחה לא תקין."}, status_code=400)
    if not isinstance(rows, list) or not rows:
        return JSONResponse({"error": "אין כרגע חשבוניות לשליחה."}, status_code=400)
    if include_vat_summary and not selected_due_dates:
        return JSONResponse({"error": "כדי להוסיף נתוני מע״מ צריך לבחור לפחות תקופת דיווח אחת."}, status_code=400)

    filtered_rows = _finance_rows_for_due_dates(rows, selected_due_dates) if selected_due_dates else _dedupe_finance_invoice_rows(rows)
    if not filtered_rows:
        return JSONResponse({"error": "לא נמצאו חשבוניות מתאימות לבחירה הזו."}, status_code=404)

    recipients = _customer_email_list(body.get("recipients") or "")
    phone = _normalize_contact_phone(body.get("phone") or "")
    if is_test_send:
        recipients = ["asafbeny@gmail.com"]
        channel = "email"
    if channel == "email" and not recipients:
        return JSONResponse({"error": "חסרה כתובת מייל לשליחה."}, status_code=400)
    if channel == "whatsapp" and not phone:
        return JSONResponse({"error": "חסר מספר ווטסאפ לשליחה."}, status_code=400)

    try:
        export_dir = _finance_export_cache_dir() / f"export_{datetime.now().strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:6]}"
        export_dir.mkdir(parents=True, exist_ok=True)
        vat_summary_rows = await _finance_vat_summary_rows_for_due_dates(selected_due_dates) if include_vat_summary else []
        filename = _finance_export_filename(format_kind, selected_due_dates)
        target_path = export_dir / filename
        if format_kind == "pdf":
            target_path.write_bytes(
                _build_finance_invoices_pdf(
                    filtered_rows,
                    report_due_date=_finance_mail_dates_label(selected_due_dates),
                    vat_summary_rows=vat_summary_rows,
                )
            )
        else:
            target_path.write_bytes(_build_finance_invoices_xlsx(filtered_rows, vat_summary_rows=vat_summary_rows))

        if channel == "whatsapp":
            await send_files_via_whatsapp(
                phone=phone,
                message=_finance_export_whatsapp_message(format_kind, selected_due_dates, include_vat_summary),
                file_paths=[str(target_path)],
            )
            return JSONResponse(
                {
                    "status": "ok",
                    "channel": "whatsapp",
                    "phone": phone,
                    "filename": target_path.name,
                    "rows_count": len(filtered_rows),
                    "due_dates": selected_due_dates,
                }
            )

        subject = _finance_export_subject(format_kind, selected_due_dates)
        message = _finance_export_mail_body(format_kind, selected_due_dates, include_vat_summary)
        html_body = _delivery_confirmation_mail_html_from_text(message)
        _send_delivery_confirmation_mail(
            ", ".join(recipients),
            subject,
            message,
            html_body,
            [str(target_path)],
        )
        return JSONResponse(
            {
                "status": "ok",
                "channel": "email",
                "recipients": recipients,
                "test_send": is_test_send,
                "filename": target_path.name,
                "rows_count": len(filtered_rows),
                "due_dates": selected_due_dates,
            }
        )
    except Exception as exc:
        log_handled_error("finance_invoices_export_deliver failed", exc)
        return JSONResponse({"error": f"לא הצלחתי להכין ולשלוח את קובץ הייצוא: {exc}"}, status_code=500)


@app.get("/finance-invoices-file/{row_id}")
async def finance_invoices_file(row_id: str):
    row_key = str(row_id or "").strip()
    if not row_key:
        return JSONResponse({"error": "חסר מזהה חשבונית."}, status_code=400)
    try:
        rows = _dedupe_finance_invoice_rows(load_marketing_rows("finance_invoices"))
        row = next((item for item in rows if str(item.get("row_id") or "").strip() == row_key), None)
        if not row:
            return JSONResponse({"error": "לא נמצאה חשבונית תואמת."}, status_code=404)
        source_file_path = Path(str(row.get("source_file_path") or "").strip())
        if source_file_path.exists() and source_file_path.is_file():
            media_type, _ = mimetypes.guess_type(str(source_file_path))
            return FileResponse(str(source_file_path), media_type=media_type or "application/octet-stream", filename=source_file_path.name)
        drive_file_id = str(row.get("drive_file_id") or "").strip()
        if drive_file_id:
            return RedirectResponse(_drive_file_view_link(drive_file_id), status_code=302)
        drive_url = str(row.get("drive_url") or "").strip()
        if drive_url:
            return RedirectResponse(drive_url, status_code=302)
        return JSONResponse({"error": "לא נמצא מסמך פתיחה לחשבונית הזו."}, status_code=404)
    except Exception as exc:
        log_handled_error("finance_invoices_file failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לפתוח את החשבונית: {exc}"}, status_code=500)


