@app.post("/finance-invoices-upload")
async def finance_invoices_upload(files: list[UploadFile] = File(...)):
    uploaded_files = files or []
    if not uploaded_files:
        return JSONResponse({"error": "לא נבחרו קבצים להעלאה."}, status_code=400)
    try:
        _ensure_finance_invoice_storage_dirs()
        saved_files = []
        drafts = []
        warnings = []
        for upload in uploaded_files:
            if not upload.filename:
                continue
            original_name = Path(str(upload.filename)).name
            target = _finance_invoice_upload_target(original_name)
            safe_name = target.name
            with target.open("wb") as file_obj:
                shutil.copyfileobj(upload.file, file_obj)
            saved_files.append({"name": safe_name, "path": str(target)})
            parsed_drafts = _finance_parse_uploaded_invoice_drafts(target, safe_name)
            if len(parsed_drafts) > 1:
                _archive_finance_path(target, bucket="processed-source-bundles")
            for draft in parsed_drafts:
                draft = _finance_impute_vat_from_total_if_needed(draft)
                local_path = Path(str(draft.get("source_file_path") or str(target)).strip())
                try:
                    drive_sync = _finance_sync_invoice_file_to_drive(local_path, draft.get("report_due_date"))
                    draft["drive_file_id"] = str(drive_sync.get("drive_file_id") or "").strip()
                    draft["drive_url"] = str(drive_sync.get("drive_url") or "").strip()
                except Exception as drive_exc:
                    warnings.append(_google_drive_sync_warning(drive_exc))
                drafts.append(_normalize_finance_invoice_row_app(draft))
        return JSONResponse(
            {
                "status": "ok",
                "files": saved_files,
                "drafts": drafts,
                "message": "הקבצים נשמרו ופורסרו. אשר את הנתונים במודאל לפני שמירה לטבלה.",
                "warning": warnings[0] if warnings else "",
            }
        )
    except Exception as exc:
        log_handled_error("finance_invoices_upload failed", exc)
        return JSONResponse({"error": f"לא הצלחתי להעלות את הקבצים: {exc}"}, status_code=500)


