        if not row:
            return JSONResponse({"error": "לא מצאתי את שורת הלקוח בטבלת השיווק."}, status_code=404)
        quote_document_id = str(entry.get("quote_document_id") or row.get("quote_document_id") or "").strip()
        remarks = ""
        footer = ""
        if quote_document_id:
            cfg = get_mode_config("prod")
