@app.post("/marketing-pipeline-save")
async def marketing_pipeline_save(request: Request):
    body = await request.json()
    incoming = dict(body.get("row") or body or {})
    target_key = str(incoming.get("customer_key") or "").strip() or _marketing_customer_key(incoming)
    if not target_key:
        return JSONResponse({"error": "חסר מפתח לקוח לעדכון שורת השיווק."}, status_code=400)
    incoming["customer_key"] = target_key
    try:
        rows = load_marketing_rows("pipeline")
        updated_row = None
        for index, row in enumerate(rows):
            if str(row.get("customer_key") or "").strip() != target_key:
                continue
            merged = dict(row)
            for field in ("customer_name", "quote_date", "item_name", "emails", "phone", "contact_name", "note_text", "comm_status", "comm_sent_at"):
                if field in incoming:
                    merged[field] = str(incoming.get(field) or "").strip()
            merged["updated_at"] = datetime.now().isoformat(timespec="seconds")
            rows[index] = merged
            updated_row = merged
            break
        if not updated_row:
            return JSONResponse({"error": "לא מצאתי את שורת הלקוח לעדכון."}, status_code=404)
        save_marketing_rows("pipeline", rows)
        history_row = append_marketing_history_row(
            {
                "created_at": datetime.now().isoformat(timespec="seconds"),
                "customer_key": str(updated_row.get("customer_key") or "").strip(),
                "customer_guid": str(updated_row.get("customer_guid") or "").strip(),
                "customer_id": str(updated_row.get("customer_id") or "").strip(),
                "customer_name": str(updated_row.get("customer_name") or "").strip(),
                "action_type": "pipeline_edit",
                "channel": "internal",
                "subject": "עודכנה שורת לקוח בתהליך שיווק",
                "details_json": json.dumps(
                    {
                        "quote_number": updated_row.get("quote_number"),
                        "emails": updated_row.get("emails"),
                        "contact_name": updated_row.get("contact_name"),
                    },
                    ensure_ascii=False,
                ),
                "result": "ok",
            }
        ).get("row")
        return JSONResponse({"status": "ok", "row": updated_row, "history_row": history_row})
    except Exception as exc:
        log_handled_error("marketing_pipeline_save failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לעדכן את שורת השיווק: {exc}"}, status_code=500)


@app.post("/marketing-pipeline-delete")
async def marketing_pipeline_delete(request: Request):
    body = await request.json()
    target_key = str(body.get("customer_key") or "").strip()
    if not target_key:
        return JSONResponse({"error": "חסר מפתח לקוח למחיקה."}, status_code=400)
    try:
        rows = load_marketing_rows("pipeline")
        removed_row = next((dict(row) for row in rows if str(row.get("customer_key") or "").strip() == target_key), None)
        if not removed_row:
            return JSONResponse({"error": "לא מצאתי את שורת הלקוח למחיקה."}, status_code=404)
        rows = [row for row in rows if str(row.get("customer_key") or "").strip() != target_key]
        save_marketing_rows("pipeline", rows)
        _delete_marketing_pipeline_quote_update_entry(target_key)
        hidden_keys = _load_hidden_marketing_pipeline_keys()
        hidden_keys.add(target_key)
        quote_number = str(removed_row.get("quote_number") or "").strip()
        if quote_number:
            hidden_keys.add(f"quote:{quote_number}")
        _save_hidden_marketing_pipeline_keys(hidden_keys)
        history_row = append_marketing_history_row(
            {
                "created_at": datetime.now().isoformat(timespec="seconds"),
                "customer_key": str(removed_row.get("customer_key") or "").strip(),
                "customer_guid": str(removed_row.get("customer_guid") or "").strip(),
                "customer_id": str(removed_row.get("customer_id") or "").strip(),
                "customer_name": str(removed_row.get("customer_name") or "").strip(),
                "action_type": "pipeline_delete",
                "channel": "internal",
                "subject": "נמחקה שורת לקוח בתהליך שיווק",
                "details_json": json.dumps({"quote_number": removed_row.get("quote_number")}, ensure_ascii=False),
                "result": "ok",
            }
        ).get("row")
        return JSONResponse({"status": "ok", "customer_key": target_key, "history_row": history_row})
    except Exception as exc:
        log_handled_error("marketing_pipeline_delete failed", exc)
        return JSONResponse({"error": f"לא הצלחתי למחוק את שורת הלקוח: {exc}"}, status_code=500)


