@app.post("/marketing-save-reminder")
async def marketing_save_reminder(request: Request):
    body = await request.json()
    customer = body.get("customer") if isinstance(body.get("customer"), dict) else body
    customer_key = _marketing_customer_key(customer)
    due_date = str(body.get("due_date") or "").strip()
    due_time = str(body.get("due_time") or "").strip() or "09:00"
    customer_name = str(body.get("customer_name") or customer.get("customer_name") or "").strip()
    if not customer_key:
        key_seed = customer_name or f"manual-{datetime.now().strftime('%Y%m%d%H%M%S')}"
        customer_key = re.sub(r"[^0-9A-Za-z\u0590-\u05FF]+", "-", str(key_seed)).strip("-").lower()
    if not customer_key:
        return JSONResponse({"error": "חסר מפתח לקוח לשמירת תזכורת."}, status_code=400)
    if not due_date:
        return JSONResponse({"error": "חסר תאריך לתזכורת."}, status_code=400)
    try:
        row = {
            "reminder_id": str(body.get("reminder_id") or "").strip(),
            "customer_key": customer_key,
            "customer_guid": str(customer.get("customer_guid") or "").strip(),
            "customer_id": str(customer.get("customer_id") or "").strip(),
            "customer_name": customer_name or str(customer.get("customer_name") or "").strip(),
            "contact_name": str(body.get("contact_name") or customer.get("contact_name") or "").strip(),
            "phone": str(body.get("phone") or customer.get("phone") or "").strip(),
            "emails": str(body.get("emails") or customer.get("emails") or "").strip(),
            "note_text": str(body.get("note_text") or customer.get("note_text") or "").strip(),
            "due_date": due_date,
            "due_time": due_time,
            "status": str(body.get("status") or "open").strip() or "open",
            "channel": str(body.get("channel") or "phone").strip() or "phone",
            "message": str(body.get("message") or "").strip(),
            "comm_status": str(body.get("comm_status") or customer.get("comm_status") or "").strip(),
            "comm_sent_at": str(body.get("comm_sent_at") or customer.get("comm_sent_at") or "").strip(),
            "auto_whatsapp_status": str(body.get("auto_whatsapp_status") or customer.get("auto_whatsapp_status") or "").strip(),
            "auto_whatsapp_sent_at": str(body.get("auto_whatsapp_sent_at") or customer.get("auto_whatsapp_sent_at") or "").strip(),
            "created_at": str(body.get("created_at") or datetime.now().isoformat(timespec="seconds")).strip(),
            "completed_at": str(body.get("completed_at") or "").strip(),
        }
        result = upsert_marketing_reminder(row)
        history_row = append_marketing_history_row(
            {
                "created_at": datetime.now().isoformat(timespec="seconds"),
                "customer_key": customer_key,
                "customer_guid": row["customer_guid"],
                "customer_id": row["customer_id"],
                "customer_name": row["customer_name"],
                "action_type": MARKETING_HISTORY_ACTION_REMINDER,
                "channel": row["channel"],
                "subject": f"תזכורת ל-{row['due_date']}",
                "details_json": json.dumps(
                    {
                        "message": row["message"],
                        "status": row["status"],
                        "due_date": row["due_date"],
                        "due_time": row["due_time"],
                    },
                    ensure_ascii=False,
                ),
                "result": "ok",
            }
        ).get("row")
        return JSONResponse({"status": "ok", **result, "history_row": history_row})
    except Exception as exc:
        log_handled_error("marketing_save_reminder failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשמור את התזכורת: {exc}"}, status_code=500)


@app.post("/marketing-reminder-delete")
async def marketing_reminder_delete(request: Request):
    body = await request.json()
    reminder_id = str(body.get("reminder_id") or "").strip()
    if not reminder_id:
        return JSONResponse({"error": "חסר מזהה תזכורת למחיקה."}, status_code=400)
    try:
        rows = load_marketing_rows("reminders")
        removed_row = next((dict(row) for row in rows if str(row.get("reminder_id") or "").strip() == reminder_id), None)
        if not removed_row:
            return JSONResponse({"error": "לא נמצאה תזכורת למחיקה."}, status_code=404)
        rows = [row for row in rows if str(row.get("reminder_id") or "").strip() != reminder_id]
        save_marketing_rows("reminders", rows)
        history_row = append_marketing_history_row(
            {
                "created_at": datetime.now().isoformat(timespec="seconds"),
                "customer_key": str(removed_row.get("customer_key") or "").strip(),
                "customer_guid": str(removed_row.get("customer_guid") or "").strip(),
                "customer_id": str(removed_row.get("customer_id") or "").strip(),
                "customer_name": str(removed_row.get("customer_name") or "").strip(),
                "action_type": "reminder_delete",
                "channel": "internal",
                "subject": "נמחקה תזכורת שיווק",
                "details_json": json.dumps({"reminder_id": reminder_id}, ensure_ascii=False),
                "result": "ok",
            }
        ).get("row")
        return JSONResponse({"status": "ok", "reminder_id": reminder_id, "history_row": history_row})
    except Exception as exc:
        log_handled_error("marketing_reminder_delete failed", exc)
        return JSONResponse({"error": f"לא הצלחתי למחוק את התזכורת: {exc}"}, status_code=500)


@app.post("/marketing-complete-reminder")
async def marketing_complete_reminder(request: Request):
    body = await request.json()
    reminder_id = str(body.get("reminder_id") or "").strip()
    if not reminder_id:
        return JSONResponse({"error": "חסר מזהה תזכורת לסגירה."}, status_code=400)
    try:
        rows = load_marketing_rows("reminders")
        updated_row = None
        for row in rows:
            if str(row.get("reminder_id") or "").strip() != reminder_id:
                continue
            row["status"] = "done"
            row["completed_at"] = datetime.now().isoformat(timespec="seconds")
            updated_row = dict(row)
            break
        if not updated_row:
            return JSONResponse({"error": "לא נמצאה תזכורת תואמת."}, status_code=404)
        save_result = save_marketing_rows("reminders", rows)
        append_marketing_history_row(
            {
                "created_at": datetime.now().isoformat(timespec="seconds"),
                "customer_key": str(updated_row.get("customer_key") or "").strip(),
                "customer_guid": str(updated_row.get("customer_guid") or "").strip(),
                "customer_id": str(updated_row.get("customer_id") or "").strip(),
                "customer_name": str(updated_row.get("customer_name") or "").strip(),
                "action_type": MARKETING_HISTORY_ACTION_REMINDER_DONE,
                "channel": str(updated_row.get("channel") or "").strip(),
                "subject": f"תזכורת הושלמה: {updated_row.get('due_date') or ''}".strip(),
                "details_json": json.dumps({"reminder_id": reminder_id}, ensure_ascii=False),
                "result": "ok",
            }
        )
        return JSONResponse({"status": "ok", "row": updated_row, "save_result": save_result})
    except Exception as exc:
        log_handled_error("marketing_complete_reminder failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לסמן את התזכורת כטופלה: {exc}"}, status_code=500)


@app.post("/marketing-send-email")
async def marketing_send_email(
    recipients: str = Form(""),
    subject: str = Form(""),
    plain_body: str = Form(""),
    html_body: str = Form(""),
    customer_key: str = Form(""),
    customer_guid: str = Form(""),
    customer_id: str = Form(""),
    customer_name: str = Form(""),
    reminder_id: str = Form(""),
    test_send: str = Form("false"),
    doc_asset_keys: str = Form(""),
    attachments: list[UploadFile] | None = File(None),
):
    upload_dir = BASE_DIR / "output" / "marketing-mails"
    is_test_send = str(test_send or "").strip().lower() == "true"
    stored_files: list[Path] = []
    try:
        for file in attachments or []:
            stored_path, _ = await _store_uploaded_attachment(file, upload_dir, fallback_name="marketing-attachment.pdf")
            stored_files.append(stored_path)
        result = _send_marketing_email_message(
            recipients=recipients,
            subject=subject,
            plain_body=plain_body,
            html_body=html_body,
            customer_key=customer_key,
            customer_guid=customer_guid,
            customer_id=customer_id,
            customer_name=customer_name,
            reminder_id=reminder_id,
            test_send=is_test_send,
            doc_asset_keys=[item.strip() for item in str(doc_asset_keys or "").split(",") if item.strip()],
            extra_attachment_paths=stored_files,
        )
        return JSONResponse(
            {
                "status": "ok",
                **result,
            }
        )
    except Exception as exc:
        log_handled_error("marketing_send_email failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשלוח את מייל השיווק: {exc}"}, status_code=500)


@app.post("/marketing-send-whatsapp")
async def marketing_send_whatsapp(request: Request):
    body = await request.json()
    customer_key = str(body.get("customer_key") or "").strip()
    reminder_id = str(body.get("reminder_id") or "").strip()
    phone = str(body.get("phone") or "").strip()
    message = str(body.get("message") or "").strip()
    doc_asset_keys = [str(item or "").strip() for item in (body.get("doc_asset_keys") or []) if str(item or "").strip()]
    customer_guid = str(body.get("customer_guid") or "").strip()
    customer_id = str(body.get("customer_id") or "").strip()
    customer_name = str(body.get("customer_name") or "").strip()
    if not phone:
        return JSONResponse({"error": "חסר מספר טלפון לשליחת וואטסאפ."}, status_code=400)
    if not message:
        return JSONResponse({"error": "חסר תוכן להודעת הוואטסאפ."}, status_code=400)
    try:
        file_paths: list[str] = []
        for asset_key in doc_asset_keys:
            spec = MARKETING_DRIVE_ASSETS.get(asset_key)
            if not spec:
                continue
            local_path = Path(spec["local_path"])
            if local_path.exists() and local_path.is_file():
                file_paths.append(str(local_path))
        await send_files_via_whatsapp(phone=phone, message=message, file_paths=file_paths)
        history_row = append_marketing_history_row(
            {
                "created_at": datetime.now().isoformat(timespec="seconds"),
                "customer_key": customer_key,
                "customer_guid": customer_guid,
                "customer_id": customer_id,
                "customer_name": customer_name,
                "action_type": MARKETING_HISTORY_ACTION_WHATSAPP,
                "channel": "whatsapp",
                "subject": "נשלחה הודעת וואטסאפ שיווקית",
                "details_json": json.dumps({"phone": phone, "message": message, "doc_asset_keys": doc_asset_keys}, ensure_ascii=False),
                "result": "ok",
            }
        ).get("row")
        sent_at = datetime.now().isoformat(timespec="seconds")
        updated_row = _update_marketing_pipeline_comm_status(
            customer_key,
            "whatsapp",
            sent_at,
        )
        if not updated_row and reminder_id:
            updated_row = _update_marketing_reminder_comm_status(
                reminder_id,
                "whatsapp",
                sent_at,
            )
        return JSONResponse({"status": "ok", "phone": phone, "row": updated_row, "history_row": history_row, "attachments_count": len(file_paths)})
    except Exception as exc:
        log_handled_error("marketing_send_whatsapp failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשלוח את הודעת הוואטסאפ: {exc}"}, status_code=500)


