@app.post("/payments-transfer-edit-start")
async def payments_transfer_edit_start(request: Request):
    body = await request.json()
    sheet_title = str(body.get("sheet_title") or "").strip()
    row_number = body.get("row_number")
    session_id = str(body.get("session_id") or "").strip()

    if not sheet_title:
        return JSONResponse({"error": "חסר שם טאב."}, status_code=400)
    try:
        row_number = int(row_number)
    except Exception:
        return JSONResponse({"error": "חסר מספר שורה תקין."}, status_code=400)
    if not session_id:
        return JSONResponse({"error": "חסר מזהה סשן לעריכה."}, status_code=400)

    user_id, user_name = _payments_current_user_identity(request)
    row_key = _payments_presence_key(sheet_title, row_number)
    now_ts = time.time()
    async with PAYMENTS_EDIT_PRESENCE_LOCK:
        _payments_cleanup_edit_presence_unlocked(now_ts)
        existing = PAYMENTS_EDIT_PRESENCE.get(row_key)
        occupied = bool(
            existing
            and str(existing.get("session_id") or "").strip() != session_id
            and str(existing.get("user_id") or "").strip() != user_id
        )
        if not occupied:
            PAYMENTS_EDIT_PRESENCE[row_key] = {
                "user_id": user_id,
                "user_name": user_name,
                "session_id": session_id,
                "updated_at": now_ts,
                "expires_at": now_ts + PAYMENTS_EDIT_PRESENCE_TTL_SECONDS,
            }
        active_editor = copy.deepcopy(existing if occupied else PAYMENTS_EDIT_PRESENCE.get(row_key) or {})
        presence_snapshot = _payments_presence_snapshot_unlocked()
    return JSONResponse(
        {
            "status": "occupied" if occupied else "ok",
            "row_key": row_key,
            "current_user_id": user_id,
            "current_user_name": user_name,
            "active_editor": active_editor,
            "presence": presence_snapshot,
        }
    )


