@app.post("/receipt-email-reminder-send")
async def receipt_email_reminder_send(request: Request):
    body = await request.json()
    mode = (body.get("mode") or "prod").strip().lower()
    invoice = body.get("invoice") or {}
    recipients = str(body.get("recipients") or "").strip()
    subject = str(body.get("subject") or "").strip()
    message = str(body.get("message") or "").strip()

    if mode not in {"prod", "sandbox"}:
        mode = "prod"

    try:
        invoice_number = str(invoice.get("number") or "").strip()
        if not invoice_number:
            return JSONResponse({"error": "חסר מספר חשבונית מס."}, status_code=400)

        recipients = recipients or _find_delivery_contact_email(str(invoice.get("customer_name") or ""))
        if not recipients:
            return JSONResponse({"error": "לא נמצאה כתובת מייל ללקוח. אפשר להזין אותה ידנית."}, status_code=400)

        subject = subject or _build_receipt_email_reminder_subject(invoice)
        message = message or _build_receipt_email_reminder_body(invoice)

        invoice_doc, invoice_mode = await _find_greeninvoice_invoice_document_any_mode(mode, invoice_number)
        if not invoice_doc:
            return JSONResponse({"error": f"לא מצאתי בחשבונית ירוקה את חשבונית המס {invoice_number}."}, status_code=404)

        raw = invoice_doc.get("raw") or {}
        url_payload = raw.get("url") or {}
        invoice_url = ""
        if isinstance(url_payload, dict):
            invoice_url = str(url_payload.get("origin") or url_payload.get("he") or "").strip()
        if not invoice_url:
            return JSONResponse({"error": "לא נמצא קישור PDF לחשבונית בחשבונית ירוקה."}, status_code=404)

        cfg = get_mode_config(invoice_mode or mode)
        client = GreenInvoiceClient(
            base_url=cfg["base_url"],
            api_key=cfg["api_key"],
            api_secret=cfg["api_secret"],
        )
        token = await client._get_token()
        temp_dir = OUTPUT_DIR / "_receipt_email_cache"
        temp_dir.mkdir(parents=True, exist_ok=True)
        temp_pdf = await client.download_pdf(token, invoice_url, temp_dir / f"receipt_invoice_{invoice_number}.pdf")
        plain_message = _payment_reminder_plain_text_with_spacers(message)
        html_message = _payment_reminder_html_from_text(message)
        _send_delivery_confirmation_mail(
            recipients,
            subject,
            plain_message,
            html_message,
            [str(temp_pdf)],
            sender_address="office@ben-yacov.com",
        )
        return JSONResponse({"status": "ok", "attachment": str(temp_pdf), "recipients": recipients})
    except Exception as exc:
        log_handled_error("receipt_email_reminder_send failed", exc)
        return JSONResponse({"error": f"לא הצלחתי לשלוח תזכורת במייל: {exc}"}, status_code=500)


def _build_delivery_confirmation_payload() -> dict:
    confirmations = load_delivery_confirmation_rows()
    suppressed_keys = _load_delivery_confirmation_suppressions()
    deduped_confirmations: list[dict] = []
    deduped_index_by_key: dict[tuple[str, str, str], int] = {}

    def _delivery_confirmation_is_suppressed(
        *,
        company: str = "",
        po_number: str = "",
        source_mode: str = "",
        tax_invoice_number: str = "",
        delivery_document_number: str = "",
    ) -> bool:
        exact_key = _delivery_confirmation_suppression_key(
            company=company,
            po_number=po_number,
            source_mode=source_mode,
            tax_invoice_number=tax_invoice_number,
            delivery_document_number=delivery_document_number,
        )
        if exact_key in suppressed_keys:
            return True
        fallback_key = _delivery_confirmation_suppression_key(
            company=company,
            po_number=po_number,
            source_mode="",
            tax_invoice_number=tax_invoice_number,
            delivery_document_number=delivery_document_number,
        )
        return fallback_key in suppressed_keys

    def _delivery_confirmation_row_merge_score(row: dict) -> tuple[int, int, int, int, int, str]:
        return (
            1 if str(row.get("history_id") or "").strip() else 0,
            1 if str(row.get("fulfillment_id") or "").strip() else 0,
            1 if str(row.get("delivery_document_id") or "").strip() else 0,
            1 if str(row.get("delivery_document_number") or "").strip() else 0,
            len(str(row.get("target_email") or "").strip()),
            str(row.get("updated_at") or "").strip(),
        )

    confirmations_deduped = False
    for row in confirmations:
        key = _delivery_confirmation_row_key(
            row.get("company", ""),
            row.get("po_number", ""),
            row.get("tax_invoice_number", ""),
        )
        existing_index = deduped_index_by_key.get(key)
        if existing_index is None:
            normalized_row = dict(row)
            normalized_row["po_number"] = _normalize_delivery_confirmation_po_number(row.get("po_number", ""))
            deduped_index_by_key[key] = len(deduped_confirmations)
            deduped_confirmations.append(normalized_row)
            continue
        confirmations_deduped = True
        current_best = deduped_confirmations[existing_index]
        candidate = dict(row)
        candidate["po_number"] = _normalize_delivery_confirmation_po_number(row.get("po_number", ""))
        if _delivery_confirmation_row_merge_score(candidate) > _delivery_confirmation_row_merge_score(current_best):
            merged = {**current_best, **candidate}
            if not str(merged.get("po_number") or "").strip():
                merged["po_number"] = _normalize_delivery_confirmation_po_number(
                    candidate.get("po_number", "") or current_best.get("po_number", "")
                )
            deduped_confirmations[existing_index] = merged
        else:
            merged = {**candidate, **current_best}
            if not str(merged.get("po_number") or "").strip():
                merged["po_number"] = _normalize_delivery_confirmation_po_number(
                    current_best.get("po_number", "") or candidate.get("po_number", "")
                )
            deduped_confirmations[existing_index] = merged
    if confirmations_deduped:
        confirmations = deduped_confirmations
        try:
            save_delivery_confirmation_rows(confirmations)
        except Exception as exc:
            log_handled_error("delivery confirmation dedupe save failed during payload build", exc)
    else:
        confirmations = deduped_confirmations

    confirmations_without_suppressed: list[dict] = []
    suppressed_existing_removed = False
    for row in confirmations:
        if _delivery_confirmation_is_suppressed(
            company=row.get("company", ""),
            po_number=row.get("po_number", ""),
            source_mode=row.get("source_mode", ""),
            tax_invoice_number=row.get("tax_invoice_number", ""),
            delivery_document_number=row.get("delivery_document_number", ""),
        ):
            suppressed_existing_removed = True
            continue
        confirmations_without_suppressed.append(row)
    if suppressed_existing_removed:
        confirmations = confirmations_without_suppressed
        try:
            save_delivery_confirmation_rows(confirmations)
        except Exception as exc:
            log_handled_error("delivery confirmation suppression save failed during payload build", exc)
    else:
        confirmations = confirmations_without_suppressed

    payments_state = load_payment_transfer_rows()
    all_payment_rows = list(payments_state.get("all_rows") or [])
    qualifying_payment_rows: list[dict] = []
    payment_rows_by_key: dict[tuple[str, str, str], dict] = {}
    payment_rows_by_fallback_key: dict[tuple[str, str, str], dict] = {}
    for payment_row in all_payment_rows:
        payment_direction = str(payment_row.get("payment_direction") or "").strip()
        invoice_date = str(payment_row.get("invoice_date") or "").strip()
        order_date = _parse_order_display_date(invoice_date)
        if payment_direction != "גביה" or not order_date or order_date < _delivery_confirmation_threshold():
            continue
        qualifying_payment_rows.append(payment_row)
        key = _delivery_confirmation_row_key(
            payment_row.get("customer_name", ""),
            payment_row.get("po_number", ""),
            payment_row.get("tax_invoice_number", ""),
        )
        payment_rows_by_key[key] = payment_row
        payment_rows_by_fallback_key[
            _delivery_confirmation_fallback_key(
                payment_row.get("customer_name", ""),
                payment_row.get("po_number", ""),
                payment_row.get("source_mode", ""),
            )
        ] = payment_row

    confirmations_changed = False
    for row in confirmations:
        key = _delivery_confirmation_row_key(
            row.get("company", ""),
            row.get("po_number", ""),
            row.get("tax_invoice_number", ""),
        )
        payment_row = payment_rows_by_key.get(key)
        if not payment_row:
            payment_row = payment_rows_by_fallback_key.get(
                _delivery_confirmation_fallback_key(
                    row.get("company", ""),
                    row.get("po_number", ""),
                    row.get("source_mode", ""),
                )
            )
        if not payment_row:
            continue
        desired_source_mode = str(payment_row.get("source_mode") or "").strip().upper()
        if desired_source_mode and str(row.get("source_mode") or "").strip().upper() != desired_source_mode:
            row["source_mode"] = desired_source_mode
            confirmations_changed = True
        desired_invoice_number = str(payment_row.get("tax_invoice_number") or "").strip()
        if desired_invoice_number and str(row.get("tax_invoice_number") or "").strip() != desired_invoice_number:
            row["tax_invoice_number"] = desired_invoice_number
            confirmations_changed = True
        desired_invoice_date = str(payment_row.get("invoice_date") or "").strip()
        if desired_invoice_date and str(row.get("invoice_date") or "").strip() != desired_invoice_date:
            row["invoice_date"] = desired_invoice_date
            confirmations_changed = True
        desired_order_total = str(payment_row.get("amount") or "").strip().replace(",", "")
        if desired_order_total:
            try:
                desired_order_total = f"{float(desired_order_total):.2f}"
            except Exception:
                desired_order_total = str(payment_row.get("amount") or "").strip()
        if desired_order_total and str(row.get("order_total") or "").strip() != desired_order_total:
            row["order_total"] = desired_order_total
            confirmations_changed = True
        desired_company = str(payment_row.get("customer_name") or "").strip()
        if desired_company and str(row.get("company") or "").strip() != desired_company:
            row["company"] = desired_company
            confirmations_changed = True
        desired_po_number = _normalize_delivery_confirmation_po_number(payment_row.get("po_number", ""))
        if desired_po_number and str(row.get("po_number") or "").strip() != desired_po_number:
            row["po_number"] = desired_po_number
            confirmations_changed = True
        if desired_source_mode and str(row.get("source_mode") or "").strip().upper() != desired_source_mode:
            row["source_mode"] = desired_source_mode
            confirmations_changed = True
    existing_keys = {
        _delivery_confirmation_row_key(
            row.get("company", ""),
            row.get("po_number", ""),
            row.get("tax_invoice_number", ""),
        )
        for row in confirmations
    }
    for payment_row in qualifying_payment_rows:
        invoice_date = str(payment_row.get("invoice_date") or "").strip()
        key = _delivery_confirmation_row_key(
            payment_row.get("customer_name", ""),
            payment_row.get("po_number", ""),
            payment_row.get("tax_invoice_number", ""),
        )
        if key in existing_keys:
            continue
        if _delivery_confirmation_is_suppressed(
            company=payment_row.get("customer_name", ""),
            po_number=payment_row.get("po_number", ""),
            source_mode=payment_row.get("source_mode", ""),
            tax_invoice_number=payment_row.get("tax_invoice_number", ""),
            delivery_document_number="",
        ):
            continue
        confirmations.append(
            {
                "order_date": invoice_date,
                "company": payment_row.get("customer_name", ""),
                "po_number": _normalize_delivery_confirmation_po_number(payment_row.get("po_number", "")),
                "invoice_date": invoice_date,
                "tax_invoice_number": payment_row.get("tax_invoice_number", ""),
                "order_total": str(payment_row.get("amount") or "").strip(),
                "target_email": "",
                "signed_delivery_name": "",
                "signed_delivery_local_path": "",
                "signed_delivery_drive_file_id": "",
                "invoice_drive_file_id": "",
                "coc_name": "",
                "coc_drive_file_id": "",
                "order_drive_folder_id": "",
                "order_drive_folder_url": "",
                "fulfillment_id": "",
                "history_id": "",
                "document_mode": "full",
                "delivery_document_number": "",
                "delivery_document_id": "",
                "sent": "FALSE",
                "sent_at": "",
                "source_mode": str(payment_row.get("source_mode") or "").strip().upper(),
            }
        )
        existing_keys.add(key)
        confirmations_changed = True
    if confirmations_changed:
        try:
            save_delivery_confirmation_rows(confirmations)
        except Exception as exc:
            log_handled_error("delivery confirmation refresh save failed during payload build", exc)
        confirmations = [dict(row) for row in confirmations]
    filtered_confirmations = []
    for row in confirmations:
        order_date = _parse_order_display_date(row.get("order_date", ""))
        if order_date and order_date >= _delivery_confirmation_threshold():
            filtered_confirmations.append(row)
    existing_contact_rows = load_delivery_contact_rows()
    contacts_rows = build_delivery_contact_rows_for_active_orders(filtered_confirmations, existing_contact_rows)
    if json.dumps(contacts_rows, ensure_ascii=False, sort_keys=True) != json.dumps(existing_contact_rows, ensure_ascii=False, sort_keys=True):
        try:
            save_delivery_contact_rows(contacts_rows)
        except Exception as exc:
            log_handled_error("delivery confirmation contacts save failed during payload build", exc)
        contacts_rows = [dict(row) for row in contacts_rows]
    contact_email_by_company = {
        _normalize_company_name(row.get("company", "")): str(row.get("email") or "").strip()
        for row in contacts_rows
        if str(row.get("email") or "").strip()
    }
    confirmation_email_sync_changed = False
    for row in confirmations:
        company_key = _normalize_company_name(row.get("company", ""))
        desired_target_email = contact_email_by_company.get(company_key, "") or _default_delivery_contact_email(
            str(row.get("company") or "")
        )
        if desired_target_email and str(row.get("target_email") or "").strip() != desired_target_email:
            row["target_email"] = desired_target_email
            confirmation_email_sync_changed = True
    if confirmation_email_sync_changed:
        try:
            save_delivery_confirmation_rows(confirmations)
        except Exception as exc:
            log_handled_error("delivery confirmation contact email sync save failed during payload build", exc)
        confirmations = [dict(row) for row in confirmations]
    sent_rows = [row for row in filtered_confirmations if str(row.get("sent", "")).strip().upper() == "TRUE"]
    unsent_rows = [row for row in filtered_confirmations if str(row.get("sent", "")).strip().upper() != "TRUE"]
    return {
        "rows": filtered_confirmations,
        "sent_rows": sent_rows,
        "unsent_rows": unsent_rows,
        "contacts_rows": contacts_rows,
        "threshold_date": _delivery_confirmation_threshold().strftime("%d/%m/%Y"),
    }


def _normalize_order_history_links(value) -> list[dict]:
    if isinstance(value, list):
        raw_items = value
    else:
        raw = str(value or "").strip()
        if not raw:
            return []
        try:
            raw_items = json.loads(raw)
        except Exception:
            return []
    links: list[dict] = []
    for item in raw_items:
        if not isinstance(item, dict):
            continue
        name = str(item.get("name") or "").strip()
        url = str(item.get("url") or "").strip()
        if not name and not url:
            continue
        links.append({"name": name, "url": url})
    return links


