@app.post("/hr-employee-delete")
async def hr_employee_delete(request: Request):
    try:
        body = await request.json()
    except Exception:
        body = {}
    employee_id = str((body or {}).get("employee_id") or "").strip()
    if not employee_id:
        return JSONResponse({"error": "חסר מזהה עובד למחיקה."}, status_code=400)
    try:
        employees = load_hr_rows("employees")
        employee = next((row for row in employees if str(row.get("employee_id") or "").strip() == employee_id), None)
        if not employee:
            return JSONResponse({"error": "העובד לא נמצא."}, status_code=404)
        payroll_rows = load_hr_rows("payroll")
        contribution_rows = load_hr_rows("contributions")
        hours_rows = load_hr_rows("hours")
        document_rows = load_hr_rows("documents")

        drive_delete_results: list[dict] = []
        local_delete_results: list[dict] = []

        for row in payroll_rows:
            if str(row.get("employee_id") or "").strip() != employee_id:
                continue
            drive_delete_results.append(_hr_delete_drive_target(str(row.get("payslip_drive_file_id") or "").strip(), "payslip"))
            local_delete_results.append(_hr_delete_local_file(_hr_local_file_path(employee_id, str(row.get("month_key") or ""), str(row.get("payslip_file_name") or ""))))
        for row in contribution_rows:
            if str(row.get("employee_id") or "").strip() != employee_id:
                continue
            drive_delete_results.append(_hr_delete_drive_target(str(row.get("split_report_drive_file_id") or "").strip(), "contribution-split"))
            drive_delete_results.append(_hr_delete_drive_target(str(row.get("proof_drive_file_id") or "").strip(), "contribution-proof"))
            local_delete_results.append(_hr_delete_local_file(_hr_local_file_path(employee_id, str(row.get("month_key") or ""), str(row.get("split_report_file_name") or ""))))
            local_delete_results.append(_hr_delete_local_file(_hr_local_file_path(employee_id, str(row.get("month_key") or ""), str(row.get("proof_file_name") or ""))))
        for row in hours_rows:
            if str(row.get("employee_id") or "").strip() != employee_id:
                continue
            drive_delete_results.append(_hr_delete_drive_target(str(row.get("hours_drive_file_id") or "").strip(), "hours"))
            local_delete_results.append(_hr_delete_local_file(_hr_local_file_path(employee_id, str(row.get("month_key") or ""), str(row.get("hours_file_name") or ""))))
        for row in document_rows:
            if str(row.get("employee_id") or "").strip() != employee_id:
                continue
            drive_delete_results.append(_hr_delete_drive_target(str(row.get("drive_file_id") or "").strip(), "document"))
            local_delete_results.append(_hr_delete_local_file(_hr_local_file_path(employee_id, str(row.get("month_key") or ""), str(row.get("file_name") or ""))))

        drive_delete_results.append(_hr_delete_drive_target(str(employee.get("drive_folder_id") or "").strip(), "employee-folder"))
        employee_dir = _hr_storage_dir() / employee_id
        if employee_dir.exists():
            try:
                shutil.rmtree(employee_dir)
                local_delete_results.append({"status": "ok", "path": str(employee_dir)})
            except Exception as exc:
                log_handled_error("hr employee local dir delete failed", exc)
                local_delete_results.append({"status": "error", "path": str(employee_dir), "error": str(exc)})

        save_hr_rows("employees", [row for row in employees if str(row.get("employee_id") or "").strip() != employee_id])
        save_hr_rows("payroll", [row for row in payroll_rows if str(row.get("employee_id") or "").strip() != employee_id])
        save_hr_rows("contributions", [row for row in contribution_rows if str(row.get("employee_id") or "").strip() != employee_id])
        save_hr_rows("hours", [row for row in hours_rows if str(row.get("employee_id") or "").strip() != employee_id])
        save_hr_rows("documents", [row for row in document_rows if str(row.get("employee_id") or "").strip() != employee_id])
        return JSONResponse({"status": "ok", "employee_id": employee_id, "drive_delete_results": drive_delete_results, "local_delete_results": local_delete_results, **_hr_state_payload(force_refresh=False)})
    except Exception as exc:
        log_handled_error("hr_employee_delete failed", exc)
        return JSONResponse({"error": f"לא הצלחתי למחוק את העובד: {exc}"}, status_code=500)


