@app.post("/working-orders-upload")
async def working_orders_upload(
    file: UploadFile = File(...),
):
    try:
        file_path, _ = await _store_uploaded_pdf(file, WORKING_ORDER_UPLOADS_DIR, fallback_name="working-order.pdf")
    except ValueError as exc:
        return JSONResponse({"error": str(exc)}, status_code=400)

    cfg = get_mode_config("prod")
    po = parse_purchase_order(file_path)
    po = await _enrich_po_for_process(po, cfg | {"mode": "prod"})
    payload = _build_process_payload_from_po(po, "prod", file.filename or file_path.name, file_path)

    drive_file_id = ""
    drive_url = ""
    drive_folder_id = ""
    drive_folder_url = ""
    try:
        root_id = _working_orders_drive_root_id()
        customer_folder_id = ensure_child_folder(root_id, _guess_customer_folder_name(po.customer_name or "לקוח"))
        order_folder_id = ensure_child_folder(customer_folder_id, _guess_order_folder_name(po.po_number or "PO", po.po_date or ""))
        uploaded = ensure_file_in_folder(order_folder_id, file_path, drive_name=file_path.name)
        drive_file_id = str(uploaded.get("id") or "").strip()
        drive_url = str(uploaded.get("web_view_link") or uploaded.get("webViewLink") or uploaded.get("webContentLink") or "").strip()
        drive_folder_id = order_folder_id
        drive_folder_url = _drive_folder_view_link(order_folder_id)
    except Exception as exc:
        log_handled_error("working order drive sync failed", exc)

    row = {
        "row_id": uuid.uuid4().hex,
        "created_at": datetime.now().isoformat(timespec="seconds"),
        "updated_at": datetime.now().isoformat(timespec="seconds"),
        "source_file_name": str(file.filename or file_path.name).strip(),
        "source_file_path": str(file_path),
        "po_date": str(payload.get("po_date") or "").strip(),
        "customer_name": str(payload.get("customer_name") or "").strip(),
        "customer_id": str(payload.get("customer_id") or "").strip(),
        "customer_email": str(payload.get("customer_email") or "").strip(),
        "customer_phone": str(payload.get("customer_phone") or "").strip(),
        "delivery_address": str(payload.get("delivery_address") or "").strip(),
        "project": str(payload.get("project") or "").strip(),
        "contact_name": str(payload.get("contact_name") or "").strip(),
        "contact_phone": str(payload.get("contact_phone") or "").strip(),
        "payment_terms_days": str(payload.get("payment_terms_days") or "").strip(),
        "payment_terms_label": str(payload.get("payment_terms_label") or "").strip(),
        "po_number": str(payload.get("po_number") or "").strip(),
        "item_description": str(payload.get("item_description") or "").strip(),
        "item_sku": str(payload.get("item_sku") or "").strip(),
        "item_unit": str(payload.get("item_unit") or "").strip(),
        "item_quantity": payload.get("item_quantity") or "",
        "item_unit_price": payload.get("item_unit_price") or "",
        "subtotal": payload.get("subtotal") or "",
        "vat": payload.get("vat") or "",
        "total": payload.get("total") or "",
        "items_count": payload.get("items_count") or "",
        "items_json": json.dumps(payload.get("items") or [], ensure_ascii=False),
        "payload_json": json.dumps(payload, ensure_ascii=False),
        "drive_file_id": drive_file_id,
        "drive_url": drive_url,
        "drive_folder_id": drive_folder_id,
        "drive_folder_url": drive_folder_url,
        "order_note_text": "",
        "order_note_file_name": "",
        "order_note_file_path": "",
        "order_note_drive_file_id": "",
        "order_note_drive_url": "",
    }
    rows = load_working_order_rows()
    rows = [existing for existing in rows if str(existing.get("row_id") or "").strip() != str(row["row_id"]).strip()]
    rows.insert(0, row)
    save_result = save_working_order_rows(rows)
    return JSONResponse({"status": "ok", "row": row, "save_result": save_result, "count": len(rows)})


@app.post("/working-orders-delete")
async def working_orders_delete(request: Request):
    try:
        body = await request.json()
    except Exception:
        body = {}
    row_id = str((body or {}).get("row_id") or "").strip()
    if not row_id:
        return JSONResponse({"error": "חסר מזהה שורה למחיקה."}, status_code=400)

    rows = load_working_order_rows()
    target_row = next((row for row in rows if str(row.get("row_id") or "").strip() == row_id), None)
    if not target_row:
        return JSONResponse({"error": "ההזמנה בעבודה לא נמצאה."}, status_code=404)

    drive_delete_results: list[dict] = []
    for label, drive_id in (
        ("file", str(target_row.get("drive_file_id") or "").strip()),
        ("note_file", str(target_row.get("order_note_drive_file_id") or "").strip()),
        ("folder", str(target_row.get("drive_folder_id") or "").strip()),
    ):
        if not drive_id:
            continue
        try:
            delete_drive_file(drive_id)
            drive_delete_results.append({"target": label, "id": drive_id, "status": "ok"})
        except Exception as exc:
            drive_delete_results.append({"target": label, "id": drive_id, "status": "error", "error": str(exc)})
            log_handled_error(f"working order drive delete failed ({label})", exc)

    local_delete_results: list[dict] = []
    for label, path_value in (
        ("source_file", str(target_row.get("source_file_path") or "").strip()),
        ("note_file", str(target_row.get("order_note_file_path") or "").strip()),
    ):
        local_result = {"target": label, "status": "skipped", "path": path_value}
        local_path = Path(path_value) if path_value else None
        if local_path and local_path.exists():
            try:
                local_path.unlink()
                local_result["status"] = "ok"
            except Exception as exc:
                local_result = {"target": label, "status": "error", "path": str(local_path), "error": str(exc)}
                log_handled_error(f"working order local file delete failed ({label})", exc)
        local_delete_results.append(local_result)

    remaining_rows = [row for row in rows if str(row.get("row_id") or "").strip() != row_id]
    save_result = save_working_order_rows(remaining_rows)
    return JSONResponse(
        {
            "status": "ok",
            "deleted_row_id": row_id,
            "rows_remaining": len(remaining_rows),
            "save_result": save_result,
            "drive_delete_results": drive_delete_results,
            "local_delete_results": local_delete_results,
        }
    )


@app.post("/working-orders-note-save")
async def working_orders_note_save(request: Request):
    try:
        form = await request.form()
    except Exception:
        return JSONResponse({"error": "לא הצלחתי לקרוא את נתוני ההערה."}, status_code=400)

    row_id = str(form.get("row_id") or "").strip()
    note_text = str(form.get("note_text") or "").strip()
    uploaded_file = form.get("file")
    if not row_id:
        return JSONResponse({"error": "חסר מזהה שורת הזמנה."}, status_code=400)

    rows = load_working_order_rows()
    row_index = next((index for index, row in enumerate(rows) if str(row.get("row_id") or "").strip() == row_id), -1)
    if row_index < 0:
        return JSONResponse({"error": "ההזמנה בעבודה לא נמצאה."}, status_code=404)

    target_row = dict(rows[row_index])
    note_file_path = str(target_row.get("order_note_file_path") or "").strip()
    note_file_name = str(target_row.get("order_note_file_name") or "").strip()
    note_drive_file_id = str(target_row.get("order_note_drive_file_id") or "").strip()
    note_drive_url = str(target_row.get("order_note_drive_url") or "").strip()

    if uploaded_file is not None and not isinstance(uploaded_file, str) and getattr(uploaded_file, "filename", ""):
        target_dir = WORKING_ORDER_NOTES_UPLOAD_DIR / (row_id or uuid.uuid4().hex)
        try:
            local_path, _ = await _store_uploaded_any_file(uploaded_file, target_dir, fallback_name="working-order-note.bin")
        except ValueError as exc:
            return JSONResponse({"error": str(exc)}, status_code=400)

        if note_file_path:
            try:
                old_path = Path(note_file_path)
                if old_path.exists():
                    old_path.unlink()
            except Exception as exc:
                log_handled_error("working order note local replace failed", exc)

        note_file_path = str(local_path)
        note_file_name = str(getattr(uploaded_file, "filename", "") or local_path.name).strip()

        try:
            target_folder_id = str(target_row.get("drive_folder_id") or "").strip()
            if not target_folder_id:
                root_id = _working_orders_drive_root_id()
                customer_folder_id = ensure_child_folder(root_id, _guess_customer_folder_name(target_row.get("customer_name") or "לקוח"))
                target_folder_id = ensure_child_folder(customer_folder_id, _guess_order_folder_name(target_row.get("po_number") or "PO", target_row.get("po_date") or ""))
                target_row["drive_folder_id"] = target_folder_id
                target_row["drive_folder_url"] = _drive_folder_view_link(target_folder_id)
            uploaded = ensure_file_in_folder(target_folder_id, Path(note_file_path), drive_name=Path(note_file_name).name or Path(note_file_path).name)
            note_drive_file_id = str(uploaded.get("id") or "").strip()
            note_drive_url = str(uploaded.get("web_view_link") or uploaded.get("webViewLink") or uploaded.get("webContentLink") or "").strip()
        except Exception as exc:
            log_handled_error("working order note drive sync failed", exc)

    target_row["order_note_text"] = note_text
    target_row["order_note_file_name"] = note_file_name
    target_row["order_note_file_path"] = note_file_path
    target_row["order_note_drive_file_id"] = note_drive_file_id
    target_row["order_note_drive_url"] = note_drive_url
    target_row["updated_at"] = datetime.now().isoformat(timespec="seconds")
    rows[row_index] = target_row
    save_result = save_working_order_rows(rows)
    return JSONResponse({"status": "ok", "row": target_row, "save_result": save_result})


@app.get("/working-order-note-file/{row_id}")
async def working_order_note_file(row_id: str):
    target_id = str(row_id or "").strip()
    if not target_id:
        return JSONResponse({"error": "חסר מזהה שורה."}, status_code=400)
    rows = load_working_order_rows()
    row = next((item for item in rows if str(item.get("row_id") or "").strip() == target_id), None)
    if not row:
        return JSONResponse({"error": "ההזמנה בעבודה לא נמצאה."}, status_code=404)
    local_path = Path(str(row.get("order_note_file_path") or "").strip()) if str(row.get("order_note_file_path") or "").strip() else None
    if not local_path or not local_path.exists():
        return JSONResponse({"error": "לא מצאתי את קובץ ההערה."}, status_code=404)
    media_type, _ = mimetypes.guess_type(str(local_path))
    return FileResponse(str(local_path), media_type=media_type or "application/octet-stream", filename=str(row.get("order_note_file_name") or local_path.name))


@app.post("/process")
async def process(
    file: UploadFile = File(...),
    mode: str = Form("sandbox"),
):
    try:
        file_path, _ = await _store_uploaded_pdf(file, UPLOADS_DIR, fallback_name="purchase-order.pdf")
    except ValueError as exc:
        return JSONResponse({"error": str(exc)}, status_code=400)

    cfg = {
        "base_url": settings.greeninvoice_sandbox_base_url if mode == "sandbox" else settings.greeninvoice_prod_base_url,
        "api_key": settings.greeninvoice_sandbox_api_key if mode == "sandbox" else settings.greeninvoice_prod_api_key,
        "api_secret": settings.greeninvoice_sandbox_api_secret if mode == "sandbox" else settings.greeninvoice_prod_api_secret,
            "mode": mode,
    }
    po = parse_purchase_order(file_path)
    po = await _enrich_po_for_process(po, cfg)
    asyncio.create_task(_sync_project_managers_from_pdf_background(file_path, po))

    first_item = _primary_merchandise_po_item(po)

    return JSONResponse(_build_process_payload_from_po(po, mode, file.filename or "", file_path))


@app.post("/finalize-quote")
async def finalize_quote(request: Request):
    try:
        body = await request.json()
        mode = body.get("mode", "sandbox")
        data = body.get("data", {})

        if mode == "prod_with_transport":
            mode = "prod"
        elif mode == "sandbox_with_transport":
            mode = "sandbox"

        source_file_name = (data.get("source_file") or "").strip()
        manual_entry = bool(data.get("manual_entry"))
        cfg = get_mode_config(mode)

        po = _build_purchase_order_from_request_data(data)

        client = GreenInvoiceClient(
            base_url=cfg["base_url"],
            api_key=cfg["api_key"],
            api_secret=cfg["api_secret"],
        )
        customer_sync_result = await _ensure_finalize_customer(po, cfg["mode"], client)
        token = await client._get_token()

        customer_guid = str(customer_sync_result.get("customer_guid") or "").strip()
        if customer_guid:
            client_payload = {"id": customer_guid}
        else:
            fallback_customer = _build_manual_customer_payload(po)
            client_payload = {
                "name": str(fallback_customer.get("name") or po.customer_name or "").strip(),
                "idNumber": str(fallback_customer.get("idNumber") or po.customer_id or "").strip(),
                "email": po.customer_email or "",
            }

        footer_text = str((po.extra or {}).get("footer_text") or "").strip()
        item_summary = _quote_item_summary_text(po)
        quote_payload = {
            "type": 10,
            "lang": "he",
            "currency": "ILS",
            "vatType": 0,
            "client": client_payload,
            "description": f"הצעת מחיר עבור הזמנת רכש {po.po_number}".strip(),
            "remarks": footer_text,
            "bottomText": footer_text,
            "income": client._rows_for_invoice(po),
            "incomeRows": client._rows_for_invoice(po),
        }
        quote_doc = await client.create_document(token, quote_payload)

        is_sandbox_mode = str(cfg["mode"] or "").strip().lower() == "sandbox"
        customer_folder_name = _sandbox_output_folder_name(
            _guess_customer_folder_name(po.customer_name),
            is_sandbox_mode,
        )
        order_folder_name = _sandbox_output_folder_name(
            _guess_order_folder_name(po.po_number, po.po_date),
            is_sandbox_mode,
        )
        local_dir = _generated_docs_root_for_sandbox_flag(is_sandbox_mode) / customer_folder_name / order_folder_name
        local_dir.mkdir(parents=True, exist_ok=True)
        quote_number = str(getattr(quote_doc, "number", "") or "").strip()
        safe_quote_po_name = _safe_folder_name(po.po_number or "quote") or "quote"
        quote_pdf_path = local_dir / f"{safe_quote_po_name}_quote_{quote_number or 'draft'}.pdf"
        if getattr(quote_doc, "url", ""):
            await client.download_pdf(token, quote_doc.url, quote_pdf_path)

        drive_sync_result = {"status": "skipped", "reason": "missing_pdf"}
        if quote_pdf_path.exists():
            try:
                drive_sync_result = _sync_quote_pdf_to_drive(po, quote_pdf_path)
            except Exception as exc:
                log_handled_error("quote drive sync failed", exc)
                drive_sync_result = {"status": "error", "error": str(exc)}

        quote_relative_file = _quote_file_relative_to_output(quote_pdf_path if quote_pdf_path.exists() else None)
        quote_drive_folder_id = str(drive_sync_result.get("order_folder_id") or "").strip()
        quote_drive_folder_url = str(drive_sync_result.get("quote_drive_folder_url") or "").strip()
        quote_drive_url = str(drive_sync_result.get("quote_drive_url") or "").strip()
        quote_drive_file_id = str(drive_sync_result.get("quote_drive_file_id") or "").strip()

        history_result = {"status": "skipped", "reason": "not_attempted"}
        try:
            history_result = append_quote_history_row(
                {
                    "history_id": uuid.uuid4().hex,
                    "created_at": datetime.now().isoformat(timespec="seconds"),
                    "input_source": _quote_history_input_source(manual_entry),
                    "mode": _quote_history_mode_label(cfg["mode"]),
                    "customer_name": po.customer_name,
                    "customer_id": po.customer_id,
                    "po_number": po.po_number,
                    "quote_number": quote_number,
                    "quote_document_id": str(getattr(quote_doc, "document_id", "") or ""),
                    "quote_date": po.po_date or datetime.now().strftime("%d/%m/%Y"),
                    "customer_email": po.customer_email or "",
                    "customer_phone": po.customer_phone or "",
                    "delivery_address": po.delivery_address or "",
                    "project": str((po.extra or {}).get("project") or "").strip(),
                    "contact_name": str((po.extra or {}).get("contact_name") or "").strip(),
                    "contact_phone": str((po.extra or {}).get("contact_phone") or "").strip(),
                    "payment_terms_days": po.payment_terms_days if po.payment_terms_days is not None else "",
                    "payment_terms_label": po.payment_terms_label or "",
                    "item_description": po.items[0].description if po.items else "",
                    "item_sku": po.items[0].sku if po.items else "",
                    "item_unit": str((po.extra or {}).get("item_unit") or "").strip(),
                    "item_quantity": po.items[0].quantity if po.items else "",
                    "item_unit_price": po.items[0].unit_price if po.items else "",
                    "item_line_total": po.items[0].line_total if po.items else "",
                    "subtotal": po.subtotal or "",
                    "vat": po.vat or "",
                    "total": po.total or "",
                    "footer_text": footer_text,
                    "items_json": json.dumps(
                        [
                            {
                                "description": str(item.description or "").strip(),
                                "sku": str(item.sku or "").strip(),
                                "unit": str(item.unit or "").strip(),
                                "quantity": item.quantity if item.quantity is not None else "",
                                "unit_price": item.unit_price if item.unit_price is not None else "",
                                "line_total": item.line_total if item.line_total is not None else "",
                            }
                            for item in (po.items or [])
                        ],
                        ensure_ascii=False,
                    ),
                    "label_split_rows_json": json.dumps(data.get("label_split_rows") or [], ensure_ascii=False),
                    "quote_drive_folder_id": quote_drive_folder_id,
                    "quote_drive_folder_url": quote_drive_folder_url,
                    "document_links_json": _quote_document_links_payload(
                        quote_number=quote_number,
                        quote_relative_file=quote_relative_file,
                        quote_drive_url=quote_drive_url,
                        quote_drive_folder_url=quote_drive_folder_url,
                    ),
                    "updated_at": datetime.now().isoformat(timespec="seconds"),
                }
            )
        except Exception as exc:
            log_handled_error("quote history append failed", exc)
            history_result = {"status": "error", "error": str(exc)}

        return JSONResponse(
            {
                "status": "ok",
                "is_quote": True,
                "mode": cfg["mode"],
                "manual_entry": manual_entry,
                "source_file": source_file_name,
                "customer_name": po.customer_name,
                "customer_email": po.customer_email or "",
                "customer_phone": po.customer_phone or "",
                "contact_phone": str((po.extra or {}).get("contact_phone") or "").strip(),
                "item_summary": item_summary,
                "quote_document_id": str(getattr(quote_doc, "document_id", "") or ""),
                "quote_document_number": quote_number,
                "quote_document_url": str(getattr(quote_doc, "url", "") or ""),
                "quote_pdf_path": str(quote_pdf_path) if quote_pdf_path.exists() else "",
                "quote_file": quote_relative_file,
                "quote_drive_file_id": quote_drive_file_id,
                "quote_drive_url": quote_drive_url,
                "quote_drive_folder_id": quote_drive_folder_id,
                "quote_drive_folder_url": quote_drive_folder_url,
                "customer_sync_result": customer_sync_result,
                "customer_created": bool(customer_sync_result.get("missing_before")),
                "customer_created_name": str(customer_sync_result.get("customer_name") or po.customer_name or "").strip(),
                "history_result": history_result,
            }
        )
    except Exception as exc:
        log_handled_error("finalize_quote failed", exc)
        return JSONResponse({"error": f"לא הצלחתי להפיק את הצעת המחיר: {exc}"}, status_code=500)


@app.post("/finalize")
async def finalize(request: Request):
    body = await request.json()
    mode = body.get("mode", "sandbox")
    data = body.get("data", {})
    document_mode = _normalize_order_document_mode(body.get("document_mode") or data.get("document_mode") or "full")
    include_transport_label = mode in ("prod_with_transport", "sandbox_with_transport")
    skip_whatsapp = bool(body.get("skip_whatsapp")) or str(request.headers.get("X-PO-Skip-WhatsApp") or "").strip().lower() in {"1", "true", "yes", "on"}
    finalize_log_context = {
        "raw_mode": str(mode or "").strip(),
        "document_mode": document_mode,
        "skip_whatsapp": skip_whatsapp,
        "customer_name": str(data.get("customer_name") or "").strip(),
        "customer_id": str(data.get("customer_id") or "").strip(),
        "po_number": str(data.get("po_number") or "").strip(),
        "manual_entry": bool(data.get("manual_entry")),
        "send_to_dad": bool(data.get("send_to_dad")),
        "source_file_name": str(data.get("source_file") or "").strip(),
        "source_file_path": str(data.get("source_file_path") or "").strip(),
        "transport_label_name": str(data.get("transport_label_name") or "").strip(),
        "transport_label_path": str(data.get("transport_label_path") or "").strip(),
        "history_id": str(data.get("history_id") or "").strip(),
        "fulfillment_id": str(data.get("fulfillment_id") or "").strip(),
    }
    logger.info("FINALIZE START | %s", json.dumps(finalize_log_context, ensure_ascii=False))

    if mode == "prod_with_transport":
        mode = "prod"
    elif mode == "sandbox_with_transport":
        mode = "sandbox"

    if mode == "prod_with_transport":
        mode = "prod"

    source_file_path = (data.get("source_file_path") or "").strip()
    source_file_name = (data.get("source_file") or "").strip()
    transport_label_path_raw = (data.get("transport_label_path") or "").strip()
    transport_label_name = (data.get("transport_label_name") or "").strip()
    send_to_dad = bool(data.get("send_to_dad"))
    manual_entry = bool(data.get("manual_entry"))
    finalize_log_context["normalized_mode"] = str(mode or "").strip()
    finalize_log_context["include_transport_label"] = include_transport_label
    finalize_log_context["transport_label_exists"] = bool(
        transport_label_path_raw and Path(transport_label_path_raw).exists()
    )
    finalize_log_context["source_file_exists"] = bool(
        source_file_path and Path(source_file_path).exists()
    )

    if include_transport_label and not transport_label_path_raw:
        logger.error("FINALIZE FAILED BEFORE RUN | missing transport label | %s", json.dumps(finalize_log_context, ensure_ascii=False))
        raise RuntimeError("חסר קובץ PDF של מדבקות משלוח עבור יצירה עם משלוח.")

    cfg = get_mode_config(mode)
    missing_greeninvoice_config = [
        label
        for label, value in (
            ("api_key", cfg.get("api_key")),
            ("api_secret", cfg.get("api_secret")),
            ("base_url", cfg.get("base_url")),
        )
        if not str(value or "").strip()
    ]
    if missing_greeninvoice_config:
        mode_label = "sandbox" if str(mode or "").strip().lower() == "sandbox" else "production"
        logger.error(
            "FINALIZE MISCONFIGURED GREENINVOICE | %s",
            json.dumps(
                {
                    **finalize_log_context,
                    "mode_label": mode_label,
                    "missing_greeninvoice_config": missing_greeninvoice_config,
                },
                ensure_ascii=False,
            ),
        )
        return JSONResponse(
            {
                "error": (
                    f"חסרה בשרת הגדרת GreenInvoice עבור מצב {mode_label}: "
                    f"{', '.join(missing_greeninvoice_config)}."
                )
            },
            status_code=503,
        )

    fulfillment_id = str(data.get("fulfillment_id") or "").strip() or uuid.uuid4().hex
    history_id = str(data.get("history_id") or "").strip() or uuid.uuid4().hex
    source_mode_label = "SB" if str(mode or "").strip().lower() == "sandbox" else "PROD"
    po = _build_purchase_order_from_request_data(data)

    client = GreenInvoiceClient(
        base_url=cfg["base_url"],
        api_key=cfg["api_key"],
        api_secret=cfg["api_secret"],
    )

    finalize_log_context["resolved_customer_name"] = str(po.customer_name or "").strip()
    finalize_log_context["resolved_customer_id"] = str(po.customer_id or "").strip()
    finalize_log_context["resolved_po_number"] = str(po.po_number or "").strip()
    finalize_log_context["resolved_total"] = str(po.total or "").strip()

    try:
        customer_sync_result = await _ensure_finalize_customer(po, cfg["mode"], client)
    except Exception as _exc:
        logger.exception("FINALIZE CUSTOMER SYNC FAILED | %s", json.dumps(finalize_log_context, ensure_ascii=False))
        return JSONResponse({"error": f"סנכרון לקוח נכשל: {_exc}"}, status_code=500)
    sales_output_root = _generated_docs_root_for_sandbox_flag(cfg["mode"] == "sandbox")

    try:
        if document_mode == "delivery_only":
            delivery_doc, delivery_pdf_path = await client.create_delivery_only(po, sales_output_root)
            invoice_doc = SimpleNamespace(document_id="", number="", url="")
            invoice_pdf_path = None
        elif document_mode == "invoice_only":
            linked_delivery_document_id = str(data.get("delivery_document_id") or data.get("linked_delivery_document_id") or "").strip()
            invoice_doc, invoice_pdf_path = await client.create_invoice_only(po, sales_output_root, linked_document_id=linked_delivery_document_id)
            delivery_doc = SimpleNamespace(document_id=linked_delivery_document_id, number=str(data.get("delivery_document_number") or "").strip(), url="")
            delivery_pdf_path = None
        else:
            delivery_doc, invoice_doc, delivery_pdf_path, invoice_pdf_path = await client.create_delivery_and_invoice(po, sales_output_root)
    except Exception as _exc:
        logger.exception("FINALIZE DOCUMENT CREATION FAILED | %s", json.dumps(finalize_log_context, ensure_ascii=False))
        return JSONResponse({"error": f"יצירת מסמך נכשלה: {_exc}"}, status_code=500)

    try:
        project_manager_rows = _project_manager_entries_from_po(po)
        if project_manager_rows and document_mode != "invoice_only":
            project_manager_result = upsert_project_manager_rows(project_manager_rows)
            print("PROJECT MANAGERS SYNC:", project_manager_result)
    except Exception as e:
        print("PROJECT MANAGERS SYNC ERROR:", repr(e))

    
    # ===== LABEL =====
    label_pdf_path = None
    label_pdf_paths = []
    label_count_for_coc = 1
    try:
        from services.label_generator_v4 import generate_label_pdf

        if document_mode == "invoice_only":
            raise RuntimeError("skip_label_generation")

        merchandise_items = _merchandise_po_items(po)
        item = merchandise_items[0] if merchandise_items else _primary_merchandise_po_item(po)
        if not merchandise_items or not item:
            raise RuntimeError("skip_label_generation")
        label_dir = Path(delivery_pdf_path).parent if delivery_pdf_path else OUTPUT_DIR
        label_dir.mkdir(parents=True, exist_ok=True)

        total_merchandise_quantity = _merchandise_quantity_total(po)
        qty_value = 1
        if total_merchandise_quantity > 0:
            qty_value = int(total_merchandise_quantity) if float(total_merchandise_quantity).is_integer() else total_merchandise_quantity
        elif item and item.quantity is not None:
            qty_value = int(item.quantity) if float(item.quantity).is_integer() else item.quantity

        raw_label_split_rows = data.get("label_split_rows") or []
        normalized_label_split_rows = []
        if isinstance(raw_label_split_rows, list):
            for raw_row in raw_label_split_rows:
                if not isinstance(raw_row, dict):
                    continue
                try:
                    label_count = int(float(raw_row.get("label_count") or 0))
                    quantity_per_label = float(raw_row.get("quantity_per_label") or 0)
                except (TypeError, ValueError):
                    continue
                if label_count <= 0 or quantity_per_label <= 0:
                    continue
                normalized_label_split_rows.append(
                    {
                        "item_index": int(float(raw_row.get("item_index") or 0)),
                        "label_count": label_count,
                        "quantity_per_label": quantity_per_label,
                    }
                )

        if normalized_label_split_rows:
            try:
                if len(merchandise_items) > 1:
                    for merchandise_index, merchandise_item in enumerate(merchandise_items):
                        split_for_item = sum(
                            row["label_count"] * row["quantity_per_label"]
                            for row in normalized_label_split_rows
                            if int(row.get("item_index") or 0) == merchandise_index
                        )
                        item_quantity = float(merchandise_item.quantity or 0)
                        if item_quantity > 0 and abs(split_for_item - item_quantity) > 0.0001:
                            raise RuntimeError(
                                f"חלוקת המדבקות לא תואמת עבור {merchandise_item.description}. הוגדרו {split_for_item} יחידות, אבל בהזמנה יש {item_quantity}."
                            )
                else:
                    total_split_quantity = sum(
                        row["label_count"] * row["quantity_per_label"] for row in normalized_label_split_rows
                    )
                    original_quantity = float(total_merchandise_quantity or (item.quantity if item and item.quantity is not None else 0))
                    if original_quantity > 0 and abs(total_split_quantity - original_quantity) > 0.0001:
                        raise RuntimeError(
                            f"חלוקת המדבקות לא תואמת לכמות הכוללת. הוגדרו {total_split_quantity} יחידות, אבל בהזמנה יש {original_quantity}."
                        )
            except Exception:
                raise

        # Label content should come from the parsed PO item, not from a non-existent
        # PurchaseOrderData attribute.
        if item and item.sku == "5430000030-00":
            label_product = "סקאי אפור חורים"
        else:
            label_product = (
                (item.description if item else "")
                or (po.extra or {}).get("item_description", "")
            )

        def _display_quantity(value):
            numeric = float(value)
            return int(numeric) if numeric.is_integer() else numeric

        label_quantities = []
        if normalized_label_split_rows:
            for split_row in normalized_label_split_rows:
                label_quantities.extend(
                    [{
                        "item_index": int(split_row.get("item_index") or 0),
                        "quantity": _display_quantity(split_row["quantity_per_label"]),
                    }] * split_row["label_count"]
                )
        elif len(merchandise_items) > 1:
            for merchandise_index, merchandise_item in enumerate(merchandise_items):
                item_quantity = float(merchandise_item.quantity or 0)
                label_quantities.append(
                    {
                        "item_index": merchandise_index,
                        "quantity": _display_quantity(item_quantity) if item_quantity > 0 else 1,
                    }
                )
        else:
            label_quantities = [{
                "item_index": 0,
                "quantity": qty_value,
            }]
        label_count_for_coc = max(len(label_quantities), 1)

        for index, split_meta in enumerate(label_quantities, start=1):
            split_item_index = int(split_meta.get("item_index") or 0)
            split_quantity = split_meta.get("quantity")
            split_item = merchandise_items[split_item_index] if 0 <= split_item_index < len(merchandise_items) else item
            safe_label_po_name = _safe_folder_name(po.po_number or "label") or "label"
            planned_label_path = (
                label_dir / f"{safe_label_po_name}_label.pdf"
                if len(label_quantities) == 1
                else label_dir / f"{safe_label_po_name}_label_{index:02d}.pdf"
            )

            label_data = {
                "customer": po.customer_name,
                "address": po.delivery_address or (po.extra or {}).get("delivery_address", ""),
                "contact_name": (po.extra or {}).get("contact_name", ""),
                "phone": (po.extra or {}).get("contact_phone", ""),
                "po_number": po.po_number,
                "product_lines": _label_product_lines_from_item(split_item) if split_item else (_label_product_lines_for_po(po) or ([label_product] if label_product else [])),
                "quantity": split_quantity,
                "sku": getattr(split_item, "sku", "") if split_item else (item.sku if item else ""),
                "unit": _label_unit_text(getattr(split_item, "unit", "") or getattr(item, "unit", "") or (po.extra or {}).get("item_unit") or ""),
            }

            print("🧪 LABEL DATA:", label_data)
            created_path = await asyncio.to_thread(
                generate_label_pdf,
                label_data,
                str(planned_label_path),
                False,
            )

            print("🧪 RAW LABEL RETURN:", created_path)
            print("🧪 LABEL RETURN:", created_path)
            created_path = Path(created_path)

            if created_path.exists():
                label_pdf_paths.append(created_path)
                print("LABEL OK:", created_path)
            else:
                print("LABEL ERROR: file was not created", created_path)

        if label_pdf_paths:
            label_pdf_path = label_pdf_paths[0]

    except Exception as e:
        if str(e) != "skip_label_generation":
            print("LABEL ERROR:", repr(e))
    # ===== COC (PLASAN ONLY) =====
    try:
        import subprocess

        if document_mode != "invoice_only" and "פלסן סאסא" in _normalize_company_name(po.customer_name or ""):
            target_dir = Path(delivery_pdf_path).parent if delivery_pdf_path else OUTPUT_DIR
            target_dir.mkdir(parents=True, exist_ok=True)

            coc_path = target_dir / f"coc_{po.po_number}.pdf"
            coc_result = subprocess.run(
                [
                    sys.executable,
                    "scripts/generate_coc.py",
                    json.dumps(
                        {
                            "po": po.po_number,
                            "sku": po.items[0].sku,
                            "desc": po.items[0].description,
                            "qty": po.items[0].quantity,
                            "date": po.po_date,
                            "rolls": label_count_for_coc,
                        }
                    ),
                    str(coc_path),
                ],
                cwd=str(BASE_DIR),
                capture_output=True,
                text=True,
                check=False,
            )
            if coc_result.returncode != 0:
                raise RuntimeError(
                    f"COC generator exited with {coc_result.returncode}: "
                    f"{(coc_result.stderr or coc_result.stdout or '').strip()}"
                )
            if not coc_path.exists():
                raise FileNotFoundError(f"COC was not created at {coc_path}")

            print("COC CREATED:", coc_path)

    except Exception as e:
        print("COC ERROR:", repr(e))

    source_po_copy_path = None
    transport_label_output_path = None
    merged_pdf_path = None
    coc_local_path = coc_path if 'coc_path' in locals() and coc_path and Path(coc_path).exists() else None
    drive_sync_result = {"status": "skipped", "reason": "not_attempted"}

    try:
        target_dir = Path(delivery_pdf_path).parent if delivery_pdf_path else (
            Path(invoice_pdf_path).parent if invoice_pdf_path else OUTPUT_DIR
        )
        target_dir.mkdir(parents=True, exist_ok=True)

        if source_file_path:
            src_path = Path(source_file_path)
            if src_path.exists() and src_path.is_file():
                source_name = source_file_name or src_path.name
                source_po_copy_path = target_dir / source_name
                shutil.copy2(src_path, source_po_copy_path)
                print("SOURCE PO COPIED:", source_po_copy_path)
            else:
                print("SOURCE PO COPY SKIPPED: source file missing", source_file_path)

        if include_transport_label and transport_label_path_raw:
            transport_src_path = Path(transport_label_path_raw)
            if transport_src_path.exists() and transport_src_path.is_file():
                transport_name = transport_label_name or transport_src_path.name
                transport_label_output_path = target_dir / transport_name
                shutil.copy2(transport_src_path, transport_label_output_path)
                print("TRANSPORT LABEL COPIED:", transport_label_output_path)
            else:
                print("TRANSPORT LABEL COPY SKIPPED: source file missing", transport_label_path_raw)

        if document_mode != "invoice_only":
            safe_merged_po_name = _safe_folder_name(po.po_number or "") if po.po_number else ""
            merged_name = f"{safe_merged_po_name}_כל המסמכים.pdf" if safe_merged_po_name else "כל המסמכים.pdf"
            merge_inputs = [
                delivery_pdf_path,
                invoice_pdf_path,
                *[path for path in label_pdf_paths if path and Path(path).exists()],
                transport_label_output_path if transport_label_output_path and Path(transport_label_output_path).exists() else None,
            ]
            # Include the original purchase order in the merged "all documents"
            # bundle for every customer when the source PDF is available.
            if source_po_copy_path and Path(source_po_copy_path).exists():
                merge_inputs.append(source_po_copy_path)
            merged_pdf_path = merge_pdfs(merge_inputs, target_dir / merged_name)
            print("MERGED PDF CREATED:", merged_pdf_path)

    except Exception as e:
        print("MERGE ERROR:", repr(e))

    file_paths = [str(merged_pdf_path)] if merged_pdf_path and Path(merged_pdf_path).exists() else []
    if not file_paths:
        if delivery_pdf_path and Path(delivery_pdf_path).exists():
            file_paths.append(str(Path(delivery_pdf_path)))
        if invoice_pdf_path and Path(invoice_pdf_path).exists():
            file_paths.append(str(Path(invoice_pdf_path)))

    async def _run_finalize_whatsapp_send() -> dict:
        if not file_paths:
            return {"status": "skipped", "reason": "no_files"}
        sent_targets: list[str] = []
        provider_results: list[dict] = []
        try:
            primary_result = await send_files_via_whatsapp(
                phone="0547720142",
                message=f"מסמכים עבור הזמנת רכש {po.po_number}",
                file_paths=file_paths,
            )
            sent_targets.append("0547720142")
            if isinstance(primary_result, dict):
                provider_results.append({"target": "0547720142", **primary_result})
            if send_to_dad:
                dad_result = await send_files_via_whatsapp(
                    phone="+972505204010",
                    message=f"מסמכים עבור הזמנת רכש {po.po_number}",
                    file_paths=file_paths,
                )
                sent_targets.append("+972505204010")
                if isinstance(dad_result, dict):
                    provider_results.append({"target": "+972505204010", **dad_result})
            provider_name = next(
                (
                    str(result.get("provider") or "").strip()
                    for result in provider_results
                    if isinstance(result, dict) and str(result.get("provider") or "").strip()
                ),
                "",
            )
            return {
                "status": "ok",
                "targets": sent_targets,
                "provider": provider_name,
                "deliveries": provider_results,
            }
        except Exception as exc:
            log_handled_error("finalize whatsapp send failed", exc)
            return {
                "status": "error",
                "error": str(exc),
                "targets": sent_targets,
                "deliveries": provider_results,
            }

    whatsapp_send_task = None if skip_whatsapp else (asyncio.create_task(_run_finalize_whatsapp_send()) if file_paths else None)

    def _perform_finalize_drive_sync():
        try:
            order_date_obj = _parse_order_display_date(po.po_date)
            if order_date_obj and order_date_obj >= _delivery_confirmation_threshold():
                existing_folder_id = str(data.get("order_drive_folder_id") or "").strip()
                company_folder_id = ""
                order_folder_id = existing_folder_id
                if not order_folder_id:
                    company_folder_id = ensure_child_folder(
                        managed_storage_root_folder_id(),
                        _guess_customer_folder_name(po.customer_name),
                    )
                    order_folder_id = ensure_child_folder(
                        company_folder_id,
                        _guess_order_folder_name(po.po_number, po.po_date),
                    )
                uploaded_files = []
                invoice_drive_file_id = ""
                delivery_drive_file_id = ""
                merged_drive_file_id = ""
                coc_drive_file_id = ""
                coc_drive_name = ""
                label_drive_file_ids = []
                for candidate_path in [
                    delivery_pdf_path,
                    invoice_pdf_path,
                    *[path for path in label_pdf_paths if path and Path(path).exists()],
                    merged_pdf_path,
                    source_po_copy_path,
                    transport_label_output_path,
                    coc_local_path,
                ]:
                    if not candidate_path:
                        continue
                    candidate = Path(candidate_path)
                    if not candidate.exists() or not candidate.is_file():
                        continue
                    uploaded = upload_file_to_folder(order_folder_id, candidate)
                    uploaded_files.append(uploaded)
                    if candidate == Path(invoice_pdf_path):
                        invoice_drive_file_id = uploaded.get("id", "")
                    if delivery_pdf_path and candidate == Path(delivery_pdf_path):
                        delivery_drive_file_id = uploaded.get("id", "")
                    if merged_pdf_path and candidate == Path(merged_pdf_path):
                        merged_drive_file_id = uploaded.get("id", "")
                    if any(candidate == Path(label_path) for label_path in label_pdf_paths if label_path):
                        uploaded_id = str(uploaded.get("id") or "").strip()
                        if uploaded_id:
                            label_drive_file_ids.append(uploaded_id)
                    if coc_local_path and candidate == Path(coc_local_path):
                        coc_drive_file_id = uploaded.get("id", "")
                        coc_drive_name = uploaded.get("name", "") or candidate.name

                confirmation_result = {"status": "skipped", "reason": "invoice_only_without_delivery_confirmation_row"}
                if document_mode != "invoice_only" or str(data.get("fulfillment_id") or "").strip() or str(data.get("history_id") or "").strip():
                    confirmation_result = upsert_delivery_confirmation_row(
                        {
                            "order_date": po.po_date,
                            "company": po.customer_name,
                            "po_number": po.po_number,
                            "source_mode": source_mode_label,
                            "invoice_date": date.today().strftime("%d/%m/%Y") if getattr(invoice_doc, "number", "") else "",
                            "tax_invoice_number": getattr(invoice_doc, "number", ""),
                            "order_total": po.total or "",
                            "target_email": _default_delivery_contact_email(po.customer_name or "") or po.customer_email or "",
                            "signed_delivery_name": "",
                            "signed_delivery_local_path": "",
                            "signed_delivery_drive_file_id": "",
                            "invoice_drive_file_id": invoice_drive_file_id,
                            "coc_name": coc_drive_name or (Path(coc_local_path).name if coc_local_path else ""),
                            "coc_drive_file_id": coc_drive_file_id,
                            "order_drive_folder_id": order_folder_id,
                            "order_drive_folder_url": f"https://drive.google.com/drive/folders/{order_folder_id}" if order_folder_id else "",
                            "fulfillment_id": fulfillment_id,
                            "history_id": history_id,
                            "document_mode": document_mode,
                            "delivery_document_number": getattr(delivery_doc, "number", ""),
                            "delivery_document_id": getattr(delivery_doc, "document_id", ""),
                            "sent": "FALSE",
                            "sent_at": "",
                        }
                    )
                return {
                    "status": "ok",
                    "company_folder_id": company_folder_id,
                    "order_folder_id": order_folder_id,
                    "uploaded_files": uploaded_files,
                    "delivery_drive_file_id": delivery_drive_file_id,
                    "invoice_drive_file_id": invoice_drive_file_id,
                    "label_drive_file_ids": label_drive_file_ids,
                    "merged_drive_file_id": merged_drive_file_id,
                    "coc_drive_file_id": coc_drive_file_id,
                    "confirmation_result": confirmation_result,
                }
            return {"status": "skipped", "reason": "before_threshold"}
        except Exception as e:
            print("DRIVE SYNC ERROR:", repr(e))
            return {"status": "error", "error": str(e)}

    drive_sync_result = await asyncio.to_thread(_perform_finalize_drive_sync)

    def _perform_finalize_sheets_append():
        print("SHEETS: append starting")
        try:
            print("🔥 CALLING GOOGLE SHEETS")
            if getattr(invoice_doc, "number", ""):
                result = append_payment_row(
                    po,
                    delivery_doc,
                    invoice_doc,
                    source_mode=source_mode_label,
                )
                print("SHEETS: append done", result)
                return result
            return {"status": "skipped", "reason": "invoice_not_created"}
        except FileNotFoundError as e:
            print("SHEETS: append failed", repr(e))
            print("SHEETS HINT: set GOOGLE_SERVICE_ACCOUNT_JSON to an existing json file path")
            return {"error": str(e)}
        except Exception as e:
            print("SHEETS: append failed", repr(e))
            return {"error": str(e)}

    sheets_result = await asyncio.to_thread(_perform_finalize_sheets_append)

    def _perform_finalize_inventory_deduction():
        inventory_result = {"status": "skipped", "reason": "not_attempted"}
        try:
            if po.items and document_mode != "invoice_only":
                deduction_results = []
                for item in po.items:
                    if _is_shipping_like_po_item(item):
                        continue
                    current_result = deduct_quietpipe_finish_inventory(
                        description=item.description,
                        quantity=item.quantity,
                        unit=getattr(item, "unit", "") or "",
                        sandbox_run=(cfg["mode"] == "sandbox"),
                        po_number=po.po_number,
                    )
                    deduction_results.append(
                        {
                            "description": item.description,
                            "quantity": item.quantity,
                            "unit": getattr(item, "unit", "") or "",
                            "result": current_result,
                        }
                    )
                successful = [entry for entry in deduction_results if str((entry.get("result") or {}).get("status") or "").lower() == "ok"]
                total_deducted_units = 0.0
                deducted_product = ""
                for entry in successful:
                    result_payload = entry.get("result") or {}
                    deducted_product = deducted_product or str(result_payload.get("product") or "").strip()
                    try:
                        total_deducted_units += float(result_payload.get("deducted_units") or 0)
                    except Exception:
                        continue
                inventory_result = {
                    "status": "ok" if successful else "skipped",
                    "lines_checked": len(deduction_results),
                    "successful_lines": len(successful),
                    "deducted_units": total_deducted_units,
                    "product": deducted_product,
                    "results": deduction_results,
                }
                print("INVENTORY DEDUCTION:", inventory_result)
        except Exception as e:
            print("INVENTORY DEDUCTION ERROR:", repr(e))
            inventory_result = {"status": "error", "error": str(e)}
        return inventory_result

    inventory_deduction_result = await asyncio.to_thread(_perform_finalize_inventory_deduction)

    def _perform_finalize_history_upsert():
        try:
            uploaded_files = list((drive_sync_result or {}).get("uploaded_files") or [])
            order_folder_id = str((drive_sync_result or {}).get("order_folder_id") or "").strip()
            current_items_payload = [
                {
                    "description": str(item.description or "").strip(),
                    "sku": str(item.sku or "").strip(),
                    "unit": str(item.unit or "").strip(),
                    "quantity": item.quantity if item.quantity is not None else "",
                    "unit_price": item.unit_price if item.unit_price is not None else "",
                    "line_total": item.line_total if item.line_total is not None else "",
                }
                for item in (po.items or [])
            ]
            ordered_items_payload = data.get("ordered_items") if isinstance(data.get("ordered_items"), list) else current_items_payload
            partial_delivery = bool(data.get("partial_delivery"))
            partial_root_history_id = str(data.get("partial_root_history_id") or "").strip()
            if partial_delivery and not partial_root_history_id:
                partial_root_history_id = history_id
            existing_document_links = _normalize_order_history_links(
                data.get("document_links_json")
                or data.get("document_links")
                or "[]"
            )
            document_links = list(existing_document_links)
            for uploaded in uploaded_files:
                if not isinstance(uploaded, dict):
                    continue
                name = str(uploaded.get("name") or "").strip()
                url = str(uploaded.get("web_view_link") or uploaded.get("webContentLink") or uploaded.get("web_content_link") or "").strip()
                if not name and not url:
                    continue
                if any(str(link.get("name") or "").strip() == name and str(link.get("url") or "").strip() == url for link in document_links):
                    continue
                document_links.append({"name": name, "url": url})
            return upsert_order_history_row(
                {
                    "history_id": history_id,
                    "created_at": str(data.get("created_at") or "").strip() or datetime.now().isoformat(timespec="seconds"),
                    "input_source": str(data.get("input_source") or "").strip() or ("ידני" if manual_entry else "קובץ"),
                    "mode": source_mode_label,
                    "customer_name": po.customer_name,
                    "customer_id": po.customer_id or "",
                    "customer_email": po.customer_email or "",
                    "customer_phone": po.customer_phone or "",
                    "delivery_address": po.delivery_address or "",
                    "project": str((po.extra or {}).get("project") or "").strip(),
                    "contact_name": str((po.extra or {}).get("contact_name") or "").strip(),
                    "contact_phone": str((po.extra or {}).get("contact_phone") or "").strip(),
                    "payment_terms_days": po.payment_terms_days if po.payment_terms_days is not None else "",
                    "payment_terms_label": po.payment_terms_label or "",
                    "po_number": po.po_number,
                    "po_date": po.po_date or "",
                    "quote_number": str(data.get("quote_number") or "").strip(),
                    "fulfillment_id": fulfillment_id,
                    "document_mode": document_mode,
                    "order_status_tag": _order_status_tag_for_mode(document_mode, getattr(invoice_doc, "number", "")),
                    "delivery_document_number": getattr(delivery_doc, "number", ""),
                    "delivery_document_id": getattr(delivery_doc, "document_id", ""),
                    "tax_invoice_number": getattr(invoice_doc, "number", ""),
                    "tax_invoice_document_id": getattr(invoice_doc, "document_id", ""),
                    "item_description": po.items[0].description if po.items else "",
                    "item_sku": po.items[0].sku if po.items else "",
                    "item_unit": str((po.extra or {}).get("item_unit") or "").strip(),
                    "item_quantity": po.items[0].quantity if po.items else "",
                    "item_unit_price": po.items[0].unit_price if po.items else "",
                    "item_line_total": po.items[0].line_total if po.items else "",
                    "subtotal": po.subtotal or "",
                    "vat": po.vat or "",
                    "total": po.total or "",
                    "footer_text": str((po.extra or {}).get("footer_text") or "").strip(),
                    "items_json": json.dumps(current_items_payload, ensure_ascii=False),
                    "ordered_items_json": json.dumps(ordered_items_payload, ensure_ascii=False),
                    "partial_delivery": "כן" if partial_delivery else "לא",
                    "partial_root_history_id": partial_root_history_id,
                    "label_split_rows_json": json.dumps(data.get("label_split_rows") or [], ensure_ascii=False),
                    "order_drive_folder_id": order_folder_id,
                    "order_drive_folder_url": f"https://drive.google.com/drive/folders/{order_folder_id}" if order_folder_id else "",
                    "delivery_drive_file_id": str((drive_sync_result or {}).get("delivery_drive_file_id") or "").strip(),
                    "invoice_drive_file_id": str((drive_sync_result or {}).get("invoice_drive_file_id") or "").strip(),
                    "merged_drive_file_id": str((drive_sync_result or {}).get("merged_drive_file_id") or "").strip(),
                    "coc_drive_file_id": str((drive_sync_result or {}).get("coc_drive_file_id") or "").strip(),
                    "document_links_json": document_links,
                    "delivery_confirmation_sent": str(data.get("delivery_confirmation_sent") or "לא").strip() or "לא",
                    "updated_at": datetime.now().isoformat(timespec="seconds"),
                }
            )
        except Exception as e:
            print("ORDER HISTORY ERROR:", repr(e))
            return {"status": "error", "error": str(e)}

    history_result = await asyncio.to_thread(_perform_finalize_history_upsert)

    whatsapp_send_result = (
        {"status": "skipped", "reason": "ui_test_skip_whatsapp"}
        if skip_whatsapp
        else (await whatsapp_send_task if whatsapp_send_task else {"status": "skipped", "reason": "no_files"})
    )

    try:
        if source_mode_label == "PROD" and str(getattr(invoice_doc, "number", "") or "").strip():
            _invalidate_finance_state_cache(schedule_refresh=True)
    except Exception as exc:
        log_handled_error("finance state invalidate after finalize failed", exc)

    working_order_cleanup_result = {"status": "skipped", "reason": "not_requested"}
    working_order_row_id = str(data.get("working_order_row_id") or "").strip()
    if source_mode_label == "PROD" and working_order_row_id:
        try:
            working_rows = load_working_order_rows()
            remaining_rows = [
                row for row in working_rows
                if str(row.get("row_id") or "").strip() != working_order_row_id
            ]
            if len(remaining_rows) != len(working_rows):
                save_result = save_working_order_rows(remaining_rows)
                working_order_cleanup_result = {
                    "status": "ok",
                    "row_id": working_order_row_id,
                    "rows_remaining": len(remaining_rows),
                    "save_result": save_result,
                }
            else:
                working_order_cleanup_result = {"status": "skipped", "reason": "row_not_found", "row_id": working_order_row_id}
        except Exception as exc:
            working_order_cleanup_result = {"status": "error", "error": str(exc), "row_id": working_order_row_id}
            log_handled_error("working order cleanup after finalize failed", exc)

    label_files = [
        str(Path(path).relative_to(OUTPUT_DIR))
        for path in label_pdf_paths
        if path and Path(path).exists()
    ]
    all_generated_files = [
        value
        for value in [
            str(Path(delivery_pdf_path).relative_to(OUTPUT_DIR)) if delivery_pdf_path else "",
            str(Path(invoice_pdf_path).relative_to(OUTPUT_DIR)) if invoice_pdf_path else "",
            *label_files,
            str(Path(merged_pdf_path).relative_to(OUTPUT_DIR)) if merged_pdf_path else "",
            str(Path(source_po_copy_path).relative_to(OUTPUT_DIR)) if source_po_copy_path else "",
            str(Path(transport_label_output_path).relative_to(OUTPUT_DIR)) if transport_label_output_path else "",
            str(Path(coc_local_path).relative_to(OUTPUT_DIR)) if coc_local_path else "",
        ]
        if value
    ]

    return JSONResponse(
        {
            "status": "ok",
            "mode": cfg["mode"],
            "document_mode": document_mode,
            "fulfillment_id": fulfillment_id,
            "delivery_document_id": delivery_doc.document_id,
            "delivery_document_number": delivery_doc.number,
            "delivery_document_url": delivery_doc.url,
            "delivery_pdf_path": str(delivery_pdf_path) if delivery_pdf_path else "",
            "invoice_document_id": invoice_doc.document_id,
            "invoice_document_number": invoice_doc.number,
            "invoice_document_url": invoice_doc.url,
            "invoice_pdf_path": str(invoice_pdf_path) if invoice_pdf_path else "",
            "files": [
                str(Path(delivery_pdf_path).relative_to(OUTPUT_DIR)) if delivery_pdf_path else "",
                str(Path(invoice_pdf_path).relative_to(OUTPUT_DIR)) if invoice_pdf_path else "",
            ],
            "label_files": label_files,
            "merged_file": str(Path(merged_pdf_path).relative_to(OUTPUT_DIR)) if merged_pdf_path else "",
            "transport_label_file": str(Path(transport_label_output_path).relative_to(OUTPUT_DIR)) if transport_label_output_path else "",
            "source_po_file": str(Path(source_po_copy_path).relative_to(OUTPUT_DIR)) if source_po_copy_path else "",
            "coc_file": str(Path(coc_local_path).relative_to(OUTPUT_DIR)) if coc_local_path else "",
            "all_generated_files": all_generated_files,
            "sent_to_dad": send_to_dad,
            "manual_entry": manual_entry,
            "customer_sync_result": customer_sync_result,
            "customer_created": (
                str((customer_sync_result or {}).get("status") or "").strip().lower() == "created"
                or (
                    bool((customer_sync_result or {}).get("missing_before"))
                    and bool(
                        str((customer_sync_result or {}).get("customer_guid") or "").strip()
                        or str((customer_sync_result or {}).get("customer_name") or "").strip()
                    )
                )
            ),
            "customer_created_name": str((customer_sync_result or {}).get("customer_name") or po.customer_name or "").strip(),
            "sheets_status": "ok" if sheets_result and "error" not in sheets_result else "error",
            "sheets_result": sheets_result,
            "inventory_deduction_result": inventory_deduction_result,
            "drive_sync_result": drive_sync_result,
            "label_drive_file_ids": list((drive_sync_result or {}).get("label_drive_file_ids") or []),
            "history_result": history_result,
            "whatsapp_send_result": whatsapp_send_result,
            "working_order_cleanup_result": working_order_cleanup_result,
        }
    )
